"""
LLVM IR code generation for fastpy.

Takes a Python AST and generates LLVM IR that calls into the fastpy
C runtime. The generated IR defines a `fastpy_main()` function that
the runtime's `main()` calls.

Milestone 1: print() with literal arguments (int, float, str, bool, None).
Milestone 2: variables, assignment, multi-statement programs.
"""

from __future__ import annotations

import ast
from dataclasses import dataclass, field
from typing import Any

import llvmlite.ir as ir


# LLVM type aliases
i8 = ir.IntType(8)
i32 = ir.IntType(32)
i64 = ir.IntType(64)
double = ir.DoubleType()
void = ir.VoidType()
i8_ptr = ir.PointerType(i8)

# Tagged value: mirrors C FpyValue struct { int tag; union { i64 i; double f; char* s; int b; FpyList* list; FpyObj* obj; } data; }
# The union is 8 bytes on 64-bit; the tag is 4 bytes plus 4 bytes padding.
# LLVM literal struct {i32, i64} — LLVM handles alignment; on most ABIs this
# is passed/returned by value in registers (or by hidden pointer for MSVC x64).
fpy_val = ir.LiteralStructType([i32, i64])
fpy_val_ptr = ir.PointerType(fpy_val)

# FpyObj layout — must match struct FpyObj in objects.h:
#   int class_id;                       (4 bytes + 4 padding)
#   FpyValue *slots;                    (8-byte pointer)
#   FpyObjAttrs *dynamic_attrs;         (8-byte pointer, NULL unless used)
# Post-Phase-21: dynamic attr storage moved out-of-line into a heap
# side-table so FpyObj is ~24 bytes (was ~1560). Used for direct-struct
# IR access to obj->slots[idx] (skips the fastpy_obj_get_slot /
# fastpy_obj_set_slot function call overhead).
# FpyObj layout on x64 (MSVC, sizeof=96):
#   offset  0: i32 refcount  (+4 pad)
#   offset  8: FpyGCNode (24 bytes: gc_prev, gc_next, gc_refs+flags)
#   offset 32: i32 magic + i32 class_id
#   offset 40: ptr dynamic_attrs
#   offset 48: ptr weakref_list
#   offset 56: CRITICAL_SECTION lock (40 bytes)
# NOTE: the 'slots' pointer field was removed — slots are always inline
# at (obj + 1), accessed via GEP arithmetic (zero pointer loads).
# ALL fields must be present so that sizeof(fpy_obj_type) == sizeof(FpyObj)
# — required for the inline-slot optimization (GEP obj, [1] → first slot).
fpy_obj_type = ir.LiteralStructType([
    i64,                             # 0: refcount (i32) + padding = 8
    i64,                             # 1: gc_node.gc_prev
    i64,                             # 2: gc_node.gc_next
    i64,                             # 3: gc_node.gc_refs (i32) + gc_flags+gc_type (i32)
    i64,                             # 4: magic (i32) + class_id (i32)
    i8_ptr,                          # 5: dynamic_attrs
    i8_ptr,                          # 6: weakref_list
    ir.ArrayType(i64, 5),            # 7: lock (CRITICAL_SECTION = 40 bytes on x64)
])
fpy_obj_ptr = ir.PointerType(fpy_obj_type)

# FpyClassDef layout — must match struct FpyClassDef in objects.h:
# FpyClassDef layout on x64:
#   offset  0: int class_id (i32) + 4 padding
#   offset  8: const char *name (i8*)
#   offset 16: int parent_id (i32) + 4 padding
#   offset 24: FpyMethodDef *methods (i8*)
#   offset 32: int method_count (i32) + int slot_count (i32)
#   offset 40: const char **slot_names (i8*)
#   offset 48: void (*destructor)(FpyObj*) (i8*)
#   offset 56: void **vtable (i8*)
#   offset 64: int vtable_size (i32) + 4 padding
#   offset 72: int *mro (pointer to C3-linearized MRO array)
#   offset 80: int mro_count (i32) + 4 padding
# Modeled as i64 + pointer pairs to match alignment (88 bytes total).
fpy_classdef_type = ir.LiteralStructType([
    i64,    # 0: class_id(i32) + padding → offset 0
    i8_ptr, # 1: name → offset 8
    i64,    # 2: parent_id(i32) + padding → offset 16
    i8_ptr, # 3: methods → offset 24
    i64,    # 4: method_count(i32) + slot_count(i32) → offset 32
    i8_ptr, # 5: slot_names → offset 40
    i8_ptr, # 6: destructor → offset 48
    i8_ptr, # 7: vtable (void**) → offset 56
    i64,    # 8: vtable_size(i32) + padding → offset 64
    i8_ptr, # 9: mro (int*) → offset 72
    i64,    # 10: mro_count(i32) + padding → offset 80
])

# FpyList layout — must match struct FpyList in objects.h:
# FpyList layout on x64:
#   offset  0: i32 refcount  (+ 4 padding)
#   offset  8: FpyGCNode     (24 bytes: gc_prev, gc_next, gc_refs+flags)
#   offset 32: ptr items     (FpyValue *)
#   offset 40: i64 length
#   offset 48: i64 capacity
#   offset 56: i32 is_tuple  (+ padding + lock)
# Represent as fields matching alignment (each i64-sized):
fpy_list_type = ir.LiteralStructType([
    i64,                             # refcount (i32) + padding
    i64,                             # gc_node.gc_prev
    i64,                             # gc_node.gc_next
    i64,                             # gc_node.gc_refs + flags
    fpy_val_ptr,                     # items (FpyValue *)
    i64,                             # length
    i64,                             # capacity
    i64,                             # is_tuple + padding + lock
])
fpy_list_ptr = ir.PointerType(fpy_list_type)
# Field indices for GEP:
_FPY_LIST_ITEMS = 4
_FPY_LIST_LENGTH = 5

# Tag constants — MUST match the C #defines in objects.h
FPY_TAG_INT = 0
FPY_TAG_FLOAT = 1
FPY_TAG_STR = 2
FPY_TAG_BOOL = 3
FPY_TAG_NONE = 4
FPY_TAG_LIST = 5
FPY_TAG_OBJ = 6
FPY_TAG_DICT = 7
FPY_TAG_BYTES = 8
FPY_TAG_SET = 9
FPY_TAG_BIGINT = 10
FPY_TAG_COMPLEX = 11
FPY_TAG_DECIMAL = 12
FPY_TAG_UNDEF = -1       # sentinel: variable alloca exists but never assigned


# ── Phase 1 of refactor: TypedValue foundation ───────────────────────
# These types exist alongside the old string-tag system. New code should
# use TypedValue; old code continues to work unchanged.

from enum import Enum, auto

class VKind(Enum):
    """Value type kinds — replaces string tags like 'int', 'str', 'list:int'."""
    INT = auto()
    FLOAT = auto()
    BOOL = auto()
    STR = auto()
    NONE = auto()
    LIST = auto()
    DICT = auto()
    SET = auto()
    TUPLE = auto()
    OBJ = auto()       # native FpyObj (user-defined class instance)
    PYOBJ = auto()      # CPython PyObject* (bridge object)
    DECIMAL = auto()
    COMPLEX = auto()
    BIGINT = auto()
    CLOSURE = auto()
    BYTES = auto()      # bytes (stored as char* like str, but tagged BYTES)
    FVALUE = auto()     # runtime-typed FpyValue {tag, data}
    UNKNOWN = auto()    # compile-time type not known
    # Specialized subtypes — each needs distinct dispatch at compile time
    PATH = auto()       # pathlib.Path (bridge object with native handlers)
    COUNTER = auto()    # collections.Counter (dict-like with count semantics)
    DEFAULTDICT = auto()  # collections.defaultdict (dict with factory)
    DEQUE = auto()      # collections.deque (list-like with O(1) popleft)
    CHAINMAP = auto()   # collections.ChainMap (layered dict)
    NATIVE_MOD = auto()  # imported native module (e.g. json, os, math)
    NATIVE_FUNC = auto()  # from-imported native function (e.g. from math import sqrt)
    LOGGER = auto()     # logging.Logger instance
    MIXED = auto()      # multiple types possible — runtime dispatch needed
    CELL = auto()       # closure cell (heap-allocated mutable capture)
    CLS = auto()        # classmethod `cls` parameter (i32 class_id)

    @property
    def is_ptr(self) -> bool:
        return self in (VKind.STR, VKind.BYTES, VKind.LIST, VKind.DICT,
                        VKind.SET, VKind.TUPLE, VKind.OBJ, VKind.PYOBJ,
                        VKind.DECIMAL, VKind.COMPLEX, VKind.BIGINT,
                        VKind.CLOSURE, VKind.CELL, VKind.PATH,
                        VKind.COUNTER, VKind.DEFAULTDICT, VKind.DEQUE,
                        VKind.CHAINMAP, VKind.NATIVE_MOD, VKind.LOGGER)

    @property
    def fpy_tag(self) -> int:
        """FPY_TAG_* constant for runtime dispatch."""
        return {
            VKind.INT: 0, VKind.FLOAT: 1, VKind.STR: 2, VKind.BOOL: 3,
            VKind.NONE: 4, VKind.LIST: 5, VKind.OBJ: 6, VKind.DICT: 7,
            VKind.BYTES: 8, VKind.SET: 9, VKind.BIGINT: 10,
            VKind.COMPLEX: 11, VKind.DECIMAL: 12, VKind.TUPLE: 5,
            VKind.PYOBJ: 6, VKind.CLOSURE: 0,
            VKind.PATH: 6, VKind.COUNTER: 7, VKind.DEFAULTDICT: 7,
            VKind.DEQUE: 5, VKind.CHAINMAP: 6,
            VKind.NATIVE_MOD: 6, VKind.LOGGER: 6,
        }.get(self, 0)

    @property
    def llvm_type(self):
        """Expected LLVM IR type for this kind."""
        if self == VKind.FLOAT: return double
        if self == VKind.BOOL: return i32
        if self == VKind.FVALUE: return fpy_val
        if self.is_ptr: return i8_ptr
        return i64

    @property
    def old_tag(self) -> str:
        """Convert to old-style string tag for compatibility."""
        return {
            VKind.INT: "int", VKind.FLOAT: "float", VKind.BOOL: "bool",
            VKind.STR: "str", VKind.BYTES: "bytes", VKind.NONE: "none",
            VKind.LIST: "list:int", VKind.DICT: "dict", VKind.SET: "set",
            VKind.TUPLE: "tuple", VKind.OBJ: "obj", VKind.PYOBJ: "pyobj",
            VKind.DECIMAL: "decimal", VKind.COMPLEX: "complex",
            VKind.BIGINT: "bigint", VKind.CLOSURE: "closure",
            VKind.FVALUE: "int", VKind.UNKNOWN: "int",
            VKind.PATH: "path", VKind.COUNTER: "counter",
            VKind.DEFAULTDICT: "defaultdict", VKind.DEQUE: "deque",
            VKind.NATIVE_MOD: "native_mod", VKind.NATIVE_FUNC: "native_func",
            VKind.LOGGER: "logger", VKind.MIXED: "mixed",
        }.get(self, "int")


# Grouped VKind sets for dispatch: list-like containers (support iteration,
# append, len), dict-like containers (support key lookup, items, values).
_LIST_LIKE = (VKind.LIST, VKind.TUPLE, VKind.DEQUE)
_DICT_LIKE = (VKind.DICT, VKind.COUNTER, VKind.DEFAULTDICT)


class ValueType:
    """Static type information for a compiled value.

    Phase 3: this class is designed to be a drop-in replacement for string
    type tags in self.variables. It supports string comparison operators
    (==, in, startswith, split) so existing code that reads variables[name][1]
    keeps working during the gradual migration to VKind-based dispatch."""

    __slots__ = ('kind', 'elem_type', 'class_name', '_tag_cache')

    def __init__(self, kind: VKind, elem_type: 'ValueType | None' = None,
                 class_name: str | None = None):
        self.kind = kind
        self.elem_type = elem_type
        self.class_name = class_name
        self._tag_cache: str | None = None

    # --- String tag conversion ---
    # _to_tag() converts ValueType to the old string format for CSA boundaries,
    # debug output, and FuncInfo.ret_tag interop. The string equality,
    # startswith/split/__contains__ compat methods were removed in C2.

    def _to_tag(self) -> str:
        """Convert to old-style string tag for backward compatibility."""
        if self._tag_cache is not None:
            return self._tag_cache
        _kind_to_tag = {
            VKind.INT: "int", VKind.FLOAT: "float", VKind.BOOL: "bool",
            VKind.STR: "str", VKind.BYTES: "bytes", VKind.NONE: "none",
            VKind.DICT: "dict", VKind.SET: "set", VKind.TUPLE: "tuple",
            VKind.OBJ: "obj", VKind.PYOBJ: "pyobj", VKind.DECIMAL: "decimal",
            VKind.COMPLEX: "complex", VKind.BIGINT: "bigint",
            VKind.CLOSURE: "closure", VKind.CELL: "cell",
            VKind.CLS: "cls", VKind.FVALUE: "int",
            VKind.UNKNOWN: "int", VKind.PATH: "path",
            VKind.COUNTER: "counter", VKind.DEFAULTDICT: "defaultdict",
            VKind.DEQUE: "deque", VKind.CHAINMAP: "chainmap",
            VKind.NATIVE_MOD: "native_mod",
            VKind.NATIVE_FUNC: "native_func", VKind.LOGGER: "logger",
            VKind.MIXED: "mixed",
        }
        base = _kind_to_tag.get(self.kind, "int")
        if self.kind == VKind.LIST and self.elem_type:
            base = f"list:{self.elem_type._to_tag()}"
        elif self.kind == VKind.LIST:
            base = "list"
        elif self.kind == VKind.TUPLE and self.elem_type:
            base = f"tuple:{self.elem_type._to_tag()}"
        self._tag_cache = base
        return base

    def __eq__(self, other):
        if isinstance(other, ValueType):
            return self.kind == other.kind and self.elem_type == other.elem_type
        if isinstance(other, VKind):
            return self.kind == other
        return NotImplemented

    def __ne__(self, other):
        result = self.__eq__(other)
        if result is NotImplemented:
            return result
        return not result

    def __hash__(self):
        return hash((self.kind, self.elem_type))

    def __repr__(self):
        return f"ValueType({self._to_tag()})"

    def __str__(self):
        return self._to_tag()

    def __bool__(self):
        return True  # a ValueType is always truthy (non-empty tag)

    # NOTE: String protocol methods (startswith, split, __contains__)
    # were removed in C2. All codegen-layer code now uses VKind-based
    # comparisons instead of treating ValueType as a string.

    # Support `tag in ("str", "int", ...)` membership tests
    # This is handled by __eq__ above via the tuple's __contains__.

    @staticmethod
    def from_old_tag(tag: str | None) -> 'ValueType':
        """Convert old string tag to ValueType (for migration)."""
        if tag is None:
            return ValueType(VKind.UNKNOWN)
        if isinstance(tag, ValueType):
            return tag  # already a ValueType
        _map = {
            "int": VKind.INT, "float": VKind.FLOAT, "bool": VKind.BOOL,
            "str": VKind.STR, "none": VKind.NONE, "dict": VKind.DICT,
            "set": VKind.SET, "tuple": VKind.TUPLE, "obj": VKind.OBJ,
            "pyobj": VKind.PYOBJ, "decimal": VKind.DECIMAL,
            "complex": VKind.COMPLEX, "bigint": VKind.BIGINT,
            "bytes": VKind.BYTES, "closure": VKind.CLOSURE,
            "mixed": VKind.MIXED, "fvalue": VKind.FVALUE,
            # Specialized collection subtypes — each has its own VKind even
            # though they share runtime structs (e.g. counter/defaultdict use
            # FpyDict, chainmap uses FpyObj).  The VKind distinction drives
            # compile-time type checks (_is_counter_expr, etc.).
            "counter": VKind.COUNTER, "defaultdict": VKind.DEFAULTDICT,
            "deque": VKind.DEQUE,
            "chainmap": VKind.CHAINMAP, "logger": VKind.LOGGER,
            "ptr": VKind.LIST,
            "path": VKind.PATH, "native_func": VKind.NATIVE_FUNC,
            "native_mod": VKind.NATIVE_MOD, "cls": VKind.CLS,
            "cell": VKind.CELL, "namedtuple_type": VKind.INT,
        }
        if tag.startswith("list"):
            if ":" in tag:
                elem = tag.split(":", 1)[1]
                return ValueType(VKind.LIST, elem_type=ValueType.from_old_tag(elem))
            return ValueType(VKind.LIST)  # bare "list" — elem_type unknown
        if tag.startswith("ptr:"):
            elem = tag.split(":", 1)[1]
            return ValueType(VKind.LIST, elem_type=ValueType.from_old_tag(elem))
        if tag.startswith("dict:"):
            return ValueType(VKind.DICT)
        if tag.startswith("tuple:"):
            elem = tag.split(":", 1)[1]
            return ValueType(VKind.TUPLE, elem_type=ValueType.from_old_tag(elem))
        kind = _map.get(tag, VKind.UNKNOWN)
        vt = ValueType(kind)
        # Preserve original tag for aliases (e.g. "bytes" -> VKind.STR)
        # so we can distinguish bytes from str at the FV wrapping level.
        vt._tag_cache = tag
        return vt


@dataclass
class TypedValue:
    """An LLVM IR value paired with its compile-time type information.
    This is the core type that all expression emitters will return
    after the refactor is complete."""
    val: ir.Value          # the LLVM IR value
    vtype: ValueType       # its static type

    def as_ptr(self, builder) -> ir.Value:
        """Coerce to i8* pointer."""
        if isinstance(self.val.type, ir.PointerType):
            return self.val
        if isinstance(self.val.type, ir.IntType):
            return builder.inttoptr(self.val, i8_ptr)
        if isinstance(self.val.type, ir.LiteralStructType) and self.val.type == fpy_val:
            data = builder.extract_value(self.val, 1)
            return builder.inttoptr(data, i8_ptr)
        return builder.inttoptr(builder.bitcast(self.val, i64), i8_ptr)

    def as_i64(self, builder) -> ir.Value:
        """Coerce to i64."""
        if isinstance(self.val.type, ir.IntType) and self.val.type.width == 64:
            return self.val
        if isinstance(self.val.type, ir.PointerType):
            return builder.ptrtoint(self.val, i64)
        if isinstance(self.val.type, ir.IntType):
            return builder.zext(self.val, i64) if self.val.type.width < 64 \
                else builder.trunc(self.val, i64)
        if isinstance(self.val.type, ir.DoubleType):
            return builder.bitcast(self.val, i64)
        if isinstance(self.val.type, ir.LiteralStructType) and self.val.type == fpy_val:
            return builder.extract_value(self.val, 1)
        return self.val

    def as_fv(self, builder) -> ir.Value:
        """Coerce to FpyValue {i32, i64} struct."""
        if (isinstance(self.val.type, ir.LiteralStructType)
                and self.val.type == fpy_val):
            return self.val
        tag = ir.Constant(i32, self.vtype.kind.fpy_tag)
        data = self.as_i64(builder)
        fv = ir.Constant(fpy_val, ir.Undefined)
        fv = builder.insert_value(fv, tag, 0)
        fv = builder.insert_value(fv, data, 1)
        return fv

    def coerce_to(self, builder, target_llvm_type) -> ir.Value:
        """Coerce to any LLVM type."""
        if self.val.type == target_llvm_type:
            return self.val
        if isinstance(target_llvm_type, ir.PointerType):
            return self.as_ptr(builder)
        if target_llvm_type == i64:
            return self.as_i64(builder)
        if target_llvm_type == i32:
            return builder.trunc(self.as_i64(builder), i32)
        if target_llvm_type == double:
            if isinstance(self.val.type, ir.IntType):
                return builder.sitofp(self.val, double)
            return self.val
        if target_llvm_type == fpy_val:
            return self.as_fv(builder)
        return self.val


# ── End Phase 1 foundation ───────────────────────────────────────────


@dataclass
class FuncInfo:
    """Metadata about a user-defined function."""
    func: ir.Function          # LLVM function
    ret_tag: str               # "int", "float", "void"
    param_count: int           # total parameter count
    defaults: list[ast.expr]   # AST nodes for default values (right-aligned)
    min_args: int              # minimum positional args = param_count - len(defaults)
    is_vararg: bool = False    # True if function uses *args
    is_kwarg: bool = False     # True if function uses **kwargs
    param_names: list = None   # list[str] — original Python parameter names
    # Post-refactor: LLVM signature is all FpyValue. These hold the *static*
    # types the body expects each param to have, used for unwrap-at-entry.
    # None means "don't convert — pass FpyValue through" (future full polymorphism).
    static_param_types: list = None  # list[ir.Type]
    static_ret_type: object = None   # ir.Type (the bare type the body produces)
    # If True, this function was declared with the post-refactor FpyValue ABI.
    # During migration, some functions (lambdas, vararg) stay on the old ABI.
    uses_fv_abi: bool = False
    # True if any return path yields None (return None / bare return).
    # Used to decide whether the call site should preserve the raw FpyValue
    # (to keep the NONE tag) rather than unwrapping to a bare LLVM value.
    may_return_none: bool = False
    # True if function uses bare-type ABI (direct i64/double params and
    # return) instead of FpyValue wrappers.  Enables LLVM to constant-fold,
    # inline, and apply SROA to tight loops and simple arithmetic functions.
    uses_bare_abi: bool = False
    # Number of keyword-only params (after *args) — used by _emit_user_call
    # to correctly partition args vs kwonly when calling vararg functions.
    n_kwonly: int = 0
    # Pre-evaluated globals for mutable defaults (list, dict, set literals).
    # Parallel to `defaults` — entry is ir.GlobalVariable or None.
    # Python evaluates defaults once at def-time; without caching, mutable
    # defaults like `def f(x=[])` would create a fresh object each call.
    default_globals: list = None


@dataclass
class ClassInfo:
    """Metadata about a user-defined class."""
    name: str
    class_id_global: ir.GlobalVariable  # LLVM global holding the runtime class_id
    methods: dict[str, ir.Function]     # method_name -> LLVM function
    parent_name: str | None             # parent class name or None
    init_arg_count: int                 # number of __init__ args (excluding self)
    init_defaults: list = None          # AST nodes for __init__ default values (right-aligned)
    init_default_globals: list = None   # Pre-evaluated globals for mutable __init__ defaults
    method_asts: dict = None            # method_name -> ast.FunctionDef for return-type inference
    classmethods: set = None            # set of method names marked @classmethod
    staticmethods: set = None           # set of method names marked @staticmethod
    properties: set = None              # set of method names marked @property
    match_args: list = None             # __match_args__ tuple entries (list[str])
    own_method_names: set = None        # methods defined in this class body (not inherited)
    abstract_methods: set = None        # methods decorated with @abstractmethod

# Type tag constants for our tagged value system (future use)
TAG_INT = 0
TAG_FLOAT = 1
TAG_STR = 2
TAG_BOOL = 3
TAG_NONE = 4


class _GenVarRewriter(ast.NodeTransformer):
    """AST transformer that rewrites local variable references into
    self._<var> attribute accesses for generator state-machine classes.

    Only names in the `local_vars` set are rewritten. Everything else
    (builtins, class names, global functions) is left unchanged.
    """

    def __init__(self, local_vars: set[str]):
        self._local_vars = local_vars

    def visit_Name(self, node: ast.Name) -> ast.AST:
        # Only rewrite names that are known local variables
        if node.id not in self._local_vars:
            return node
        # Don't rewrite 'self' — it's the method parameter
        if node.id == "self":
            return node
        # Don't rewrite '_sent' — it's the send() parameter
        if node.id == "_sent":
            return node

        attr_name = f"_{node.id}"
        if isinstance(node.ctx, ast.Store):
            # x = ... -> self._x = ...
            new_node = ast.Attribute(
                value=ast.Name(id="self", ctx=ast.Load()),
                attr=attr_name,
                ctx=ast.Store())
        elif isinstance(node.ctx, ast.Del):
            new_node = ast.Attribute(
                value=ast.Name(id="self", ctx=ast.Load()),
                attr=attr_name,
                ctx=ast.Del())
        else:
            # ... = x -> ... = self._x
            new_node = ast.Attribute(
                value=ast.Name(id="self", ctx=ast.Load()),
                attr=attr_name,
                ctx=ast.Load())
        return ast.copy_location(new_node, node)

    def visit_FunctionDef(self, node: ast.FunctionDef) -> ast.AST:
        # Don't recurse into nested function definitions — their
        # local variables are their own scope
        return node


class _SafeIRBuilder(ir.IRBuilder):
    """IRBuilder subclass that auto-coerces type mismatches in call().

    When a function expects i8* (pointer) but receives i64 (integer), or
    vice versa, this builder automatically inserts inttoptr/ptrtoint
    conversions. This prevents LLVM type errors from crashing compilation
    when the codegen doesn't know the exact type of a value (e.g., values
    loaded from FpyValue that could be either pointers or scalars).

    Phase E1 audit: coercion_count tracks how many auto-coercions happen
    per compilation. High counts indicate callers that should be fixed to
    produce correct types directly."""

    coercion_count: int = 0  # class-level counter for audit
    # E1: per-function coercion tracking (enabled by FASTPY_COERCION_DEBUG=1)
    _coercion_sites: dict = {}  # {fn_name: {(arg_idx, from_type, to_type): count}}
    _coercion_debug: bool = False

    @classmethod
    def enable_coercion_debug(cls):
        cls._coercion_debug = True
        cls._coercion_sites = {}

    @classmethod
    def coercion_report(cls) -> str:
        """Return a summary of coercion sites, sorted by frequency."""
        if not cls._coercion_sites:
            return f"Total coercions: {cls.coercion_count} (no site details)"
        lines = [f"Total coercions: {cls.coercion_count}"]
        flat = []
        for fn, sites in cls._coercion_sites.items():
            for (idx, ft, tt), count in sites.items():
                flat.append((count, fn, idx, ft, tt))
        flat.sort(reverse=True)
        for count, fn, idx, ft, tt in flat[:30]:
            lines.append(f"  {count:5d}x  {fn}  arg[{idx}]: {ft} → {tt}")
        return "\n".join(lines)

    def call(self, fn, args, name='', cconv=None, tail=False, fastmath=(),
             attrs=(), arg_attrs=None):
        # Auto-coerce argument types to match function signature
        if hasattr(fn, 'function_type'):
            param_types = fn.function_type.args
            coerced = list(args)
            for i, (arg, ptype) in enumerate(zip(coerced, param_types)):
                if arg.type == ptype:
                    continue
                _SafeIRBuilder.coercion_count += 1
                if _SafeIRBuilder._coercion_debug:
                    fn_name = getattr(fn, 'name', str(fn))
                    key = (i, str(arg.type), str(ptype))
                    sites = _SafeIRBuilder._coercion_sites.setdefault(fn_name, {})
                    sites[key] = sites.get(key, 0) + 1
                # i64 → i8* (pointer)
                if (isinstance(ptype, ir.PointerType)
                        and isinstance(arg.type, ir.IntType)
                        and arg.type.width == 64):
                    coerced[i] = super().inttoptr(arg, ptype)
                # i8* → i64
                elif (isinstance(ptype, ir.IntType) and ptype.width == 64
                      and isinstance(arg.type, ir.PointerType)):
                    coerced[i] = super().ptrtoint(arg, ptype)
                # i32 → i64 (widen)
                elif (isinstance(ptype, ir.IntType) and ptype.width == 64
                      and isinstance(arg.type, ir.IntType)
                      and arg.type.width < 64):
                    coerced[i] = super().zext(arg, ptype)
                # int → int (widen or narrow)
                elif (isinstance(ptype, ir.IntType)
                      and isinstance(arg.type, ir.IntType)
                      and ptype.width != arg.type.width):
                    if arg.type.width < ptype.width:
                        coerced[i] = super().zext(arg, ptype)
                    else:
                        coerced[i] = super().trunc(arg, ptype)
                # i8* → i32 (ptrtoint + trunc)
                elif (isinstance(ptype, ir.IntType) and ptype.width == 32
                      and isinstance(arg.type, ir.PointerType)):
                    tmp = super().ptrtoint(arg, i64)
                    coerced[i] = super().trunc(tmp, ptype)
                # i32 → i8* (zext + inttoptr)
                elif (isinstance(ptype, ir.PointerType)
                      and isinstance(arg.type, ir.IntType)
                      and arg.type.width < 64):
                    tmp = super().zext(arg, i64)
                    coerced[i] = super().inttoptr(tmp, ptype)
                # {i32, i64} FpyValue → i8* (extract data, inttoptr)
                elif (isinstance(ptype, ir.PointerType)
                      and isinstance(arg.type, ir.LiteralStructType)
                      and arg.type == fpy_val):
                    data = super().extract_value(arg, 1)
                    coerced[i] = super().inttoptr(data, ptype)
                # {i32, i64} FpyValue → i64 (extract data)
                elif (isinstance(ptype, ir.IntType) and ptype.width == 64
                      and isinstance(arg.type, ir.LiteralStructType)
                      and arg.type == fpy_val):
                    coerced[i] = super().extract_value(arg, 1)
                # double → i64 (bitcast)
                elif (isinstance(ptype, ir.IntType) and ptype.width == 64
                      and isinstance(arg.type, ir.DoubleType)):
                    coerced[i] = super().bitcast(arg, ptype)
                # i64 → double (bitcast)
                elif (isinstance(ptype, ir.DoubleType)
                      and isinstance(arg.type, ir.IntType)):
                    coerced[i] = super().bitcast(arg, ptype)
                # double → i8* (bitcast to i64, then inttoptr)
                elif (isinstance(ptype, ir.PointerType)
                      and isinstance(arg.type, ir.DoubleType)):
                    tmp = super().bitcast(arg, i64)
                    coerced[i] = super().inttoptr(tmp, ptype)
                # i8* → double (ptrtoint, then bitcast)
                elif (isinstance(ptype, ir.DoubleType)
                      and isinstance(arg.type, ir.PointerType)):
                    tmp = super().ptrtoint(arg, i64)
                    coerced[i] = super().bitcast(tmp, ptype)
                # i64 → {i32,i64} FpyValue (wrap as INT)
                elif (isinstance(ptype, ir.LiteralStructType) and ptype == fpy_val
                      and isinstance(arg.type, ir.IntType) and arg.type.width == 64):
                    fv = ir.Constant(fpy_val, ir.Undefined)
                    fv = super().insert_value(fv, ir.Constant(i32, 0), 0)
                    fv = super().insert_value(fv, arg, 1)
                    coerced[i] = fv
                # i8* → {i32,i64} FpyValue (wrap as STR)
                elif (isinstance(ptype, ir.LiteralStructType) and ptype == fpy_val
                      and isinstance(arg.type, ir.PointerType)):
                    data = super().ptrtoint(arg, i64)
                    fv = ir.Constant(fpy_val, ir.Undefined)
                    fv = super().insert_value(fv, ir.Constant(i32, 2), 0)
                    fv = super().insert_value(fv, data, 1)
                    coerced[i] = fv
                # double → {i32,i64} FpyValue (wrap as FLOAT)
                elif (isinstance(ptype, ir.LiteralStructType) and ptype == fpy_val
                      and isinstance(arg.type, ir.DoubleType)):
                    data = super().bitcast(arg, i64)
                    fv = ir.Constant(fpy_val, ir.Undefined)
                    fv = super().insert_value(fv, ir.Constant(i32, 1), 0)
                    fv = super().insert_value(fv, data, 1)
                    coerced[i] = fv
                # {i32,i64} → i32 (extract data, trunc)
                elif (isinstance(ptype, ir.IntType) and ptype.width == 32
                      and isinstance(arg.type, ir.LiteralStructType)
                      and arg.type == fpy_val):
                    data = super().extract_value(arg, 1)
                    coerced[i] = super().trunc(data, ptype)
            args = coerced
        # Pad missing args with zero/null defaults
        if hasattr(fn, 'function_type'):
            expected = len(fn.function_type.args)
            while len(args) < expected:
                ptype = fn.function_type.args[len(args)]
                if isinstance(ptype, ir.PointerType):
                    args.append(ir.Constant(ptype, None))
                elif isinstance(ptype, ir.DoubleType):
                    args.append(ir.Constant(ptype, 0.0))
                elif isinstance(ptype, ir.IntType):
                    args.append(ir.Constant(ptype, 0))
                else:
                    args.append(ir.Constant(i64, 0))
        result = super().call(fn, args, name=name, cconv=cconv, tail=tail,
                              fastmath=fastmath, attrs=attrs, arg_attrs=arg_attrs)
        # If the function returns void but caller expects a value,
        # return a zero constant so the IR doesn't reference a void value
        if (hasattr(fn, 'function_type')
                and isinstance(fn.function_type.return_type, ir.VoidType)):
            return ir.Constant(i64, 0)
        return result

    def _coerce_pair(self, lhs, rhs):
        """Coerce lhs and rhs to the same type for comparison/binop."""
        if lhs.type == rhs.type:
            return lhs, rhs
        # Pointer vs any int: convert pointer to int (ptrtoint + widen if needed)
        if isinstance(lhs.type, ir.PointerType) and isinstance(rhs.type, ir.IntType):
            lhs = super().ptrtoint(lhs, i64)
            if rhs.type.width != 64:
                rhs = super().zext(rhs, i64)
            return lhs, rhs
        if isinstance(rhs.type, ir.PointerType) and isinstance(lhs.type, ir.IntType):
            rhs = super().ptrtoint(rhs, i64)
            if lhs.type.width != 64:
                lhs = super().zext(lhs, i64)
            return lhs, rhs
        # Pointer vs double: convert pointer to i64, then compare as i64
        if isinstance(lhs.type, ir.PointerType) and isinstance(rhs.type, ir.DoubleType):
            return super().ptrtoint(lhs, i64), super().bitcast(rhs, i64)
        if isinstance(rhs.type, ir.PointerType) and isinstance(lhs.type, ir.DoubleType):
            return super().bitcast(lhs, i64), super().ptrtoint(rhs, i64)
        # FpyValue vs scalar: extract data
        if isinstance(lhs.type, ir.LiteralStructType) and lhs.type == fpy_val:
            lhs = super().extract_value(lhs, 1)
            return self._coerce_pair(lhs, rhs)
        if isinstance(rhs.type, ir.LiteralStructType) and rhs.type == fpy_val:
            rhs = super().extract_value(rhs, 1)
            return self._coerce_pair(lhs, rhs)
        # Width mismatch: widen the narrower one
        if isinstance(lhs.type, ir.IntType) and isinstance(rhs.type, ir.IntType):
            if lhs.type.width < rhs.type.width:
                return super().zext(lhs, rhs.type), rhs
            else:
                return lhs, super().zext(rhs, lhs.type)
        # double vs int: convert int to double
        if isinstance(lhs.type, ir.DoubleType) and isinstance(rhs.type, ir.IntType):
            return lhs, super().sitofp(rhs, ir.DoubleType())
        if isinstance(rhs.type, ir.DoubleType) and isinstance(lhs.type, ir.IntType):
            return super().sitofp(lhs, ir.DoubleType()), rhs
        return lhs, rhs

    def icmp_signed(self, op, lhs, rhs, name=''):
        lhs, rhs = self._coerce_pair(lhs, rhs)
        return super().icmp_signed(op, lhs, rhs, name=name)

    def icmp_unsigned(self, op, lhs, rhs, name=''):
        lhs, rhs = self._coerce_pair(lhs, rhs)
        return super().icmp_unsigned(op, lhs, rhs, name=name)

    def fcmp_ordered(self, op, lhs, rhs, name='', flags=()):
        """Auto-coerce float comparison operands."""
        if lhs.type != rhs.type:
            # int → double
            if isinstance(lhs.type, ir.IntType):
                lhs = super().sitofp(lhs, ir.DoubleType())
            if isinstance(rhs.type, ir.IntType):
                rhs = super().sitofp(rhs, ir.DoubleType())
            # ptr → i64 → double (shouldn't happen but be safe)
            if isinstance(lhs.type, ir.PointerType):
                lhs = super().ptrtoint(lhs, i64)
                lhs = super().sitofp(lhs, ir.DoubleType())
            if isinstance(rhs.type, ir.PointerType):
                rhs = super().ptrtoint(rhs, i64)
                rhs = super().sitofp(rhs, ir.DoubleType())
        return super().fcmp_ordered(op, lhs, rhs, name=name, flags=flags)

    def fcmp_unordered(self, op, lhs, rhs, name='', flags=()):
        """Auto-coerce float comparison operands."""
        if lhs.type != rhs.type:
            if isinstance(lhs.type, ir.IntType):
                lhs = super().sitofp(lhs, ir.DoubleType())
            if isinstance(rhs.type, ir.IntType):
                rhs = super().sitofp(rhs, ir.DoubleType())
        return super().fcmp_unordered(op, lhs, rhs, name=name, flags=flags)

    def _coerce_float_pair(self, lhs, rhs):
        """Coerce operands for float operations (fadd/fsub/fmul/fdiv)."""
        if lhs.type == rhs.type:
            return lhs, rhs
        if isinstance(lhs.type, ir.IntType):
            lhs = super().sitofp(lhs, ir.DoubleType())
        if isinstance(rhs.type, ir.IntType):
            rhs = super().sitofp(rhs, ir.DoubleType())
        if isinstance(lhs.type, ir.PointerType):
            lhs = super().ptrtoint(lhs, i64)
            lhs = super().sitofp(lhs, ir.DoubleType())
        if isinstance(rhs.type, ir.PointerType):
            rhs = super().ptrtoint(rhs, i64)
            rhs = super().sitofp(rhs, ir.DoubleType())
        return lhs, rhs

    def insert_value(self, agg, value, idx, name=''):
        """Auto-coerce value for insert_value into FpyValue struct."""
        if (isinstance(agg.type, ir.LiteralStructType) and agg.type == fpy_val
                and idx == 1 and isinstance(value.type, ir.PointerType)):
            value = super().ptrtoint(value, i64)
        elif (isinstance(agg.type, ir.LiteralStructType) and agg.type == fpy_val
              and idx == 1 and isinstance(value.type, ir.IntType) and value.type.width == 32):
            value = super().zext(value, i64)
        elif (isinstance(agg.type, ir.LiteralStructType) and agg.type == fpy_val
              and idx == 0 and isinstance(value.type, ir.IntType) and value.type.width == 64):
            value = super().trunc(value, i32)
        return super().insert_value(agg, value, idx, name=name)

    def extract_value(self, agg, idx, name=''):
        """Guard extract_value against non-aggregate types."""
        if not isinstance(agg.type, (ir.LiteralStructType, ir.ArrayType)):
            # Can't extract from a scalar — return the value itself
            return agg
        return super().extract_value(agg, idx, name=name)

    def zext(self, value, typ, name=''):
        """Handle zext on non-integer types (extract from FpyValue first)."""
        if isinstance(value.type, ir.LiteralStructType) and value.type == fpy_val:
            value = super().extract_value(value, 1)
        if isinstance(value.type, ir.PointerType):
            value = super().ptrtoint(value, i64)
        if isinstance(value.type, ir.DoubleType):
            # zext is only valid for integers; convert double → i64 first
            value = super().fptosi(value, i64)
        if value.type == typ:
            return value
        return super().zext(value, typ, name=name)

    def trunc(self, value, typ, name=''):
        """Handle trunc on non-integer types."""
        if isinstance(value.type, ir.LiteralStructType) and value.type == fpy_val:
            value = super().extract_value(value, 1)
        if isinstance(value.type, ir.PointerType):
            value = super().ptrtoint(value, i64)
        if isinstance(value.type, ir.DoubleType):
            value = super().fptosi(value, i64)
        if value.type == typ:
            return value
        return super().trunc(value, typ, name=name)

    def bitcast(self, value, typ, name=''):
        """Safe bitcast that routes int↔ptr through inttoptr/ptrtoint.

        LLVM does not allow bitcast between integers and pointers (or
        between scalars and aggregate types).  This override transparently
        uses the correct conversion instruction so callers don't need to
        worry about the distinction.
        """
        if value.type == typ:
            return value
        val_is_int = isinstance(value.type, ir.IntType)
        val_is_ptr = isinstance(value.type, ir.PointerType)
        val_is_dbl = isinstance(value.type, ir.DoubleType)
        tgt_is_int = isinstance(typ, ir.IntType)
        tgt_is_ptr = isinstance(typ, ir.PointerType)
        tgt_is_dbl = isinstance(typ, ir.DoubleType)
        # int → pointer: use inttoptr
        if val_is_int and tgt_is_ptr:
            return super().inttoptr(value, typ)
        # pointer → int: use ptrtoint
        if val_is_ptr and tgt_is_int:
            return super().ptrtoint(value, typ)
        # pointer → pointer: allowed bitcast (or just use value as-is
        # with opaque pointers)
        if val_is_ptr and tgt_is_ptr:
            return super().bitcast(value, typ, name=name)
        # FpyValue struct → scalar: extract data field first
        if isinstance(value.type, ir.LiteralStructType) and tgt_is_int:
            data = super().extract_value(value, 1)
            if data.type == typ:
                return data
            return super().zext(data, typ) if typ.width > data.type.width \
                else super().trunc(data, typ)
        if isinstance(value.type, ir.LiteralStructType) and tgt_is_dbl:
            data = super().extract_value(value, 1)
            return super().bitcast(data, typ, name=name)
        if isinstance(value.type, ir.LiteralStructType) and tgt_is_ptr:
            data = super().extract_value(value, 1)
            return super().inttoptr(data, typ)
        # All remaining same-width scalar↔scalar bitcasts are valid
        return super().bitcast(value, typ, name=name)

    def fadd(self, lhs, rhs, name=''):
        lhs, rhs = self._coerce_float_pair(lhs, rhs)
        return super().fadd(lhs, rhs, name=name)

    def fsub(self, lhs, rhs, name=''):
        lhs, rhs = self._coerce_float_pair(lhs, rhs)
        return super().fsub(lhs, rhs, name=name)

    def fmul(self, lhs, rhs, name=''):
        lhs, rhs = self._coerce_float_pair(lhs, rhs)
        return super().fmul(lhs, rhs, name=name)

    def fdiv(self, lhs, rhs, name=''):
        lhs, rhs = self._coerce_float_pair(lhs, rhs)
        return super().fdiv(lhs, rhs, name=name)

    def select(self, cond, lhs, rhs, name='', flags=()):
        """Auto-coerce select (ternary) operands to same type."""
        if lhs.type != rhs.type:
            lhs, rhs = self._coerce_pair(lhs, rhs)
        return super().select(cond, lhs, rhs, name=name, flags=flags)

    def add(self, lhs, rhs, name=''):
        lhs, rhs = self._coerce_pair(lhs, rhs)
        return super().add(lhs, rhs, name=name)

    def sub(self, lhs, rhs, name=''):
        lhs, rhs = self._coerce_pair(lhs, rhs)
        return super().sub(lhs, rhs, name=name)

    def mul(self, lhs, rhs, name=''):
        lhs, rhs = self._coerce_pair(lhs, rhs)
        return super().mul(lhs, rhs, name=name)

    def sdiv(self, lhs, rhs, name=''):
        lhs, rhs = self._coerce_pair(lhs, rhs)
        return super().sdiv(lhs, rhs, name=name)

    def srem(self, lhs, rhs, name=''):
        lhs, rhs = self._coerce_pair(lhs, rhs)
        return super().srem(lhs, rhs, name=name)

    def udiv(self, lhs, rhs, name=''):
        lhs, rhs = self._coerce_pair(lhs, rhs)
        return super().udiv(lhs, rhs, name=name)

    def urem(self, lhs, rhs, name=''):
        lhs, rhs = self._coerce_pair(lhs, rhs)
        return super().urem(lhs, rhs, name=name)

    def xor(self, lhs, rhs, name=''):
        lhs, rhs = self._coerce_pair(lhs, rhs)
        return super().xor(lhs, rhs, name=name)

    def shl(self, lhs, rhs, name=''):
        lhs, rhs = self._coerce_pair(lhs, rhs)
        return super().shl(lhs, rhs, name=name)

    def lshr(self, lhs, rhs, name=''):
        lhs, rhs = self._coerce_pair(lhs, rhs)
        return super().lshr(lhs, rhs, name=name)

    def ashr(self, lhs, rhs, name=''):
        lhs, rhs = self._coerce_pair(lhs, rhs)
        return super().ashr(lhs, rhs, name=name)

    def and_(self, lhs, rhs, name=''):
        lhs, rhs = self._coerce_pair(lhs, rhs)
        return super().and_(lhs, rhs, name=name)

    def or_(self, lhs, rhs, name=''):
        lhs, rhs = self._coerce_pair(lhs, rhs)
        return super().or_(lhs, rhs, name=name)

    def store(self, value, ptr, align=None):
        """Auto-coerce value to match pointer's pointee type."""
        if hasattr(ptr.type, 'pointee'):
            target = ptr.type.pointee
            if value.type != target:
                if target == i64 and isinstance(value.type, ir.PointerType):
                    value = super().ptrtoint(value, i64)
                elif target == i64 and isinstance(value.type, ir.LiteralStructType):
                    value = super().extract_value(value, 1)
                elif isinstance(target, ir.PointerType) and isinstance(value.type, ir.IntType):
                    value = super().inttoptr(value, target)
                elif (isinstance(target, ir.PointerType)
                      and isinstance(value.type, ir.LiteralStructType)
                      and value.type == fpy_val):
                    # FpyValue → pointer: extract data and inttoptr
                    data = super().extract_value(value, 1)
                    value = super().inttoptr(data, target)
                elif isinstance(target, ir.PointerType) and isinstance(value.type, ir.PointerType):
                    # Pointer type mismatch (e.g., i8* vs i8**) — bitcast
                    value = super().bitcast(value, target)
                elif target == fpy_val and isinstance(value.type, ir.IntType):
                    # Wrap bare int as FpyValue(INT)
                    fv = ir.Constant(fpy_val, ir.Undefined)
                    fv = super().insert_value(fv, ir.Constant(i32, 0), 0)
                    fv = super().insert_value(fv, value, 1)
                    value = fv
                elif target == fpy_val and isinstance(value.type, ir.PointerType):
                    # Wrap bare pointer as FpyValue(STR)
                    data = super().ptrtoint(value, i64)
                    fv = ir.Constant(fpy_val, ir.Undefined)
                    fv = super().insert_value(fv, ir.Constant(i32, 2), 0)
                    fv = super().insert_value(fv, data, 1)
                    value = fv
        if align is not None:
            return super().store(value, ptr, align=align)
        return super().store(value, ptr)

    def ret(self, value):
        """Auto-coerce return value to match function's return type."""
        ret_type = self.function.return_value.type
        if value.type != ret_type:
            if isinstance(ret_type, ir.VoidType):
                return super().ret_void()
            # int → int (widen or narrow)
            if isinstance(ret_type, ir.IntType) and isinstance(value.type, ir.IntType):
                if value.type.width < ret_type.width:
                    value = super().zext(value, ret_type)
                elif value.type.width > ret_type.width:
                    value = super().trunc(value, ret_type)
            elif isinstance(ret_type, ir.IntType) and isinstance(value.type, ir.PointerType):
                value = super().ptrtoint(value, i64)
                if ret_type.width != 64:
                    value = super().trunc(value, ret_type)
            elif isinstance(ret_type, ir.IntType) and isinstance(value.type, ir.LiteralStructType):
                value = super().extract_value(value, 1)
                if ret_type.width != 64:
                    value = super().trunc(value, ret_type)
            elif isinstance(ret_type, ir.PointerType) and isinstance(value.type, ir.IntType):
                value = super().inttoptr(value, ret_type)
            elif (isinstance(ret_type, ir.PointerType)
                  and isinstance(value.type, ir.LiteralStructType)):
                data = super().extract_value(value, 1)
                value = super().inttoptr(data, ret_type)
            elif ret_type == fpy_val and isinstance(value.type, ir.IntType):
                fv = ir.Constant(fpy_val, ir.Undefined)
                fv = super().insert_value(fv, ir.Constant(i32, 0), 0)
                fv = super().insert_value(fv, value, 1)
                value = fv
            elif ret_type == fpy_val and isinstance(value.type, ir.PointerType):
                data = super().ptrtoint(value, i64)
                fv = ir.Constant(fpy_val, ir.Undefined)
                fv = super().insert_value(fv, ir.Constant(i32, 2), 0)
                fv = super().insert_value(fv, data, 1)
                value = fv
            # double ↔ int
            elif isinstance(ret_type, ir.DoubleType) and isinstance(value.type, ir.IntType):
                value = super().bitcast(value, ret_type) if value.type.width == 64 \
                    else super().sitofp(value, ret_type)
            elif isinstance(ret_type, ir.IntType) and isinstance(value.type, ir.DoubleType):
                value = super().bitcast(value, i64)
                if ret_type.width != 64:
                    value = super().trunc(value, ret_type)
            # double ↔ pointer
            elif isinstance(ret_type, ir.DoubleType) and isinstance(value.type, ir.PointerType):
                value = super().ptrtoint(value, i64)
                value = super().bitcast(value, ret_type)
            elif isinstance(ret_type, ir.PointerType) and isinstance(value.type, ir.DoubleType):
                value = super().bitcast(value, i64)
                value = super().inttoptr(value, ret_type)
            # FpyValue → double
            elif isinstance(ret_type, ir.DoubleType) and isinstance(value.type, ir.LiteralStructType):
                data = super().extract_value(value, 1)
                value = super().bitcast(data, ret_type)
        return super().ret(value)

    def ret_void(self):
        """Handle ret_void when function expects a return value."""
        ret_type = self.function.return_value.type
        if not isinstance(ret_type, ir.VoidType):
            if ret_type == fpy_val:
                fv = ir.Constant(fpy_val, ir.Undefined)
                fv = super().insert_value(fv, ir.Constant(i32, 4), 0)
                fv = super().insert_value(fv, ir.Constant(i64, 0), 1)
                return super().ret(fv)
            elif isinstance(ret_type, ir.PointerType):
                return super().ret(ir.Constant(ret_type, None))
            elif isinstance(ret_type, ir.IntType):
                return super().ret(ir.Constant(ret_type, 0))
            elif isinstance(ret_type, ir.DoubleType):
                return super().ret(ir.Constant(ret_type, 0.0))
        return super().ret_void()


class CodeGen:
    """Generates LLVM IR from a Python AST."""

    def __init__(self, threading_mode: int = 0, int64_mode: bool = False,
                 typed_mode: bool = False,
                 source_filename: str = "<module>",
                 analyze_mode: bool = False) -> None:
        self._current_scope_stmts = []  # Phase 4: initialize early
        self.module = ir.Module(name="fastpy_module")
        # Use the host platform's LLVM triple and data layout for correct
        # struct layout (padding/alignment) and object file format.
        import llvmlite.binding as _llvm
        _llvm.initialize_native_target()
        _llvm.initialize_native_asmprinter()
        self.module.triple = _llvm.get_default_triple()
        _target = _llvm.Target.from_triple(self.module.triple)
        _tm = _target.create_target_machine()
        self.module.data_layout = str(_tm.target_data)
        self._threading_mode = threading_mode
        # Integer mode: False = BigInt fallback on overflow (default, Python-compatible)
        # True = i64-only with OverflowError on overflow (faster, not Python-compatible)
        self._int64_mode = int64_mode
        # Typed mode: use type annotations (int, float, bool, str) for fast-path
        # code generation — annotated vars use native LLVM types instead of FpyValue.
        self._typed_mode = typed_mode
        self._source_filename = source_filename

        # Optimization analysis mode: when True, every optimization decision
        # records a finding for the analysis report.  Zero overhead when False.
        self._analyze_mode = analyze_mode
        self._opt_findings: list = []   # list[OptimizationFinding]
        self._current_scope = "module"  # updated on function/class/method entry

        # BigInt overflow flag: set by _emit_int_binop when checked_pow/mul/add/sub
        # might overflow to BigInt.  Consumed by _emit_binop to produce an FpyValue
        # struct with the correct runtime tag (BIGINT vs INT).
        self._bigint_overflow_flag: 'ir.Value | None' = None

        # Per-function dict mapping variable name → (native_alloca, VKind).
        # Populated from function parameter annotations and AnnAssign statements
        # when _typed_mode is True.  Variables in this dict bypass the FpyValue
        # wrapping/unwrapping in _store_variable / _load_variable.
        self._native_vars: dict[str, tuple] = {}

        # Pre-initialize attributes that generate() sets later,
        # so early exceptions don't leave them missing.
        self._singledispatch = {}
        self._singledispatch_variants = {}
        self._cpython_functions = set()
        self._cpython_classes = set()
        # Track sys.stdout/stderr reassignments so reads fall through to
        # the CPython bridge instead of returning integer sentinels.
        self._sys_reassigned_attrs: set[str] = set()
        # Phase 4: function aliases — tracks `f = my_func` so `f(args)`
        # calls the compiled my_func instead of falling back to bridge.
        self._func_aliases: dict[str, str] = {}  # alias_name → original_func_name
        # Bound method aliases: `f = lst.insert` → f(i, v) rewrites to
        # lst.insert(i, v) at compile time.  Maps alias_name →
        # (obj_var_name, method_name).
        self._bound_method_aliases: dict[str, tuple[str, str]] = {}

        # Declare runtime functions
        self._declare_runtime_functions()

        # Emit threading mode global — overrides the weak default in threading.c.
        # Use no explicit linkage (default = external definition with init).
        gvar = ir.GlobalVariable(self.module, i32,
                                 name="fpy_threading_mode")
        gvar.initializer = ir.Constant(i32, threading_mode)

        # String constant counter
        self._str_counter = 0

        # Reference counting: emit incref/decref at variable stores and scope exits.
        self._USE_REFCOUNT = True

        # Module-level flag: True only when the program uses integer operations
        # that could produce BigInt (e.g. ** with large exponents, huge int
        # literals).  When False, integer arithmetic uses plain LLVM add/sub/mul
        # (no fpy_checked_add runtime call overhead).
        self._program_uses_bigint = False

        # Hot-loop flag: True while emitting statements inside a while/for loop
        # body.  Suppresses per-statement fpy_current_line stores that prevent
        # LLVM from optimizing the loop.  The line number at loop entry is
        # still recorded.
        self._in_hot_loop = False

        # Per-function bare-ABI flag: True when the current function being
        # compiled uses bare-type ABI (direct i64/double params/locals/return)
        # instead of FpyValue wrappers.  Checked by _store_variable and
        # _load_variable to bypass FV wrapping/unwrapping.
        self._current_fn_bare_abi = False

        # Temporary value tracking for GC: expressions that create heap
        # objects (string concat, list literal, etc.) push FpyValue pairs
        # here. Statement boundaries flush with decref.
        self._rc_temps: list[tuple] = []  # list of (tag_val, data_val) LLVM values

        # Counter for unique block names
        self._block_counter = 0

        # Per-function state (saved/restored when entering nested functions)
        self.function: ir.Function | None = None
        self.builder: ir.IRBuilder | None = None
        self.variables: dict[str, tuple[ir.AllocaInstr, str]] = {}
        self._loop_stack: list[tuple[ir.Block, ir.Block]] = []
        self._in_try_block: bool = False
        # Stack of finally-body AST lists currently enclosing the emitter.
        # A `return` inside a try-with-finally must emit all pending finally
        # bodies in LIFO order before actually returning.
        self._finally_stack: list[list[ast.stmt]] = []

        # Generator functions: set of function names that contain yield
        self._generator_funcs: set[str] = set()

        # CPython module imports: module_name -> LLVM global (i8* PyObject*)
        self._cpython_modules: dict[str, ir.GlobalVariable] = {}

        # User-defined functions: name -> FuncInfo
        self._user_functions: dict[str, FuncInfo] = {}

        # User-defined classes: name -> ClassInfo
        self._user_classes: dict[str, ClassInfo] = {}

        # Global variables: name -> (global_var, type_tag)
        # Module-level vars that functions can access via 'global' keyword
        self._global_vars: dict[str, tuple[ir.GlobalVariable, str]] = {}

        # Variables assigned Ellipsis literal (...) — tracked for print dispatch
        self._ellipsis_vars: set[str] = set()

        # Exception variables from `except FooError as e:` — maps variable
        # name → exception class name so type(e).__name__ returns the correct
        # exception class (not "str", which is what the message string is).
        self._exc_vars: dict[str, str] = {}
        # Allocas holding the saved runtime class name for each exception
        # variable, so type(e).__name__ returns the actual raised class.
        self._exc_class_allocas: dict = {}

        # Annotated variable names whose annotations are contradicted by
        # assignments in the same scope.  Pre-scanned before codegen so the
        # AnnAssign handler can skip native alloca creation for them.
        self._unsafe_typed_vars: set[str] = set()

        # Per-variable integer overflow policy from Annotated markers or
        # constructor calls (unchecked_int / checked_int).
        # Maps variable name → "unchecked" | "checked".
        # "unchecked": raw LLVM add/sub/mul, no overflow detection
        # "checked":   LLVM overflow intrinsics, OverflowError (no BigInt)
        self._int_mode_vars: dict[str, str] = {}

        # Pre-scanned list element types from append() analysis
        # Maps variable name -> inferred element type (e.g. "list", "str", "obj")
        self._list_append_types: dict[str, str] = {}

        # Current class name while emitting class method bodies (for super() lookup)
        self._current_class: str | None = None

        # Per-class container attribute detection:
        # Maps class name -> (list_attrs, dict_attrs)
        self._class_container_attrs: dict[str, tuple[set[str], set[str]]] = {}

        # Per-class float/string/bool attribute detection (including inherited attrs)
        self._per_class_float_attrs: dict[str, set[str]] = {}
        self._per_class_string_attrs: dict[str, set[str]] = {}
        self._per_class_bool_attrs: dict[str, set[str]] = {}

        # Class-level constant attributes: class_name -> {attr: ast.Constant}
        self._class_const_attrs: dict[str, dict[str, ast.expr]] = {}

        # Track variable -> class name for object-typed variables.
        # _obj_var_class: "best known" class (could be base class)
        # _obj_var_pinned: variables whose EXACT runtime class is known
        #   (from direct constructor: x = Foo()).  Only these should
        #   prevent polymorphic dispatch in _receiver_may_be_subclass.
        self._obj_var_class: dict[str, str] = {}
        self._obj_var_pinned: set[str] = set()

        # Track dict variables whose values are all lists (so d[k] returns a list)
        self._dict_var_list_values: set[str] = set()

        # Track dict variables whose values are all dicts (so d[k] returns a dict)
        self._dict_var_dict_values: set[str] = set()

        # Track dict variables whose values are all ints (so d[k] returns an int)
        self._dict_var_int_values: set[str] = set()
        # Track dict variables whose values are all class instances
        # (so d[k] returns an obj pointer, not a string-representation).
        self._dict_var_obj_values: set[str] = set()
        # Per-key value types for mixed-value dicts: maps variable name to
        # a dict of {key_str: type_tag}. Enables `d["age"]` to return int
        # even when the dict also contains string-valued keys. Populated
        # for module/function-scope dicts whose values have known types
        # per key, either directly (literals) or via propagation from a
        # list-of-dicts loop variable.
        self._dict_var_key_types: dict[str, dict[str, str]] = {}

        # Track tuple variable element types for subscript dispatch
        self._tuple_elem_types: dict[str, str] = {}

        # Per-class object attribute types: class_name -> attr -> nested_class_name.
        # E.g., Entity.pos holds a Position → _class_obj_attr_types["Entity"]["pos"] = "Position"
        self._class_obj_attr_types: dict[str, dict[str, str]] = {}

        # Per-class static attribute slots: class_name -> {attr: slot_index}.
        # Built by scanning all methods for self.attr and obj.attr patterns.
        # Inherited attrs keep the parent's slot index (child slots start after).
        self._class_attr_slots: dict[str, dict[str, int]] = {}
        # Per-class init-only attributes: attrs set in __init__ and NEVER
        # modified by any other method, module code, or external store.
        # Loads from these slots can be marked !invariant.load, enabling
        # LLVM to hoist them out of loops (e.g., `p.x` in a tight loop).
        self._class_init_only_attrs: dict[str, set[str]] = {}

    def _declare_runtime_functions(self) -> None:
        """Declare external runtime functions we can call."""
        self.runtime = {}

        # void fastpy_print_newline(void)
        ft = ir.FunctionType(void, [])
        self.runtime["print_newline"] = ir.Function(self.module, ft, name="fastpy_print_newline")

        # FpyValue operations — the print/write dispatch is now done via these,
        # replacing the old typed variants (print_int/float/str/bool/none,
        # list_print, tuple_print, dict_print, obj_print, and their write_*
        # counterparts). All print/write goes through fv_print / fv_write.
        ft = ir.FunctionType(void, [i32, i64])
        self.runtime["fv_print"] = ir.Function(self.module, ft, name="fastpy_fv_print")
        self.runtime["fv_write"] = ir.Function(self.module, ft, name="fastpy_fv_write")
        ft = ir.FunctionType(i8_ptr, [i32, i64])
        self.runtime["fv_repr"] = ir.Function(self.module, ft, name="fastpy_fv_repr")
        self.runtime["fv_str"] = ir.Function(self.module, ft, name="fastpy_fv_str")
        ft = ir.FunctionType(i32, [i32, i64])
        self.runtime["fv_truthy"] = ir.Function(self.module, ft, name="fastpy_fv_truthy")
        # int32_t fastpy_fv_compare(i32 tag1, i64 data1, i32 tag2, i64 data2, i32 op)
        ft = ir.FunctionType(i32, [i32, i64, i32, i64, i32])
        self.runtime["fv_compare"] = ir.Function(self.module, ft, name="fastpy_fv_compare")
        # int64_t fastpy_fv_len(i32 tag, i64 data)
        ft = ir.FunctionType(i64, [i32, i64])
        self.runtime["fv_len"] = ir.Function(self.module, ft, name="fastpy_fv_len")
        # void fastpy_fv_iter_get(i32 tag, i64 data, i64 index, i32* out_tag, i64* out_data)
        ft = ir.FunctionType(void, [i32, i64, i64, ir.PointerType(i32), ir.PointerType(i64)])
        self.runtime["fv_iter_get"] = ir.Function(self.module, ft, name="fastpy_fv_iter_get")
        # void fastpy_fv_subscript(i32 c_tag, i64 c_data, i32 k_tag, i64 k_data, i32* out_tag, i64* out_data)
        ft = ir.FunctionType(void, [i32, i64, i32, i64, ir.PointerType(i32), ir.PointerType(i64)])
        self.runtime["fv_subscript"] = ir.Function(self.module, ft, name="fastpy_fv_subscript")
        # i32 fastpy_fv_contains(i32 c_tag, i64 c_data, i32 v_tag, i64 v_data)
        ft = ir.FunctionType(i32, [i32, i64, i32, i64])
        self.runtime["fv_contains"] = ir.Function(self.module, ft, name="fastpy_fv_contains")
        # void fastpy_fv_binop(i32 lt, i64 ld, i32 rt, i64 rd, i32 op, i32* out_tag, i64* out_data)
        ft = ir.FunctionType(void, [i32, i64, i32, i64, i32, ir.PointerType(i32), ir.PointerType(i64)])
        self.runtime["fv_binop"] = ir.Function(self.module, ft, name="fastpy_fv_binop")

        # int64_t fastpy_pow_int(int64_t base, int64_t exp)
        ft = ir.FunctionType(i64, [i64, i64])
        self.runtime["pow_int"] = ir.Function(self.module, ft, name="fastpy_pow_int")
        ft = ir.FunctionType(i64, [i64, i64, i64])
        self.runtime["pow_mod"] = ir.Function(self.module, ft, name="fastpy_pow_mod")

        # double fastpy_pow_float(double base, double exp)
        ft = ir.FunctionType(double, [double, double])
        self.runtime["pow_float"] = ir.Function(self.module, ft, name="fastpy_pow_float")

        # String operations
        ft = ir.FunctionType(i8_ptr, [i8_ptr, i8_ptr])
        self.runtime["str_concat"] = ir.Function(self.module, ft, name="fastpy_str_concat")
        ft = ir.FunctionType(i64, [i8_ptr])
        self.runtime["str_len"] = ir.Function(self.module, ft, name="fastpy_str_len")
        ft = ir.FunctionType(i8_ptr, [i8_ptr, i64])
        self.runtime["str_index"] = ir.Function(self.module, ft, name="fastpy_str_index")
        ft = ir.FunctionType(i8_ptr, [i8_ptr, i64, i64, i64, i64])
        self.runtime["str_slice"] = ir.Function(self.module, ft, name="fastpy_str_slice")
        ft = ir.FunctionType(i8_ptr, [i8_ptr, i64, i64, i64, i64, i64])
        self.runtime["str_slice_step"] = ir.Function(self.module, ft, name="fastpy_str_slice_step")
        ft = ir.FunctionType(i8_ptr, [i8_ptr, i64])
        self.runtime["str_repeat"] = ir.Function(self.module, ft, name="fastpy_str_repeat")
        ft = ir.FunctionType(i8_ptr, [i8_ptr])
        self.runtime["str_lower"] = ir.Function(self.module, ft, name="fastpy_str_lower")
        # str.encode() → returns bytes (same content, different tag)
        ft = ir.FunctionType(i8_ptr, [i8_ptr])
        self.runtime["str_encode"] = ir.Function(self.module, ft, name="fastpy_str_encode")
        ft = ir.FunctionType(i8_ptr, [i64])
        self.runtime["int_to_str"] = ir.Function(self.module, ft, name="fastpy_int_to_str")
        ft = ir.FunctionType(i8_ptr, [double])
        self.runtime["float_to_str"] = ir.Function(self.module, ft, name="fastpy_float_to_str")

        # List operations (lists are opaque pointers = i8*)
        ft = ir.FunctionType(i8_ptr, [])
        self.runtime["list_new"] = ir.Function(self.module, ft, name="fastpy_list_new")
        # FV-ABI list element operations (Phase 4 of tagged-value refactor).
        # The old typed variants (list_append_int/float/str/bool/none/list,
        # list_set_int/str) are superseded by the FV versions and removed.
        ft = ir.FunctionType(void, [i8_ptr, i32, i64])
        self.runtime["list_append_fv"] = ir.Function(self.module, ft, name="fastpy_list_append_fv")
        ft = ir.FunctionType(void, [i8_ptr, i64, ir.PointerType(i32), ir.PointerType(i64)])
        self.runtime["list_get_fv"] = ir.Function(self.module, ft, name="fastpy_list_get_fv")
        ft = ir.FunctionType(void, [i8_ptr, i64, i32, i64])
        self.runtime["list_set_fv"] = ir.Function(self.module, ft, name="fastpy_list_set_fv")
        ft = ir.FunctionType(void, [i8_ptr, i8_ptr, i32, i64])
        self.runtime["dict_set_fv"] = ir.Function(self.module, ft, name="fastpy_dict_set_fv")
        ft = ir.FunctionType(void, [i8_ptr, i8_ptr, ir.PointerType(i32), ir.PointerType(i64)])
        self.runtime["dict_get_fv"] = ir.Function(self.module, ft, name="fastpy_dict_get_fv")
        self.runtime["dict_get_fv_safe"] = ir.Function(self.module, ft, name="fastpy_dict_get_fv_safe")
        ft = ir.FunctionType(void, [i8_ptr, i32, i64, i32, i64])
        self.runtime["dict_set_kv_fv"] = ir.Function(self.module, ft, name="fastpy_dict_set_kv_fv")
        ft = ir.FunctionType(void, [i8_ptr, i32, i64, ir.PointerType(i32), ir.PointerType(i64)])
        self.runtime["dict_get_kv_fv"] = ir.Function(self.module, ft, name="fastpy_dict_get_kv_fv")
        ft = ir.FunctionType(i32, [i8_ptr, i32, i64])
        self.runtime["dict_has_kv_key"] = ir.Function(self.module, ft, name="fastpy_dict_has_kv_key")
        ft = ir.FunctionType(i64, [i8_ptr])
        self.runtime["list_length"] = ir.Function(self.module, ft, name="fastpy_list_length")
        ft = ir.FunctionType(i8_ptr, [i8_ptr])
        self.runtime["list_to_str"] = ir.Function(self.module, ft, name="fastpy_list_to_str")
        ft = ir.FunctionType(i8_ptr, [i8_ptr])
        self.runtime["list_sorted"] = ir.Function(self.module, ft, name="fastpy_list_sorted")
        self.runtime["list_from_obj_iter"] = ir.Function(self.module, ft, name="fastpy_list_from_obj_iter")
        ft = ir.FunctionType(i64, [i8_ptr])
        self.runtime["list_min_fv"] = ir.Function(self.module, ft, name="fastpy_list_min_fv")
        self.runtime["list_max_fv"] = ir.Function(self.module, ft, name="fastpy_list_max_fv")
        ft = ir.FunctionType(i8_ptr, [i8_ptr])
        self.runtime["list_reversed"] = ir.Function(self.module, ft, name="fastpy_list_reversed")
        ft = ir.FunctionType(i8_ptr, [i8_ptr])
        self.runtime["str_reversed"] = ir.Function(self.module, ft, name="fastpy_str_reversed")
        ft = ir.FunctionType(i64, [i32, i64])
        self.runtime["hash_fv"] = ir.Function(self.module, ft, name="fastpy_hash_fv")
        ft = ir.FunctionType(i8_ptr, [i8_ptr])
        self.runtime["list_set"] = ir.Function(self.module, ft, name="fastpy_list_set")
        ft = ir.FunctionType(i8_ptr, [i8_ptr, i8_ptr])
        self.runtime["set_union"] = ir.Function(self.module, ft, name="fastpy_set_union")
        ft = ir.FunctionType(i8_ptr, [i8_ptr, i8_ptr])
        self.runtime["set_intersection"] = ir.Function(self.module, ft, name="fastpy_set_intersection")
        ft = ir.FunctionType(i8_ptr, [i8_ptr, i8_ptr])
        self.runtime["set_difference"] = ir.Function(self.module, ft, name="fastpy_set_difference")
        ft = ir.FunctionType(i8_ptr, [i8_ptr, i8_ptr])
        self.runtime["set_symmetric_diff"] = ir.Function(self.module, ft, name="fastpy_set_symmetric_diff")
        ft = ir.FunctionType(i32, [i8_ptr, i8_ptr])
        self.runtime["set_issubset"] = ir.Function(self.module, ft, name="fastpy_set_issubset")
        self.runtime["set_issuperset"] = ir.Function(self.module, ft, name="fastpy_set_issuperset")
        self.runtime["set_isdisjoint"] = ir.Function(self.module, ft, name="fastpy_set_isdisjoint")
        ft = ir.FunctionType(i8_ptr, [i8_ptr])
        self.runtime["set_copy"] = ir.Function(self.module, ft, name="fastpy_set_copy")
        ft = ir.FunctionType(void, [i8_ptr])
        self.runtime["set_clear"] = ir.Function(self.module, ft, name="fastpy_set_clear")
        ft = ir.FunctionType(void, [i8_ptr, i32.as_pointer(), i64.as_pointer()])
        self.runtime["set_pop_fv"] = ir.Function(self.module, ft, name="fastpy_set_pop_fv")
        ft = ir.FunctionType(void, [i8_ptr, i8_ptr])
        self.runtime["set_update"] = ir.Function(self.module, ft, name="fastpy_set_update")
        ft = ir.FunctionType(i8_ptr, [i8_ptr])  # str_split(s) -> list
        self.runtime["str_split"] = ir.Function(self.module, ft, name="fastpy_str_split")
        ft = ir.FunctionType(i64, [i8_ptr, i8_ptr])
        self.runtime["str_compare"] = ir.Function(self.module, ft, name="fastpy_str_compare")
        ft = ir.FunctionType(i8_ptr, [i8_ptr])
        self.runtime["str_upper"] = ir.Function(self.module, ft, name="fastpy_str_upper")
        ft = ir.FunctionType(i8_ptr, [i8_ptr, i8_ptr, i8_ptr])
        self.runtime["str_replace"] = ir.Function(self.module, ft, name="fastpy_str_replace")
        ft = ir.FunctionType(i8_ptr, [i8_ptr, i8_ptr, i8_ptr, i64])
        self.runtime["str_replace_count"] = ir.Function(self.module, ft, name="fastpy_str_replace_count")
        ft = ir.FunctionType(i32, [i8_ptr, i8_ptr])
        self.runtime["str_startswith"] = ir.Function(self.module, ft, name="fastpy_str_startswith")
        ft = ir.FunctionType(i32, [i8_ptr, i8_ptr])
        self.runtime["str_endswith"] = ir.Function(self.module, ft, name="fastpy_str_endswith")
        ft = ir.FunctionType(i32, [i8_ptr, i8_ptr])
        self.runtime["str_contains"] = ir.Function(self.module, ft, name="fastpy_str_contains")
        ft = ir.FunctionType(i8_ptr, [i8_ptr, i8_ptr])
        self.runtime["str_removeprefix"] = ir.Function(self.module, ft, name="fastpy_str_removeprefix")
        self.runtime["str_removesuffix"] = ir.Function(self.module, ft, name="fastpy_str_removesuffix")
        ft = ir.FunctionType(i8_ptr, [i8_ptr, i64, i8_ptr])
        self.runtime["str_center_fill"] = ir.Function(self.module, ft, name="fastpy_str_center_fill")
        self.runtime["str_ljust_fill"] = ir.Function(self.module, ft, name="fastpy_str_ljust_fill")
        self.runtime["str_rjust_fill"] = ir.Function(self.module, ft, name="fastpy_str_rjust_fill")
        ft = ir.FunctionType(i32, [i8_ptr])
        self.runtime["str_isupper"] = ir.Function(self.module, ft, name="fastpy_str_isupper")
        self.runtime["str_islower"] = ir.Function(self.module, ft, name="fastpy_str_islower")
        self.runtime["str_istitle"] = ir.Function(self.module, ft, name="fastpy_str_istitle")
        self.runtime["str_isidentifier"] = ir.Function(self.module, ft, name="fastpy_str_isidentifier")
        self.runtime["str_isprintable"] = ir.Function(self.module, ft, name="fastpy_str_isprintable")
        self.runtime["str_isdecimal"] = ir.Function(self.module, ft, name="fastpy_str_isdecimal")
        self.runtime["str_isnumeric"] = ir.Function(self.module, ft, name="fastpy_str_isnumeric")
        ft = ir.FunctionType(i8_ptr, [i8_ptr])
        self.runtime["str_casefold"] = ir.Function(self.module, ft, name="fastpy_str_casefold")
        ft = ir.FunctionType(i8_ptr, [i8_ptr, i64])
        self.runtime["str_expandtabs"] = ir.Function(self.module, ft, name="fastpy_str_expandtabs")
        ft = ir.FunctionType(i8_ptr, [i8_ptr, i8_ptr])
        self.runtime["str_partition"] = ir.Function(self.module, ft, name="fastpy_str_partition")
        self.runtime["str_rpartition"] = ir.Function(self.module, ft, name="fastpy_str_rpartition")
        ft = ir.FunctionType(i8_ptr, [i8_ptr, i8_ptr, i64])
        self.runtime["str_rsplit"] = ir.Function(self.module, ft, name="fastpy_str_rsplit")
        ft = ir.FunctionType(i8_ptr, [i8_ptr])
