        ft = ir.FunctionType(void, [i32])
        self.runtime["set_ret_tag"] = ir.Function(self.module, ft, name="fastpy_set_ret_tag")
        ft = ir.FunctionType(i32, [])
        self.runtime["get_ret_tag"] = ir.Function(self.module, ft, name="fastpy_get_ret_tag")

