    def _emit_import(self, node: ast.Import) -> None:
        """Emit `import module` — loads a CPython module (.pyd or .py)
        via the CPython C API and stores the PyObject* as a variable."""
        for alias in node.names:
            mod_name = alias.name
            var_name = alias.asname if alias.asname else mod_name

            # Native module: mark as native AND import through CPython bridge.
            # The native dispatch handles known functions (os.getcwd, math.sqrt),
            # but non-native attributes (os.name, os.sep) need the real module
            # object for bridge fallback. Storing NULL caused segfaults.
            if mod_name in self._NATIVE_MODULES:
                if not hasattr(self, '_native_modules'):
                    self._native_modules = set()
                self._native_modules.add(var_name)
                # Import the REAL module through CPython so bridge fallback works
                mod_ptr = self.builder.call(
                    self.runtime["cpython_import"],
                    [self._make_string_constant(mod_name)])
                self._store_variable(var_name, mod_ptr, ValueType(VKind.NATIVE_MOD))
                # For dotted imports (import os.path), also store top-level name
                if "." in var_name:
                    top = var_name.split(".")[0]
                    if top not in self.variables:
                        self._native_modules.add(top)
                        top_ptr = self.builder.call(
                            self.runtime["cpython_import"],
                            [self._make_string_constant(top)])
                        self._store_variable(top, top_ptr, ValueType(VKind.NATIVE_MOD))
                continue

            # Create a global to hold the module PyObject*
            if mod_name not in self._cpython_modules:
                gvar = ir.GlobalVariable(
                    self.module, i8_ptr,
                    name=f"fastpy.pymod.{mod_name}")
                gvar.initializer = ir.Constant(i8_ptr, None)
                gvar.linkage = "private"
                self._cpython_modules[mod_name] = gvar

            # Import via CPython's import mechanism.  The JIT import
            # (fpy_jit_import) tried to compile modules at runtime, but
            # it applies name prefixing that breaks attribute access for
            # stdlib modules.  CPython import is correct for all modules.
            name_ptr = self._make_string_constant(mod_name)
            mod_ptr = self.builder.call(
                self.runtime["cpython_import"], [name_ptr])
            self.builder.store(mod_ptr, self._cpython_modules[mod_name])

            # For dotted imports (e.g. `import os.path`), Python binds
            # the top-level module name. `import os.path` creates `os`.
            if "." in var_name:
                top_name = var_name.split(".")[0]
                # Import the top-level module too
                if top_name not in self._cpython_modules:
                    gvar = ir.GlobalVariable(
                        self.module, i8_ptr,
                        name=f"fastpy.pymod.{top_name}")
                    gvar.initializer = ir.Constant(i8_ptr, None)
                    gvar.linkage = "private"
                    self._cpython_modules[top_name] = gvar
                top_name_ptr = self._make_string_constant(top_name)
                top_mod = self.builder.call(
                    self.runtime["cpython_import"], [top_name_ptr])
                self.builder.store(top_mod, self._cpython_modules[top_name])
                self._store_variable(top_name, top_mod, ValueType(VKind.PYOBJ))
            else:
                # Module-level imports must be LLVM globals so user
                # functions can access them as bare names.
                if (self.function.name == "fastpy_main"
                        and var_name not in self._global_vars):
                    gvar = ir.GlobalVariable(
                        self.module, i8_ptr,
                        name=f"fastpy.import.{var_name}")
                    gvar.initializer = ir.Constant(i8_ptr, None)
                    gvar.linkage = "private"
                    self._global_vars[var_name] = (
                        gvar, ValueType(VKind.PYOBJ))
                self._store_variable(var_name, mod_ptr, ValueType(VKind.PYOBJ))

    def _emit_import_from(self, node: ast.ImportFrom) -> None:
        """Emit `from module import name1, name2`."""
        mod_name = node.module

        # Star imports (`from X import *`) cannot be resolved at compile
        # time — they depend on the module's __all__ or dir().  Fall back
        # to CPython exec so the runtime handles the namespace injection.
        if any(alias.name == '*' for alias in node.names):
            return self._bridge_fallback_stmt(
                node, f"star import: from {mod_name} import *")

        # Native module: store function markers instead of pyobj
        if mod_name in self._NATIVE_MODULES:
            if not hasattr(self, '_native_imports'):
                self._native_imports = {}
            for alias in node.names:
                attr_name = alias.name
                var_name = alias.asname if alias.asname else attr_name
                self._native_imports[var_name] = (mod_name, attr_name)
                # Store dummy — calls are intercepted in _emit_call_expr
                self._store_variable(var_name, ir.Constant(i64, 0), "native_func")
            # At module level, also import the real objects via CPython
            # bridge so they're accessible as values (e.g. `type=Path`
            # passes the callable as an argument, not via native dispatch).
            if self.function.name == "fastpy_main":
                if mod_name not in self._cpython_modules:
                    gv = ir.GlobalVariable(
                        self.module, i8_ptr,
                        name=f"fastpy.pymod.{mod_name}")
                    gv.initializer = ir.Constant(i8_ptr, None)
                    gv.linkage = "private"
                    self._cpython_modules[mod_name] = gv
                name_ptr = self._make_string_constant(mod_name)
                mod_ptr = self.builder.call(
                    self.runtime["cpython_import"], [name_ptr])
                self.builder.store(mod_ptr, self._cpython_modules[mod_name])
                for alias in node.names:
                    attr_name = alias.name
                    var_name = alias.asname if alias.asname else attr_name
                    if var_name not in self._global_vars:
                        gvar = ir.GlobalVariable(
                            self.module, i8_ptr,
                            name=f"fastpy.fromimport.{var_name}")
                        gvar.initializer = ir.Constant(i8_ptr, None)
                        gvar.linkage = "private"
                        self._global_vars[var_name] = (
                            gvar, ValueType(VKind.PYOBJ))
                    attr_ptr = self._make_string_constant(attr_name)
                    pyobj = self.builder.call(
                        self.runtime["cpython_getattr"],
                        [mod_ptr, attr_ptr])
                    self.builder.store(
                        pyobj, self._global_vars[var_name][0])
            return

        if mod_name not in self._cpython_modules:
            gvar = ir.GlobalVariable(
                self.module, i8_ptr,
                name=f"fastpy.pymod.{mod_name}")
            gvar.initializer = ir.Constant(i8_ptr, None)
            gvar.linkage = "private"
            self._cpython_modules[mod_name] = gvar

        name_ptr = self._make_string_constant(mod_name)
        mod_ptr = self.builder.call(
            self.runtime["cpython_import"], [name_ptr])
        self.builder.store(mod_ptr, self._cpython_modules[mod_name])

        for alias in node.names:
            attr_name = alias.name
            var_name = alias.asname if alias.asname else attr_name
            attr_ptr = self._make_string_constant(attr_name)
            pyobj = self.builder.call(
                self.runtime["cpython_getattr"], [mod_ptr, attr_ptr])
            # Check if the attribute is callable (function) or a value
            # (constant like pi). For constants, convert to native FpyValue
            # at import time. For callables, keep as pyobj.
            # Use cpython_to_fv to convert — if it's a callable, it will
            # come back as OBJ tag (opaque). Store as pyobj either way
            # since we need the callable pointer for function calls.
            # Module-level from-imports must be LLVM globals so user
            # functions can access them (e.g. `from pathlib import Path`
            # then `Path(...)` inside a function).  Stack allocas in
            # fastpy_main are invisible to other LLVM functions.
            if (self.function.name == "fastpy_main"
                    and var_name not in self._global_vars):
                gvar = ir.GlobalVariable(
                    self.module, i8_ptr,
                    name=f"fastpy.fromimport.{var_name}")
                gvar.initializer = ir.Constant(i8_ptr, None)
                gvar.linkage = "private"
                self._global_vars[var_name] = (
                    gvar, ValueType(VKind.PYOBJ))
            self._store_variable(var_name, pyobj, ValueType(VKind.PYOBJ))
            # Track the module/attr so we can re-fetch at call time
            if not hasattr(self, '_bridge_imports'):
                self._bridge_imports = {}
            self._bridge_imports[var_name] = (mod_name, attr_name)

    def _emit_async_funcdef(self, node: ast.AsyncFunctionDef) -> None:
        """Emit `async def f(): ...` by compiling as a regular function.

        In an AOT binary, there's no event loop to yield to, so async
        functions are compiled synchronously: `await expr` becomes just
        `expr` (the awaited call is executed immediately).

        For programs that use asyncio.run() or asyncio.gather(), those
        still route through the CPython bridge via import. But standalone
        async functions (the common case in compiled code) become native.

        Since asyncio is now a native module (run/gather/sleep handled natively),
        async functions that use asyncio are also compiled natively.
        """
        # Transform async def into regular def by stripping await.
        # Create a regular FunctionDef with the same body, where:
        # - `await expr` → just `expr` (synchronous call)
        # - `async for` → regular `for`
        # - `async with` → regular `with`
        sync_node = self._async_to_sync(node)
        # Declare and emit as a regular function
        if sync_node.name not in self._user_functions:
            self._declare_user_function(sync_node)
        self._emit_function_def(sync_node)

    def _async_to_sync(self, node: ast.AsyncFunctionDef) -> ast.FunctionDef:
        """Transform an async function definition into a synchronous one.
        Strips await, async for, async with into their sync equivalents."""
        import copy

        class AsyncStripper(ast.NodeTransformer):
            def visit_Await(self, node):
                # await expr → just expr
                self.generic_visit(node)
                return node.value

            def visit_AsyncFor(self, node):
                self.generic_visit(node)
                return ast.For(
                    target=node.target, iter=node.iter,
                    body=node.body, orelse=node.orelse)

            def visit_AsyncWith(self, node):
                self.generic_visit(node)
                return ast.With(items=node.items, body=node.body)

        # Create FunctionDef from AsyncFunctionDef
        sync = ast.FunctionDef(
            name=node.name,
            args=copy.deepcopy(node.args),
            body=copy.deepcopy(node.body),
            decorator_list=[],
            returns=node.returns)
        ast.copy_location(sync, node)
        # Strip async constructs
        sync = AsyncStripper().visit(sync)
        ast.fix_missing_locations(sync)
        return sync

    def _emit_try_star(self, node: ast.TryStar) -> None:
        """Emit try/except* (exception groups).
        Simplified implementation: when ExceptionGroup is raised, the inner
        exception types are stored. except* matches against the inner types.
        For the common case of single-type groups, this is semantically
        equivalent to CPython's behavior."""
        # TryStar has the same structure as Try: body, handlers, orelse, finalbody
        has_except = bool(node.handlers)
        has_finally = bool(node.finalbody)

        except_block = self._new_block("trystar.except") if has_except else None
        finally_block = self._new_block("trystar.finally") if has_finally else None
        end_block = self._new_block("trystar.end")

        if has_finally:
            self._finally_stack.append(node.finalbody)

        # Emit try body with exception checking
        saved_in_try = self._in_try_block
        saved_exc_target = getattr(self, '_try_except_target', None)
        self._in_try_block = True
        exc_target = except_block if except_block else (finally_block if finally_block else end_block)
        self._try_except_target = exc_target
        for stmt in node.body:
            if self.builder.block.is_terminated:
                break
            self._emit_stmt(stmt)
            if self.builder.block.is_terminated:
                break
            pending = self.builder.call(self.runtime["exc_pending"], [])
            is_exc = self.builder.icmp_signed("!=", pending, ir.Constant(i32, 0))
            cont_block = self._new_block("trystar.cont")
            self.builder.cbranch(is_exc, exc_target, cont_block)
            self.builder.position_at_end(cont_block)

        self._in_try_block = saved_in_try
        self._try_except_target = saved_exc_target
        if not self.builder.block.is_terminated:
            if finally_block:
                self.builder.branch(finally_block)
            else:
                self.builder.branch(end_block)

        # Except* handlers — match against inner exception types for groups.
        # Unlike regular except, ALL matching except* handlers run (not just first).
        # Strategy: pre-compute all match results while exception is live,
        # store them in allocas, clear exception, then run matched handlers.
        if has_except:
            self.builder.position_at_end(except_block)
            exc_type = self.builder.call(self.runtime["exc_get_type"], [])
            saved_exc_type_alloca = self._create_entry_alloca(i32, "saved.exc.type")
            saved_exc_msg_alloca = self._create_entry_alloca(i8_ptr, "saved.exc.msg")
            self.builder.store(exc_type, saved_exc_type_alloca)
            saved_msg = self.builder.call(self.runtime["exc_get_msg"], [])
            self.builder.store(saved_msg, saved_exc_msg_alloca)
            self._saved_exc_type = saved_exc_type_alloca
            self._saved_exc_msg = saved_exc_msg_alloca

            # Check if this is an ExceptionGroup
            exc_group_name = self._make_string_constant("ExceptionGroup")
            expected_group_id = self.builder.call(
                self.runtime["exc_name_to_id"], [exc_group_name])
            is_group = self.builder.icmp_signed("==", exc_type, expected_group_id)

            # Phase 1: pre-compute match results for each handler
            # while exception state is still live (exc_group_has_type reads globals)
            handler_match_allocas = []
            for hi, handler in enumerate(node.handlers):
                match_alloca = self._create_entry_alloca(
                    ir.IntType(1), f"estarMatch.{hi}")
                match_result = ir.Constant(ir.IntType(1), 0)

                def _compute_match(type_node):
                    if isinstance(type_node, ast.Name):
                        n = self._make_string_constant(type_node.id)
                        eid = self.builder.call(
                            self.runtime["exc_name_to_id"], [n])
                        gm = self.builder.call(
                            self.runtime["exc_group_has_type"], [eid])
                        gm_bool = self.builder.icmp_signed(
                            "!=", gm, ir.Constant(i32, 0))
                        g_res = self.builder.and_(is_group, gm_bool)
                        d_match = self.builder.icmp_signed("==", exc_type, eid)
                        ng = self.builder.not_(is_group)
                        d_res = self.builder.and_(ng, d_match)
                        return self.builder.or_(g_res, d_res)
                    elif isinstance(type_node, ast.Attribute):
                        n = self._make_string_constant(type_node.attr)
                        eid = self.builder.call(
                            self.runtime["exc_name_to_id"], [n])
                        gm = self.builder.call(
                            self.runtime["exc_group_has_type"], [eid])
                        gm_bool = self.builder.icmp_signed(
                            "!=", gm, ir.Constant(i32, 0))
                        g_res = self.builder.and_(is_group, gm_bool)
                        d_match = self.builder.icmp_signed("==", exc_type, eid)
                        ng = self.builder.not_(is_group)
                        d_res = self.builder.and_(ng, d_match)
                        return self.builder.or_(g_res, d_res)
                    return None

                if handler.type is not None:
                    if isinstance(handler.type, ast.Tuple):
                        for elt in handler.type.elts:
                            m = _compute_match(elt)
                            if m is not None:
                                match_result = self.builder.or_(match_result, m)
                    else:
                        m = _compute_match(handler.type)
                        if m is not None:
                            match_result = m
                        else:
                            match_result = ir.Constant(ir.IntType(1), 1)
                else:
                    match_result = ir.Constant(ir.IntType(1), 1)

                self.builder.store(match_result, match_alloca)
                handler_match_allocas.append(match_alloca)

            # Phase 2: clear exception so handler bodies can execute normally
            self.builder.call(self.runtime["exc_clear"], [])

            # Phase 3: run all matched handlers
            for hi, handler in enumerate(node.handlers):
                handler_block = self._new_block("exceptstar.handler")
                next_handler = self._new_block("exceptstar.next")

                matched = self.builder.load(handler_match_allocas[hi])
                self.builder.cbranch(matched, handler_block, next_handler)

                self.builder.position_at_end(handler_block)
                if handler.name:
                    msg = self.builder.load(saved_exc_msg_alloca)
                    self._store_variable(handler.name, msg, ValueType(VKind.STR))
                self._emit_stmts(handler.body)
                if not self.builder.block.is_terminated:
                    self.builder.branch(next_handler)

                self.builder.position_at_end(next_handler)

            # After all handlers, continue
            if not self.builder.block.is_terminated:
                if finally_block:
                    self.builder.branch(finally_block)
                else:
                    self.builder.branch(end_block)

            if not self.builder.block.is_terminated:
                if finally_block:
                    self.builder.branch(finally_block)
                else:
                    self.builder.call(self.runtime["exc_unhandled"], [])
                    self.builder.unreachable()

        if has_finally:
            self._finally_stack.pop()

        if has_finally:
            self.builder.position_at_end(finally_block)
            self._emit_stmts(node.finalbody)
            if not self.builder.block.is_terminated:
                self.builder.branch(end_block)

        self.builder.position_at_end(end_block)

    # ── Optimization analysis recording ─────────────────────────────────

    def _record_finding(self, severity: str, category: str,
                        node_or_line, construct: str,
                        missed: str, reason: str,
                        impact: str, suggestion: str = "") -> None:
        """Record an optimization finding (no-op when analyze_mode is off)."""
        if not self._analyze_mode:
            return
        from compiler.analysis import OptimizationFinding
        line = (getattr(node_or_line, 'lineno', None)
                if not isinstance(node_or_line, int)
                else node_or_line)
        self._opt_findings.append(OptimizationFinding(
            severity=severity,
            category=category,
            line=line,
            scope=self._current_scope,
            construct=construct,
            optimization_missed=missed,
            reason=reason,
            impact_estimate=impact,
            suggestion=suggestion,
        ))

    # ── Phase 4: Bridge fallback infrastructure ─────────────────────────
    # When the compiler encounters a pattern it can't handle natively,
    # these methods fall back to CPython instead of raising CodeGenError.
    # Every fallback is logged for documentation (see BRIDGE_FALLBACKS.md).

    _bridge_fallback_log: list[str] = []  # class-level log

    def _bridge_fallback_expr(self, node: ast.expr, reason: str) -> ir.Value:
        """Fall back to CPython bridge for an expression we can't compile.

        Converts the expression to source text, passes it to exec/eval
        via the bridge, and returns the result. This is the universal
        escape hatch — any Python expression can be evaluated this way.

        For simple cases (function calls, method calls), uses the more
        efficient direct bridge path instead of exec."""
        self._bridge_fallback_log.append(
            f"line {getattr(node, 'lineno', '?')}: {reason}")
        from compiler.analysis import CRITICAL, IMPACT_BRIDGE
        self._record_finding(
            CRITICAL, "bridge_fallback", node,
            construct=reason,
            missed="Bridge fallback (CPython interpreter)",
            reason=reason,
            impact=IMPACT_BRIDGE,
            suggestion="Simplify this expression to use constructs "
                       "the compiler handles natively",
        )

        # Don't retry method/call paths — they may have called us, causing
        # infinite recursion. Just return 0 as a safe default.
        return ir.Constant(i64, 0)

    def _bridge_fallback_stmt(self, node: ast.stmt, reason: str) -> None:
        """Fall back to CPython bridge for a statement we can't compile.
        Currently a no-op (skips the statement) — logged for documentation."""
        self._bridge_fallback_log.append(
            f"line {getattr(node, 'lineno', '?')}: {reason}")
        from compiler.analysis import CRITICAL, IMPACT_BRIDGE
        self._record_finding(
            CRITICAL, "bridge_fallback", node,
            construct=reason,
            missed="Bridge fallback (CPython interpreter)",
            reason=reason,
            impact=IMPACT_BRIDGE,
            suggestion="Simplify this statement to use constructs "
                       "the compiler handles natively",
        )

    def _emit_cpython_method_call(self, node: ast.Call) -> ir.Value:
        """Emit a call to a function accessed via CPython module attribute.
        E.g., math.sqrt(4.0) where math is a pyobj-tagged variable."""
        attr = node.func  # ast.Attribute
        # inspect.signature(func) where func is a user function:
        # Create a dummy Python function with the right signature via
        # bridge exec so inspect.signature() sees correct parameters.
        if (isinstance(attr.value, ast.Name)
                and attr.value.id == "inspect"
                and attr.attr == "signature"
                and len(node.args) == 1
                and isinstance(node.args[0], ast.Name)
                and node.args[0].id in self._user_functions):
            info = self._user_functions[node.args[0].id]
            names = info.param_names or [f"_p{i}" for i in range(info.param_count)]
            n_defaults = len(info.defaults) if info.defaults else 0
            # Build parameter list with defaults: "a, b, c=0"
            parts = []
            for i, pname in enumerate(names):
                # Parameters with defaults are right-aligned
                if i >= len(names) - n_defaults:
                    parts.append(f"{pname}=0")
                else:
                    parts.append(pname)
            sig_str = ", ".join(parts)
            # Exec code that creates a function and gets its signature
            code = f"import inspect\ndef _f({sig_str}): pass\n_sig = inspect.signature(_f)"
            code_ptr = self._make_string_constant(code)
            name_ptr = self._make_string_constant("_sig")
            sig_obj = self.builder.call(
                self.runtime["cpython_exec_get"], [code_ptr, name_ptr])
            # Return as FpyValue with OBJ tag
            return self._fv_build_from_slots(
                ir.Constant(i32, FPY_TAG_OBJ),
                self.builder.ptrtoint(sig_obj, i64))
        # Get the module/object pointer
        obj = self._emit_expr_value(attr.value)
        if (isinstance(obj.type, ir.LiteralStructType)
              and obj.type == fpy_val):
            # FpyValue — convert to PyObject* properly via bridge
            # (raw data extraction is wrong for STR/LIST/DICT/etc.)
            rcv_tag = self.builder.extract_value(obj, 0)
            rcv_data = self.builder.extract_value(obj, 1)
            obj = self.builder.call(
                self.runtime["cpython_to_pyobj"], [rcv_tag, rcv_data])
        elif isinstance(obj.type, ir.IntType):
            obj = self._ensure_ptr(obj)
        # Get the callable attribute
        attr_name = self._make_string_constant(attr.attr)
        callable_ptr = self.builder.call(
            self.runtime["cpython_getattr"], [obj, attr_name])

        # Prepare output slots
        out_tag = self._create_entry_alloca(i32, "pycall.tag")
        out_data = self._create_entry_alloca(i64, "pycall.data")

        # If there are keyword arguments, use the general call_kw path
        if node.keywords:
            n_pos = len(node.args)
            n_kw = len(node.keywords)
            # Build positional arg arrays
            tags_alloca = self.builder.alloca(
                ir.ArrayType(i32, max(n_pos, 1)), name="kw.tags")
            data_alloca = self.builder.alloca(
                ir.ArrayType(i64, max(n_pos, 1)), name="kw.data")
            for i, arg_node in enumerate(node.args):
                val = self._emit_expr_value(arg_node)
                t_ir, d_ir = self._to_bridge_tag_data_ir(val, arg_node)
                tag_ptr = self.builder.gep(tags_alloca,
                    [ir.Constant(i32, 0), ir.Constant(i32, i)])
                data_ptr = self.builder.gep(data_alloca,
                    [ir.Constant(i32, 0), ir.Constant(i32, i)])
                self.builder.store(t_ir, tag_ptr)
                self.builder.store(d_ir, data_ptr)
            # Build keyword arg arrays
            names_alloca = self.builder.alloca(
                ir.ArrayType(i8_ptr, n_kw), name="kw.names")
            kw_tags_alloca = self.builder.alloca(
                ir.ArrayType(i32, n_kw), name="kw.ktags")
            kw_data_alloca = self.builder.alloca(
                ir.ArrayType(i64, n_kw), name="kw.kdata")
            for i, kw in enumerate(node.keywords):
                name_ptr = self._make_string_constant(kw.arg)
                val = self._emit_expr_value(kw.value)
                t_ir, d_ir = self._to_bridge_tag_data_ir(val, kw.value)
                n_ptr = self.builder.gep(names_alloca,
                    [ir.Constant(i32, 0), ir.Constant(i32, i)])
                t_ptr = self.builder.gep(kw_tags_alloca,
                    [ir.Constant(i32, 0), ir.Constant(i32, i)])
                d_ptr = self.builder.gep(kw_data_alloca,
                    [ir.Constant(i32, 0), ir.Constant(i32, i)])
                self.builder.store(name_ptr, n_ptr)
                self.builder.store(t_ir, t_ptr)
                self.builder.store(d_ir, d_ptr)
            # Call
            tags_base = self.builder.gep(tags_alloca,
                [ir.Constant(i32, 0), ir.Constant(i32, 0)])
            data_base = self.builder.gep(data_alloca,
                [ir.Constant(i32, 0), ir.Constant(i32, 0)])
            names_base = self.builder.gep(names_alloca,
                [ir.Constant(i32, 0), ir.Constant(i32, 0)])
            kt_base = self.builder.gep(kw_tags_alloca,
                [ir.Constant(i32, 0), ir.Constant(i32, 0)])
            kd_base = self.builder.gep(kw_data_alloca,
                [ir.Constant(i32, 0), ir.Constant(i32, 0)])
            self.builder.call(self.runtime["cpython_call_kw"],
                              [callable_ptr,
                               ir.Constant(i32, n_pos), tags_base, data_base,
                               ir.Constant(i32, n_kw), names_base, kt_base, kd_base,
                               out_tag, out_data])
            tag_val = self.builder.load(out_tag)
            data_val = self.builder.load(out_data)
            return self._fv_build_from_slots(tag_val, data_val)

        n_args = len(node.args)
        if n_args == 0:
            self.builder.call(self.runtime["cpython_call0"],
                              [callable_ptr, out_tag, out_data])
        elif n_args == 1:
            arg = self._emit_expr_value(node.args[0])
            t_ir, d_ir = self._to_bridge_tag_data_ir(arg, node.args[0])
            self.builder.call(self.runtime["cpython_call1"],
                              [callable_ptr,
                               t_ir, d_ir,
                               out_tag, out_data])
        elif n_args == 2:
            a1 = self._emit_expr_value(node.args[0])
            t1_ir, d1_ir = self._to_bridge_tag_data_ir(a1, node.args[0])
            a2 = self._emit_expr_value(node.args[1])
            t2_ir, d2_ir = self._to_bridge_tag_data_ir(a2, node.args[1])
            self.builder.call(self.runtime["cpython_call2"],
                              [callable_ptr,
                               t1_ir, d1_ir,
                               t2_ir, d2_ir,
                               out_tag, out_data])
        elif n_args == 3:
            a1 = self._emit_expr_value(node.args[0])
            t1_ir, d1_ir = self._to_bridge_tag_data_ir(a1, node.args[0])
            a2 = self._emit_expr_value(node.args[1])
            t2_ir, d2_ir = self._to_bridge_tag_data_ir(a2, node.args[1])
            a3 = self._emit_expr_value(node.args[2])
            t3_ir, d3_ir = self._to_bridge_tag_data_ir(a3, node.args[2])
            self.builder.call(self.runtime["cpython_call3"],
                              [callable_ptr,
                               t1_ir, d1_ir,
                               t2_ir, d2_ir,
                               t3_ir, d3_ir,
                               out_tag, out_data])
        else:
            # 4+ positional args: use call_kw with 0 keyword args
            tags_alloca = self.builder.alloca(
                ir.ArrayType(i32, n_args), name="call.tags")
            data_alloca = self.builder.alloca(
                ir.ArrayType(i64, n_args), name="call.data")
            for i, arg_node in enumerate(node.args):
                val = self._emit_expr_value(arg_node)
                t_ir, d_ir = self._to_bridge_tag_data_ir(val, arg_node)
                tp = self.builder.gep(tags_alloca,
                    [ir.Constant(i64, 0), ir.Constant(i32, i)])
                self.builder.store(t_ir, tp)
                dp = self.builder.gep(data_alloca,
                    [ir.Constant(i64, 0), ir.Constant(i32, i)])
                self.builder.store(d_ir, dp)
            tags_base = self.builder.gep(tags_alloca,
                [ir.Constant(i32, 0), ir.Constant(i32, 0)])
            data_base = self.builder.gep(data_alloca,
                [ir.Constant(i32, 0), ir.Constant(i32, 0)])
            # null pointers for keyword args (none)
            null_names = ir.Constant(ir.PointerType(i8_ptr), None)
            null_tags = ir.Constant(ir.PointerType(i32), None)
            null_data = ir.Constant(ir.PointerType(i64), None)
            self.builder.call(self.runtime["cpython_call_kw"],
                              [callable_ptr,
                               ir.Constant(i32, n_args), tags_base, data_base,
                               ir.Constant(i32, 0), null_names, null_tags, null_data,
                               out_tag, out_data])

        # Return the result — determine bare type from tag
        tag_val = self.builder.load(out_tag)
        data_val = self.builder.load(out_data)

        # For now, return as FpyValue and let the caller handle it
        return self._fv_build_from_slots(tag_val, data_val)

    def _emit_bridge_stdout_flush(self) -> None:
        """Flush Python's sys.stdout to sync bridge output with native output.

        When mixing native printf (fastpy_fv_print) with Python's print()
        (inside bridge-compiled functions like @contextmanager), output order
        can be wrong because Python's stdout is fully buffered when piped.
        This creates a flush function via exec_get and calls it.

        Also reconfigures Python's stdout to avoid double-newline issues on
        Windows (Python TextIOWrapper's \\r\\n + C _O_TEXT \\r\\n = \\r\\r\\n)."""
        if not hasattr(self, '_bridge_flush_gvar'):
            code = (
                "import sys, os\n"
                "def _fpy_flush():\n"
                "    sys.stdout.flush()\n"
                "# Reconfigure stdout: write_through for immediate output,\n"
                "# newline='\\n' to avoid double \\r\\n on Windows.\n"
                "try:\n"
                "    sys.stdout.reconfigure(write_through=True, newline='\\n')\n"
                "except (AttributeError, OSError):\n"
                "    pass\n"
            )
            code_ptr = self._make_string_constant(code)
            name_ptr = self._make_string_constant("_fpy_flush")
            flush_fn = self.builder.call(
                self.runtime["cpython_exec_get"], [code_ptr, name_ptr])
            # Store in a global so we can reuse it
            gvar = ir.GlobalVariable(
                self.module, i8_ptr, name="fastpy.bridge_flush")
            gvar.initializer = ir.Constant(i8_ptr, None)
            gvar.linkage = "private"
            self.builder.store(flush_fn, gvar)
            self._bridge_flush_gvar = gvar
        flush_fn = self.builder.load(self._bridge_flush_gvar)
        self.builder.call(
            self.runtime["cpython_call0_raw"], [flush_fn])

    def _emit_cpython_call_raw(self, node: ast.Call) -> ir.Value:
        """Emit a CPython method call that returns the raw PyObject* (i8_ptr).
        Used when the result will be stored as pyobj for downstream operations."""
        attr = node.func  # ast.Attribute or ast.Name
        # Handle direct PYOBJ function calls: ctx("test") where ctx is pyobj.
        # The callable is already a PyObject*, just call it directly.
        if isinstance(attr, ast.Name):
            callable_ptr = self._emit_expr_value(attr)
            callable_ptr = self._ensure_ptr(callable_ptr)
            return self._emit_cpython_call_raw_with_callable(node, callable_ptr)
        # inspect.signature(func) where func is a user function:
        # Create a dummy Python function with the right signature via
        # bridge exec so inspect.signature() sees correct parameters.
        if (isinstance(attr.value, ast.Name)
                and attr.value.id == "inspect"
                and attr.attr == "signature"
                and len(node.args) == 1
                and isinstance(node.args[0], ast.Name)
                and node.args[0].id in self._user_functions):
            info = self._user_functions[node.args[0].id]
            names = info.param_names or [f"_p{i}" for i in range(info.param_count)]
            n_defaults = len(info.defaults) if info.defaults else 0
            parts = []
            for i, pname in enumerate(names):
                if i >= len(names) - n_defaults:
                    parts.append(f"{pname}=0")
                else:
                    parts.append(pname)
            sig_str = ", ".join(parts)
            code = f"import inspect\ndef _f({sig_str}): pass\n_sig = inspect.signature(_f)"
            code_ptr = self._make_string_constant(code)
            name_ptr = self._make_string_constant("_sig")
            return self.builder.call(
                self.runtime["cpython_exec_get"], [code_ptr, name_ptr])
        obj = self._emit_expr_value(attr.value)
        obj = self._ensure_ptr(obj)
        attr_name = self._make_string_constant(attr.attr)
        callable_ptr = self.builder.call(
            self.runtime["cpython_getattr"], [obj, attr_name])
        return self._emit_cpython_call_raw_with_callable(node, callable_ptr)

    def _emit_cpython_call_raw_with_callable(self, node: ast.Call,
                                               callable_ptr: 'ir.Value') -> 'ir.Value':
        """Call a known PyObject* callable and return the raw PyObject* result.

        Shared implementation for _emit_cpython_call_raw when the callable
        is already resolved (either from getattr on an object or from a
        direct PYOBJ variable like @contextmanager-decorated functions).
        """
        if node.keywords:
            n_pos = len(node.args)
            n_kw = len(node.keywords)
            tags_alloca = self.builder.alloca(
                ir.ArrayType(i32, max(n_pos, 1)), name="raw.tags")
            data_alloca = self.builder.alloca(
                ir.ArrayType(i64, max(n_pos, 1)), name="raw.data")
            for i, arg_node in enumerate(node.args):
                val = self._emit_expr_value(arg_node)
                t_ir, d_ir = self._to_bridge_tag_data_ir(val, arg_node)
                self.builder.store(t_ir,
                    self.builder.gep(tags_alloca,
                        [ir.Constant(i32, 0), ir.Constant(i32, i)]))
                self.builder.store(d_ir,
                    self.builder.gep(data_alloca,
                        [ir.Constant(i32, 0), ir.Constant(i32, i)]))
            names_alloca = self.builder.alloca(
                ir.ArrayType(i8_ptr, n_kw), name="raw.knames")
            kt_alloca = self.builder.alloca(
                ir.ArrayType(i32, n_kw), name="raw.ktags")
            kd_alloca = self.builder.alloca(
                ir.ArrayType(i64, n_kw), name="raw.kdata")
            for i, kw in enumerate(node.keywords):
                name_ptr = self._make_string_constant(kw.arg)
                val = self._emit_expr_value(kw.value)
                t_ir, d_ir = self._to_bridge_tag_data_ir(val, kw.value)
                self.builder.store(name_ptr,
                    self.builder.gep(names_alloca,
                        [ir.Constant(i32, 0), ir.Constant(i32, i)]))
                self.builder.store(t_ir,
                    self.builder.gep(kt_alloca,
                        [ir.Constant(i32, 0), ir.Constant(i32, i)]))
                self.builder.store(d_ir,
                    self.builder.gep(kd_alloca,
                        [ir.Constant(i32, 0), ir.Constant(i32, i)]))
            return self.builder.call(self.runtime["cpython_call_kw_raw"],
                [callable_ptr,
                 ir.Constant(i32, n_pos),
                 self.builder.gep(tags_alloca, [ir.Constant(i32, 0), ir.Constant(i32, 0)]),
                 self.builder.gep(data_alloca, [ir.Constant(i32, 0), ir.Constant(i32, 0)]),
                 ir.Constant(i32, n_kw),
                 self.builder.gep(names_alloca, [ir.Constant(i32, 0), ir.Constant(i32, 0)]),
                 self.builder.gep(kt_alloca, [ir.Constant(i32, 0), ir.Constant(i32, 0)]),
                 self.builder.gep(kd_alloca, [ir.Constant(i32, 0), ir.Constant(i32, 0)])])
        n_args = len(node.args)
        if n_args == 0:
            return self.builder.call(
                self.runtime["cpython_call0_raw"], [callable_ptr])
        elif n_args == 1:
            arg = self._emit_expr_value(node.args[0])
            t_ir, d_ir = self._to_bridge_tag_data_ir(arg, node.args[0])
            return self.builder.call(
                self.runtime["cpython_call1_raw"],
                [callable_ptr, t_ir, d_ir])
        elif n_args == 2:
            a1 = self._emit_expr_value(node.args[0])
            t1_ir, d1_ir = self._to_bridge_tag_data_ir(a1, node.args[0])
            a2 = self._emit_expr_value(node.args[1])
            t2_ir, d2_ir = self._to_bridge_tag_data_ir(a2, node.args[1])
            return self.builder.call(
                self.runtime["cpython_call2_raw"],
                [callable_ptr, t1_ir, d1_ir, t2_ir, d2_ir])
        else:
            # 3+ positional args: use keyword call path with 0 keywords
            tags_alloca = self.builder.alloca(
                ir.ArrayType(i32, n_args), name="raw.tags")
            data_alloca = self.builder.alloca(
                ir.ArrayType(i64, n_args), name="raw.data")
            for i, arg_node in enumerate(node.args):
                val = self._emit_expr_value(arg_node)
                t_ir, d_ir = self._to_bridge_tag_data_ir(val, arg_node)
                self.builder.store(t_ir, self.builder.gep(
                    tags_alloca,
                    [ir.Constant(i32, 0), ir.Constant(i32, i)]))
                self.builder.store(d_ir, self.builder.gep(
                    data_alloca,
                    [ir.Constant(i32, 0), ir.Constant(i32, i)]))
            return self.builder.call(
                self.runtime["cpython_call_kw_raw"],
                [callable_ptr,
                 ir.Constant(i32, n_args),
                 self.builder.gep(tags_alloca,
                    [ir.Constant(i32, 0), ir.Constant(i32, 0)]),
                 self.builder.gep(data_alloca,
                    [ir.Constant(i32, 0), ir.Constant(i32, 0)]),
                 ir.Constant(i32, 0),
                 ir.Constant(ir.PointerType(i8_ptr), None),
                 ir.Constant(ir.PointerType(i32), None),
                 ir.Constant(ir.PointerType(i64), None)])

    def _emit_cpython_call_with_ptr(self, callable_ptr: 'ir.Value',
                                     node: ast.Call) -> 'ir.Value':
        """Call a known PyObject* callable with the given args. Returns FpyValue."""
        out_tag = self._create_entry_alloca(i32, "brcall.tag")
        out_data = self._create_entry_alloca(i64, "brcall.data")
        n_args = len(node.args)
        if node.keywords:
            # Use kwargs path
            n_pos = len(node.args)
            n_kw = len(node.keywords)
            tags_alloca = self.builder.alloca(ir.ArrayType(i32, max(n_pos, 1)))
            data_alloca = self.builder.alloca(ir.ArrayType(i64, max(n_pos, 1)))
            for i, arg_node in enumerate(node.args):
                val = self._emit_expr_value(arg_node)
                t_ir, d_ir = self._to_bridge_tag_data_ir(val, arg_node)
                tp = self.builder.gep(tags_alloca, [ir.Constant(i64, 0), ir.Constant(i32, i)])
                self.builder.store(t_ir, tp)
                dp = self.builder.gep(data_alloca, [ir.Constant(i64, 0), ir.Constant(i32, i)])
                self.builder.store(d_ir, dp)
            kw_names = self.builder.alloca(ir.ArrayType(i8_ptr, max(n_kw, 1)))
            kw_tags = self.builder.alloca(ir.ArrayType(i32, max(n_kw, 1)))
            kw_data = self.builder.alloca(ir.ArrayType(i64, max(n_kw, 1)))
            for i, kw in enumerate(node.keywords):
                np = self.builder.gep(kw_names, [ir.Constant(i64, 0), ir.Constant(i32, i)])
                self.builder.store(self._make_string_constant(kw.arg), np)
                val = self._emit_expr_value(kw.value)
                t_ir, d_ir = self._to_bridge_tag_data_ir(val, kw.value)
                tp = self.builder.gep(kw_tags, [ir.Constant(i64, 0), ir.Constant(i32, i)])
                self.builder.store(t_ir, tp)
                dp = self.builder.gep(kw_data, [ir.Constant(i64, 0), ir.Constant(i32, i)])
                self.builder.store(d_ir, dp)
            t_ptr = self.builder.gep(tags_alloca, [ir.Constant(i64, 0), ir.Constant(i32, 0)])
            d_ptr = self.builder.gep(data_alloca, [ir.Constant(i64, 0), ir.Constant(i32, 0)])
            kn_ptr = self.builder.gep(kw_names, [ir.Constant(i64, 0), ir.Constant(i32, 0)])
            kt_ptr = self.builder.gep(kw_tags, [ir.Constant(i64, 0), ir.Constant(i32, 0)])
            kd_ptr = self.builder.gep(kw_data, [ir.Constant(i64, 0), ir.Constant(i32, 0)])
            self.builder.call(self.runtime["cpython_call_kw"],
                              [callable_ptr, ir.Constant(i32, n_pos),
                               t_ptr, d_ptr, ir.Constant(i32, n_kw),
                               kn_ptr, kt_ptr, kd_ptr, out_tag, out_data])
        elif n_args == 0:
            self.builder.call(self.runtime["cpython_call0"],
                              [callable_ptr, out_tag, out_data])
        elif n_args == 1:
            arg = self._emit_expr_value(node.args[0])
            t_ir, d_ir = self._to_bridge_tag_data_ir(arg, node.args[0])
            self.builder.call(self.runtime["cpython_call1"],
                              [callable_ptr, t_ir, d_ir,
                               out_tag, out_data])
        elif n_args == 2:
            a1 = self._emit_expr_value(node.args[0])
            t1_ir, d1_ir = self._to_bridge_tag_data_ir(a1, node.args[0])
            a2 = self._emit_expr_value(node.args[1])
            t2_ir, d2_ir = self._to_bridge_tag_data_ir(a2, node.args[1])
            self.builder.call(self.runtime["cpython_call2"],
                              [callable_ptr, t1_ir, d1_ir,
                               t2_ir, d2_ir, out_tag, out_data])
        elif n_args == 3:
            a1 = self._emit_expr_value(node.args[0])
            t1_ir, d1_ir = self._to_bridge_tag_data_ir(a1, node.args[0])
            a2 = self._emit_expr_value(node.args[1])
            t2_ir, d2_ir = self._to_bridge_tag_data_ir(a2, node.args[1])
            a3 = self._emit_expr_value(node.args[2])
            t3_ir, d3_ir = self._to_bridge_tag_data_ir(a3, node.args[2])
            self.builder.call(self.runtime["cpython_call3"],
                              [callable_ptr, t1_ir, d1_ir,
                               t2_ir, d2_ir,
                               t3_ir, d3_ir, out_tag, out_data])
        else:
            # Fallback: use kwargs path with 0 kwargs
            tags_alloca = self.builder.alloca(ir.ArrayType(i32, n_args))
            data_alloca = self.builder.alloca(ir.ArrayType(i64, n_args))
            for i, arg_node in enumerate(node.args):
                val = self._emit_expr_value(arg_node)
                t_ir, d_ir = self._to_bridge_tag_data_ir(val, arg_node)
                tp = self.builder.gep(tags_alloca, [ir.Constant(i64, 0), ir.Constant(i32, i)])
                self.builder.store(t_ir, tp)
                dp = self.builder.gep(data_alloca, [ir.Constant(i64, 0), ir.Constant(i32, i)])
                self.builder.store(d_ir, dp)
            t_ptr = self.builder.gep(tags_alloca, [ir.Constant(i64, 0), ir.Constant(i32, 0)])
            d_ptr = self.builder.gep(data_alloca, [ir.Constant(i64, 0), ir.Constant(i32, 0)])
            kn_ptr = ir.Constant(ir.PointerType(i8_ptr), None)
            kt_ptr = ir.Constant(ir.PointerType(i32), None)
            kd_ptr = ir.Constant(ir.PointerType(i64), None)
            self.builder.call(self.runtime["cpython_call_kw"],
                              [callable_ptr, ir.Constant(i32, n_args),
                               t_ptr, d_ptr, ir.Constant(i32, 0),
                               kn_ptr, kt_ptr, kd_ptr, out_tag, out_data])

        tag_val = self.builder.load(out_tag)
        data_val = self.builder.load(out_data)
        return self._fv_build_from_slots(tag_val, data_val)

    def _emit_cpython_direct_call(self, node: ast.Call) -> None:
        """Emit a call to a pyobj-tagged callable (statement context)."""
        self._emit_cpython_direct_call_expr(node)

    def _emit_cpython_direct_call_expr(self, node: ast.Call) -> ir.Value:
        """Emit a call to a pyobj-tagged callable (expression context).
        Returns an FpyValue struct."""
        name = node.func.id
        callable_ptr = self._load_variable(name, node)
        callable_ptr = self._ensure_ptr(callable_ptr)

        out_tag = self._create_entry_alloca(i32, "pycall.tag")
        out_data = self._create_entry_alloca(i64, "pycall.data")

        n_args = len(node.args)
        if n_args == 0:
            self.builder.call(self.runtime["cpython_call0"],
                              [callable_ptr, out_tag, out_data])
        elif n_args == 1:
            arg = self._emit_expr_value(node.args[0])
            t_ir, d_ir = self._to_bridge_tag_data_ir(arg, node.args[0])
            self.builder.call(self.runtime["cpython_call1"],
                              [callable_ptr,
                               t_ir, d_ir,
                               out_tag, out_data])
        elif n_args == 2:
            a1 = self._emit_expr_value(node.args[0])
            t1_ir, d1_ir = self._to_bridge_tag_data_ir(a1, node.args[0])
            a2 = self._emit_expr_value(node.args[1])
            t2_ir, d2_ir = self._to_bridge_tag_data_ir(a2, node.args[1])
            self.builder.call(self.runtime["cpython_call2"],
                              [callable_ptr,
                               t1_ir, d1_ir,
                               t2_ir, d2_ir,
                               out_tag, out_data])
        elif n_args == 3:
            a1 = self._emit_expr_value(node.args[0])
            t1_ir, d1_ir = self._to_bridge_tag_data_ir(a1, node.args[0])
            a2 = self._emit_expr_value(node.args[1])
            t2_ir, d2_ir = self._to_bridge_tag_data_ir(a2, node.args[1])
            a3 = self._emit_expr_value(node.args[2])
            t3_ir, d3_ir = self._to_bridge_tag_data_ir(a3, node.args[2])
            self.builder.call(self.runtime["cpython_call3"],
                              [callable_ptr,
                               t1_ir, d1_ir,
                               t2_ir, d2_ir,
                               t3_ir, d3_ir,
                               out_tag, out_data])
        else:
            return self._bridge_fallback_expr(node, f"CPython call with {n_args} args (max 3)")

        tag_val = self.builder.load(out_tag)
        data_val = self.builder.load(out_data)
        return self._fv_build_from_slots(tag_val, data_val)

    def _emit_try(self, node: ast.Try) -> None:
        """Emit try/except/finally using flag-based exception checking."""
        has_except = bool(node.handlers)
        has_finally = bool(node.finalbody)

        except_block = self._new_block("try.except") if has_except else None
        finally_block = self._new_block("try.finally") if has_finally else None
        end_block = self._new_block("try.end")

        # Push finally body — in scope for try body AND except handlers
        if has_finally:
            self._finally_stack.append(node.finalbody)

        # Emit try body — after each statement, check for pending exception
        saved_in_try = self._in_try_block
        saved_exc_target = getattr(self, '_try_except_target', None)
        self._in_try_block = True
        exc_target = except_block if except_block else (finally_block if finally_block else end_block)
        self._try_except_target = exc_target
        for stmt in node.body:
            if self.builder.block.is_terminated:
                break
            self._emit_stmt(stmt)
            if self.builder.block.is_terminated:
                break
            # Check for pending exception after each statement
            pending = self.builder.call(self.runtime["exc_pending"], [])
            is_exc = self.builder.icmp_signed("!=", pending, ir.Constant(i32, 0))
            cont_block = self._new_block("try.cont")
            exc_target = except_block if except_block else (finally_block if finally_block else end_block)
            self.builder.cbranch(is_exc, exc_target, cont_block)
            self.builder.position_at_end(cont_block)

        self._in_try_block = saved_in_try
        self._try_except_target = saved_exc_target
        # No exception — run else block (if present), then jump to finally/end
        has_else = bool(node.orelse)
        if not self.builder.block.is_terminated:
            if has_else:
                else_block = self._new_block("try.else")
                self.builder.branch(else_block)
                self.builder.position_at_end(else_block)
                self._emit_stmts(node.orelse)
            if not self.builder.block.is_terminated:
                if finally_block:
                    self.builder.branch(finally_block)
                else:
                    self.builder.branch(end_block)

        # Except handlers
        if has_except:
            self.builder.position_at_end(except_block)
            exc_type = self.builder.call(self.runtime["exc_get_type"], [])
            # Save exception info for bare `raise` (re-raise) support.
            # These allocas hold the type+msg so exc_clear doesn't lose them.
            saved_exc_type_alloca = self._create_entry_alloca(i32, "saved.exc.type")
            saved_exc_msg_alloca = self._create_entry_alloca(i8_ptr, "saved.exc.msg")
            saved_exc_class_alloca = self._create_entry_alloca(i8_ptr, "saved.exc.class")
            self.builder.store(exc_type, saved_exc_type_alloca)
            saved_msg = self.builder.call(self.runtime["exc_get_msg"], [])
            self.builder.store(saved_msg, saved_exc_msg_alloca)
            saved_class = self.builder.call(self.runtime["exc_get_class_name"], [])
            self.builder.store(saved_class, saved_exc_class_alloca)
            self._saved_exc_type = saved_exc_type_alloca
            self._saved_exc_msg = saved_exc_msg_alloca
            self._saved_exc_class = saved_exc_class_alloca

            for handler in node.handlers:
                if handler.type is None:
                    # bare except:
                    if handler.name:
                        msg = self.builder.call(self.runtime["exc_get_msg"], [])
                        self._store_variable(handler.name, msg, ValueType(VKind.STR))
                    self.builder.call(self.runtime["exc_clear"], [])
                    self._emit_stmts(handler.body)
                    if not self.builder.block.is_terminated:
                        if finally_block:
                            self.builder.branch(finally_block)
                        else:
                            self.builder.branch(end_block)
                else:
                    handler_block = self._new_block("except.handler")
                    next_handler = self._new_block("except.next")

                    if isinstance(handler.type, ast.Name):
                        handler_type_name = handler.type.id
                        exc_name = self._make_string_constant(handler_type_name)
                        expected_id = self.builder.call(
                            self.runtime["exc_name_to_id"], [exc_name])
                        # "Exception"/"BaseException" catch everything
                        if handler_type_name in ("Exception", "BaseException"):
                            matches = ir.Constant(ir.IntType(1), 1)
                        else:
                            # FPY_EXC_GENERIC = 99 in the runtime
                            _EXC_GENERIC = ir.Constant(i32, 99)
                            is_generic = self.builder.icmp_signed(
                                "==", exc_type, _EXC_GENERIC)
                            handler_is_generic = self.builder.icmp_signed(
                                "==", expected_id, _EXC_GENERIC)
                            both_generic = self.builder.and_(
                                is_generic, handler_is_generic)
                            # For user-defined exceptions: match via class hierarchy
                            raised_name = self.builder.call(
                                self.runtime["exc_get_class_name"], [])
                            class_match = self.builder.call(
                                self.runtime["exc_class_matches"],
                                [raised_name, exc_name])
                            class_match_bool = self.builder.icmp_signed(
                                "!=", class_match, ir.Constant(i32, 0))
                            hierarchy_match = self.builder.and_(
                                both_generic, class_match_bool)
                            # For builtin exceptions: match via ID
                            builtin_match = self.builder.and_(
                                self.builder.not_(is_generic),
                                self.builder.icmp_signed("==", exc_type, expected_id))
                            matches = self.builder.or_(
                                builtin_match, hierarchy_match)
                        self.builder.cbranch(matches, handler_block, next_handler)
                    elif isinstance(handler.type, ast.Tuple):
                        # except (TypeError, ValueError): — OR chain of type checks
                        any_match = ir.Constant(ir.IntType(1), 0)
                        for elt in handler.type.elts:
                            if isinstance(elt, ast.Name):
                                elt_name = self._make_string_constant(elt.id)
                                elt_id = self.builder.call(
                                    self.runtime["exc_name_to_id"], [elt_name])
                                elt_match = self.builder.icmp_signed(
                                    "==", exc_type, elt_id)
                                any_match = self.builder.or_(any_match, elt_match)
                            elif isinstance(elt, ast.Attribute):
                                elt_name = self._make_string_constant(elt.attr)
                                elt_id = self.builder.call(
                                    self.runtime["exc_name_to_id"], [elt_name])
                                elt_match = self.builder.icmp_signed(
                                    "==", exc_type, elt_id)
                                any_match = self.builder.or_(any_match, elt_match)
                        self.builder.cbranch(any_match, handler_block, next_handler)
                    elif isinstance(handler.type, ast.Attribute):
                        exc_name = self._make_string_constant(handler.type.attr)
                        expected_id = self.builder.call(
                            self.runtime["exc_name_to_id"], [exc_name])
                        matches = self.builder.icmp_signed("==", exc_type, expected_id)
                        self.builder.cbranch(matches, handler_block, next_handler)
                    else:
                        self.builder.branch(handler_block)

                    self.builder.position_at_end(handler_block)
                    if handler.name:
                        # User-defined exception class: retrieve the object
                        # so attributes set in __init__ are accessible.
                        _exc_cls_name = None
                        if isinstance(handler.type, ast.Name):
                            _exc_cls_name = handler.type.id
                        _cls_has_init = (
                            _exc_cls_name
                            and _exc_cls_name in self._user_classes
                            and self._user_classes[_exc_cls_name]
                                .methods.get("__init__"))
                        if _cls_has_init:
                            # User-class with custom __init__: retrieve the
                            # object so attributes (e.code etc.) are accessible.
                            obj = self.builder.call(
                                self.runtime["exc_get_obj"], [])
                            self._store_variable(
                                handler.name, obj,
                                ValueType(VKind.OBJ,
                                          class_name=_exc_cls_name))
                            self._obj_var_class[handler.name] = _exc_cls_name
                        else:
                            # Standard exception or user-class without custom
                            # __init__ (e.g. class AppError(Exception): pass):
                            # store message string so str(e) / print(e) works.
                            msg = self.builder.call(
                                self.runtime["exc_get_msg"], [])
                            self._store_variable(
                                handler.name, msg, ValueType(VKind.STR))
                            # Clear any stale OBJ class mapping from a
                            # previous handler that used the same variable
                            # name for a user-class exception.
                            self._obj_var_class.pop(handler.name, None)
                        # Track the exception class for type(e).__name__:
                        # Use the saved runtime class name (actual raised type),
                        # not the handler's declared type (which may be a parent).
                        if isinstance(handler.type, ast.Name):
                            self._exc_vars[handler.name] = handler.type.id
                        elif isinstance(handler.type, ast.Tuple):
                            for elt in handler.type.elts:
                                if isinstance(elt, ast.Name):
                                    self._exc_vars[handler.name] = elt.id
                                    break
                        # Store alloca for runtime class name lookup
                        self._exc_class_allocas[handler.name] = saved_exc_class_alloca
                    self.builder.call(self.runtime["exc_clear"], [])
                    self._emit_stmts(handler.body)
                    if not self.builder.block.is_terminated:
                        if finally_block:
                            self.builder.branch(finally_block)
                        else:
                            self.builder.branch(end_block)

                    self.builder.position_at_end(next_handler)

            # No handler matched — propagate to outer scope
            if not self.builder.block.is_terminated:
                if finally_block:
                    self.builder.branch(finally_block)
                elif self._in_try_block and self._try_except_target:
                    # Inside an outer try block: jump to its except handler
                    # so the exception propagates correctly through nested trys.
                    self.builder.branch(self._try_except_target)
                else:
                    self.builder.call(self.runtime["exc_unhandled"], [])
                    self.builder.unreachable()

        # Pop finally from stack before emitting the finally block itself
        # (so returns inside finally don't re-emit itself)
        if has_finally:
            self._finally_stack.pop()

        # Finally block
        if has_finally:
            self.builder.position_at_end(finally_block)
            self._emit_stmts(node.finalbody)
            if not self.builder.block.is_terminated:
                self.builder.branch(end_block)

        self.builder.position_at_end(end_block)

    def _emit_raise(self, node: ast.Raise) -> None:
        """Emit raise ExcType('msg'). Sets the exception flag; caller checks it."""
        if node.exc is None:
            # bare raise — re-raise the saved exception from the
            # enclosing except handler.
            if hasattr(self, '_saved_exc_type') and self._saved_exc_type:
                exc_type = self.builder.load(self._saved_exc_type)
                exc_msg = self.builder.load(self._saved_exc_msg)
                self.builder.call(self.runtime["raise"], [exc_type, exc_msg])
                # Restore the class name for user-defined exceptions
                # (builtins are auto-set by fastpy_raise, but GENERIC
                # types need the saved name from the except handler).
                if (hasattr(self, '_saved_exc_class')
                        and self._saved_exc_class):
                    saved = self.builder.load(self._saved_exc_class)
                    self.builder.call(
                        self.runtime["exc_set_class_name"], [saved])
            return

        if isinstance(node.exc, ast.Call) and isinstance(node.exc.func, ast.Name):
            exc_name = node.exc.func.id
            name_ptr = self._make_string_constant(exc_name)
            exc_id = self.builder.call(self.runtime["exc_name_to_id"], [name_ptr])

            # ExceptionGroup("g", [ValueError("a"), ...]) — store inner types
            if exc_name == "ExceptionGroup" and len(node.exc.args) >= 2:
                group_msg = self._emit_expr_value(node.exc.args[0])
                if not isinstance(group_msg.type, ir.PointerType):
                    group_msg = self._value_to_str(group_msg, node)
                self.builder.call(self.runtime["raise"], [exc_id, group_msg])
                self.builder.call(self.runtime["exc_set_class_name"], [name_ptr])
                # Extract ALL inner exception types from the list literal
                inner_list = node.exc.args[1]
                if isinstance(inner_list, ast.List) and inner_list.elts:
                    for inner_exc in inner_list.elts:
                        if (isinstance(inner_exc, ast.Call)
                                and isinstance(inner_exc.func, ast.Name)):
                            inner_name = self._make_string_constant(
                                inner_exc.func.id)
                            inner_id = self.builder.call(
                                self.runtime["exc_name_to_id"], [inner_name])
                            self.builder.call(
                                self.runtime["exc_group_add_inner"], [inner_id])
                    # Also set the legacy single-type field for backward compat
                    first_exc = inner_list.elts[0]
                    if (isinstance(first_exc, ast.Call)
                            and isinstance(first_exc.func, ast.Name)):
                        inner_name = self._make_string_constant(
                            first_exc.func.id)
                        inner_id = self.builder.call(
                            self.runtime["exc_name_to_id"], [inner_name])
                        self.builder.call(
                            self.runtime["exc_set_group_inner"], [inner_id])
            else:
                # User-defined exception class with custom __init__:
                # construct the object so except ... as e: can access
                # custom attributes (e.code etc.).
                # Classes without __init__ (e.g. class AppError(Exception): pass)
                # are treated like standard exceptions — message-only.
                _exc_cls_info = self._user_classes.get(exc_name)
                _init_func = (_exc_cls_info.methods.get("__init__")
                              if _exc_cls_info else None)
                if _init_func is not None:
                    # Evaluate all args once, then pick the right one
                    # as the exception message. If the __init__ body
                    # calls super().__init__(X), use the arg that maps
                    # to X; otherwise default to the first arg.
                    _arg_vals = []
                    for arg_node in node.exc.args:
                        _arg_vals.append(self._emit_expr_value(arg_node))
                    _msg_arg_idx = 0  # default: first arg
                    # Scan __init__ AST for super().__init__(param)
                    _init_ast = (_exc_cls_info.method_asts.get("__init__")
                                 if _exc_cls_info.method_asts else None)
                    if _init_ast is not None:
                        _init_params = [a.arg for a in _init_ast.args.args
                                        if a.arg != "self"]
                        for _si_stmt in ast.walk(_init_ast):
                            if (isinstance(_si_stmt, ast.Expr)
                                    and isinstance(_si_stmt.value, ast.Call)
                                    and isinstance(_si_stmt.value.func,
                                                   ast.Attribute)
                                    and _si_stmt.value.func.attr == "__init__"):
                                _si_func = _si_stmt.value.func
                                _is_super = (
                                    (isinstance(_si_func.value, ast.Call)
                                     and isinstance(_si_func.value.func,
                                                    ast.Name)
                                     and _si_func.value.func.id == "super")
                                    or (isinstance(_si_func.value, ast.Name)
                                        and _si_func.value.id == "super"))
                                if _is_super and _si_stmt.value.args:
                                    _super_arg = _si_stmt.value.args[0]
                                    if (isinstance(_super_arg, ast.Name)
                                            and _super_arg.id in _init_params):
                                        _msg_arg_idx = _init_params.index(
                                            _super_arg.id)
                                    break
                    if _arg_vals:
                        _mi = min(_msg_arg_idx, len(_arg_vals) - 1)
                        msg = _arg_vals[_mi]
                        if not isinstance(msg.type, ir.PointerType):
                            msg = self._value_to_str(msg, node)
                    else:
                        msg = self._make_string_constant("")
                    # Build the object: obj_new + __init__
                    _exc_cls_id = self.builder.load(
                        _exc_cls_info.class_id_global)
                    obj = self.builder.call(
                        self.runtime["obj_new"], [_exc_cls_id])
                    call_args = [obj] + _arg_vals
                    self.builder.call(_init_func, call_args)
                    self.builder.call(self.runtime["raise_with_obj"],
                                      [exc_id, msg, obj])
                    self.builder.call(self.runtime["exc_set_class_name"], [name_ptr])
                else:
                    # Standard exception or user-class without __init__
                    if node.exc.args:
                        msg = self._emit_expr_value(node.exc.args[0])
                        if not isinstance(msg.type, ir.PointerType):
                            msg = self._value_to_str(msg, node)
                    else:
                        msg = self._make_string_constant("")
                    self.builder.call(self.runtime["raise"], [exc_id, msg])
                    self.builder.call(self.runtime["exc_set_class_name"], [name_ptr])
                # Handle "raise X from Y" — evaluate the cause expression
                # (for side effects) even though we can't attach __cause__
                # to the exception struct. This avoids silently ignoring it.
                if node.cause is not None:
                    self._emit_expr_value(node.cause)
            # If we're inside a try block, the exception check after this
            # statement will catch it. If not, early-return so the caller
            # can check the exception flag.
            if not self._in_try_block:
                # Pop shadow frame before early return (traceback already
                # snapshotted by fastpy_raise above)
                if not self._current_fn_bare_abi:
                    self.builder.call(self.runtime["shadow_pop"], [])
                ret_type = self.function.return_value.type
                if isinstance(ret_type, ir.VoidType):
                    self.builder.ret_void()
                elif isinstance(ret_type, ir.LiteralStructType):
                    self.builder.ret(self._fv_none())
                elif isinstance(ret_type, ir.DoubleType):
                    self.builder.ret(ir.Constant(double, 0.0))
                elif isinstance(ret_type, ir.PointerType):
                    self.builder.ret(ir.Constant(ret_type, None))
                else:
                    self.builder.ret(ir.Constant(ret_type, 0))
            return

        # raise ExcName (bare name, no call — no message)
        if isinstance(node.exc, ast.Name):
            exc_name = node.exc.id
            name_ptr = self._make_string_constant(exc_name)
            exc_id = self.builder.call(self.runtime["exc_name_to_id"], [name_ptr])
            msg = self._make_string_constant("")
            self.builder.call(self.runtime["raise"], [exc_id, msg])
            self.builder.call(self.runtime["exc_set_class_name"], [name_ptr])
            if not self._in_try_block:
                if not self._current_fn_bare_abi:
                    self.builder.call(self.runtime["shadow_pop"], [])
                ret_type = self.function.return_value.type
                if isinstance(ret_type, ir.VoidType):
                    self.builder.ret_void()
                elif isinstance(ret_type, ir.LiteralStructType):
                    self.builder.ret(self._fv_none())
                elif isinstance(ret_type, ir.DoubleType):
                    self.builder.ret(ir.Constant(double, 0.0))
                elif isinstance(ret_type, ir.PointerType):
                    self.builder.ret(ir.Constant(ret_type, None))
                else:
                    self.builder.ret(ir.Constant(ret_type, 0))
            return

        self._bridge_fallback_stmt(node, "unsupported raise expression")

    def _emit_return(self, node: ast.Return) -> None:
        """Emit a return statement.

        If there are pending finally bodies (we're inside one or more
        try-with-finally blocks), emit them in LIFO order before the
        actual return.
        """
        # Evaluate the return value first (side effects happen before finally).
        # When the function returns FpyValue, use _load_or_wrap_fv so that
        # dict subscripts, list subscripts, and FV-backed variables preserve
        # their runtime tag instead of being unwrapped then re-wrapped with
        # a possibly-wrong compile-time tag.
        expected = self.function.return_value.type
        if node.value is not None:
            if isinstance(expected, ir.LiteralStructType):
                # For FV-returning functions, check if the function's static
                # return type is float — if so, promote int returns to float
                # before wrapping, so the runtime tag matches what callers
                # expect.
                ret_info = next(
                    (i for i in self._user_functions.values()
                     if i.func is self.function), None)
                if (ret_info is not None
                        and ret_info.static_ret_type is double):
                    # Force float tag: evaluate, promote int→double, wrap.
                    # In FV-ABI, parameters may carry float values with
                    # "int" static tag (because call-site analysis couldn't
                    # determine types).  For Name returns that might be
                    # FV-backed, load the raw FpyValue and use the runtime
                    # tag to pick bitcast (float data) vs sitofp (int data).
                    if (self._USE_FV_LOCALS
                            and isinstance(node.value, ast.Name)
                            and node.value.id in self.variables):
                        alloca, _vtag = self.variables[node.value.id]
                        if (isinstance(alloca.type, ir.PointerType)
                                and alloca.type.pointee is fpy_val):
                            fv = self.builder.load(alloca, name=f"{node.value.id}.retfv")
                            tag = self.builder.extract_value(fv, 0)
                            data = self.builder.extract_value(fv, 1)
                            is_float = self.builder.icmp_unsigned(
                                "==", tag, ir.Constant(i32, FPY_TAG_FLOAT))
                            float_val = self.builder.bitcast(data, double)
                            int_val = self.builder.sitofp(data, double)
                            bare = self.builder.select(is_float, float_val, int_val)
                            value = self._fv_from_float(bare)
                        else:
                            bare = self._emit_expr_value(node.value)
                            if isinstance(bare.type, ir.IntType):
                                bare = self.builder.sitofp(bare, double)
                            value = self._fv_from_float(bare)
                    else:
                        bare = self._emit_expr_value(node.value)
                        if isinstance(bare.type, ir.IntType):
                            if bare.type.width == 1 or bare.type.width == 32:
                                bare = self.builder.zext(bare, i64)
                            if isinstance(bare.type, ir.IntType):
                                bare = self.builder.sitofp(bare, double)
                        value = self._fv_from_float(bare)
                else:
                    value = self._load_or_wrap_fv(node.value)
            else:
                # Generator yield: when returning an attribute value from a
                # generator send() method, load both tag and data from the
                # attribute slot and call set_ret_tag() so the caller (next/
                # send dispatch) can recover the runtime type.  Without this,
                # string/list/None values lose their tag and print as ints.
                _gen_fv = getattr(self, '_gen_class_fv_attrs', {})
                _gen_yield_tag_handled = False
                if (self._current_class
                        and self._current_class in _gen_fv
                        and isinstance(node.value, ast.Attribute)
                        and isinstance(node.value.value, ast.Name)
                        and node.value.value.id == "self"):
                    _yield_slot = self._get_attr_slot(node.value)
                    if _yield_slot is not None:
                        _yield_obj = self._emit_expr_value(node.value.value)
                        _yield_obj = self._ensure_ptr(_yield_obj)
                        _yield_tag, _yield_data = self._emit_slot_get_direct(
                            _yield_obj, _yield_slot)
                        self.builder.call(
                            self.runtime["set_ret_tag"], [_yield_tag])
                        value = _yield_data
                        _gen_yield_tag_handled = True
                if not _gen_yield_tag_handled:
                    value = self._emit_expr_value(node.value)
        else:
            value = None

        # When inside a try block, a runtime exception may have been
        # raised during the return expression evaluation (e.g.,
        # `return a / b` where b==0 raises ZeroDivisionError).
        # Check for pending exception and route to the except handler
        # instead of returning.
        if self._in_try_block and node.value is not None:
            exc_target = getattr(self, '_try_except_target', None)
            if exc_target is not None:
                pending = self.builder.call(self.runtime["exc_pending"], [])
                is_exc = self.builder.icmp_signed(
                    "!=", pending, ir.Constant(i32, 0))
                no_exc_block = self._new_block("ret.noexc")
                self.builder.cbranch(is_exc, exc_target, no_exc_block)
                self.builder.position_at_end(no_exc_block)

        # Emit enclosing finally bodies in LIFO order. Take a snapshot to
        # avoid re-entrance if a finally body itself has a try-finally.
        if self._finally_stack:
            for finalbody in reversed(self._finally_stack):
                saved_stack = self._finally_stack
                self._finally_stack = []
                self._emit_stmts(finalbody)
                self._finally_stack = saved_stack
                if self.builder.block.is_terminated:
                    return  # finally block unconditionally terminated

        # Pop shadow stack before returning (skip for bare-ABI — no frame pushed)
        if not self._current_fn_bare_abi:
            self.builder.call(self.runtime["shadow_pop"], [])

        # Scope cleanup: decref all locals except the return value
        ret_var_name = None
        if node.value is not None and isinstance(node.value, ast.Name):
            ret_var_name = node.value.id
        # If we're returning a parameter (borrowed reference), incref it
        # BEFORE scope cleanup so the caller receives an owned reference.
        # Local variables transfer their existing reference via exclude_var
        # (not decref'd), but parameters were never incref'd on entry, so
        # we must create a new owned reference here.
        if (self._USE_REFCOUNT and ret_var_name is not None
                and ret_var_name in getattr(self, '_current_func_params', set())):
            if isinstance(value.type, ir.LiteralStructType):
                # FV return: extract tag+data from the FpyValue struct
                _ret_tag = self.builder.extract_value(value, 0)
                _ret_data = self.builder.extract_value(value, 1)
                self.builder.call(self.runtime["rc_incref"],
                                  [_ret_tag, _ret_data])
            elif isinstance(value.type, ir.PointerType):
                # Pointer return (e.g. raw obj pointer)
                _ret_data = self.builder.ptrtoint(value, i64)
                _ret_tag = ir.Constant(i32, FPY_TAG_OBJ)
                self.builder.call(self.runtime["rc_incref"],
                                  [_ret_tag, _ret_data])
        # If returning a Subscript or Attribute expression, the value is
        # a borrowed reference from a container or object slot.  Incref
        # before scope cleanup so the caller receives an owned reference.
        # Without this, the caller uses steal=True (no incref) and the
        # borrowed ref leaks a refcount on every scope_decref of the
        # caller's local holding the return value.
        # NOTE: Attribute/Subscript return incref is DISABLED.
        # The caller's _store_variable(steal=False) handles the incref.
        # Adding it here would double-incref, causing leaks.  The original
        # bug (hold() returning self.link without incref) was a misdiagnosis:
        # the caller already increfs via _store_variable.
        self._emit_scope_decref(exclude_var=ret_var_name)

        if node.value is None:
            self.builder.ret_void()
        else:
            if isinstance(expected, ir.VoidType):
                # Function was declared void but has return value — ignore value
                self.builder.ret_void()
            elif isinstance(expected, ir.LiteralStructType):
                # value is already an FpyValue from _load_or_wrap_fv above.
                self.builder.ret(value)
            elif value.type != expected:
                # FpyValue → i64 conversion: closures/methods use i64 ABI
                # externally but FV locals internally. Extract the data
                # field and store the tag in fpy_ret_tag so the caller
                # can recover it.
                if (isinstance(expected, ir.IntType)
                        and isinstance(value.type, ir.LiteralStructType)):
                    tag = self.builder.extract_value(value, 0)
                    data = self.builder.extract_value(value, 1)
                    self.builder.call(self.runtime["set_ret_tag"], [tag])
                    self.builder.ret(data)
                    return
                # Save original value before type conversion so tag
                # inference can see the pre-conversion type (e.g. pointer
                # before ptrtoint).
                pre_conv_value = value
                # Type mismatch — try conversion
                if isinstance(expected, ir.IntType) and isinstance(value.type, ir.IntType):
                    if expected.width > value.type.width:
                        value = self.builder.zext(value, expected)
                    else:
                        value = self.builder.trunc(value, expected)
                elif isinstance(expected, ir.IntType) and isinstance(value.type, ir.DoubleType):
                    # Bitcast to preserve the float bit pattern when passing
                    # through an i64 channel.  fptosi truncates (1.5 → 1),
                    # destroying the value.  The caller uses the ret_tag to
                    # know it should bitcast i64 back to double.
                    value = self.builder.bitcast(value, expected)
                elif isinstance(expected, ir.DoubleType) and isinstance(value.type, ir.IntType):
                    value = self.builder.bitcast(value, expected)
                elif isinstance(expected, ir.IntType) and isinstance(value.type, ir.PointerType):
                    value = self.builder.ptrtoint(value, expected)
                elif isinstance(expected, ir.PointerType) and isinstance(value.type, ir.IntType):
                    value = self.builder.inttoptr(value, expected)
                # For closure/method functions, store the tag before ret
                # so callers using get_ret_tag() recover the correct type.
                # Closures always return i64 (via wrapper), so check IntType.
                # Methods may return i64, i8*, double, i32 — check all.
                _is_closure = self.function.name.startswith("fastpy.closure.")
                _is_method = self.function.name.startswith("fastpy.class.")
                _needs_ret_tag = (
                    (_is_closure and isinstance(expected, ir.IntType))
                    or _is_method)
                if _needs_ret_tag:
                    # Prefer runtime tag from FV-local variable when returning
                    # a parameter — the FpyValue's tag field holds the actual
                    # type that the static _infer_ret_tag_for_value misses.
                    _used_fv_tag = False
                    if (isinstance(node.value, ast.Name)
                            and node.value.id in self.variables
                            and node.value.id != "self"):
                        _rv_alloca, _rv_vtag = self.variables[node.value.id]
                        if (isinstance(_rv_alloca.type, ir.PointerType)
                                and _rv_alloca.type.pointee is fpy_val):
                            _rv_fv = self.builder.load(
                                _rv_alloca,
                                name=f"{node.value.id}.ret_fv")
                            _rv_rt = self.builder.extract_value(
                                _rv_fv, 0,
                                name=f"{node.value.id}.ret_tag")
                            self.builder.call(
                                self.runtime["set_ret_tag"], [_rv_rt])
                            _used_fv_tag = True
                    # Method call return: the called method already set
                    # ret_tag — forward it via get_ret_tag() so the caller
                    # chain preserves the runtime type.
                    if (not _used_fv_tag
                            and _is_method
                            and isinstance(node.value, ast.Call)
                            and isinstance(
                                getattr(node.value, 'func', None),
                                ast.Attribute)):
                        _call_method = node.value.func.attr
                        if self._direct_method_may_return_ptr(
                                None, _call_method):
                            _fwd_tag = self.builder.call(
                                self.runtime["get_ret_tag"], [])
                            self.builder.call(
                                self.runtime["set_ret_tag"], [_fwd_tag])
                            _used_fv_tag = True
                    # Closure call return: forward inner callee's ret_tag
                    if (not _used_fv_tag
                            and _is_closure
                            and isinstance(node.value, ast.Call)
                            and isinstance(node.value.func, ast.Name)
                            and node.value.func.id in self.variables
                            and self._var_kind(
                                node.value.func.id) == VKind.CLOSURE):
                        _fwd_tag = self.builder.call(
                            self.runtime["get_ret_tag"], [])
                        self.builder.call(
                            self.runtime["set_ret_tag"], [_fwd_tag])
                        _used_fv_tag = True
                    if not _used_fv_tag:
                        tag = self._infer_ret_tag_for_value(
                            pre_conv_value, node.value)
                        self.builder.call(self.runtime["set_ret_tag"],
                                          [ir.Constant(i32, tag)])
                self.builder.ret(value)
            else:
                # For closure/method functions, store the tag before ret
                _is_closure = self.function.name.startswith("fastpy.closure.")
                _is_method = self.function.name.startswith("fastpy.class.")
                _needs_ret_tag = (
                    (_is_closure and isinstance(expected, ir.IntType))
                    or _is_method)
                if _needs_ret_tag:
                    # Prefer the runtime tag from the slot when returning a
                    # self-attribute.  The static inference
                    # (_infer_ret_tag_for_value) can't determine the correct
                    # tag for mixed-type attributes like generator _yf_val
                    # (init'd to 0 but may hold STR/OBJ at runtime).
                    _used_slot_tag = False
                    if (_is_method
                            and isinstance(node.value, ast.Attribute)
                            and isinstance(node.value.value, ast.Name)
                            and node.value.value.id == "self"):
                        _slot_idx = self._get_attr_slot(node.value)
                        if _slot_idx is not None:
                            _self_ptr = self._emit_expr_value(
                                node.value.value)
                            _self_ptr = self._ensure_ptr(_self_ptr)
                            _slot_tag, _ = self._emit_slot_get_direct(
                                _self_ptr, _slot_idx)
                            self.builder.call(
                                self.runtime["set_ret_tag"],
                                [_slot_tag])
                            _used_slot_tag = True
                    # Method call return: the called method already set
                    # ret_tag — forward it via get_ret_tag() so the
                    # caller chain preserves the runtime type.  Covers
                    # self.method(), self.attr.method(), and any method
                    # call returning dynamic types.
                    if (not _used_slot_tag
                            and _is_method
                            and isinstance(node.value, ast.Call)
                            and isinstance(getattr(node.value, 'func', None),
                                           ast.Attribute)
                            and self._direct_method_may_return_ptr(
                                None, node.value.func.attr)):
                        _fwd_tag = self.builder.call(
                            self.runtime["get_ret_tag"], [])
                        self.builder.call(
                            self.runtime["set_ret_tag"], [_fwd_tag])
                        _used_slot_tag = True
                    # return <fv_local_var> — extract the runtime tag from
                    # the FpyValue alloca.  The variable may hold any type
                    # at runtime (e.g. a method returning its parameter),
                    # and _infer_ret_tag_for_value would hardcode INT.
                    if (not _used_slot_tag
                            and isinstance(node.value, ast.Name)
                            and node.value.id in self.variables
                            and node.value.id != "self"):
                        _rv_alloca, _rv_vtag = self.variables[node.value.id]
                        if (isinstance(_rv_alloca.type, ir.PointerType)
                                and _rv_alloca.type.pointee is fpy_val):
                            _rv_fv = self.builder.load(
                                _rv_alloca,
                                name=f"{node.value.id}.ret_fv2")
                            _rv_rt = self.builder.extract_value(
                                _rv_fv, 0,
                                name=f"{node.value.id}.ret_tag2")
                            self.builder.call(
                                self.runtime["set_ret_tag"], [_rv_rt])
                            _used_slot_tag = True
                    # return closure_call(...) — the inner callee already
                    # set fpy_ret_tag via set_ret_tag (e.g., the i64 wrapper
                    # forwards the FV return tag).  Forward it instead of
                    # overriding with a static inference that defaults to INT.
                    if (not _used_slot_tag
                            and isinstance(node.value, ast.Call)
                            and isinstance(node.value.func, ast.Name)
                            and node.value.func.id in self.variables
                            and self._var_kind(
                                node.value.func.id) == VKind.CLOSURE):
                        _fwd_tag = self.builder.call(
                            self.runtime["get_ret_tag"], [])
                        self.builder.call(
                            self.runtime["set_ret_tag"], [_fwd_tag])
                        _used_slot_tag = True
                    if not _used_slot_tag:
                        tag = self._infer_ret_tag_for_value(value, node.value)
                        self.builder.call(self.runtime["set_ret_tag"],
                                          [ir.Constant(i32, tag)])
                self.builder.ret(value)

    def _flush_rc_temps(self) -> None:
        """Decref any temporary values created during expression evaluation.
        Called at statement boundaries to free temporaries that weren't
        stored in variables (e.g., intermediate strings from concat)."""
        if not self._USE_REFCOUNT or not self._rc_temps:
            return
        for tag_val, data_val in self._rc_temps:
            self.builder.call(self.runtime["rc_decref"], [tag_val, data_val])
        self._rc_temps.clear()

    def _emit_scope_decref(self, exclude_var: str | None = None) -> None:
        """Emit decref for all FV-local variables in the current scope.
        Called before every function exit (return/implicit return).
        The `exclude_var` is the variable being returned (don't decref it —
        ownership transfers to the caller).
        Function parameters are BORROWED references — the caller owns them,
        so we must NOT decref them here."""
        if not self._USE_REFCOUNT:
            return
        param_names = getattr(self, '_current_func_params', set())
        for var_name, (alloca, tag) in self.variables.items():
            if var_name == exclude_var:
                continue
            if var_name in param_names:
                continue  # borrowed reference from caller
            if self._tag_kind(tag) == VKind.CELL:
                continue  # cells are managed separately
            if var_name in self._global_vars:
                continue  # globals outlive the function
            if not (isinstance(alloca.type, ir.PointerType)
                    and alloca.type.pointee is fpy_val):
                continue  # not an FV local
            # Skip decref for variables known to be non-refcounted scalars
            # (INT, FLOAT, BOOL, NONE).  rc_decref checks tag < FPY_TAG_STR
            # and returns immediately for these, but the function call
            # overhead adds up in tight loops with inlined methods.
            vk = self._var_kind(var_name)
            if vk in (VKind.INT, VKind.FLOAT, VKind.BOOL, VKind.NONE):
                continue
            fv = self.builder.load(alloca, name=f"{var_name}.cleanup")
            fv_tag = self.builder.extract_value(fv, 0)
            fv_data = self.builder.extract_value(fv, 1)
            self.builder.call(self.runtime["rc_decref"], [fv_tag, fv_data])

    def _infer_ret_tag_for_value(self, value: ir.Value,
                                  node: ast.expr) -> int:
        """Infer the FpyValue tag for a bare LLVM value being returned.
        Used by closures and methods to store the runtime tag in
        fpy_ret_tag so callers using get_ret_tag() recover the type."""
        if isinstance(value.type, ir.IntType):
            if value.type.width == 1 or value.type.width == 32:
                return FPY_TAG_BOOL  # comparisons, bool ops
            # Check AST for bool-typed expressions
            if self._is_bool_typed(node):
                return FPY_TAG_BOOL
            # AST-based checks: for methods returning i64, the value
            # may actually be a pointer (list/dict/str/obj) encoded as
            # i64.  Check the AST node to recover the true type.
            if node is not None:
                if self._is_list_expr(node):
                    return FPY_TAG_LIST
                if self._is_tuple_expr(node):
                    return FPY_TAG_LIST  # tuples stored as FpyList
                if self._is_dict_expr(node):
                    return FPY_TAG_DICT
                if self._is_obj_expr(node):
                    return FPY_TAG_OBJ
                # String self-attribute access: return self.name where
                # name is a known string attr
                ttag = self._infer_type_tag(node, value)
                if ttag is not None:
                    if ttag.kind == VKind.STR:
                        return FPY_TAG_STR
                    if ttag.kind == VKind.NONE:
                        return FPY_TAG_NONE
            return FPY_TAG_INT
        if isinstance(value.type, ir.DoubleType):
            return FPY_TAG_FLOAT
        if isinstance(value.type, ir.PointerType):
            if self._is_list_expr(node):
                return FPY_TAG_LIST
            if self._is_tuple_expr(node):
                return FPY_TAG_LIST  # tuples stored as FpyList
            if self._is_dict_expr(node):
                return FPY_TAG_DICT
            if self._is_obj_expr(node):
                return FPY_TAG_OBJ
            return FPY_TAG_STR
        return FPY_TAG_INT

    def _wrap_return_value(self, value: ir.Value, node: ast.AST) -> ir.Value:
        """Wrap a bare return value into an FpyValue, choosing the tag from
        the current function's static_ret_type if available, otherwise from
        the LLVM type of `value` itself."""
        # Use the static return type to decide tag (avoids mis-tagging strings
        # as ints when value came in as i8*, etc.)
        static_ret = None
        for info in self._user_functions.values():
            if info.func is self.function:
                static_ret = info.static_ret_type
                break
        # Match the static type: int → INT, float → FLOAT, ptr → STR by default
        # (caller's expected tag from static inference)
        if static_ret is double:
            if isinstance(value.type, ir.IntType):
                value = self.builder.sitofp(value, double)
            return self._fv_from_float(value)
        if static_ret is i8_ptr:
            # Pointer return — could be str, list, dict, tuple, obj.
            # Use the ret_tag to disambiguate.
            info = next((i for i in self._user_functions.values() if i.func is self.function), None)
            if info is not None:
                _rtk = self._tag_kind(info.ret_tag)
                if _rtk == VKind.LIST:
                    return self._fv_from_list(value)
                if _rtk == VKind.DICT:
                    return self._fv_from_list(value)  # dicts stored as FpyList*
            # Default: treat as string
            value = self._ensure_ptr(value)
            return self._fv_from_str(value)
        # Fallback: infer from LLVM type
        if isinstance(value.type, ir.IntType):
            if value.type.width == 64:
                return self._fv_from_int(value)
            # i32 bool
            return self._fv_from_bool(value)
        if isinstance(value.type, ir.DoubleType):
            return self._fv_from_float(value)
        if isinstance(value.type, ir.PointerType):
            return self._fv_from_str(value)
        raise CodeGenError(f"Cannot wrap return value of type {value.type} into FpyValue", node)

    def _infer_for_tuple_elem_types(self, iter_node: ast.expr, n: int) -> list[str]:
        """Given `for a,b in <iter>`, infer types of a and b from the first tuple.

        Returns list of "int" or "unknown" (default). If the iter is
        `enumerate(...)` we know the first is an int index.
        """
        types: list[str] = ["unknown"] * n
        # enumerate(x): first is int, second inherits x's element type
        if (isinstance(iter_node, ast.Call) and isinstance(iter_node.func, ast.Name)
                and iter_node.func.id == "enumerate"):
            if n >= 1:
                types[0] = "int"
            if n >= 2 and iter_node.args:
                arg = iter_node.args[0]
                # String iteration: enumerate("hello") or enumerate(str_var)
                # yields individual characters, which are strings.
                if (isinstance(arg, ast.Constant)
                        and isinstance(arg.value, str)):
                    types[1] = "str"
                elif isinstance(arg, ast.JoinedStr):
                    types[1] = "str"
                elif (isinstance(arg, ast.Name)
                      and arg.id in self.variables
                      and self._var_kind(arg.id) == VKind.STR):
                    types[1] = "str"
                else:
                    # Use _get_list_elem_type which handles Name lookups
                    # (variable elem_type) as well as AST inference.
                    types[1] = self._get_list_elem_type(arg)
            return types
        # zip(a, b): check each side's first element
        if (isinstance(iter_node, ast.Call) and isinstance(iter_node.func, ast.Name)
                and iter_node.func.id == "zip"):
            for i, arg in enumerate(iter_node.args[:n]):
                types[i] = self._get_list_elem_type(arg)
            return types
        # sorted(d.items()) / d.items(): keys are strings, values inherit from dict
        items_call = None
        if (isinstance(iter_node, ast.Call) and isinstance(iter_node.func, ast.Attribute)
                and iter_node.func.attr == "items"):
            items_call = iter_node
        elif (isinstance(iter_node, ast.Call) and isinstance(iter_node.func, ast.Name)
                and iter_node.func.id == "sorted" and iter_node.args
                and isinstance(iter_node.args[0], ast.Call)
                and isinstance(iter_node.args[0].func, ast.Attribute)
                and iter_node.args[0].func.attr == "items"):
            items_call = iter_node.args[0]
        if items_call is not None and n >= 2:
            dict_node = items_call.func.value
            # Detect whether keys are ints or strings
            if self._is_int_keyed_dict(dict_node):
                types[0] = "int"
            else:
                types[0] = "str"
            if isinstance(dict_node, ast.Name):
                if dict_node.id in self._dict_var_int_values:
                    types[1] = "int"
                elif dict_node.id in self._dict_var_list_values:
                    types[1] = "list"
                else:
                    types[1] = "str"
            return types
        # Literal list of tuples: look at first tuple's elements
        list_node = iter_node
        if isinstance(iter_node, ast.Name):
            # Look up the variable's most recent list-of-tuples assignment in the function
            list_node = self._lookup_list_literal(iter_node.id)
        if isinstance(list_node, ast.List) and list_node.elts:
            first = list_node.elts[0]
            if isinstance(first, (ast.Tuple, ast.List)):
                for i, el in enumerate(first.elts[:n]):
                    if isinstance(el, ast.Constant):
                        if isinstance(el.value, bool):
                            types[i] = "int"
                        elif isinstance(el.value, int):
                            types[i] = "int"
                        elif isinstance(el.value, float):
                            types[i] = "float"
                        elif isinstance(el.value, str):
                            types[i] = "str"
                    elif isinstance(el, (ast.List, ast.ListComp)):
                        types[i] = "list"
                    elif isinstance(el, (ast.Tuple,)):
                        types[i] = "tuple"
                    elif isinstance(el, (ast.Dict, ast.DictComp)):
                        types[i] = "dict"
                    elif isinstance(el, ast.Name) and el.id in self.variables:
                        types[i] = str(self.variables[el.id][1])
        # For Name iterators not resolved from literal: try to propagate
        # element types from the variable's type tag.
        if isinstance(iter_node, ast.Name) and list_node is None:
            _raw_tag = self.variables.get(iter_node.id, (None, ValueType(VKind.UNKNOWN)))[1]
            _vt = _raw_tag if isinstance(_raw_tag, ValueType) else ValueType.from_old_tag(str(_raw_tag))
            # If we know nothing specific, keep defaults but don't force "str"
            if _vt.kind == VKind.LIST and _vt.elem_type is not None:
                # e.g. list:list or list:obj — propagate inner type for all slots
                inner = _vt.elem_type._to_tag()
                for i in range(n):
                    if self._tag_kind(types[i]) == VKind.STR:
                        types[i] = inner
        return types

    def _lookup_list_literal(self, name: str) -> ast.expr | None:
        """Look up the most recent assignment of a list literal to `name` in this scope."""
        stmts = getattr(self, "_current_scope_stmts", None)
        if stmts is None:
            return None
        for stmt in stmts:
            for sub in ast.walk(stmt):
                if (isinstance(sub, ast.Assign) and len(sub.targets) == 1
                        and isinstance(sub.targets[0], ast.Name)
                        and sub.targets[0].id == name
                        and isinstance(sub.value, ast.List)):
                    return sub.value
        return None

    def _emit_for_enumerate_obj(self, node: ast.For) -> None:
        """Emit `for idx, val in enumerate(obj):` using the iterator protocol.

        For objects with __iter__/__next__ (generators, custom iterators),
        we cannot materialize the iterable into a list (it may be infinite).
        Instead, use the iterator protocol with a manual counter.
        """
        targets = node.target.elts
        call = node.iter  # Call(func=Name('enumerate'), args=[obj], ...)
        obj_node = call.args[0]

        # Optional start value
        start_val = ir.Constant(i64, 0)
        if len(call.args) >= 2:
            start_val = self._emit_expr_value(call.args[1])
        else:
            for kw in call.keywords:
                if kw.arg == "start":
                    start_val = self._emit_expr_value(kw.value)
                    break

        # Evaluate the object and call __iter__()
        obj = self._emit_expr_value(obj_node)
        obj = self._ensure_ptr(obj)
        iter_name_ptr = self._make_string_constant("__iter__")
        iterator = self.builder.call(
            self.runtime["obj_call_method0"], [obj, iter_name_ptr])
        iter_ptr = self._ensure_ptr(iterator)
        next_name_ptr = self._make_string_constant("__next__")

        # Counter variable
        self._block_counter += 1
        cnt_name = f"__enum_cnt_{self._block_counter}"
        self._store_variable(cnt_name, start_val, ValueType(VKind.INT))

        cond_block = self._new_block("forenum_obj.cond")
        body_block = self._new_block("forenum_obj.body")
        else_block = self._new_block("forenum_obj.else") if node.orelse else None
        end_block = self._new_block("forenum_obj.end")

        self.builder.branch(cond_block)
        self.builder.position_at_end(cond_block)

        # Call __next__() — StopIteration signals end
        result = self.builder.call(
            self.runtime["obj_call_method0"], [iter_ptr, next_name_ptr])
        pending = self.builder.call(self.runtime["exc_pending"], [])
        has_exc = self.builder.icmp_signed(
            "!=", pending, ir.Constant(i32, 0))
        after_loop = else_block if else_block else end_block
        self.builder.cbranch(has_exc, after_loop, body_block)

        self.builder.position_at_end(body_block)
        cnt = self._load_variable(cnt_name, node)

        # Assign counter to first target
        idx_target = targets[0]
        if isinstance(idx_target, ast.Name):
            self._store_variable(idx_target.id, cnt, ValueType(VKind.INT))

        # Assign value to second target — recover the runtime tag from
        # the method call so mixed-type generators work correctly.
        val_target = targets[1]
        if isinstance(val_target, ast.Name):
            ret_tag = self.builder.call(self.runtime["get_ret_tag"], [])
            fv = self._fv_build_from_slots(ret_tag, result)
            self._store_variable(val_target.id, fv, ValueType(VKind.FVALUE))

        # Increment counter
        new_cnt = self.builder.add(cnt, ir.Constant(i64, 1))
        self._store_variable(cnt_name, new_cnt, ValueType(VKind.INT))

        self._loop_stack.append((end_block, cond_block))
        _prev_hot = self._in_hot_loop
        self._in_hot_loop = True
        self._emit_stmts(node.body)
        self._in_hot_loop = _prev_hot
        self._loop_stack.pop()
        if not self.builder.block.is_terminated:
            self.builder.branch(cond_block)

        if else_block:
            self.builder.position_at_end(else_block)
            self.builder.call(self.runtime["exc_clear"], [])
            self._emit_stmts(node.orelse)
            if not self.builder.block.is_terminated:
                self.builder.branch(end_block)

        self.builder.position_at_end(end_block)
        self.builder.call(self.runtime["exc_clear"], [])

    def _emit_for_enumerate_inline(self, node: ast.For) -> None:
        """Optimized `for idx, val in enumerate(lst):` — no tuple allocation.

        Instead of calling fastpy_enumerate() which materializes N tuples,
        emit an inline indexed loop:
            counter = start
            for __idx in range(len(lst)):
                idx_var = counter
                val_var = lst[__idx]
                ... body ...
                counter += 1
        """
        targets = node.target.elts
        call = node.iter  # Call(func=Name('enumerate'), args=[lst], ...)

        # Get the list argument and optional start (positional or keyword)
        lst_node = call.args[0]
        start_val = ir.Constant(i64, 0)
        if len(call.args) >= 2:
            start_val = self._emit_expr_value(call.args[1])
        else:
            for kw in call.keywords:
                if kw.arg == "start":
                    start_val = self._emit_expr_value(kw.value)
                    break

        # Detect if the enumerate arg is a string (not a list)
        _is_str_iter = False
        if isinstance(lst_node, ast.Constant) and isinstance(lst_node.value, str):
            _is_str_iter = True
        elif (isinstance(lst_node, ast.Name) and lst_node.id in self.variables):
            _, _tag = self.variables[lst_node.id]
            if self._tag_kind(_tag) == VKind.STR:
                _is_str_iter = True

        # Evaluate the iterable
        lst_tv = self._emit_expr(lst_node)
        lst_ptr = lst_tv.as_ptr(self.builder)
        if _is_str_iter:
            lst_len = self._rt_call("str_len", [lst_ptr])
        else:
            lst_len = self._rt_call("list_length", [lst_ptr])

        # Index and counter variables
        self._block_counter += 1
        idx_name = f"__enum_idx_{self._block_counter}"
        cnt_name = f"__enum_cnt_{self._block_counter}"
        self._store_variable(idx_name, ir.Constant(i64, 0), ValueType(VKind.INT))
        self._store_variable(cnt_name, start_val, ValueType(VKind.INT))

        cond_block = self._new_block("forenum.cond")
        body_block = self._new_block("forenum.body")
        incr_block = self._new_block("forenum.incr")
        end_block = self._new_block("forenum.end")

        self.builder.branch(cond_block)

        self.builder.position_at_end(cond_block)
        idx = self._load_variable(idx_name, node)
        cond = self.builder.icmp_signed("<", idx, lst_len)
        self.builder.cbranch(cond, body_block, end_block)

        self.builder.position_at_end(body_block)
        idx = self._load_variable(idx_name, node)
        cnt = self._load_variable(cnt_name, node)

        # Assign the counter variable (first target)
        idx_target = targets[0]
        if isinstance(idx_target, ast.Name):
            self._store_variable(idx_target.id, cnt, ValueType(VKind.INT))

        # Assign the element variable (second target)
        val_target = targets[1]
        if _is_str_iter:
            # String iteration: extract single character via str_index
            if isinstance(val_target, ast.Name):
                ch = self._rt_call("str_index", [lst_ptr, idx])
                self._store_variable(val_target.id, ch, ValueType(VKind.STR))
        elif isinstance(val_target, ast.Name):
            elem_type = self._get_list_elem_type(lst_node)
            _ek = elem_type.kind
            if _ek == VKind.FLOAT:
                var_tag = "float"
            elif _ek == VKind.STR:
                var_tag = "str"
            elif _ek == VKind.LIST:
                var_tag = str(elem_type) if elem_type.elem_type else "list:int"
            elif _ek == VKind.OBJ:
                var_tag = "obj"
            elif _ek == VKind.PYOBJ:
                var_tag = "pyobj"
            else:
                var_tag = "int"
            self._fv_store_from_list(val_target.id, lst_ptr, idx, var_tag)
        elif isinstance(val_target, (ast.Tuple, ast.List)):
            # Nested unpack: for i, (a, b) in enumerate(pairs)
            inner_list = self._list_get_as_bare(lst_ptr, idx, "list")
            self._unpack_targets_from_list(val_target.elts, inner_list, node)

        self._loop_stack.append((end_block, incr_block))
        _prev_hot = self._in_hot_loop
        self._in_hot_loop = True
        self._emit_stmts(node.body)
        self._in_hot_loop = _prev_hot
        self._loop_stack.pop()
        if not self.builder.block.is_terminated:
            self.builder.branch(incr_block)

        self.builder.position_at_end(incr_block)
        idx = self._load_variable(idx_name, node)
        cnt = self._load_variable(cnt_name, node)
        self._store_variable(idx_name, self.builder.add(idx, ir.Constant(i64, 1)), ValueType(VKind.INT))
        self._store_variable(cnt_name, self.builder.add(cnt, ir.Constant(i64, 1)), ValueType(VKind.INT))
        self.builder.branch(cond_block)

        self.builder.position_at_end(end_block)

    def _unpack_targets_from_list(self, targets, list_ptr, node) -> None:
        """Recursively unpack targets from a list pointer.

        Handles ast.Name (via _fv_store_from_list), ast.Tuple/ast.List
        (recurse with inner list), and falls back to bridge for anything else.
        """
        for i, tgt in enumerate(targets):
            idx_const = ir.Constant(i64, i)
            if isinstance(tgt, ast.Name):
                self._fv_store_from_list(tgt.id, list_ptr, idx_const, "unknown")
            elif isinstance(tgt, (ast.Tuple, ast.List)):
                inner_list = self._list_get_as_bare(list_ptr, idx_const, "list")
                self._unpack_targets_from_list(tgt.elts, inner_list, node)
            else:
                self._bridge_fallback_stmt(node, "unsupported nested unpack target")

    def _emit_for_tuple_unpack(self, node: ast.For) -> None:
        """Emit for (k, v) in <list> or for i, (name, score) in enumerate(zip(...))."""
        targets = node.target.elts

        # Optimization: for i, val in enumerate(lst) — avoid tuple allocation
        # Skip for objects with __iter__ protocol (generators etc.) which
        # need lazy iteration via __next__ — materializing them hangs for
        # infinite iterators.
        if (len(targets) == 2
                and isinstance(node.iter, ast.Call)
                and isinstance(node.iter.func, ast.Name)
                and node.iter.func.id == "enumerate"
                and len(node.iter.args) >= 1
                and not self._is_obj_expr(node.iter.args[0])):
            self._emit_for_enumerate_inline(node)
            return
        # for i, val in enumerate(obj) — use iterator protocol with counter
        if (len(targets) == 2
                and isinstance(node.iter, ast.Call)
                and isinstance(node.iter.func, ast.Name)
                and node.iter.func.id == "enumerate"
                and len(node.iter.args) >= 1
                and self._is_obj_expr(node.iter.args[0])):
            self._emit_for_enumerate_obj(node)
            return

        # F2 optimization: for k, v in dict.items() — zero-copy iteration.
        # Reads dict->keys[i] and dict->values[i] directly instead of
        # materializing a list of 2-element tuples via fastpy_dict_items().
        if (len(targets) == 2
                and all(isinstance(t, ast.Name) for t in targets)
                and isinstance(node.iter, ast.Call)
                and isinstance(node.iter.func, ast.Attribute)
                and node.iter.func.attr == "items"
                and not node.iter.args
                and self._is_dict_expr(node.iter.func.value)):
            self._emit_for_dict_items_zerocopy(node)
            return

        iter_tv = self._emit_expr(node.iter)
        iter_val = iter_tv.as_ptr(self.builder)
        iter_len = self._rt_call("list_length", [iter_val])

        # Unique per-loop index name so nested `for a,b in ...` loops
        # don't clobber each other's counter.
        self._block_counter += 1
        idx_name = f"__for_tup_idx_{self._block_counter}"
        self._store_variable(idx_name, ir.Constant(i64, 0), ValueType(VKind.INT))

        cond_block = self._new_block("fort.cond")
        body_block = self._new_block("fort.body")
        incr_block = self._new_block("fort.incr")
        end_block = self._new_block("fort.end")

        self.builder.branch(cond_block)

        self.builder.position_at_end(cond_block)
        idx = self._load_variable(idx_name, node)
        cond = self.builder.icmp_signed("<", idx, iter_len)
        self.builder.cbranch(cond, body_block, end_block)

        self.builder.position_at_end(body_block)
        idx = self._load_variable(idx_name, node)
        # Iter elements are list/tuple pointers — fetch as bare i8*
        elem_list = self._list_get_as_bare(iter_val, idx, "list")

        # Determine inner element types from AST: first tuple's elements
        inner_types = self._infer_for_tuple_elem_types(node.iter, len(targets))

        # Check for starred target in the tuple
        star_idx = None
        for _si, tgt in enumerate(targets):
            if isinstance(tgt, ast.Starred):
                star_idx = _si
                break

        if star_idx is not None:
            # Starred unpacking: for a, *rest, z in data
            inner_len = self._rt_call("list_length", [elem_list])
            n_fixed = len(targets) - 1
            for i, tgt in enumerate(targets):
                if isinstance(tgt, ast.Starred):
                    name = tgt.value.id if isinstance(tgt.value, ast.Name) else None
                    if name is None or name == "_":
                        continue
                    start = ir.Constant(i64, star_idx)
                    n_after = len(targets) - star_idx - 1
                    stop = self.builder.sub(inner_len, ir.Constant(i64, n_after))
                    rest = self._rt_call("list_slice", [
                        elem_list, start, stop, ir.Constant(i64, 1),
                        ir.Constant(i64, 1)])
                    self._store_variable(name, rest, ValueType(VKind.LIST, elem_type=ValueType(VKind.INT)))
                elif isinstance(tgt, ast.Name):
                    if i < star_idx:
                        el_idx = ir.Constant(i64, i)
                    else:
                        offset = len(targets) - i
                        el_idx = self.builder.sub(inner_len, ir.Constant(i64, offset))
                    self._fv_store_from_list(tgt.id, elem_list, el_idx, "unknown")
                else:
                    self._bridge_fallback_stmt(node, "unsupported starred for target")
        else:
            # Unpack targets — handle both simple names and nested tuples
            for i, tgt in enumerate(targets):
                idx_const = ir.Constant(i64, i)
                if isinstance(tgt, ast.Name):
                    elem_type = inner_types[i] if i < len(inner_types) else "str"
                    # Use _fv_store_from_list so the runtime tag is preserved
                    # (compile-time inference may be wrong for mixed-type tuples
                    # like dict.items() returning (str, int) pairs).
                    self._fv_store_from_list(tgt.id, elem_list, idx_const, elem_type)
                elif isinstance(tgt, (ast.Tuple, ast.List)):
                    # Nested tuple/list: get the sub-list and unpack it
                    inner_list = self._list_get_as_bare(elem_list, idx_const, "list")
                    self._unpack_targets_from_list(tgt.elts, inner_list, node)
                else:
                    self._bridge_fallback_stmt(node, "unsupported for tuple unpack target")

        self._loop_stack.append((end_block, incr_block))
        _prev_hot = self._in_hot_loop
        self._in_hot_loop = True
        self._emit_stmts(node.body)
        self._in_hot_loop = _prev_hot
        self._loop_stack.pop()
        if not self.builder.block.is_terminated:
            self.builder.branch(incr_block)

        self.builder.position_at_end(incr_block)
        idx = self._load_variable(idx_name, node)
        self._store_variable(idx_name, self.builder.add(idx, ir.Constant(i64, 1)), ValueType(VKind.INT))
        self.builder.branch(cond_block)

        self.builder.position_at_end(end_block)

        # Decref temporary iterables (e.g. `for k, v in enumerate(lst):`)
        _is_named_var = (isinstance(node.iter, ast.Name)
                         and (node.iter.id in self.variables
                              or node.iter.id in self._global_vars))
        if not _is_named_var and self._USE_REFCOUNT:
            _tag = ir.Constant(i32, FPY_TAG_LIST)
            _data = self.builder.ptrtoint(iter_val, i64)
            self.builder.call(self.runtime["rc_decref"], [_tag, _data])

    def _emit_for_string(self, node: ast.For) -> None:
        """Emit for ch in string: iterate over characters."""
        var_name = node.target.id
        str_tv = self._emit_expr(node.iter)
        str_val = str_tv.as_ptr(self.builder)
        str_len = self._rt_call("str_len", [str_val])

        idx_name = f"__idx_str_{var_name}"
        self._store_variable(idx_name, ir.Constant(i64, 0), ValueType(VKind.INT))

        cond_block = self._new_block("fors.cond")
        body_block = self._new_block("fors.body")
        incr_block = self._new_block("fors.incr")
        end_block = self._new_block("fors.end")

        self.builder.branch(cond_block)
        self.builder.position_at_end(cond_block)
        idx = self._load_variable(idx_name, node)
        cond = self.builder.icmp_signed("<", idx, str_len)
        self.builder.cbranch(cond, body_block, end_block)

        self.builder.position_at_end(body_block)
        idx = self._load_variable(idx_name, node)
        ch = self._rt_call("str_index", [str_val, idx])
        self._store_variable(var_name, ch, ValueType(VKind.STR))

        self._loop_stack.append((end_block, incr_block))
        _prev_hot = self._in_hot_loop
        self._in_hot_loop = True
        self._emit_stmts(node.body)
        self._in_hot_loop = _prev_hot
        self._loop_stack.pop()
        if not self.builder.block.is_terminated:
            self.builder.branch(incr_block)

        self.builder.position_at_end(incr_block)
        idx = self._load_variable(idx_name, node)
        self._store_variable(idx_name, self.builder.add(idx, ir.Constant(i64, 1)), ValueType(VKind.INT))
        self.builder.branch(cond_block)

        self.builder.position_at_end(end_block)

        # Decref temporary string iterables (e.g. `for ch in get_str():`)
        _is_named_var = (isinstance(node.iter, ast.Name)
                         and (node.iter.id in self.variables
                              or node.iter.id in self._global_vars))
        if not _is_named_var and self._USE_REFCOUNT:
            _tag = ir.Constant(i32, FPY_TAG_STR)
            _data = self.builder.ptrtoint(str_val, i64)
            self.builder.call(self.runtime["rc_decref"], [_tag, _data])

    def _emit_for_iter_protocol(self, node: ast.For) -> None:
        """Emit `for x in obj` using __iter__/__next__ protocol.
        Calls obj.__iter__() to get the iterator, then repeatedly
        calls iterator.__next__() until StopIteration is raised."""
        var_name = node.target.id

        # Get the iterable and call __iter__()
        obj = self._emit_expr_value(node.iter)
        obj = self._ensure_ptr(obj)
        iter_name = self._make_string_constant("__iter__")
        iterator = self.builder.call(
            self.runtime["obj_call_method0"], [obj, iter_name])
        # iterator is i64 (result of method call) — convert to ptr
        iter_ptr = self._ensure_ptr(iterator)

        next_name = self._make_string_constant("__next__")

        cond_block = self._new_block("foriter.cond")
        body_block = self._new_block("foriter.body")
        else_block = self._new_block("foriter.else") if node.orelse else None
        end_block = self._new_block("foriter.end")

        self.builder.branch(cond_block)
        self.builder.position_at_end(cond_block)

        # Call __next__() — if StopIteration is raised, exit loop
        # We need to wrap in a try-like mechanism. Use exc_pending
        # after the call to detect StopIteration.
        result = self.builder.call(
            self.runtime["obj_call_method0"], [iter_ptr, next_name])
        pending = self.builder.call(self.runtime["exc_pending"], [])
        has_exc = self.builder.icmp_signed(
            "!=", pending, ir.Constant(i32, 0))
        after_loop = else_block if else_block else end_block
        self.builder.cbranch(has_exc, after_loop, body_block)

        self.builder.position_at_end(body_block)
        # Store the result as the loop variable.
        # obj_call_method0 returns i64 (bare data); recover the runtime
        # tag via get_ret_tag() and build a proper FpyValue so the loop
        # variable preserves type info (generators may yield any type).
        ret_tag = self.builder.call(self.runtime["get_ret_tag"], [])
        fv = self._fv_build_from_slots(ret_tag, result)
        self._store_variable(var_name, fv, ValueType(VKind.FVALUE))

        self._loop_stack.append((end_block, cond_block))
        _prev_hot = self._in_hot_loop
        self._in_hot_loop = True
        self._emit_stmts(node.body)
        self._in_hot_loop = _prev_hot
        self._loop_stack.pop()
        if not self.builder.block.is_terminated:
            self.builder.branch(cond_block)

        if else_block:
            self.builder.position_at_end(else_block)
            # Clear the StopIteration exception
            self.builder.call(self.runtime["exc_clear"], [])
            self._emit_stmts(node.orelse)
            if not self.builder.block.is_terminated:
                self.builder.branch(end_block)

        self.builder.position_at_end(end_block)
        # Clear StopIteration if still pending
        self.builder.call(self.runtime["exc_clear"], [])

    def _emit_for_getitem_protocol(self, node: ast.For) -> None:
        """Emit ``for x in obj`` using the __getitem__ sequence protocol.

        Python falls back to calling __getitem__(0), __getitem__(1), ...
        until IndexError is raised when __iter__ is not defined."""
        var_name = node.target.id

        # Get the iterable object
        obj = self._emit_expr_value(node.iter)
        obj = self._ensure_ptr(obj)
        getitem_name = self._make_string_constant("__getitem__")

        # Index counter — starts at 0, incremented each iteration
        idx_slot = self._create_entry_alloca(i64, "getitem.idx")
        self.builder.store(ir.Constant(i64, 0), idx_slot)

        cond_block = self._new_block("forgetitem.cond")
        body_block = self._new_block("forgetitem.body")
        else_block = self._new_block("forgetitem.else") if node.orelse else None
        end_block = self._new_block("forgetitem.end")

        self.builder.branch(cond_block)
        self.builder.position_at_end(cond_block)

        # Load current index
        idx = self.builder.load(idx_slot)

        # Call __getitem__(idx) — if IndexError is raised, exit loop
        result = self.builder.call(
            self.runtime["obj_call_method1"],
            [obj, getitem_name, idx])
        pending = self.builder.call(self.runtime["exc_pending"], [])
        has_exc = self.builder.icmp_signed(
            "!=", pending, ir.Constant(i32, 0))
        after_loop = else_block if else_block else end_block
        self.builder.cbranch(has_exc, after_loop, body_block)

        self.builder.position_at_end(body_block)
        # Store the result as the loop variable with runtime tag
        ret_tag = self.builder.call(self.runtime["get_ret_tag"], [])
        fv = self._fv_build_from_slots(ret_tag, result)
        self._store_variable(var_name, fv, ValueType(VKind.FVALUE))

        # Increment index
        next_idx = self.builder.add(idx, ir.Constant(i64, 1))
        self.builder.store(next_idx, idx_slot)

        self._loop_stack.append((end_block, cond_block))
        _prev_hot = self._in_hot_loop
        self._in_hot_loop = True
        self._emit_stmts(node.body)
        self._in_hot_loop = _prev_hot
        self._loop_stack.pop()
        if not self.builder.block.is_terminated:
            self.builder.branch(cond_block)

        if else_block:
            self.builder.position_at_end(else_block)
            # Clear the IndexError exception
            self.builder.call(self.runtime["exc_clear"], [])
            self._emit_stmts(node.orelse)
            if not self.builder.block.is_terminated:
                self.builder.branch(end_block)

        self.builder.position_at_end(end_block)
        # Clear IndexError if still pending
        self.builder.call(self.runtime["exc_clear"], [])

    def _emit_for_pyobj(self, node: ast.For) -> None:
        """Emit `for x in iterable` using CPython's iteration protocol.
        Uses raw PyObject* iteration to keep items as Python objects,
        allowing downstream pyobj operations (print, method calls, etc.)."""
        var_name = node.target.id

        # Get the raw PyObject* for the iterable.
        # For pyobj call expressions, use _emit_cpython_call_raw to avoid
        # pyobject_to_fpy conversion (which turns Python lists into FpyList*).
        if (isinstance(node.iter, ast.Call)
                and isinstance(node.iter.func, ast.Attribute)
                and self._is_pyobj_receiver(node.iter.func.value)):
            obj = self._emit_cpython_call_raw(node.iter)
            obj = self._ensure_ptr(obj)
        else:
            iter_tv = self._emit_expr(node.iter)
            obj = iter_tv.as_ptr(self.builder)
        iterator = self.builder.call(self.runtime["cpython_iter"], [obj])

        # Use raw iteration: each item stays as PyObject*
        item_slot = self._create_entry_alloca(i8_ptr, "pyiter.item")

        cond_block = self._new_block("pyiter.cond")
        body_block = self._new_block("pyiter.body")
        end_block = self._new_block("pyiter.end")

        self.builder.branch(cond_block)
        self.builder.position_at_end(cond_block)

        # iter_next_raw returns PyObject* or NULL
        raw_item = self.builder.call(
            self.runtime["cpython_iter_next_raw"], [iterator])
        null_ptr = ir.Constant(i8_ptr, None)
        is_null = self.builder.icmp_unsigned("==", raw_item, null_ptr)
        self.builder.cbranch(is_null, end_block, body_block)

        self.builder.position_at_end(body_block)
        # Store the raw PyObject* as pyobj — keeps item as a Python object
        # for downstream operations (print, attribute access, method calls).
        self._store_variable(var_name, raw_item, ValueType(VKind.PYOBJ))

        self._loop_stack.append((end_block, cond_block))
        _prev_hot = self._in_hot_loop
        self._in_hot_loop = True
        self._emit_stmts(node.body)
        self._in_hot_loop = _prev_hot
        self._loop_stack.pop()
        if not self.builder.block.is_terminated:
            self.builder.branch(cond_block)

        self.builder.position_at_end(end_block)

    def _emit_for_deque(self, node: ast.For) -> None:
        """Emit `for x in deque` by converting to list first, then iterating."""
        var_name = node.target.id

        # Convert deque to list for iteration (Phase 2: TypedValue)
        dq_tv = self._emit_expr(node.iter)
        lst = self._rt_call("deque_to_list", [dq_tv])

        # Now iterate the list (reuse the standard list iteration)
        # Store the list as a temporary and emit a list for-loop
        length = self._rt_call("list_length", [lst])

        idx_alloca = self._create_entry_alloca(i64, "dqfor.idx")
        self.builder.store(ir.Constant(i64, 0), idx_alloca)

        cond_block = self._new_block("dqfor.cond")
        body_block = self._new_block("dqfor.body")
        end_block = self._new_block("dqfor.end")

        self.builder.branch(cond_block)
        self.builder.position_at_end(cond_block)
        idx = self.builder.load(idx_alloca)
        cmp = self.builder.icmp_signed("<", idx, length)
        self.builder.cbranch(cmp, body_block, end_block)

        self.builder.position_at_end(body_block)
        tag_slot = self._create_entry_alloca(i32, "dqfor.tag")
        data_slot = self._create_entry_alloca(i64, "dqfor.data")
        self._rt_call("list_get_fv",
                          [lst, idx, tag_slot, data_slot])
        elem_tag = self.builder.load(tag_slot)
        elem_data = self.builder.load(data_slot)
        fv_elem = self._fv_build_from_slots(elem_tag, elem_data)
        self._store_variable(var_name, fv_elem, ValueType(VKind.MIXED))

        self._loop_stack.append((end_block, cond_block))
        _prev_hot = self._in_hot_loop
        self._in_hot_loop = True
        self._emit_stmts(node.body)
        self._in_hot_loop = _prev_hot
        self._loop_stack.pop()
        if not self.builder.block.is_terminated:
            next_idx = self.builder.add(
                self.builder.load(idx_alloca), ir.Constant(i64, 1))
            self.builder.store(next_idx, idx_alloca)
            self.builder.branch(cond_block)

        self.builder.position_at_end(end_block)

        # deque_to_list() always returns a temporary list — decref it
        if self._USE_REFCOUNT:
            _tag = ir.Constant(i32, FPY_TAG_LIST)
            _data = self.builder.ptrtoint(lst, i64)
            self.builder.call(self.runtime["rc_decref"], [_tag, _data])

    def _emit_for_fvalue(self, node: ast.For) -> None:
        """Emit for x in <fvalue>: runtime-dispatched iteration for FVALUE/MIXED.

        The iterable's type is only known at runtime (e.g. json.loads result).
        Uses fv_len for length and fv_iter_get for element access — both do
        tag-based dispatch at runtime (list→items[i], dict→keys[i], str→char[i]).
        """
        var_name = node.target.id

        # Load the raw fpy_val to get the runtime tag + data.
        # Supports both Name nodes (direct variable) and general expressions
        # (e.g. user["scores"] where user is MIXED from json iteration).
        if isinstance(node.iter, ast.Name):
            fv = self._load_fv_raw(node.iter.id)
        else:
            fv = self._emit_expr_value(node.iter)
            # If the expression didn't return an fpy_val struct (shouldn't
            # happen but guard defensively), wrap it as one.
            if not (isinstance(fv.type, ir.LiteralStructType)
                    and fv.type == fpy_val):
                fv = self._wrap_bare_to_fv(fv, ValueType(VKind.FVALUE))
        tag = self._fv_tag(fv)
        data = self._fv_data_i64(fv)

        # Length via runtime dispatch (handles list/dict/set/str/bytes)
        iter_len = self.builder.call(self.runtime["fv_len"], [tag, data])

        # Index variable
        idx_name = f"__idx_{var_name}"
        self._store_variable(idx_name, ir.Constant(i64, 0), ValueType(VKind.INT))

        cond_block = self._new_block("forfv.cond")
        body_block = self._new_block("forfv.body")
        incr_block = self._new_block("forfv.incr")
        else_block = self._new_block("forfv.else") if node.orelse else None
        end_block = self._new_block("forfv.end")

        self.builder.branch(cond_block)

        self.builder.position_at_end(cond_block)
        idx = self._load_variable(idx_name, node)
        cond = self.builder.icmp_signed("<", idx, iter_len)
        after_loop = else_block if else_block else end_block
        self.builder.cbranch(cond, body_block, after_loop)

        self.builder.position_at_end(body_block)
        idx = self._load_variable(idx_name, node)

        # Element via runtime dispatch — fv_iter_get handles all container types
        out_tag_slot = self._create_entry_alloca(i32, "forfv.elem.tag")
        out_data_slot = self._create_entry_alloca(i64, "forfv.elem.data")
        self.builder.call(self.runtime["fv_iter_get"],
                          [tag, data, idx, out_tag_slot, out_data_slot])
        elem_tag = self.builder.load(out_tag_slot)
        elem_data = self.builder.load(out_data_slot)
        fv_elem = self._fv_build_from_slots(elem_tag, elem_data)
        self._store_variable(var_name, fv_elem, ValueType(VKind.MIXED))

        self._loop_stack.append((end_block, incr_block))
        _prev_hot = self._in_hot_loop
        self._in_hot_loop = True
        self._emit_stmts(node.body)
        self._in_hot_loop = _prev_hot
        self._loop_stack.pop()
        if not self.builder.block.is_terminated:
            self.builder.branch(incr_block)

        self.builder.position_at_end(incr_block)
        idx = self._load_variable(idx_name, node)
        incremented = self.builder.add(idx, ir.Constant(i64, 1))
        self._store_variable(idx_name, incremented, ValueType(VKind.INT))
        self.builder.branch(cond_block)

        if else_block:
            self.builder.position_at_end(else_block)
            self._emit_stmts(node.orelse)
            if not self.builder.block.is_terminated:
                self.builder.branch(end_block)

        self.builder.position_at_end(end_block)

    def _emit_for_list(self, node: ast.For) -> None:
        """Emit for x in <list>: iterate over list elements by index."""
        var_name = node.target.id

        # Evaluate the list (Phase 2: use TypedValue for proper coercion)
        iter_tv = self._emit_expr(node.iter)
        list_val = iter_tv.as_ptr(self.builder)
        list_len = self._rt_call("list_length", [list_val])

        # Index variable
        idx_name = f"__idx_{var_name}"
        self._store_variable(idx_name, ir.Constant(i64, 0), ValueType(VKind.INT))

        cond_block = self._new_block("forl.cond")
        body_block = self._new_block("forl.body")
        incr_block = self._new_block("forl.incr")
        else_block = self._new_block("forl.else") if node.orelse else None
        end_block = self._new_block("forl.end")

        self.builder.branch(cond_block)

        self.builder.position_at_end(cond_block)
        idx = self._load_variable(idx_name, node)
        cond = self.builder.icmp_signed("<", idx, list_len)
        after_loop = else_block if else_block else end_block
        self.builder.cbranch(cond, body_block, after_loop)

        self.builder.position_at_end(body_block)
        # Get element via FV-ABI getter; store into the loop variable's FV
        # alloca directly, bypassing the unwrap-then-rewrap round-trip.
        idx = self._load_variable(idx_name, node)
        elem_type = self._get_list_elem_type(node.iter)
        elem_kind = elem_type.kind
        # Dict-value lists (e.g. data["users"] where values are lists of
        # dicts/mixed types): the default elem_type is INT but the actual
        # elements may be dicts/strings/objects.  Upgrade to MIXED so the
        # loop variable supports runtime-dispatched subscript, method
        # calls, etc.
        if elem_kind == VKind.INT and not elem_type.elem_type:
            _from_dict = False
            # Case 1: `for x in var:` where var was assigned from dict[key]
            if (isinstance(node.iter, ast.Name)
                    and node.iter.id in self.variables):
                _iter_vt = self.variables[node.iter.id][1]
                _iter_vt = (_iter_vt if isinstance(_iter_vt, ValueType)
                            else ValueType.from_old_tag(_iter_vt))
                if _iter_vt.kind == VKind.LIST:
                    _iter_name = node.iter.id
                    tree = getattr(self, '_csa_root_tree', None)
                    if tree:
                        for n in ast.walk(tree):
                            if (isinstance(n, ast.Assign)
                                    and len(n.targets) == 1
                                    and isinstance(n.targets[0], ast.Name)
                                    and n.targets[0].id == _iter_name
                                    and isinstance(n.value, ast.Subscript)
                                    and isinstance(n.value.value, ast.Name)
                                    and n.value.value.id in self.variables
                                    and self._var_kind(n.value.value.id)
                                        in (VKind.DICT, VKind.DEFAULTDICT)):
                                _from_dict = True
                                break
            # Case 2: `for x in d["key"]:` — direct subscript on a dict
            # variable that has list values
            elif (isinstance(node.iter, ast.Subscript)
                      and isinstance(node.iter.value, ast.Name)):
                _base = node.iter.value.id
                if (_base in self.variables
                        and self._var_kind(_base)
                            in (VKind.DICT, VKind.DEFAULTDICT)):
                    _from_dict = True
                elif _base in self._dict_var_list_values:
                    _from_dict = True
            # Case 3: `for x in var:` where var was assigned from
            # d.get(key, []) or d.setdefault(key, []).  The returned
            # list's element type is unknown at compile time — the
            # default [] tells us nothing about the dict's actual values.
            if (not _from_dict
                    and isinstance(node.iter, ast.Name)
                    and node.iter.id in self.variables):
                _iter_vt = self.variables[node.iter.id][1]
                _iter_vt = (_iter_vt if isinstance(_iter_vt, ValueType)
                            else ValueType.from_old_tag(_iter_vt))
                if _iter_vt.kind == VKind.LIST:
                    _iter_name = node.iter.id
                    tree = getattr(self, '_csa_root_tree', None)
                    if tree:
                        for n in ast.walk(tree):
                            if (isinstance(n, ast.Assign)
                                    and len(n.targets) == 1
                                    and isinstance(n.targets[0], ast.Name)
                                    and n.targets[0].id == _iter_name
                                    and isinstance(n.value, ast.Call)
                                    and isinstance(n.value.func, ast.Attribute)
                                    and n.value.func.attr in ("get", "setdefault")
                                    and self._is_dict_expr(n.value.func.value)):
                                _from_dict = True
                                break
            if _from_dict:
                elem_kind = VKind.MIXED
        # Determine the variable's tag from the list's element type
        if elem_kind == VKind.LIST:
            var_tag = elem_type if elem_type.elem_type else ValueType(VKind.LIST, elem_type=ValueType(VKind.INT))
        else:
            var_tag = ValueType(elem_kind) if elem_kind != VKind.INT else ValueType(VKind.INT)

        # F1 optimization: for int/float element lists, use inline GEP
        # to read element data directly instead of calling list_get_fv.
        # This eliminates one function call per loop iteration (~2ns).
        # Only safe when the element type is CONFIDENTLY determined (not
        # the fallback "int" default which could mask strings/objects).
        # Confidence check: elem_type was explicitly set from a variable's
        # tag with element info, a literal with typed elements, or a
        # known-typed expression.
        _f1_safe = (
            elem_kind in (VKind.INT, VKind.FLOAT)
            and self._USE_FV_LOCALS
            and self._is_confident_elem_type(node.iter, elem_type)
        )
        if _f1_safe:
            bare = self._inline_list_get_no_bounds(list_val, idx, elem_type)
            self._store_variable(var_name, bare, var_tag)
        else:
            self._fv_store_from_list(var_name, list_val, idx, var_tag)

        # Mixed-value dict support for `for p in list_of_dicts:`. Build a
        # per-key type map so `p["age"]` (int) and `p["name"]` (str) in
        # the loop body use the right unwrap path.
        if elem_kind == VKind.DICT:
            key_types = self._infer_list_of_dicts_key_types(node.iter)
            if key_types:
                self._dict_var_key_types[var_name] = key_types

        self._loop_stack.append((end_block, incr_block))
        _prev_hot = self._in_hot_loop
        self._in_hot_loop = True
        self._emit_stmts(node.body)
        self._in_hot_loop = _prev_hot
        self._loop_stack.pop()
        if not self.builder.block.is_terminated:
            self.builder.branch(incr_block)

        self.builder.position_at_end(incr_block)
        idx = self._load_variable(idx_name, node)
        incremented = self.builder.add(idx, ir.Constant(i64, 1))
        self._store_variable(idx_name, incremented, ValueType(VKind.INT))
        self.builder.branch(cond_block)

        if else_block:
            self.builder.position_at_end(else_block)
            self._emit_stmts(node.orelse)
            if not self.builder.block.is_terminated:
                self.builder.branch(end_block)

        self.builder.position_at_end(end_block)

        # Decref temporary iterables (e.g. `for x in make_list():`).
        # Named variables are borrowed references — the variable owns
        # them, so only decref when the iterable is a temporary.
        _is_named_var = (isinstance(node.iter, ast.Name)
                         and (node.iter.id in self.variables
                              or node.iter.id in self._global_vars))
        if not _is_named_var and self._USE_REFCOUNT:
            _tag = ir.Constant(i32, FPY_TAG_LIST)
            _data = self.builder.ptrtoint(list_val, i64)
            self.builder.call(self.runtime["rc_decref"], [_tag, _data])

    def _emit_for_dict(self, node: ast.For) -> None:
        """Emit for k in <dict>/<set>: zero-copy iteration over the dict's
        compact key array.  Reads keys[i] directly via dict_key_fv instead
        of materializing a temporary list with dict_keys().
        """
        var_name = node.target.id

        # F2: zero-copy — get length directly, iterate via dict_key_fv
        dict_tv = self._emit_expr(node.iter)
        dict_val = dict_tv.as_ptr(self.builder)
        dict_len = self._rt_call("dict_length", [dict_val])

        # Determine the key/element type. For sets, the elements can be
        # any type (int, str, etc.). For dicts, keys are typically strings
        # but may be ints. Use VKind to determine:
        # SET → "int" (default), DICT → "str" (default, but check for int keys).
        key_type = "str"
        if dict_tv.vtype.kind == VKind.SET:
            # Try to infer element type from set literal or comprehension
            key_type = "int"  # default for sets (most common)
            if isinstance(node.iter, ast.Set):
                if (node.iter.elts and isinstance(node.iter.elts[0], ast.Constant)
                        and isinstance(node.iter.elts[0].value, str)):
                    key_type = "str"
            elif isinstance(node.iter, ast.Name) and node.iter.id in self.variables:
                # Check if the set was built from string elements
                pass  # int is a safe default for sets
        elif (isinstance(node.iter, ast.Name)
                and self._is_int_keyed_dict(node.iter)):
            key_type = "int"
        elif isinstance(node.iter, ast.Dict):
            # Dict literal: check if keys are int constants
            if (node.iter.keys
                    and all(isinstance(k, ast.Constant)
                            and isinstance(k.value, int)
                            for k in node.iter.keys if k is not None)):
                key_type = "int"

        idx_name = f"__idx_{var_name}"
        self._store_variable(idx_name, ir.Constant(i64, 0), ValueType(VKind.INT))

        cond_block = self._new_block("ford.cond")
        body_block = self._new_block("ford.body")
        incr_block = self._new_block("ford.incr")
        else_block = self._new_block("ford.else") if node.orelse else None
        end_block = self._new_block("ford.end")

        self.builder.branch(cond_block)

        self.builder.position_at_end(cond_block)
        idx = self._load_variable(idx_name, node)
        cond = self.builder.icmp_signed("<", idx, dict_len)
        after_loop = else_block if else_block else end_block
        self.builder.cbranch(cond, body_block, after_loop)

        self.builder.position_at_end(body_block)
        idx = self._load_variable(idx_name, node)
        # Zero-copy: read directly from dict->keys[idx]
        self._fv_store_from_list(var_name, dict_val, idx, key_type,
                                 get_fn="dict_key_fv")

        self._loop_stack.append((end_block, incr_block))
        _prev_hot = self._in_hot_loop
        self._in_hot_loop = True
        self._emit_stmts(node.body)
        self._in_hot_loop = _prev_hot
        self._loop_stack.pop()
        if not self.builder.block.is_terminated:
            self.builder.branch(incr_block)

        self.builder.position_at_end(incr_block)
        idx = self._load_variable(idx_name, node)
        incremented = self.builder.add(idx, ir.Constant(i64, 1))
        self._store_variable(idx_name, incremented, ValueType(VKind.INT))
        self.builder.branch(cond_block)

        if else_block:
            self.builder.position_at_end(else_block)
            self._emit_stmts(node.orelse)
            if not self.builder.block.is_terminated:
                self.builder.branch(end_block)

        self.builder.position_at_end(end_block)
        # No temporary list to decref — zero-copy iteration

    def _emit_for_dict_items_zerocopy(self, node: ast.For) -> None:
        """Emit for (k, v) in dict.items() using zero-copy access.

        Reads dict->keys[i] and dict->values[i] directly instead of
        materializing a list of N 2-element tuples.  Eliminates N+1 heap
        allocations per loop execution.
        """
        targets = node.target.elts
        key_target = targets[0]  # ast.Name (guard checked by caller)
        val_target = targets[1]  # ast.Name

        # Emit the dict (not the .items() call)
        dict_tv = self._emit_expr(node.iter.func.value)
        dict_val = dict_tv.as_ptr(self.builder)
        dict_len = self._rt_call("dict_length", [dict_val])

        # Infer key/value types
        inner_types = self._infer_for_tuple_elem_types(node.iter, 2)
        key_type = inner_types[0] if inner_types else "str"
        val_type = inner_types[1] if len(inner_types) > 1 else "str"

        self._block_counter += 1
        idx_name = f"__for_di_idx_{self._block_counter}"
        self._store_variable(idx_name, ir.Constant(i64, 0), ValueType(VKind.INT))

        cond_block = self._new_block("fdi.cond")
        body_block = self._new_block("fdi.body")
        incr_block = self._new_block("fdi.incr")
        else_block = self._new_block("fdi.else") if node.orelse else None
        end_block = self._new_block("fdi.end")

        self.builder.branch(cond_block)

        self.builder.position_at_end(cond_block)
        idx = self._load_variable(idx_name, node)
        cond = self.builder.icmp_signed("<", idx, dict_len)
        after_loop = else_block if else_block else end_block
        self.builder.cbranch(cond, body_block, after_loop)

        self.builder.position_at_end(body_block)
        idx = self._load_variable(idx_name, node)

        # Zero-copy: read key and value directly from dict arrays
        self._fv_store_from_list(key_target.id, dict_val, idx, key_type,
                                 get_fn="dict_key_fv")
        self._fv_store_from_list(val_target.id, dict_val, idx, val_type,
                                 get_fn="dict_value_fv")

        self._loop_stack.append((end_block, incr_block))
        _prev_hot = self._in_hot_loop
        self._in_hot_loop = True
        self._emit_stmts(node.body)
        self._in_hot_loop = _prev_hot
        self._loop_stack.pop()
        if not self.builder.block.is_terminated:
            self.builder.branch(incr_block)

        self.builder.position_at_end(incr_block)
        idx = self._load_variable(idx_name, node)
        incremented = self.builder.add(idx, ir.Constant(i64, 1))
        self._store_variable(idx_name, incremented, ValueType(VKind.INT))
        self.builder.branch(cond_block)

        if else_block:
            self.builder.position_at_end(else_block)
            self._emit_stmts(node.orelse)
            if not self.builder.block.is_terminated:
                self.builder.branch(end_block)

        self.builder.position_at_end(end_block)

    def _emit_break(self, node: ast.Break) -> None:
        if not self._loop_stack:
            raise CodeGenError("'break' outside loop", node)
        end_block, _ = self._loop_stack[-1]
        self.builder.branch(end_block)

    def _emit_continue(self, node: ast.Continue) -> None:
        if not self._loop_stack:
            raise CodeGenError("'continue' outside loop", node)
        _, continue_block = self._loop_stack[-1]
        self.builder.branch(continue_block)

    # -----------------------------------------------------------------
    # Conditions and comparisons
    # -----------------------------------------------------------------

    def _emit_condition(self, node: ast.expr) -> ir.Value:
        """Emit an expression as a boolean condition (i1)."""
        if isinstance(node, ast.Compare):
            return self._emit_compare(node)
        elif isinstance(node, ast.BoolOp):
            # In condition context, emit short-circuit conditions directly.
            # This ensures each operand uses type-aware truthiness
            # (list_length, str_len, etc.) via _emit_condition, instead of
            # evaluating the BoolOp to a value and doing a null-pointer check.
            if isinstance(node.op, ast.And):
                return self._emit_condition_and(node.values)
            elif isinstance(node.op, ast.Or):
                return self._emit_condition_or(node.values)
            val = self._emit_boolop(node)
            return self._truthiness(val)
        elif isinstance(node, ast.UnaryOp) and isinstance(node.op, ast.Not):
            cond = self._emit_condition(node.operand)
            return self.builder.not_(cond)
        elif isinstance(node, ast.Constant):
            # Constant used as condition: if True, if False, if 0, etc.
            val = bool(node.value)
            return ir.Constant(ir.IntType(1), 1 if val else 0)
        elif isinstance(node, ast.Name):
            # Variable used as condition: always use _truthiness_of_expr which
            # handles FV-backed vars (fv_truthy), objects (__bool__/__len__),
            # lists, dicts, strings, sets, etc. via type-aware dispatch.
            return self._truthiness_of_expr(node)
        else:
            # General expression: evaluate and check truthiness
            return self._truthiness_of_expr(node)

    def _emit_condition_and(self, values: list[ast.expr]) -> ir.Value:
        """Emit short-circuit AND for boolean condition context (returns i1).

        Unlike ``_emit_short_circuit_and`` (which returns operand values),
        this evaluates each operand as a condition via ``_emit_condition``,
        ensuring type-aware truthiness (list_length, str_len, etc.).
        """
        result_alloca = self._create_entry_alloca(ir.IntType(1), "cond.and")
        merge_block = self._new_block("cond.and.end")

        for i, val_node in enumerate(values):
            cond = self._emit_condition(val_node)
            self.builder.store(cond, result_alloca)
            if i < len(values) - 1:
                next_block = self._new_block("cond.and.next")
                self.builder.cbranch(cond, next_block, merge_block)
                self.builder.position_at_end(next_block)
            else:
                self.builder.branch(merge_block)

        self.builder.position_at_end(merge_block)
        return self.builder.load(result_alloca)

    def _emit_condition_or(self, values: list[ast.expr]) -> ir.Value:
        """Emit short-circuit OR for boolean condition context (returns i1)."""
        result_alloca = self._create_entry_alloca(ir.IntType(1), "cond.or")
        merge_block = self._new_block("cond.or.end")

        for i, val_node in enumerate(values):
            cond = self._emit_condition(val_node)
            self.builder.store(cond, result_alloca)
            if i < len(values) - 1:
                next_block = self._new_block("cond.or.next")
                self.builder.cbranch(cond, merge_block, next_block)
                self.builder.position_at_end(next_block)
            else:
                self.builder.branch(merge_block)

        self.builder.position_at_end(merge_block)
        return self.builder.load(result_alloca)

    def _truthiness(self, value: ir.Value) -> ir.Value:
        """Convert an LLVM value to a boolean (i1) via Python truthiness.

        For pointer values, this checks non-null — NOT emptiness. Callers that
        know the value is a string/list/dict should use a length check instead
        (see `_truthiness_of_expr`).
        """
        if isinstance(value.type, ir.IntType):
            if value.type.width == 1:
                return value
            return self.builder.icmp_signed("!=", value, ir.Constant(value.type, 0))
        elif isinstance(value.type, ir.DoubleType):
            return self.builder.fcmp_ordered("!=", value, ir.Constant(double, 0.0))
        elif isinstance(value.type, ir.PointerType):
            null_ptr = ir.Constant(value.type, None)
            return self.builder.icmp_unsigned("!=", value, null_ptr)
        else:
            return ir.Constant(ir.IntType(1), 0)

    def _truthiness_of_expr(self, node: ast.expr) -> ir.Value:
        """Type-aware truthiness: empty str/list/dict → False, else non-null.

        For Name nodes backed by an FV alloca and dict/list subscripts,
        dispatch through `fv_truthy` which handles every tag at runtime.
        AST-level checks remain for cases where we know the type at
        compile time (literals, function returns) and can avoid the FV
        round-trip.
        """
        # FV-backed variables: dispatch via runtime tag, no AST guessing
        if (self._USE_FV_LOCALS and isinstance(node, ast.Name)
                and node.id in self.variables
                and node.id not in self._global_vars):
            alloca, type_tag = self.variables[node.id]
            if (self._tag_kind(type_tag) != VKind.CELL
                    and isinstance(alloca.type, ir.PointerType)
                    and alloca.type.pointee is fpy_val):
                fv = self.builder.load(alloca, name=f"{node.id}.fv")
                return self._fv_call_truthy(fv)
        # Dict/list subscript: dispatch via runtime tag from FV getter
        if (isinstance(node, ast.Subscript)
                and not isinstance(node.slice, ast.Slice)
                and (self._is_dict_expr(node.value) or self._is_list_expr(node.value))):
            fv = self._load_or_wrap_fv(node)
            return self._fv_call_truthy(fv)
        # Object attribute: dispatch via runtime tag from obj_get_fv
        if (isinstance(node, ast.Attribute)
                and not (isinstance(node.value, ast.Name)
                         and node.value.id in self._user_classes)):
            fv = self._load_or_wrap_fv(node)
            if fv.type is fpy_val:
                return self._fv_call_truthy(fv)
        if self._is_list_expr(node):
            val = self._emit_expr_value(node)
            length = self._rt_call("list_length", [val])
            return self.builder.icmp_signed("!=", length, ir.Constant(i64, 0))
        if self._is_dict_expr(node):
            val = self._emit_expr_value(node)
            length = self._rt_call("dict_length", [val])
            return self.builder.icmp_signed("!=", length, ir.Constant(i64, 0))
        # __bool__ on user-class objects
        if self._is_obj_expr(node):
            obj_cls = self._infer_object_class(node)
            if obj_cls and self._class_has_method(obj_cls, "__bool__"):
                obj = self._emit_expr_value(node)
                obj = self._ensure_ptr(obj)
                name_ptr = self._make_string_constant("__bool__")
                result = self.builder.call(
                    self.runtime["obj_call_method0"], [obj, name_ptr])
                # __bool__ returns i32 but obj_call_method0 returns i64;
                # upper 32 bits of RAX may contain garbage. Truncate to
                # i32 before comparing to get the actual bool value.
                result_i32 = self.builder.trunc(result, i32)
                return self.builder.icmp_signed(
                    "!=", result_i32, ir.Constant(i32, 0))
        val = self._emit_expr_value(node)
        # FpyValue struct (from bridge method calls, etc.): use fv_truthy
        if (isinstance(val.type, ir.LiteralStructType)
                and val.type == fpy_val):
            return self._fv_call_truthy(val)
        if isinstance(val.type, ir.PointerType):
            # Strings: empty string → False
            null_ptr = ir.Constant(val.type, None)
            is_non_null = self.builder.icmp_unsigned("!=", val, null_ptr)
            length = self._rt_call("str_len", [val])
            has_len = self.builder.icmp_signed("!=", length, ir.Constant(i64, 0))
            return self.builder.and_(is_non_null, has_len)
        return self._truthiness(val)

    def _try_fold_type_compare(self, node: ast.Compare) -> 'ir.Value | None':
        """Fold `type(x) == int` / `type(x) is int` to a compile-time bool.

        Handles single comparisons of the form `type(expr) == <builtin>` or
        `type(expr) is <builtin>`.  When the argument's type can be inferred
        at compile time, folds to a constant True/False.  When the argument
        is FV-typed (runtime tag), emits a tag check instead.
        Returns None if the pattern doesn't match."""
        if len(node.ops) != 1:
            return None
        op = node.ops[0]
        if not isinstance(op, (ast.Eq, ast.NotEq, ast.Is, ast.IsNot)):
            return None
        is_neg = isinstance(op, (ast.NotEq, ast.IsNot))

        # Left side must be type(arg)
        left = node.left
        if not (isinstance(left, ast.Call) and isinstance(left.func, ast.Name)
                and left.func.id == "type" and len(left.args) == 1):
            return None

        # Right side must be a builtin type name
        right = node.comparators[0]
        if not (isinstance(right, ast.Name)
                and right.id in ("int", "float", "str", "bool",
                                 "list", "dict", "set", "tuple",
                                 "type", "complex", "bytes")):
            return None

        _BUILTIN_TO_VKIND = {
            "int": VKind.INT, "float": VKind.FLOAT, "str": VKind.STR,
            "bool": VKind.BOOL, "list": VKind.LIST, "dict": VKind.DICT,
            "set": VKind.SET, "tuple": VKind.TUPLE, "bytes": VKind.BYTES,
            "complex": VKind.COMPLEX,
        }
        target_kind = _BUILTIN_TO_VKIND.get(right.id)
        if target_kind is None:
            return None

        # Infer the type of the argument
        arg = left.args[0]
        arg_vt = self._infer_type_tag(arg, None)
        arg_kind = arg_vt.kind

        # If we can determine the type at compile time, fold to constant
        if arg_kind not in (VKind.UNKNOWN, VKind.FVALUE):
            matches = (arg_kind == target_kind)
            val = matches != is_neg  # XOR with negation
            return ir.Constant(ir.IntType(1), int(val))

        # Runtime fallback: load FV tag and compare with target FPY_TAG
        _KIND_TO_FPY_TAG = {
            VKind.INT: FPY_TAG_INT, VKind.FLOAT: FPY_TAG_FLOAT,
            VKind.STR: FPY_TAG_STR, VKind.BOOL: FPY_TAG_BOOL,
            VKind.LIST: FPY_TAG_LIST, VKind.DICT: FPY_TAG_DICT,
            VKind.SET: FPY_TAG_SET, VKind.TUPLE: FPY_TAG_LIST,
            VKind.BYTES: FPY_TAG_BYTES, VKind.COMPLEX: FPY_TAG_COMPLEX,
        }
        target_fpy_tag = _KIND_TO_FPY_TAG.get(target_kind)
        if target_fpy_tag is None:
            return None

        # Load the FV and check the runtime tag
        if isinstance(arg, ast.Name) and arg.id in self.variables:
            alloca, vt = self.variables[arg.id]
            if (isinstance(alloca.type, ir.PointerType)
                    and alloca.type.pointee is fpy_val):
                fv = self.builder.load(alloca)
                tag = self._fv_tag(fv)
                cmp_op = "!=" if is_neg else "=="
                return self.builder.icmp_unsigned(
                    cmp_op, tag, ir.Constant(i32, target_fpy_tag))

        return None

    def _emit_compare(self, node: ast.Compare) -> ir.Value:
        """Emit a comparison expression. Handles chained comparisons.

        Phase 2: uses TypedValue for left operand to dispatch the correct
        comparison function based on VKind instead of raw LLVM types.
        This fixes bugs where pointer-typed values (sets, dicts, objects)
        would fall through to string comparison."""

        # ---- Compile-time fold: type(x) == <builtin_type> ----
        # Python's `type(x) == int` (or `is`) pattern.  When the left side
        # is a `type(arg)` call and the right side is a builtin type name,
        # we can resolve this at compile time using the inferred VKind of
        # the argument, or at runtime using the FpyValue tag.
        _TYPE_CHECK = self._try_fold_type_compare(node)
        if _TYPE_CHECK is not None:
            return _TYPE_CHECK

        tv_left = self._emit_expr(node.left)
        left = tv_left.val
        result = None

        for op, comparator_node in zip(node.ops, node.comparators):
            # Handle `is`/`is not` specially (identity comparison)
            if isinstance(op, (ast.Is, ast.IsNot)):
                cmp = self._emit_is_compare(op, node.left, comparator_node, node)
            # Handle `in`/`not in` specially
            elif isinstance(op, (ast.In, ast.NotIn)):
                cmp = self._emit_in_compare(op, left, comparator_node, node,
                                                    left_kind=tv_left.vtype.kind)
            else:
                tv_right = self._emit_expr(comparator_node)
                right = tv_right.val
                cmp_left, cmp_right = left, right
                left_kind = tv_left.vtype.kind

                # --- VKind-based fast path dispatch ---

                # NONE comparison: None == None → True; None == <anything> → False.
                # Must be the first check because None is i64(0) and would
                # otherwise match type-specific handlers (STR, LIST, etc.)
                # that dereference the None operand as a null pointer.
                if (left_kind == VKind.NONE or tv_right.vtype.kind == VKind.NONE):
                    if left_kind == VKind.NONE and tv_right.vtype.kind == VKind.NONE:
                        cmp = ir.Constant(ir.IntType(1), 1 if isinstance(op, ast.Eq) else 0)
                    else:
                        cmp = ir.Constant(ir.IntType(1), 1 if isinstance(op, ast.NotEq) else 0)

                # OBJ comparison: dispatch to __eq__/__ne__/__lt__/__le__/__gt__/__ge__
                elif (left_kind == VKind.OBJ
                        and isinstance(op, (ast.Eq, ast.NotEq, ast.Lt,
                                            ast.LtE, ast.Gt, ast.GtE))
                        and isinstance(cmp_left.type, ir.PointerType)):
                    _dunder_map = {
                        ast.Eq: "__eq__", ast.NotEq: "__ne__",
                        ast.Lt: "__lt__", ast.LtE: "__le__",
                        ast.Gt: "__gt__", ast.GtE: "__ge__",
                    }
                    method_name = self._make_string_constant(
                        _dunder_map[type(op)])
                    if isinstance(cmp_right.type, ir.PointerType):
                        right_as_i64 = self.builder.ptrtoint(cmp_right, i64)
                    else:
                        right_as_i64 = cmp_right
                        if isinstance(right_as_i64.type, ir.IntType):
                            if right_as_i64.type.width != 64:
                                right_as_i64 = self.builder.zext(
                                    right_as_i64, i64)
                    result_i64 = self.builder.call(
                        self.runtime["obj_call_method1"],
                        [cmp_left, method_name, right_as_i64])
                    cmp = self.builder.icmp_signed("!=", result_i64, ir.Constant(i64, 0))

                # Cross-type comparison with known VKinds: route through
                # fv_compare when both sides have known, incompatible types
                # (e.g. INT vs LIST, STR vs INT).  Must come before the
                # type-specific paths (LIST, SET, DICT, STR) because those
                # only check left_kind and assume the right side matches.
                elif (isinstance(op, (ast.Eq, ast.NotEq, ast.Lt, ast.LtE,
                                      ast.Gt, ast.GtE))
                        and left_kind != VKind.UNKNOWN
                        and tv_right.vtype.kind != VKind.UNKNOWN
                        and left_kind != tv_right.vtype.kind
                        # INT/FLOAT/BOOL cross-comparison handled below
                        and not ({left_kind, tv_right.vtype.kind}
                                 <= {VKind.INT, VKind.FLOAT, VKind.BOOL})
                        # BIGINT+INT handled by BIGINT path below
                        and not (left_kind == VKind.BIGINT
                                 and tv_right.vtype.kind in
                                 (VKind.INT, VKind.BOOL))
                        and not (tv_right.vtype.kind == VKind.BIGINT
                                 and left_kind in
                                 (VKind.INT, VKind.BOOL))
                        # PYOBJ uses CPython rich comparison (below)
                        and left_kind != VKind.PYOBJ
                        and tv_right.vtype.kind != VKind.PYOBJ
                        # STR↔BYTES uses shared str_compare (below)
                        and not ({left_kind, tv_right.vtype.kind}
                                 <= {VKind.STR, VKind.BYTES})):
                    _cmp_ops = {ast.Eq: 0, ast.NotEq: 1, ast.Lt: 2,
                                ast.LtE: 3, ast.Gt: 4, ast.GtE: 5}
                    l_tag, l_data = self._to_tag_data_ir(
                        cmp_left, node.left)
                    r_tag, r_data = self._to_tag_data_ir(
                        cmp_right, comparator_node)
                    cmp_result = self.builder.call(
                        self.runtime["fv_compare"],
                        [l_tag, l_data, r_tag, r_data,
                         ir.Constant(i32, _cmp_ops[type(op)])])
                    cmp = self.builder.icmp_signed(
                        "!=", cmp_result, ir.Constant(i32, 0))

                # LIST/TUPLE equality
                elif (left_kind in (VKind.LIST, VKind.TUPLE)
                        and isinstance(op, (ast.Eq, ast.NotEq))):
                    eq_result = self._rt_call("list_equal",
                                              [tv_left.as_ptr(self.builder),
                                               tv_right.as_ptr(self.builder)])
                    truthy = self.builder.icmp_signed("!=", eq_result, ir.Constant(i32, 0))
                    if isinstance(op, ast.NotEq):
                        truthy = self.builder.not_(truthy)
                    cmp = truthy

                # LIST/TUPLE lexicographic ordering
                elif (left_kind in (VKind.LIST, VKind.TUPLE)
                        and isinstance(op, (ast.Lt, ast.LtE, ast.Gt, ast.GtE))):
                    cmp_result = self._rt_call("list_compare",
                                               [tv_left.as_ptr(self.builder),
                                                tv_right.as_ptr(self.builder)])
                    zero = ir.Constant(i64, 0)
                    if isinstance(op, ast.Lt):
                        cmp = self.builder.icmp_signed("<", cmp_result, zero)
                    elif isinstance(op, ast.LtE):
                        cmp = self.builder.icmp_signed("<=", cmp_result, zero)
                    elif isinstance(op, ast.Gt):
                        cmp = self.builder.icmp_signed(">", cmp_result, zero)
                    else:
                        cmp = self.builder.icmp_signed(">=", cmp_result, zero)

                # SET equality
                elif (left_kind == VKind.SET
                        and isinstance(op, (ast.Eq, ast.NotEq))):
                    eq_result = self._rt_call("set_equal",
                                              [tv_left.as_ptr(self.builder),
                                               tv_right.as_ptr(self.builder)])
                    truthy = self.builder.icmp_signed("!=", eq_result, ir.Constant(i32, 0))
                    if isinstance(op, ast.NotEq):
                        truthy = self.builder.not_(truthy)
                    cmp = truthy

                # SET subset/superset: <= >= < >
                elif (left_kind == VKind.SET
                        and isinstance(op, (ast.LtE, ast.GtE,
                                            ast.Lt, ast.Gt))):
                    lp = tv_left.as_ptr(self.builder)
                    rp = tv_right.as_ptr(self.builder)
                    if isinstance(op, (ast.LtE, ast.Lt)):
                        # s1 <= s2 → issubset(s1, s2)
                        sub = self._rt_call("set_issubset", [lp, rp])
                    else:
                        # s1 >= s2 → issubset(s2, s1)
                        sub = self._rt_call("set_issubset", [rp, lp])
                    cmp = self.builder.icmp_signed(
                        "!=", sub, ir.Constant(i32, 0))
                    if isinstance(op, (ast.Lt, ast.Gt)):
                        # Proper subset/superset: also require not equal
                        eq = self._rt_call("set_equal", [lp, rp])
                        not_eq = self.builder.icmp_signed(
                            "==", eq, ir.Constant(i32, 0))
                        cmp = self.builder.and_(cmp, not_eq)

                # DICT equality (including defaultdict/Counter)
                elif (left_kind in _DICT_LIKE
                        and isinstance(op, (ast.Eq, ast.NotEq))):
                    eq_result = self._rt_call("dict_equal",
                                              [tv_left.as_ptr(self.builder),
                                               tv_right.as_ptr(self.builder)])
                    truthy = self.builder.icmp_signed("!=", eq_result, ir.Constant(i32, 0))
                    if isinstance(op, ast.NotEq):
                        truthy = self.builder.not_(truthy)
                    cmp = truthy

                # BIGINT comparison
                elif (left_kind == VKind.BIGINT
                        or tv_right.vtype.kind == VKind.BIGINT):
                    # Promote INT operand to BigInt if needed
                    if left_kind == VKind.BIGINT:
                        l_ptr = tv_left.as_ptr(self.builder)
                    else:
                        l_ptr = self.builder.call(
                            self.runtime["bigint_from_i64"],
                            [tv_left.as_i64(self.builder)])
                    if tv_right.vtype.kind == VKind.BIGINT:
                        r_ptr = tv_right.as_ptr(self.builder)
                    else:
                        r_ptr = self.builder.call(
                            self.runtime["bigint_from_i64"],
                            [tv_right.as_i64(self.builder)])
                    cmp_result = self.builder.call(
                        self.runtime["bigint_cmp"], [l_ptr, r_ptr])
                    zero = ir.Constant(i32, 0)
                    if isinstance(op, ast.Eq):
                        cmp = self.builder.icmp_signed("==", cmp_result, zero)
                    elif isinstance(op, ast.NotEq):
                        cmp = self.builder.icmp_signed("!=", cmp_result, zero)
                    elif isinstance(op, ast.Lt):
                        cmp = self.builder.icmp_signed("<", cmp_result, zero)
                    elif isinstance(op, ast.LtE):
                        cmp = self.builder.icmp_signed("<=", cmp_result, zero)
                    elif isinstance(op, ast.Gt):
                        cmp = self.builder.icmp_signed(">", cmp_result, zero)
                    else:
                        cmp = self.builder.icmp_signed(">=", cmp_result, zero)

                # STR comparison (only when we KNOW it's a string, not a generic ptr)
                elif (left_kind == VKind.STR
                        and isinstance(op, (ast.Eq, ast.NotEq, ast.Lt, ast.LtE,
                                            ast.Gt, ast.GtE))):
                    cmp_result = self._rt_call("str_compare",
                                               [tv_left.as_ptr(self.builder),
                                                tv_right.as_ptr(self.builder)])
                    if isinstance(op, ast.Eq):
                        cmp = self.builder.icmp_signed("==", cmp_result, ir.Constant(i64, 0))
                    elif isinstance(op, ast.NotEq):
                        cmp = self.builder.icmp_signed("!=", cmp_result, ir.Constant(i64, 0))
                    elif isinstance(op, ast.Lt):
                        cmp = self.builder.icmp_signed("<", cmp_result, ir.Constant(i64, 0))
                    elif isinstance(op, ast.LtE):
                        cmp = self.builder.icmp_signed("<=", cmp_result, ir.Constant(i64, 0))
                    elif isinstance(op, ast.Gt):
                        cmp = self.builder.icmp_signed(">", cmp_result, ir.Constant(i64, 0))
                    else:
                        cmp = self.builder.icmp_signed(">=", cmp_result, ir.Constant(i64, 0))

                # BYTES comparison: same as STR since bytes are char* internally
                elif ((left_kind == VKind.BYTES or tv_right.vtype.kind == VKind.BYTES)
                        and isinstance(op, (ast.Eq, ast.NotEq))):
                    cmp_result = self._rt_call("str_compare",
                                               [tv_left.as_ptr(self.builder),
                                                tv_right.as_ptr(self.builder)])
                    if isinstance(op, ast.Eq):
                        cmp = self.builder.icmp_signed("==", cmp_result, ir.Constant(i64, 0))
                    else:
                        cmp = self.builder.icmp_signed("!=", cmp_result, ir.Constant(i64, 0))

                # PYOBJ comparison: dispatch to CPython rich comparison.
                # When one side is PYOBJ and the other is native, convert
                # the native side to PyObject* via cpython_to_pyobj first.
                elif ((left_kind == VKind.PYOBJ
                        or tv_right.vtype.kind == VKind.PYOBJ)
                        and isinstance(op, (ast.Eq, ast.NotEq, ast.Lt, ast.LtE,
                                            ast.Gt, ast.GtE))):
                    _cmp_ops = {ast.Eq: 0, ast.NotEq: 1, ast.Lt: 2,
                                ast.LtE: 3, ast.Gt: 4, ast.GtE: 5}
                    # Get left as PyObject*
                    if left_kind == VKind.PYOBJ:
                        left_pyobj = tv_left.as_ptr(self.builder)
                    else:
                        _lt, _ld = self._to_tag_data_ir(cmp_left, node.left)
                        left_pyobj = self.builder.call(
                            self.runtime["cpython_to_pyobj"], [_lt, _ld])
                    # Get right as PyObject*
                    if tv_right.vtype.kind == VKind.PYOBJ:
                        right_pyobj = tv_right.as_ptr(self.builder)
                    else:
                        _rt, _rd = self._to_tag_data_ir(cmp_right, comparator_node)
                        right_pyobj = self.builder.call(
                            self.runtime["cpython_to_pyobj"], [_rt, _rd])
                    cmp_result = self.builder.call(
                        self.runtime["cpython_compare"],
                        [left_pyobj, right_pyobj,
                         ir.Constant(i32, _cmp_ops[type(op)])])
                    cmp = self.builder.icmp_signed("!=", cmp_result,
                                                    ir.Constant(i32, 0))

                # --- Fallback: LLVM-type-based dispatch (old code) ---
                # Catches UNKNOWN-kind pointer comparisons that still need
                # string comparison (legacy code paths not yet on TypedValue).
                elif (isinstance(cmp_left.type, ir.PointerType)
                        and isinstance(cmp_right.type, ir.PointerType)
                        and isinstance(op, (ast.Eq, ast.NotEq))):
                    # Legacy fallback: OBJ with __eq__ not caught above
                    if self._is_obj_expr(node.left) and isinstance(op, ast.Eq):
                        method_name = self._make_string_constant("__eq__")
                        right_as_i64 = self.builder.ptrtoint(cmp_right, i64)
                        result_i64 = self.builder.call(
                            self.runtime["obj_call_method1"],
                            [cmp_left, method_name, right_as_i64])
                        cmp = self.builder.icmp_signed("!=", result_i64, ir.Constant(i64, 0))
                    else:
                        # Assume string comparison for UNKNOWN pointer types
                        cmp_result = self._rt_call("str_compare", [cmp_left, cmp_right])
                        if isinstance(op, ast.Eq):
                            cmp = self.builder.icmp_signed("==", cmp_result, ir.Constant(i64, 0))
                        else:
                            cmp = self.builder.icmp_signed("!=", cmp_result, ir.Constant(i64, 0))

                elif isinstance(cmp_left.type, ir.DoubleType) or isinstance(cmp_right.type, ir.DoubleType):
                    if isinstance(cmp_left.type, ir.IntType):
                        cmp_left = self.builder.sitofp(cmp_left, double)
                    if isinstance(cmp_right.type, ir.IntType):
                        cmp_right = self.builder.sitofp(cmp_right, double)
                    cmp = self._emit_float_compare(op, cmp_left, cmp_right, node)

                # FV locals type mismatch: one side is i64 (compile-time INT
                # but runtime STR from cpython_to_fv), the other is i8* (STR).
                # Convert the i64 to pointer and compare as strings. This
                # only fires for genuine type mismatches — normal same-typed
                # comparisons never reach this path.
                elif (isinstance(cmp_left.type, ir.IntType)
                        and isinstance(cmp_right.type, ir.PointerType)
                        and isinstance(op, (ast.Eq, ast.NotEq,
                                            ast.Lt, ast.LtE, ast.Gt, ast.GtE))):
                    left_as_ptr = self._ensure_ptr(cmp_left)
                    cmp_result = self._rt_call("str_compare",
                                               [left_as_ptr, cmp_right])
                    zero = ir.Constant(i64, 0)
                    if isinstance(op, ast.Eq):
                        cmp = self.builder.icmp_signed("==", cmp_result, zero)
                    elif isinstance(op, ast.NotEq):
                        cmp = self.builder.icmp_signed("!=", cmp_result, zero)
                    elif isinstance(op, ast.Lt):
                        cmp = self.builder.icmp_signed("<", cmp_result, zero)
                    elif isinstance(op, ast.LtE):
                        cmp = self.builder.icmp_signed("<=", cmp_result, zero)
                    elif isinstance(op, ast.Gt):
                        cmp = self.builder.icmp_signed(">", cmp_result, zero)
                    else:
                        cmp = self.builder.icmp_signed(">=", cmp_result, zero)
                elif (isinstance(cmp_left.type, ir.PointerType)
                        and isinstance(cmp_right.type, ir.IntType)
                        and isinstance(op, (ast.Eq, ast.NotEq,
                                            ast.Lt, ast.LtE, ast.Gt, ast.GtE))):
                    right_as_ptr = self._ensure_ptr(cmp_right)
                    cmp_result = self._rt_call("str_compare",
                                               [cmp_left, right_as_ptr])
                    zero = ir.Constant(i64, 0)
                    if isinstance(op, ast.Eq):
                        cmp = self.builder.icmp_signed("==", cmp_result, zero)
                    elif isinstance(op, ast.NotEq):
                        cmp = self.builder.icmp_signed("!=", cmp_result, zero)
                    elif isinstance(op, ast.Lt):
                        cmp = self.builder.icmp_signed("<", cmp_result, zero)
                    elif isinstance(op, ast.LtE):
                        cmp = self.builder.icmp_signed("<=", cmp_result, zero)
                    elif isinstance(op, ast.Gt):
                        cmp = self.builder.icmp_signed(">", cmp_result, zero)
                    else:
                        cmp = self.builder.icmp_signed(">=", cmp_result, zero)

                # FpyValue struct comparison: one or both operands are
                # {i32, i64} with runtime type tags.  Convert the non-FV
                # side to (tag, data) via _to_tag_data_ir and dispatch
                # through the runtime fv_compare.
                elif (isinstance(op, (ast.Eq, ast.NotEq, ast.Lt,
                                      ast.LtE, ast.Gt, ast.GtE))
                        and ((isinstance(cmp_left.type, ir.LiteralStructType)
                              and cmp_left.type == fpy_val)
                             or (isinstance(cmp_right.type, ir.LiteralStructType)
                                 and cmp_right.type == fpy_val))):
                    _cmp_ops = {ast.Eq: 0, ast.NotEq: 1, ast.Lt: 2,
                                ast.LtE: 3, ast.Gt: 4, ast.GtE: 5}
                    l_tag, l_data = self._to_tag_data_ir(
                        cmp_left, node.left)
                    r_tag, r_data = self._to_tag_data_ir(
                        cmp_right, comparator_node)
                    cmp_result = self.builder.call(
                        self.runtime["fv_compare"],
                        [l_tag, l_data, r_tag, r_data,
                         ir.Constant(i32, _cmp_ops[type(op)])])
                    cmp = self.builder.icmp_signed(
                        "!=", cmp_result, ir.Constant(i32, 0))

                # Mixed-type variable comparison: one or both operands come
                # from FV-backed variables with "mixed" type. The raw i64
                # data was extracted by _emit_expr_value, losing the tag.
                # Re-load the full FpyValue and use runtime comparison.
                elif (isinstance(op, (ast.Eq, ast.NotEq, ast.Lt,
                                      ast.LtE, ast.Gt, ast.GtE))
                        and (self._is_mixed_var(node.left)
                             or self._is_mixed_var(comparator_node))):
                    _cmp_ops = {ast.Eq: 0, ast.NotEq: 1, ast.Lt: 2,
                                ast.LtE: 3, ast.Gt: 4, ast.GtE: 5}
                    l_fv = self._load_or_wrap_fv(node.left)
                    r_fv = self._load_or_wrap_fv(comparator_node)
                    l_tag, l_data = self._fv_unpack(l_fv)
                    r_tag, r_data = self._fv_unpack(r_fv)
                    cmp_result = self.builder.call(
                        self.runtime["fv_compare"],
                        [l_tag, l_data, r_tag, r_data,
                         ir.Constant(i32, _cmp_ops[type(op)])])
                    cmp = self.builder.icmp_signed(
                        "!=", cmp_result, ir.Constant(i32, 0))

                else:
                    cmp = self._emit_int_compare(op, cmp_left, cmp_right, node)
                left = right
                tv_left = tv_right

            if result is None:
                result = cmp
            else:
                result = self.builder.and_(result, cmp)

        return result

    def _emit_is_compare(self, op, left_node, right_node, node) -> ir.Value:
        """Emit `is` / `is not` comparison. Supports None and Ellipsis."""
        # Check if comparing to None
        is_none_check = (
            (isinstance(left_node, ast.Constant) and left_node.value is None) or
            (isinstance(right_node, ast.Constant) and right_node.value is None)
        )
        # Check if comparing to Ellipsis
        is_ellipsis = (
            (isinstance(left_node, ast.Constant) and left_node.value is ...) or
            (isinstance(right_node, ast.Constant) and right_node.value is ...)
        )
        # For `x is True` / `x is False` — use value comparison
        is_bool_check = (
            (isinstance(left_node, ast.Constant) and isinstance(left_node.value, bool)) or
            (isinstance(right_node, ast.Constant) and isinstance(right_node.value, bool))
        )
        if is_ellipsis:
            # Ellipsis is a singleton — `x is ...` is always True if x was
            # assigned `...`, but we represent ... as i64(0). For now, just
            # compare values (both ... are i64(0)).
            left = self._emit_expr_value(left_node)
            right = self._emit_expr_value(right_node)
            if isinstance(op, ast.IsNot):
                return self.builder.icmp_signed("!=", left, right)
            return self.builder.icmp_signed("==", left, right)
        if is_bool_check and not is_none_check:
            left = self._emit_expr_value(left_node)
            right = self._emit_expr_value(right_node)
            if isinstance(op, ast.IsNot):
                return self.builder.icmp_signed("!=", left, right)
            return self.builder.icmp_signed("==", left, right)
        if not is_none_check:
            # General 'is' — compare as pointer/value equality
            left = self._emit_expr_value(left_node)
            right = self._emit_expr_value(right_node)
            # Coerce to same type for comparison
            if isinstance(left.type, ir.PointerType) and isinstance(right.type, ir.IntType):
                right = self._ensure_ptr(right)
            elif isinstance(right.type, ir.PointerType) and isinstance(left.type, ir.IntType):
                left = self._ensure_ptr(left)
            if left.type != right.type:
                if isinstance(left.type, ir.PointerType):
                    left = self.builder.ptrtoint(left, i64)
                if isinstance(right.type, ir.PointerType):
                    right = self.builder.ptrtoint(right, i64)
            if isinstance(op, ast.IsNot):
                return self.builder.icmp_signed("!=", left, right)
            return self.builder.icmp_signed("==", left, right)
        # Determine if the non-None side is statically known to be None
        other = left_node if isinstance(right_node, ast.Constant) and right_node.value is None else right_node

        # For FV-backed variables, compare the runtime tag with FPY_TAG_NONE.
        # This handles functions that return None on some paths but not others.
        if (self._USE_FV_LOCALS and isinstance(other, ast.Name)
                and other.id in self.variables
                and other.id not in self._global_vars):
            alloca, _ = self.variables[other.id]
            if (isinstance(alloca.type, ir.PointerType)
                    and alloca.type.pointee is fpy_val):
                fv = self.builder.load(alloca, name=f"{other.id}.fv.isnone")
                tag = self.builder.extract_value(fv, 0, name="is_none.tag")
                if isinstance(op, ast.IsNot):
                    return self.builder.icmp_signed(
                        "!=", tag, ir.Constant(i32, FPY_TAG_NONE))
                return self.builder.icmp_signed(
                    "==", tag, ir.Constant(i32, FPY_TAG_NONE))

        # For Attribute expressions on objects (e.g. `obj.attr is None`),
        # load the full FV via slot read and check the runtime tag. The
        # data-only path in _emit_attr_load would lose the NONE tag.
        if (self._USE_FV_LOCALS
                and isinstance(other, ast.Attribute)
                and self._is_obj_expr(other.value)):
            fv = self._load_or_wrap_fv(other)
            tag = self.builder.extract_value(fv, 0, name="is_none.tag")
            if isinstance(op, ast.IsNot):
                return self.builder.icmp_signed(
                    "!=", tag, ir.Constant(i32, FPY_TAG_NONE))
            return self.builder.icmp_signed(
                "==", tag, ir.Constant(i32, FPY_TAG_NONE))

        # For Call expressions on user functions that may return None
        # (e.g. `func(x) is None`), call via FV path to get the runtime
        # tag.  Without this, the unwrapped return loses the NONE tag.
        if (self._USE_FV_LOCALS
                and isinstance(other, ast.Call)
                and isinstance(other.func, ast.Name)
                and other.func.id in self._user_functions):
            info = self._user_functions[other.func.id]
            if info.uses_fv_abi and info.may_return_none:
                fv = self._emit_user_call_fv(other)
                tag = self.builder.extract_value(fv, 0, name="is_none.tag")
                if isinstance(op, ast.IsNot):
                    return self.builder.icmp_signed(
                        "!=", tag, ir.Constant(i32, FPY_TAG_NONE))
                return self.builder.icmp_signed(
                    "==", tag, ir.Constant(i32, FPY_TAG_NONE))

        # Class variable attribute access: cls.attr is None / ClassName.attr is None
        # Load the pointer from the class var global and compare to null.
        if isinstance(other, ast.Attribute):
            attr_class = None
            if (isinstance(other.value, ast.Name)
                    and other.value.id in self._user_classes):
                attr_class = other.value.id
            elif (isinstance(other.value, ast.Name)
                  and self._current_class is not None
                  and other.value.id in self.variables
                  and self._tag_kind(self.variables[other.value.id][1]) == VKind.CLS):
                attr_class = self._current_class
            if attr_class:
                key = (attr_class, other.attr)
                if key in getattr(self, "_class_var_globals", {}):
                    gvar, gtag = self._class_var_globals[key]
                    val = self.builder.load(gvar)
                    if isinstance(val.type, ir.PointerType):
                        cmp = self.builder.icmp_unsigned(
                            "==", val, ir.Constant(val.type, None))
                    else:
                        cmp = self.builder.icmp_signed(
                            "==", val, ir.Constant(val.type, 0))
                    if isinstance(op, ast.IsNot):
                        return self.builder.not_(cmp)
                    return cmp

        is_other_none = False
        if isinstance(other, ast.Constant) and other.value is None:
            is_other_none = True
        elif isinstance(other, ast.Name) and other.id in self.variables:
            if self._var_kind(other.id) == VKind.NONE:
                is_other_none = True
        val = 1 if is_other_none else 0
        if isinstance(op, ast.IsNot):
            val = 1 - val
        return ir.Constant(ir.IntType(1), val)

    def _emit_in_compare(self, op, left_val, container_node, node,
                          *, left_kind=None) -> ir.Value:
        """Emit `in` / `not in` comparison.

        Phase 2: uses VKind pre-inference for container type dispatch.
        Infers the container type from AST/variable tags before emitting,
        then dispatches to the right containment check.

        left_kind: optional VKind of the left operand.  When provided,
        used to disambiguate FV-backed string variables (stored as i64)
        from true int values in dict key lookups."""
        # Pre-infer container type from AST without emitting
        c_vt = self._infer_type_tag(container_node, None)
        c_kind = c_vt.kind

        # For sets: O(1) hash lookup via dict-backed set
        if c_kind == VKind.SET or self._is_set_expr(container_node):
            container = self._emit_expr_value(container_node)
            container = self._ensure_ptr(container)
            tag, data = self._bare_to_tag_data(left_val, None)
            result = self.builder.call(
                self.runtime["set_contains_fv"],
                [container, ir.Constant(i32, tag), data])
            result = self.builder.trunc(result, ir.IntType(1))
            if isinstance(op, ast.NotIn):
                result = self.builder.not_(result)
            return result
        # For list/tuple: iterate and compare
        if (c_kind in (VKind.LIST, VKind.TUPLE)
                or self._is_list_expr(container_node)
                or self._is_tuple_expr(container_node)
                or isinstance(container_node, (ast.List, ast.Tuple))):
            container = self._emit_expr_value(container_node)
            length = self._rt_call("list_length", [container])

            # Linear search
            result_alloca = self.builder.alloca(ir.IntType(1), name="in.result")
            self.builder.store(ir.Constant(ir.IntType(1), 0), result_alloca)

            idx_alloca = self.builder.alloca(i64, name="in.idx")
            self.builder.store(ir.Constant(i64, 0), idx_alloca)

            cond_block = self._new_block("in.cond")
            body_block = self._new_block("in.body")
            end_block = self._new_block("in.end")

            self.builder.branch(cond_block)

            self.builder.position_at_end(cond_block)
            idx = self.builder.load(idx_alloca)
            cond = self.builder.icmp_signed("<", idx, length)
            self.builder.cbranch(cond, body_block, end_block)

            self.builder.position_at_end(body_block)
            idx = self.builder.load(idx_alloca)
            # Use the FV getter once; unwrap based on the static elem_type
            elem_type = self._get_list_elem_type(container_node)
            if elem_type.kind == VKind.STR or isinstance(left_val.type, ir.PointerType):
                elem = self._list_get_as_bare(container, idx, "str")
                cmp_result = self._rt_call("str_compare", [left_val, elem])
                eq = self.builder.icmp_signed("==", cmp_result, ir.Constant(i64, 0))
            elif elem_type.kind == VKind.FLOAT or isinstance(left_val.type, ir.DoubleType):
                elem = self._list_get_as_bare(container, idx, "float")
                cmp_left = left_val
                if isinstance(cmp_left.type, ir.IntType):
                    cmp_left = self.builder.sitofp(cmp_left, double)
                eq = self.builder.fcmp_ordered("==", cmp_left, elem)
            else:
                elem = self._list_get_as_bare(container, idx, "int")
                eq = self.builder.icmp_signed("==", left_val, elem)
            found_block = self._new_block("in.found")
            next_block = self._new_block("in.next")
            self.builder.cbranch(eq, found_block, next_block)

            self.builder.position_at_end(found_block)
            self.builder.store(ir.Constant(ir.IntType(1), 1), result_alloca)
            self.builder.branch(end_block)

            self.builder.position_at_end(next_block)
            idx = self.builder.load(idx_alloca)
            self.builder.store(self.builder.add(idx, ir.Constant(i64, 1)), idx_alloca)
            self.builder.branch(cond_block)

            self.builder.position_at_end(end_block)
            result = self.builder.load(result_alloca)
            if isinstance(op, ast.NotIn):
                result = self.builder.not_(result)
            return result

        # ChainMap 'in': "key" in cm
        if c_kind == VKind.CHAINMAP or self._is_chainmap_expr(container_node):
            container = self._emit_expr_value(container_node)
            container = self._ensure_ptr(container)
            left_val = self._ensure_ptr(left_val)
            result = self.builder.call(
                self.runtime["chainmap_contains"], [container, left_val])
            result_i1 = self.builder.icmp_signed("!=", result, ir.Constant(i32, 0))
            if isinstance(op, ast.NotIn):
                result_i1 = self.builder.not_(result_i1)
            return result_i1

        # Dict 'in': "key" in dict/defaultdict/Counter
        if c_kind in _DICT_LIKE or self._is_dict_expr(container_node):
            container = self._emit_expr_value(container_node)
            # Ensure container is i8* (global dicts may be stored as i64)
            container = self._ensure_ptr(container)
            # Determine whether the left value is actually a string.
            # FV-backed string variables are loaded as i64 (IntType), but
            # they must be routed through dict_has_key (string hash table),
            # not dict_has_int_key.  Use left_kind from the caller when
            # available; fall back to AST-level inference on node.left.
            left_is_str = (left_kind == VKind.STR)
            if not left_is_str and left_kind is None:
                # Fallback: check AST for string literals / string variables
                l_vt = self._infer_type_tag(node.left, None)
                if l_vt.kind == VKind.STR:
                    left_is_str = True

            # Tuple/list key: use generic FpyValue-keyed contains
            _left_is_tuple = (isinstance(node.left, (ast.Tuple, ast.List))
                              or (isinstance(node.left, ast.Name)
                                  and node.left.id in self.variables
                                  and self._var_kind(node.left.id)
                                  in (VKind.LIST, VKind.TUPLE)))
            if _left_is_tuple:
                kt, kd = self._bare_to_tag_data(left_val, node.left)
                if not isinstance(kd, ir.Constant) and isinstance(kd.type, ir.PointerType):
                    kd = self.builder.ptrtoint(kd, i64)
                result = self.builder.call(
                    self.runtime["dict_has_kv_key"],
                    [container, ir.Constant(i32, kt), kd])
            elif left_is_str:
                # String key — convert i64 → i8* if needed
                left_val = self._ensure_ptr(left_val)
                result = self.builder.call(
                    self.runtime["dict_has_key"], [container, left_val])
            elif isinstance(left_val.type, ir.IntType):
                result = self.builder.call(
                    self.runtime["dict_has_int_key"], [container, left_val])
            else:
                if not isinstance(left_val.type, ir.PointerType):
                    left_val = self._ensure_ptr(left_val)
                result = self.builder.call(
                    self.runtime["dict_has_key"], [container, left_val])
            result_i1 = self.builder.icmp_signed("!=", result, ir.Constant(i32, 0))
            if isinstance(op, ast.NotIn):
                result_i1 = self.builder.not_(result_i1)
            return result_i1

        # MIXED/FVALUE container: runtime dispatch via fv_contains.
        # The container holds a runtime-tagged FpyValue — the actual
        # type (str, list, dict, …) is only known at runtime.
        # Handles both Name variables and general expressions (e.g.
        # subscript results like user["scores"]).
        if c_kind in (VKind.MIXED, VKind.FVALUE):
            fv = None
            if isinstance(container_node, ast.Name):
                fv = self._load_fv_raw(container_node.id)
            if fv is None:
                # General expression: evaluate and check for fpy_val
                fv = self._emit_expr_value(container_node)
                if not (isinstance(fv.type, ir.LiteralStructType)
                        and fv.type == fpy_val):
                    fv = self._wrap_bare_to_fv(fv, ValueType(VKind.FVALUE))
            c_tag = self._fv_tag(fv)
            c_data = self._fv_data_i64(fv)
            v_tag, v_data = self._to_tag_data_ir(left_val, node.left
                                                  if hasattr(node, 'left')
                                                  else None)
            result_i32 = self.builder.call(
                self.runtime["fv_contains"],
                [c_tag, c_data, v_tag, v_data])
            result = self.builder.icmp_signed(
                "!=", result_i32, ir.Constant(i32, 0))
            if isinstance(op, ast.NotIn):
                result = self.builder.not_(result)
            return result

        # String 'in': "x" in "hello"
        if c_kind == VKind.STR:
            container = self._emit_expr_value(container_node)
            result = self._rt_call("str_contains", [container, left_val])
            result_i1 = self.builder.icmp_signed("!=", result, ir.Constant(i32, 0))
            if isinstance(op, ast.NotIn):
                result_i1 = self.builder.not_(result_i1)
            return result_i1

        # pyobj-tagged container: route through CPython bridge
        # Must come before legacy pointer fallback, because pyobj containers
        # are also raw pointers but need CPython __contains__, not str_contains.
        if (isinstance(container_node, ast.Name)
                and container_node.id in self.variables
                and self._var_kind(container_node.id) == VKind.PYOBJ):
            container = self._load_variable(container_node.id, container_node)
            container = self._ensure_ptr(container)
            # Use CPython's __contains__ via bridge
            contains_name = self._make_string_constant("__contains__")
            method = self.builder.call(
                self.runtime["cpython_getattr"], [container, contains_name])
            tag, data = self._bare_to_tag_data(left_val, None)
            out_tag = self._create_entry_alloca(i32, "pyin.tag")
            out_data = self._create_entry_alloca(i64, "pyin.data")
            self.builder.call(self.runtime["cpython_call1"],
                              [method, ir.Constant(i32, tag), data,
                               out_tag, out_data])
            result = self.builder.load(out_data)
            result_i1 = self.builder.icmp_signed(
                "!=", result, ir.Constant(i64, 0))
            if isinstance(op, ast.NotIn):
                result_i1 = self.builder.not_(result_i1)
            return result_i1

        # __contains__ on user-class objects — must come before the legacy
        # string fallback because OBJ values are also pointers.
        if c_kind == VKind.OBJ or self._is_obj_expr(container_node):
            container = self._emit_expr_value(container_node)
            container = self._ensure_ptr(container)
            if isinstance(left_val.type, ir.PointerType):
                arg = self.builder.ptrtoint(left_val, i64)
            elif isinstance(left_val.type, ir.DoubleType):
                arg = self.builder.bitcast(left_val, i64)
            elif isinstance(left_val.type, ir.IntType) and left_val.type.width != 64:
                arg = self.builder.zext(left_val, i64)
            else:
                arg = left_val
            name_ptr = self._make_string_constant("__contains__")
            result = self.builder.call(
                self.runtime["obj_call_method1"],
                [container, name_ptr, arg])
            result_i1 = self.builder.icmp_signed(
                "!=", result, ir.Constant(i64, 0))
            if isinstance(op, ast.NotIn):
                result_i1 = self.builder.not_(result_i1)
            return result_i1

        # Legacy fallback: string 'in' for unknown pointer types
        container = self._emit_expr_value(container_node)
        if isinstance(container.type, ir.PointerType) and isinstance(left_val.type, ir.PointerType):
            result = self._rt_call("str_contains", [container, left_val])
            result_i1 = self.builder.icmp_signed("!=", result, ir.Constant(i32, 0))
            if isinstance(op, ast.NotIn):
                result_i1 = self.builder.not_(result_i1)
            return result_i1

        # Fallback: use CPython __contains__ via bridge
        container = self._emit_expr_value(container_node)
        container = self._ensure_ptr(container)
        tag, data = self._bare_to_tag_data(left_val, None)
        contains = self._make_string_constant("__contains__")
        callable_ptr = self.builder.call(
            self.runtime["cpython_getattr"], [container, contains])
        out_tag = self._create_entry_alloca(i32, "in.tag")
        out_data = self._create_entry_alloca(i64, "in.data")
        self.builder.call(self.runtime["cpython_call1"],
                          [callable_ptr, ir.Constant(i32, tag), data,
                           out_tag, out_data])
        result = self.builder.load(out_data)
        result_i1 = self.builder.icmp_signed("!=", result, ir.Constant(i64, 0))
        if isinstance(op, ast.NotIn):
            result_i1 = self.builder.not_(result_i1)
        return result_i1

    def _emit_int_compare(
        self, op: ast.cmpop, left: ir.Value, right: ir.Value, node: ast.AST
    ) -> ir.Value:
        ops = {
            ast.Lt: "<", ast.LtE: "<=", ast.Gt: ">", ast.GtE: ">=",
            ast.Eq: "==", ast.NotEq: "!=",
        }
        op_str = ops.get(type(op))
        if op_str is None:
            return self._bridge_fallback_expr(node, f"unsupported comparison: {type(op).__name__}")
        return self.builder.icmp_signed(op_str, left, right)

    def _emit_float_compare(
        self, op: ast.cmpop, left: ir.Value, right: ir.Value, node: ast.AST
    ) -> ir.Value:
        ops = {
            ast.Lt: "<", ast.LtE: "<=", ast.Gt: ">", ast.GtE: ">=",
            ast.Eq: "==", ast.NotEq: "!=",
        }
        op_str = ops.get(type(op))
        if op_str is None:
            return self._bridge_fallback_expr(node, f"unsupported comparison: {type(op).__name__}")
        return self.builder.fcmp_ordered(op_str, left, right)

    def _emit_boolop(self, node: ast.BoolOp) -> ir.Value:
        """Emit short-circuit boolean operations (and, or)."""
        if isinstance(node.op, ast.And):
            return self._emit_short_circuit_and(node.values)
        elif isinstance(node.op, ast.Or):
            return self._emit_short_circuit_or(node.values)
        else:
            return self._bridge_fallback_expr(node, f"unsupported bool op: {type(node.op).__name__}")

    def _emit_short_circuit_and(self, values: list[ast.expr]) -> ir.Value:
        """Emit short-circuit AND — returns the operand value, not a bool.

        Python: `a and b` returns `a` if `a` is falsy, else `b`.
        """
        # Determine the common result type from all operands
        result_type = self._common_boolop_type(values)
        result_alloca = self._create_entry_alloca(result_type, "and.result")
        merge_block = self._new_block("and.end")

        for i, val_node in enumerate(values):
            val = self._emit_expr_value(val_node)
            if i < len(values) - 1:
                # Test truthiness BEFORE coercion so the original type
                # (pointer vs int) is preserved. Coercing a list pointer
                # to i64 via ptrtoint always yields non-zero (truthy),
                # which breaks empty-list semantics.
                is_list = self._is_list_expr(val_node)
                truthy = self._value_truthiness(val, is_list=is_list)
            coerced = self._coerce_to_type(val, result_type)
            self.builder.store(coerced, result_alloca)
            if i < len(values) - 1:
                next_block = self._new_block("and.next")
                # If truthy, continue; else short-circuit with current value
                self.builder.cbranch(truthy, next_block, merge_block)
                self.builder.position_at_end(next_block)
            else:
                self.builder.branch(merge_block)

        self.builder.position_at_end(merge_block)
        return self.builder.load(result_alloca)

    def _emit_short_circuit_or(self, values: list[ast.expr]) -> ir.Value:
        """Emit short-circuit OR — returns the operand value, not a bool.

        Python: `a or b` returns `a` if `a` is truthy, else `b`.
        """
        result_type = self._common_boolop_type(values)
        result_alloca = self._create_entry_alloca(result_type, "or.result")
        merge_block = self._new_block("or.end")

        for i, val_node in enumerate(values):
            val = self._emit_expr_value(val_node)
            if i < len(values) - 1:
                # Test truthiness BEFORE coercion (see _emit_short_circuit_and).
                is_list = self._is_list_expr(val_node)
                truthy = self._value_truthiness(val, is_list=is_list)
            coerced = self._coerce_to_type(val, result_type)
            self.builder.store(coerced, result_alloca)
            if i < len(values) - 1:
                next_block = self._new_block("or.next")
                # If truthy, short-circuit; else continue
                self.builder.cbranch(truthy, merge_block, next_block)
                self.builder.position_at_end(next_block)
            else:
                self.builder.branch(merge_block)

        self.builder.position_at_end(merge_block)
        return self.builder.load(result_alloca)

    def _common_boolop_type(self, values: list[ast.expr]) -> ir.Type:
        """Determine a common LLVM type for boolop operands."""
        has_str = False
        has_float = False
        has_int = False
        has_non_bool = False
        for v in values:
            if isinstance(v, ast.Constant):
                if isinstance(v.value, bool):
                    pass  # bool only — keep as i32
                elif isinstance(v.value, str):
                    has_str = True
                    has_non_bool = True
                elif isinstance(v.value, float):
                    has_float = True
                    has_non_bool = True
                elif isinstance(v.value, int):
                    has_int = True
                    has_non_bool = True
            elif isinstance(v, ast.Name) and v.id in self.variables:
                kind = self._var_kind(v.id)
                has_non_bool = True
                if kind == VKind.STR:
                    has_str = True
                elif kind == VKind.FLOAT:
                    has_float = True
                elif kind in (VKind.LIST, VKind.DICT):
                    has_str = True  # pointer type
                else:
                    has_int = True
            elif isinstance(v, ast.JoinedStr):
                has_str = True
                has_non_bool = True
            elif isinstance(v, ast.Compare):
                pass  # comparison returns bool
            elif isinstance(v, ast.BoolOp):
                pass  # nested and/or returns bool
            elif (isinstance(v, ast.Call)
                    and self._call_returns_bool(v)):
                pass  # method/function known to return bool
            else:
                has_int = True
                has_non_bool = True
        # If all operands are bool, keep i32 so prints as True/False
        if not has_non_bool:
            return i32
        if has_str:
            return i8_ptr
        if has_float:
            return double
        return i64

    def _call_returns_bool(self, node: ast.Call) -> bool:
        """Check if a Call AST node is known to return a boolean.

        Handles:
        - User class method calls (obj.method) whose body only returns
          comparisons or boolean operations
        - User function calls whose body only returns comparisons/boolops
        - Built-in bool-returning functions: isinstance, hasattr, callable,
          any, all, str.startswith, str.endswith, etc.
        """
        # Method call: obj.method(...)
        if isinstance(node.func, ast.Attribute):
            method_name = node.func.attr
            # Built-in bool-returning string methods
            if method_name in ("startswith", "endswith", "isdigit",
                               "isalpha", "isalnum", "isspace",
                               "isupper", "islower", "istitle"):
                return True
            # User class method: check method AST
            obj_cls = self._infer_object_class(node.func.value)
            if obj_cls:
                ci = self._user_classes.get(obj_cls)
                if ci and ci.method_asts and method_name in ci.method_asts:
                    return self._ast_returns_bool(ci.method_asts[method_name])
            else:
                # Object class unknown (e.g. parameter) — check if ALL
                # classes that define this method return bool.
                _all_bool = False
                for _cn, _ci in self._user_classes.items():
                    if _ci.method_asts and method_name in _ci.method_asts:
                        if self._ast_returns_bool(_ci.method_asts[method_name]):
                            _all_bool = True
                        else:
                            _all_bool = False
                            break
                if _all_bool:
                    return True
            return False
        # Function call: func(...)
        if isinstance(node.func, ast.Name):
            fname = node.func.id
            # Built-in bool-returning functions
            if fname in ("isinstance", "hasattr", "callable",
                         "any", "all", "bool"):
                return True
            # User function: check AST
            _func_asts = getattr(self, '_csa_func_asts', {})
            if fname in _func_asts:
                return self._ast_returns_bool(_func_asts[fname])
        return False

    def _ast_returns_bool(self, func_def: ast.FunctionDef) -> bool:
        """Check if a function/method AST only returns boolean expressions."""
        found_return = False
        for node in ast.walk(func_def):
            if isinstance(node, ast.Return) and node.value is not None:
                found_return = True
                if not self._expr_is_bool_ast(node.value):
                    return False
        return found_return

    def _expr_is_bool_ast(self, node: ast.expr) -> bool:
        """Check if an AST expression is known to produce a boolean."""
        if isinstance(node, ast.Compare):
            return True
        if isinstance(node, ast.BoolOp):
            return all(self._expr_is_bool_ast(v) for v in node.values)
        if isinstance(node, ast.UnaryOp) and isinstance(node.op, ast.Not):
            return True
        if isinstance(node, ast.Constant) and isinstance(node.value, bool):
            return True
        if isinstance(node, ast.Call):
            return self._call_returns_bool(node)
        return False

    def _value_truthiness(self, value: ir.Value, *, is_list: bool = False) -> ir.Value:
        """Return i1 indicating whether the value is truthy.

        When *is_list* is True the pointer is treated as a list (uses
        list_length) rather than as a string (str_len).
        """
        if isinstance(value.type, ir.IntType):
            return self.builder.icmp_signed("!=", value, ir.Constant(value.type, 0))
        if isinstance(value.type, ir.DoubleType):
            return self.builder.fcmp_ordered("!=", value, ir.Constant(double, 0.0))
        if isinstance(value.type, ir.PointerType):
            if is_list:
                length = self._rt_call("list_length", [value])
            else:
                # Empty string is falsy; also check non-null pointer
                length = self._rt_call("str_len", [value])
            return self.builder.icmp_signed("!=", length, ir.Constant(i64, 0))
        # FpyValue {i32, i64}: use fv_truthy runtime call
        if (isinstance(value.type, ir.LiteralStructType)
                and len(value.type.elements) == 2
                and isinstance(value.type.elements[0], ir.IntType)
                and value.type.elements[0].width == 32
                and isinstance(value.type.elements[1], ir.IntType)
                and value.type.elements[1].width == 64):
            tag = self.builder.extract_value(value, 0, "fv.tag")
            data = self.builder.extract_value(value, 1, "fv.data")
            truthy = self.builder.call(self.runtime["fv_truthy"],
                                        [tag, data])
            return self.builder.icmp_signed("!=", truthy,
                                             ir.Constant(i32, 0))
        return ir.Constant(ir.IntType(1), 0)

    def _try_indirect_func_call(self, node: ast.Call) -> ir.Value | None:
        """Try to call a variable as a function pointer (indirect call).

        When a user function is passed as an argument (e.g., apply(add, x, y)),
        the parameter holds the function's raw pointer as i64. This method
        loads that pointer, casts it to the function's actual calling convention,
        and calls it. Returns None if not applicable."""
        if not isinstance(node.func, ast.Name):
            return None
        name = node.func.id
        if name not in self.variables:
            return None
        # Check if we know what function this might be (from _param_func_map)
        # to determine the right calling convention
        resolved = self._resolve_func_alias(name)
        info = self._user_functions.get(resolved)
        # Determine calling convention. Only proceed if we KNOW the ABI.
        # If we can't determine it, return None to let closure call handle it.
        if info is not None:
            uses_fv = info.uses_fv_abi
        else:
            # Check _param_func_targets for this parameter's known targets
            uses_fv = None  # unknown
            current_fn = getattr(self, '_current_func_name', None)
            current_fn_info = self._user_functions.get(current_fn) if current_fn else None
            if current_fn and current_fn_info:
                pidx = None
                for i, arg in enumerate(current_fn_info.func.args):
                    if arg.name == name:
                        pidx = i
                        break
                if pidx is not None:
                    targets = getattr(self, '_param_func_targets', {})
                    key = (current_fn, pidx)
                    if key in targets:
                        # All targets must agree on ABI
                        abis = set()
                        for target in targets[key]:
                            if target in self._user_functions:
                                abis.add(self._user_functions[target].uses_fv_abi)
                        if len(abis) == 1:
                            uses_fv = abis.pop()
            if uses_fv is None:
                return None  # can't determine ABI — let closure call handle it

        # Load the function pointer from the variable
        func_ptr_i64 = self._load_variable(name, node)
        if not isinstance(func_ptr_i64.type, ir.IntType):
            return None

        n_args = len(node.args)

        if uses_fv:
            # FV-ABI: {i32, i64}(({i32, i64})*)
            fv_func_type = ir.FunctionType(fpy_val, [fpy_val] * n_args)
            func_ptr = self.builder.inttoptr(func_ptr_i64,
                                              ir.PointerType(fv_func_type))
            fv_args = []
            for arg_node in node.args:
                tv = self._emit_expr(arg_node)
                fv_args.append(tv.as_fv(self.builder))
            result = self.builder.call(func_ptr, fv_args)
            return self.builder.extract_value(result, 1)
        else:
            # i64-ABI (lambdas, simple functions): i64(i64, i64, ...)
            i64_func_type = ir.FunctionType(i64, [i64] * n_args)
            func_ptr = self.builder.inttoptr(func_ptr_i64,
                                              ir.PointerType(i64_func_type))
            i64_args = []
            for arg_node in node.args:
                val = self._emit_expr_value(arg_node)
                if isinstance(val.type, ir.PointerType):
                    val = self.builder.ptrtoint(val, i64)
                elif isinstance(val.type, ir.LiteralStructType):
                    val = self.builder.extract_value(val, 1)
                elif isinstance(val.type, ir.IntType) and val.type.width != 64:
                    val = self.builder.zext(val, i64)
                i64_args.append(val)
            return self.builder.call(func_ptr, i64_args)

    def _iter_class_chain(self, cls_name: str):
        """Yield class names in the inheritance chain (cls, parent, grandparent...)."""
        while cls_name and cls_name in self._user_classes:
            yield cls_name
            cls_name = self._user_classes[cls_name].parent_name

    def _resolve_func_alias(self, name: str) -> str:
        """Resolve function aliases: if name is an alias for a user function,
        return the original function name. Follows chains (g=f, f=add → add).
        Returns name unchanged if not an alias."""
        seen = set()
        while name in self._func_aliases and name not in seen:
            seen.add(name)
            name = self._func_aliases[name]
        return name

    def _rewrite_bound_method(self, node: ast.Call) -> ast.Call | None:
        """If node is a call through a bound-method alias (e.g. f = lst.pop;
        f(0)), rewrite it to lst.pop(0).  Returns the new AST node or None."""
        if not isinstance(node.func, ast.Name):
            return None
        alias = node.func.id
        if alias not in self._bound_method_aliases:
            return None
        obj_name, method_name = self._bound_method_aliases[alias]
        # Build an equivalent ast.Call: obj.method(args...)
        new_func = ast.Attribute(
            value=ast.Name(id=obj_name, ctx=ast.Load()),
            attr=method_name,
            ctx=ast.Load(),
        )
        ast.copy_location(new_func, node.func)
        ast.copy_location(new_func.value, node.func)
        new_call = ast.Call(
            func=new_func,
            args=node.args,
            keywords=node.keywords,
        )
        ast.copy_location(new_call, node)
        return new_call

    def _emit_call(self, node: ast.Call) -> None:
        """Emit a function call (as a statement — discard return value)."""
        # Rewrite bound-method aliases: f = lst.pop → f(0) becomes lst.pop(0)
        _bm_rewrite = self._rewrite_bound_method(node)
        if _bm_rewrite is not None:
            node = _bm_rewrite
        if isinstance(node.func, ast.Name):
            name = self._resolve_func_alias(node.func.id)
            if name == "print":
                self._emit_print(node)
                return
            # Builtin functions that modify state (handled in _emit_call_expr)
            elif name in ("setattr", "delattr"):
                self._emit_call_expr(node)
                return
            # Check if it's a closure variable or callable function pointer
            elif name in self.variables:
                _vk = self._var_kind(name)
                if _vk == VKind.OBJ:
                    # OBJ variable: check for __call__ method before
                    # falling through to closure call (which would crash).
                    _call_cls = self._obj_var_class.get(name)
                    if _call_cls and self._class_has_method(_call_cls, "__call__"):
                        self._emit_call_expr(node)
                        return
                if _vk in (VKind.CLOSURE, VKind.FVALUE,
                           VKind.MIXED, VKind.OBJ):
                    self._emit_closure_call(node)
                    return
            # Module-level pyobj from-imports (e.g. Template, Context from
            # `from django.template import Context, Template`) accessible
            # inside functions without explicit `global` declaration.
            bridge_imports = getattr(self, '_bridge_imports', {})
            if name not in self.variables and name in bridge_imports:
                mod, attr = bridge_imports[name]
                mod_ptr = self.builder.call(
                    self.runtime["cpython_import"],
                    [self._make_string_constant(mod)])
                func_ptr = self.builder.call(
                    self.runtime["cpython_getattr"],
                    [mod_ptr, self._make_string_constant(attr)])
                self._emit_cpython_call_with_ptr(func_ptr, node)
                return
            # Singledispatch: emit the dispatch switch
            if name in self._singledispatch and node.args:
                self._emit_singledispatch_call(node, name)
                return
            elif name in self._user_functions:
                self._emit_user_call(node)
                return
            elif name in self._user_classes:
                self._emit_constructor(node)
                return
            # Builtin dispatch via registry (mirrors _emit_call_expr).
            # Without this, builtins used as bare statements (next(c),
            # iter(x), etc.) fall through to the CPython bridge instead
            # of using native handlers like _emit_builtin_next.
            handler_name = self._BUILTIN_DISPATCH.get(name)
            if handler_name:
                getattr(self, handler_name)(node)
                return
        if isinstance(node.func, ast.Attribute):
            # Nested class constructor: Outer.Inner(args)
            if (isinstance(node.func.value, ast.Name)
                    and node.func.value.id in self._user_classes
                    and node.func.attr in self._user_classes):
                synth = ast.Call(
                    func=ast.Name(id=node.func.attr, ctx=ast.Load()),
                    args=node.args, keywords=node.keywords)
                self._emit_constructor(synth)
                return
            # Native module call (asyncio.run, json.dumps, etc.)
            if isinstance(node.func.value, ast.Name):
                _nm = node.func.value.id
                _is_native = ((self._has_var(_nm)
                              and self._var_kind(_nm) == VKind.PYOBJ)
                             or _nm in getattr(self, '_native_modules', set()))
                if _is_native:
                    result = self._emit_native_module_call(
                        _nm, node.func.attr, node)
                    if result is not None:
                        return
            # Check if receiver is a CPython module/object (pyobj-tagged)
            # Handles arbitrary chain depth: User.objects.filter(...).count()
            if self._is_pyobj_receiver(node.func.value):
                self._emit_cpython_method_call(node)
                return
            # Mixed-type list subscript method: b[1].append(5) where b
            # is list:mixed. The element at index 1 may be a nested list
            # (tag LIST) — get it via list_get_fv and dispatch the method
            # on the inner container. This preserves shared references
            # from copy.copy() shallow copies.
            if (isinstance(node.func.value, ast.Subscript)
                    and self._is_list_expr(node.func.value.value)
                    and self._get_list_elem_type(
                        node.func.value.value).kind == VKind.MIXED):
                self._emit_mixed_elem_method(node)
                return
            self._emit_method_call(node)
            return
        # Call-on-Call as statement: f()(5), c()()(), C()(args), etc.
        # Delegate to _emit_call_expr which has the call-on-call handler.
        if isinstance(node.func, ast.Call):
            self._emit_call_expr(node)
            return
        # Check for weakref dereference used as statement: r()
        if (isinstance(node.func, ast.Name)
                and node.func.id in getattr(self, '_weakref_vars', set())):
            self._emit_weakref_deref(node)
            return
        # Check for direct pyobj call: func(args) where func is pyobj-tagged
        if (isinstance(node.func, ast.Name)
                and node.func.id in self.variables
                and self._var_kind(node.func.id) == VKind.PYOBJ):
            self._emit_cpython_direct_call(node)
            return
        # Try indirect function pointer call for function-valued variables
        if isinstance(node.func, ast.Name) and node.func.id in self.variables:
            result = self._try_indirect_func_call(node)
            if result is not None:
                return
            self._emit_closure_call(node)
            return
        # exec/eval as statements — route through our locals-aware handlers
        if isinstance(node.func, ast.Name) and node.func.id == "exec":
            if len(node.args) >= 1:
                # Compile-time exec: literal string → parse and compile inline
                if (isinstance(node.args[0], ast.Constant)
                        and isinstance(node.args[0].value, str)):
                    self._compile_exec_literal(node.args[0].value, node)
                    return
                # Dynamic exec: route through CPython bridge
                locals_dict = self._emit_locals_dict()
                arg = self._emit_expr_value(node.args[0])
                if isinstance(arg.type, ir.PointerType):
                    code_ptr = arg
                elif isinstance(arg.type, ir.IntType):
                    code_ptr = self._ensure_ptr(arg)
                else:
                    code_ptr = self._ensure_ptr(arg)
                self.builder.call(self.runtime["cpython_exec_locals"],
                                  [code_ptr, locals_dict])
                return
        if isinstance(node.func, ast.Name) and node.func.id == "eval":
            # eval() used as a statement (return value discarded)
            self._emit_call_expr(node)
            return
        # CPython bridge fallback for builtin calls used as statements
        # (e.g. next(gen), iter(x), etc.)
        if isinstance(node.func, ast.Name):
            name = node.func.id
            if (name not in self._user_functions
                    and name not in self._user_classes
                    and name not in self.variables
                    and name not in getattr(self, '_bridge_imports', {})):
                builtin_name = self._make_string_constant("builtins")
                builtins_mod = self.builder.call(
                    self.runtime["cpython_import"], [builtin_name])
                func_name = self._make_string_constant(name)
                callable_ptr = self.builder.call(
                    self.runtime["cpython_getattr"],
                    [builtins_mod, func_name])
                out_tag = self._create_entry_alloca(i32, "pyblt.tag")
                out_data = self._create_entry_alloca(i64, "pyblt.data")
                n_args = len(node.args)
                if n_args == 0:
                    self.builder.call(self.runtime["cpython_call0"],
                                      [callable_ptr, out_tag, out_data])
                elif n_args == 1:
                    arg = self._emit_expr_value(node.args[0])
                    t_ir, d_ir = self._to_tag_data_ir(arg, node.args[0])
                    self.builder.call(self.runtime["cpython_call1"],
                                      [callable_ptr,
                                       t_ir, d_ir,
                                       out_tag, out_data])
                elif n_args == 2:
                    a1 = self._emit_expr_value(node.args[0])
                    t1_ir, d1_ir = self._to_tag_data_ir(a1, node.args[0])
                    a2 = self._emit_expr_value(node.args[1])
                    t2_ir, d2_ir = self._to_tag_data_ir(a2, node.args[1])
                    self.builder.call(self.runtime["cpython_call2"],
                                      [callable_ptr,
                                       t1_ir, d1_ir,
                                       t2_ir, d2_ir,
                                       out_tag, out_data])
                return
        # General fallback: Subscript calls (fns[0]()), etc.
        # Route through _emit_call_expr which handles these patterns.
        if isinstance(node.func, ast.Subscript):
            self._emit_call_expr(node)
            return
        self._bridge_fallback_stmt(node, f"unsupported function call: {ast.dump(node.func)[:60]}")

    # ── Singledispatch native dispatch ───────────────────────────────

    # Maps Python type names to FPY_TAG values for singledispatch switches
    _TYPE_TO_TAG = {
        "int": FPY_TAG_INT, "float": FPY_TAG_FLOAT, "str": FPY_TAG_STR,
        "bool": FPY_TAG_BOOL, "list": FPY_TAG_LIST, "dict": FPY_TAG_DICT,
        "set": FPY_TAG_SET, "bytes": FPY_TAG_BYTES,
    }

    def _emit_singledispatch_call(self, node: ast.Call,
                                   base_name: str) -> ir.Value:
        """Emit a native singledispatch call with a switch on the first
        argument's runtime FV tag. Returns i64 (or void sentinel for
        statement context).
        """
        dispatch = self._singledispatch[base_name]

        # Get the first argument's FV tag at runtime
        first_arg_node = node.args[0]
        first_fv = self._load_or_wrap_fv(first_arg_node)
        first_tag = self.builder.extract_value(first_fv, 0, name="sd.tag")
        first_data = self.builder.extract_value(first_fv, 1, name="sd.data")

        # Prepare remaining args (emit once, shared across branches)
        extra_args = [self._emit_expr_value(a) for a in node.args[1:]]

        # Build the switch: one branch per registered type, default → base
        default_b = self._new_block(f"sd.{base_name}.default")
        merge_b = self._new_block(f"sd.{base_name}.merge")

        # Result alloca (for expression context — stores the return value)
        result_alloca = self._create_entry_alloca(i64, f"sd.{base_name}.result")
        self.builder.store(ir.Constant(i64, 0), result_alloca)

        # Build switch cases
        switch = self.builder.switch(first_tag, default_b)
        for type_name, mangled in dispatch.items():
            tag_val = self._TYPE_TO_TAG.get(type_name)
            if tag_val is None:
                # User class: match by class_id via OBJ tag + runtime check.
                # For simplicity, fall through to default for unknown types.
                continue
            case_b = self._new_block(f"sd.{base_name}.{type_name}")
            switch.add_case(ir.Constant(i32, tag_val), case_b)

            # Emit the variant call in this block
            self.builder.position_at_end(case_b)
            variant_info = self._user_functions.get(mangled)
            if variant_info is not None:
                if variant_info.uses_fv_abi:
                    # FV ABI: pass FpyValue struct directly
                    call_args = [first_fv] + [
                        self._load_or_wrap_fv(a) for a in node.args[1:]]
                else:
                    call_args = [first_data] + [
                        self._coerce_to_type(a, p.type)
                        for a, p in zip(extra_args,
                                        list(variant_info.func.args)[1:])]
                    fp = variant_info.func.args[0]
                    if fp.type != first_data.type:
                        call_args[0] = self._coerce_to_type(first_data, fp.type)
                ret = self.builder.call(variant_info.func, call_args)
                if ret.type != void:
                    stored = ret
                    if isinstance(stored.type, ir.PointerType):
                        stored = self.builder.ptrtoint(stored, i64)
                    elif isinstance(stored.type, ir.DoubleType):
                        stored = self.builder.bitcast(stored, i64)
                    elif isinstance(stored.type, ir.IntType) and stored.type.width != 64:
                        stored = self.builder.zext(stored, i64)
                    self.builder.store(stored, result_alloca)
            self.builder.branch(merge_b)

        # Default block: call the base function
        self.builder.position_at_end(default_b)
        base_info = self._user_functions.get(base_name)
        if base_info is not None:
            if base_info.uses_fv_abi:
                base_args = [first_fv] + [
                    self._load_or_wrap_fv(a) for a in node.args[1:]]
            else:
                base_args = [first_data] + [
                    self._coerce_to_type(a, p.type)
                    for a, p in zip(extra_args,
                                    list(base_info.func.args)[1:])]
                fp = base_info.func.args[0]
                if fp.type != first_data.type:
                    base_args[0] = self._coerce_to_type(first_data, fp.type)
            ret = self.builder.call(base_info.func, base_args)
            if ret.type != void:
                stored = ret
                if isinstance(stored.type, ir.PointerType):
                    stored = self.builder.ptrtoint(stored, i64)
                elif isinstance(stored.type, ir.DoubleType):
                    stored = self.builder.bitcast(stored, i64)
                elif isinstance(stored.type, ir.IntType) and stored.type.width != 64:
                    stored = self.builder.zext(stored, i64)
                self.builder.store(stored, result_alloca)
        self.builder.branch(merge_b)

        # Merge
        self.builder.position_at_end(merge_b)
        return self.builder.load(result_alloca)

    def _coerce_to_type(self, value: ir.Value, target_type: ir.Type) -> ir.Value:
        """Coerce an LLVM value to the target type."""
        if value.type == target_type:
            return value
        if isinstance(target_type, ir.PointerType) and isinstance(value.type, ir.IntType):
            return self.builder.inttoptr(value, target_type)
        if isinstance(target_type, ir.IntType) and isinstance(value.type, ir.PointerType):
            return self.builder.ptrtoint(value, target_type)
        if isinstance(target_type, ir.DoubleType) and isinstance(value.type, ir.IntType):
            return self.builder.bitcast(value, target_type)
        if isinstance(target_type, ir.IntType) and isinstance(value.type, ir.DoubleType):
            return self.builder.bitcast(value, target_type)
        if isinstance(target_type, ir.IntType) and isinstance(value.type, ir.IntType):
            if target_type.width > value.type.width:
                return self.builder.zext(value, target_type)
            return self.builder.trunc(value, target_type)
        # FpyValue {i32, i64} → i64: extract the data field
        if (isinstance(target_type, ir.IntType)
                and isinstance(value.type, ir.LiteralStructType)
                and len(value.type.elements) == 2
                and isinstance(value.type.elements[0], ir.IntType)
                and value.type.elements[0].width == 32
                and isinstance(value.type.elements[1], ir.IntType)
                and value.type.elements[1].width == 64):
            return self.builder.extract_value(value, 1, "coerce.data")
        # FpyValue {i32, i64} → i8*: extract data and inttoptr
        if (isinstance(target_type, ir.PointerType)
                and isinstance(value.type, ir.LiteralStructType)
                and len(value.type.elements) == 2
                and isinstance(value.type.elements[0], ir.IntType)
                and value.type.elements[0].width == 32
                and isinstance(value.type.elements[1], ir.IntType)
                and value.type.elements[1].width == 64):
            data = self.builder.extract_value(value, 1, "coerce.data")
            return self.builder.inttoptr(data, target_type)
        return value

    def _emit_weakref_deref(self, node: ast.Call) -> ir.Value:
        """Dereference a weak reference: r() → target object or None.

        Emits: ptr = fpy_weakref_deref(wr); if ptr == NULL → None, else → OBJ.
        Returns an FpyValue (tag, data) struct or an i64 depending on context."""
        name = node.func.id
        val = self._load_variable(name, node)
        # val is an i64 holding the FpyWeakRef* pointer
        if isinstance(val.type, ir.IntType):
            wr_ptr = self._ensure_ptr(val)
        elif isinstance(val.type, ir.LiteralStructType):
            # FV: extract the data field (i64) and convert to pointer
            wr_ptr = self._ensure_ptr(val)
        else:
            wr_ptr = val
        obj_ptr = self.builder.call(self.runtime["weakref_deref"], [wr_ptr])
        # obj_ptr is NULL if the referent was collected → return None
        # Otherwise return OBJ-tagged FpyValue
        if self._USE_FV_LOCALS:
            result_alloca = self._create_entry_alloca(fpy_val, "wr.result")
            is_null = self.builder.icmp_unsigned(
                "==", self.builder.ptrtoint(obj_ptr, i64), ir.Constant(i64, 0))
            none_bb = self._new_block("wr.none")
            alive_bb = self._new_block("wr.alive")
            merge_bb = self._new_block("wr.merge")
            self.builder.cbranch(is_null, none_bb, alive_bb)
            # Dead ref → None
            self.builder.position_at_end(none_bb)
            none_val = ir.Constant(fpy_val, (ir.Constant(i32, FPY_TAG_NONE),
                                              ir.Constant(i64, 0)))
            self.builder.store(none_val, result_alloca)
            self.builder.branch(merge_bb)
            # Alive ref → OBJ
            self.builder.position_at_end(alive_bb)
            obj_i64 = self.builder.ptrtoint(obj_ptr, i64)
            alive_val = self.builder.insert_value(
                ir.Constant(fpy_val, ir.Undefined),
                ir.Constant(i32, FPY_TAG_OBJ), 0)
            alive_val = self.builder.insert_value(alive_val, obj_i64, 1)
            self.builder.store(alive_val, result_alloca)
            self.builder.branch(merge_bb)
            self.builder.position_at_end(merge_bb)
            return self.builder.load(result_alloca)
        else:
            # Non-FV mode: return the object pointer as i64 (0 if dead)
            return self.builder.ptrtoint(obj_ptr, i64)

    def _emit_closure_call(self, node: ast.Call) -> ir.Value:
        """Call a closure or function-pointer variable."""
        name = node.func.id
        val = self._load_variable(name, node)
        n_args = len(node.args)

        # Special case: cls() inside a classmethod constructs an instance.
        # The cls parameter is an i32 class_id; call obj_new + __init__ directly.
        if name == "cls" and isinstance(val.type, ir.IntType) and val.type.width == 32:
            obj = self.builder.call(self.runtime["obj_new"], [val])
            # Call __init__ directly if we know the class (preserves FpyValue tags)
            cls_name = self._current_class
            cls_info = self._user_classes.get(cls_name) if cls_name else None
            init_func = cls_info.methods.get("__init__") if cls_info else None
            if init_func and cls_info:
                # Build args: [self, *user_args]
                # Use the call-site param types to determine correct wrapping
                call_args = [obj]  # self
                for arg_node in node.args:
                    param_idx = len(call_args)
                    if param_idx < len(init_func.args):
                        param_type = init_func.args[param_idx].type
                        if param_type == fpy_val:
                            # Need FpyValue — wrap based on expression type
                            v = self._emit_expr_value(arg_node)
                            if isinstance(v.type, ir.LiteralStructType) and v.type == fpy_val:
                                call_args.append(v)
                            elif isinstance(v.type, ir.PointerType):
                                call_args.append(self._fv_from_str(v))
                            elif isinstance(v.type, ir.DoubleType):
                                call_args.append(self._fv_build(FPY_TAG_FLOAT,
                                    self.builder.bitcast(v, i64)))
                            else:
                                # i64 — could be int or packed pointer
                                # Use call-site type of cls() to determine types
                                cls_call_types = self._call_site_param_types.get("cls", [])
                                arg_idx = node.args.index(arg_node)
                                ct = cls_call_types[arg_idx] if arg_idx < len(cls_call_types) else None
                                _ctk = self._tag_kind(ct) if ct else None
                                if (_ctk == VKind.STR
                                        or (isinstance(arg_node, ast.Name)
                                            and arg_node.id in self.variables
                                            and self._var_kind(arg_node.id) == VKind.STR)):
                                    call_args.append(self._fv_build(FPY_TAG_STR, v))
                                elif (_ctk == VKind.BOOL
                                      or (isinstance(arg_node, ast.Constant) and isinstance(arg_node.value, bool))):
                                    bval = self.builder.zext(v, i64) if v.type.width < 64 else v
                                    call_args.append(self._fv_build(FPY_TAG_BOOL, bval))
                                else:
                                    call_args.append(self._fv_from_int(v))
                        else:
                            v = self._emit_expr_value(arg_node)
                            if isinstance(param_type, ir.IntType) and isinstance(v.type, ir.PointerType):
                                v = self.builder.ptrtoint(v, param_type)
                            elif isinstance(param_type, ir.PointerType) and isinstance(v.type, ir.IntType):
                                v = self.builder.inttoptr(v, param_type)
                            call_args.append(v)
                    else:
                        call_args.append(self._emit_expr_value(arg_node))
                self.builder.call(init_func, call_args)
            else:
                # Fallback: runtime dispatch via obj_call_init
                init_args = []
                for arg_node in node.args:
                    v = self._emit_expr_value(arg_node)
                    if isinstance(v.type, ir.PointerType):
                        v = self.builder.ptrtoint(v, i64)
                    init_args.append(v)
                n_init = len(init_args)
                if n_init == 0:
                    self.builder.call(self.runtime["obj_call_init0"], [obj])
                elif n_init == 1:
                    self.builder.call(self.runtime["obj_call_init1"], [obj, init_args[0]])
                elif n_init == 2:
                    self.builder.call(self.runtime["obj_call_init2"], [obj, init_args[0], init_args[1]])
                elif n_init == 3:
                    self.builder.call(self.runtime["obj_call_init3"],
                                  [obj, init_args[0], init_args[1], init_args[2]])
                elif n_init == 4:
                    self.builder.call(self.runtime["obj_call_init4"],
                                  [obj, init_args[0], init_args[1], init_args[2], init_args[3]])
                else:
                    return self._bridge_fallback_expr(node, f"cls() with {n_init} args (max 4)")
            return obj

        # Check if this is an actual closure variable vs a raw function pointer
        _, tag = self.variables.get(name, (None, ValueType(VKind.INT)))
        is_closure = (self._tag_kind(tag) == VKind.CLOSURE)

        # Handle f(*args) — Starred arg in closure/function-pointer call.
        # Common in decorator wrappers: def wrapper(*args): return f(*args)
        # Uses closure_call_list which unpacks the args list at runtime
        # and dispatches to the function pointer with the right arity.
        has_starred = any(isinstance(a, ast.Starred) for a in node.args)
        if has_starred and n_args == 1 and isinstance(node.args[0], ast.Starred):
            args_list = self._emit_expr_value(node.args[0].value)
            args_list = self._ensure_ptr(args_list)
            ptr = self._ensure_ptr(val)
            _star_result = self.builder.call(
                self.runtime["closure_call_list"], [ptr, args_list])
            # Build FpyValue from runtime ret_tag so the type is preserved
            _rt = self.builder.call(self.runtime["get_ret_tag"], [])
            return self._fv_build_from_slots(_rt, _star_result)

        # Handle f(**kwargs) — Double-star unpack in closure/function-pointer call.
        # Common in decorator wrappers: def wrapper(**kw): return f(**kw)
        # Uses closure_call_dict which dispatches based on callee type:
        #   - has_kwarg closure: passes dict directly
        #   - regular function: extracts dict values as positional args
        _kwargs_result = None
        has_dstar = any(kw.arg is None for kw in node.keywords)
        if has_dstar and len(node.keywords) == 1 and n_args == 0:
            # Simple forwarding: func(**kwargs)
            dict_val = self._emit_expr_value(node.keywords[0].value)
            dict_ptr = self._ensure_ptr(dict_val)
            ptr = self._ensure_ptr(val)
            _kwargs_result = self.builder.call(
                self.runtime["closure_call_dict"], [ptr, dict_ptr])

        # Handle f(key=val, ...) — Named keyword args in closure call.
        # Pack them into a dict and dispatch via closure_call_dict.
        elif node.keywords and n_args == 0:
            dict_ptr = self.builder.call(self.runtime["dict_new"], [])
            for kw in node.keywords:
                if kw.arg is None:
                    # **spread — get the dict and merge
                    spread = self._emit_expr_value(kw.value)
                    spread = self._ensure_ptr(spread)
                    self.builder.call(self.runtime["dict_update"],
                                      [dict_ptr, spread])
                else:
                    key = self._make_string_constant(kw.arg)
                    kw_val = self._emit_expr_value(kw.value)
                    kw_tag, kw_data = self._bare_to_tag_data(kw_val, kw.value)
                    self.builder.call(self.runtime["dict_set_fv"],
                                      [dict_ptr, key,
                                       ir.Constant(i32, kw_tag), kw_data])
            ptr = self._ensure_ptr(val)
            _kwargs_result = self.builder.call(
                self.runtime["closure_call_dict"], [ptr, dict_ptr])

        if _kwargs_result is not None:
            _drt = getattr(self, '_decorated_ret_tags', {}).get(name)
            if _drt == "str":
                return self.builder.inttoptr(_kwargs_result, i8_ptr)
            if _drt == "float":
                return self.builder.bitcast(_kwargs_result, double)
            # Build FpyValue from runtime ret_tag so the type is preserved
            # (the i64 wrapper of the callee sets ret_tag before returning)
            _rt = self.builder.call(self.runtime["get_ret_tag"], [])
            return self._fv_build_from_slots(_rt, _kwargs_result)

        # Always use call_ptr (auto-detects closures via magic number).
        # A "closure"-tagged variable might be either a real FpyClosure*
        # (from a decorator that returns a nested function) or a raw
        # function pointer (from an identity-style decorator).
        ptr = self._ensure_ptr(val)
        # Check if we know the return type (e.g., from decorator application)
        _drt = getattr(self, '_decorated_ret_tags', {}).get(name)
        if n_args == 0:
            result = self.builder.call(self.runtime["call_ptr0"], [ptr])
        elif n_args == 1:
            a = self._emit_expr_value(node.args[0])
            # Set arg tag in side-channel before dispatch (for i64 wrappers
            # and _pack_args1 to preserve type through *args forwarding).
            # FpyValue structs carry a runtime tag that _bare_to_tag_data
            # discards (returns INT); extract the dynamic tag directly.
            if (isinstance(a.type, ir.LiteralStructType)
                    and a.type == fpy_val):
                dyn_tag = self.builder.extract_value(a, 0)
                a = self.builder.extract_value(a, 1)
                self.builder.call(self.runtime["set_arg_tag"],
                                  [ir.Constant(i32, 0), dyn_tag])
            else:
                tag0, _ = self._bare_to_tag_data(a, node.args[0])
                self.builder.call(self.runtime["set_arg_tag"],
                                  [ir.Constant(i32, 0), ir.Constant(i32, tag0)])
            if isinstance(a.type, ir.PointerType):
                a = self.builder.ptrtoint(a, i64)
            result = self.builder.call(self.runtime["call_ptr1"], [ptr, a])
        elif n_args == 2:
            a = self._emit_expr_value(node.args[0])
            b = self._emit_expr_value(node.args[1])
            def _set_arg_tag_dynamic(val, arg_node, idx):
                if (isinstance(val.type, ir.LiteralStructType)
                        and val.type == fpy_val):
                    dyn_tag = self.builder.extract_value(val, 0)
                    self.builder.call(self.runtime["set_arg_tag"],
                                      [ir.Constant(i32, idx), dyn_tag])
                    return self.builder.extract_value(val, 1)
                else:
                    t, _ = self._bare_to_tag_data(val, arg_node)
                    self.builder.call(self.runtime["set_arg_tag"],
                                      [ir.Constant(i32, idx),
                                       ir.Constant(i32, t)])
                    return val
            a = _set_arg_tag_dynamic(a, node.args[0], 0)
            b = _set_arg_tag_dynamic(b, node.args[1], 1)
            if isinstance(a.type, ir.PointerType):
                a = self.builder.ptrtoint(a, i64)
            if isinstance(b.type, ir.PointerType):
                b = self.builder.ptrtoint(b, i64)
            result = self.builder.call(self.runtime["call_ptr2"], [ptr, a, b])
        else:
            result = None  # handled below in 3+ args path
        if result is not None:
            # Convert raw i64 result based on known return type
            if _drt == "str":
                return self.builder.inttoptr(result, i8_ptr)
            if _drt == "float":
                return self.builder.bitcast(result, double)
            if _drt is not None:
                return result
            # Unknown return type: use runtime ret_tag to build FpyValue
            # (the i64 wrapper of the callee sets ret_tag before returning)
            _rt = self.builder.call(self.runtime["get_ret_tag"], [])
            return self._fv_build_from_slots(_rt, result)

        # 3+ args: pack into list and use closure_call_list
        if n_args >= 3:
            ptr = self._ensure_ptr(val)
            args_list = self.builder.call(self.runtime["list_new"], [])
            for arg_node in node.args:
                v = self._emit_expr_value(arg_node)
                tag, data = self._bare_to_tag_data(v, arg_node)
                self._rt_call("list_append_fv",
                              [args_list, ir.Constant(i32, tag), data])
            _r3 = self.builder.call(self.runtime["closure_call_list"], [ptr, args_list])
            _rt3 = self.builder.call(self.runtime["get_ret_tag"], [])
            return self._fv_build_from_slots(_rt3, _r3)
        return self._bridge_fallback_expr(node, f"call with {n_args} args for {name}")

    def _emit_constructor(self, node: ast.Call) -> ir.Value:
        """Emit a class constructor call: ClassName(args)."""
        class_name = node.func.id
        # Resolve to monomorphized variant if the class has scalar-conflicting
        # constructor sigs. This returns the variant's mangled name (e.g.
        # Processor__i for int instances, Processor__d for float).
        if class_name in self._monomorphized_classes:
            class_name = self._resolve_class_specialization(
                class_name, node.args, node.keywords)
        cls_info = self._user_classes[class_name]

        # ABC enforcement: raise TypeError when instantiating a class
        # with unimplemented abstract methods (Bug 14).
        if cls_info.abstract_methods:
            abs_names = sorted(cls_info.abstract_methods)
            msg = (f"Can't instantiate abstract class {class_name} "
                   f"with abstract method{'s' if len(abs_names) > 1 else ''} "
                   f"{', '.join(abs_names)}")
            return self._emit_type_error(msg, node)

        # Create new object — call __new__ if the class defines one,
        # otherwise use the default obj_new allocator.
        class_id = self.builder.load(cls_info.class_id_global)
        new_fn = cls_info.methods.get("__new__") if cls_info.methods else None
        if new_fn is not None:
            # __new__(cls, *args) — pass class_id + constructor args
            new_args = [class_id]
            for arg_node in node.args:
                v = self._emit_expr_value(arg_node)
                if isinstance(v.type, ir.PointerType):
                    v = self.builder.ptrtoint(v, i64)
                elif isinstance(v.type, ir.DoubleType):
                    v = self.builder.bitcast(v, i64)
                elif isinstance(v.type, ir.IntType) and v.type.width != 64:
                    v = self.builder.zext(v, i64)
                new_args.append(v)
            # Coerce to match __new__'s parameter types
            coerced_new = []
            for val, param in zip(new_args, new_fn.args):
                if val.type != param.type:
                    if isinstance(param.type, ir.IntType) and isinstance(val.type, ir.IntType):
                        if param.type.width < val.type.width:
                            val = self.builder.trunc(val, param.type)
                        else:
                            val = self.builder.zext(val, param.type)
                    elif isinstance(param.type, ir.PointerType) and isinstance(val.type, ir.IntType):
                        val = self.builder.inttoptr(val, param.type)
                    elif isinstance(param.type, ir.IntType) and isinstance(val.type, ir.PointerType):
                        val = self.builder.ptrtoint(val, param.type)
                coerced_new.append(val)
            obj = self.builder.call(new_fn, coerced_new)
            # __new__ returns an i8* object pointer
            obj = self._ensure_ptr(obj)
        else:
            obj = self.builder.call(self.runtime["obj_new"], [class_id])

        def coerce_to_i64(v):
            if isinstance(v.type, ir.PointerType):
                return self.builder.ptrtoint(v, i64)
            elif isinstance(v.type, ir.DoubleType):
                return self.builder.bitcast(v, i64)
            elif isinstance(v.type, ir.IntType) and v.type.width != 64:
                return self.builder.zext(v, i64)
            return v

        # Call __init__ via runtime dispatch — coerce all args to i64
        init_args = []
        for arg_node in node.args:
            v = self._emit_expr_value(arg_node)
            init_args.append(coerce_to_i64(v))

        defaults = cls_info.init_defaults or []

        # Handle keyword arguments
        if node.keywords:
            # Get __init__ param names
            init_ast = cls_info.method_asts.get("__init__") if cls_info.method_asts else None
            if init_ast is not None:
                init_params = [a.arg for a in init_ast.args.args[1:]]  # skip self
                kw_values: dict[int, ir.Value] = {}
                for kw in node.keywords:
                    if kw.arg is None:
                        continue
                    if kw.arg not in init_params:
                        return self._bridge_fallback_expr(node, f"{class_name}() got unexpected keyword argument '{kw.arg}'")
                    idx = init_params.index(kw.arg)
                    if idx < len(init_args):
                        return self._bridge_fallback_expr(node, f"{class_name}() got multiple values for '{kw.arg}'")
                    kw_values[idx] = coerce_to_i64(self._emit_expr_value(kw.value))
                while len(init_args) < cls_info.init_arg_count:
                    idx = len(init_args)
                    if idx in kw_values:
                        init_args.append(kw_values[idx])
                    else:
                        default_idx = idx - (cls_info.init_arg_count - len(defaults))
                        if default_idx >= 0 and default_idx < len(defaults):
                            cached = self._load_cached_default(cls_info.init_default_globals, default_idx)
                            v = cached if cached is not None else self._emit_expr_value(defaults[default_idx])
                            init_args.append(coerce_to_i64(v))
                        else:
                            raise CodeGenError(
                                f"{class_name}() missing argument at position {idx}",
                                node,
                            )

        # Fill in defaults for missing args (positional-only case)
        n_provided = len(init_args)
        if n_provided < cls_info.init_arg_count:
            n_defaults_to_use = cls_info.init_arg_count - n_provided
            defaults_start = len(defaults) - n_defaults_to_use
            if defaults_start < 0:
                raise CodeGenError(
                    f"{class_name}() missing required argument(s)", node,
                )
            for di_off, default_node in enumerate(defaults[defaults_start:]):
                di = defaults_start + di_off
                cached = self._load_cached_default(cls_info.init_default_globals, di)
                v = cached if cached is not None else self._emit_expr_value(default_node)
                init_args.append(coerce_to_i64(v))

        # Direct __init__ dispatch: since the class is known statically, we
        # can call the init function directly instead of going through
        # fastpy_obj_call_initN's method name lookup. (The runtime fallback
        # is still used for classes without a user-defined __init__.)
        init_fn = cls_info.methods.get("__init__") if cls_info.methods else None
        init_info = (self._user_functions.get(f"{class_name}.__init__")
                     if init_fn is not None else None)
        n_args = len(init_args)
        if init_fn is not None:
            direct_args = [obj]  # first param is self (i8*)
            if init_info is not None and init_info.uses_fv_abi:
                # FV-ABI init: wrap each arg as FpyValue, preserving
                # runtime tags (None, obj, etc.) through the boundary.
                for idx, arg_node in enumerate(node.args[:n_args]):
                    fv = self._load_or_wrap_fv(arg_node)
                    direct_args.append(fv)
                # Fill defaults if needed
                for d_idx in range(len(node.args), n_args):
                    val = init_args[d_idx]
                    # Determine the AST node for proper wrapping
                    default_offset = d_idx - (cls_info.init_arg_count - len(defaults))
                    d_node = (defaults[default_offset]
                              if 0 <= default_offset < len(defaults)
                              else None)
                    fv = self._wrap_arg_value(val, d_node)
                    direct_args.append(fv)
            else:
                # Legacy (non-FV-ABI) init: coerce args to declared types.
                for val, param in zip(init_args, list(init_fn.args)[1:]):
                    if val.type != param.type:
                        if isinstance(param.type, ir.IntType) and isinstance(val.type, ir.PointerType):
                            val = self.builder.ptrtoint(val, param.type)
                        elif isinstance(param.type, ir.PointerType) and isinstance(val.type, ir.IntType):
                            val = self.builder.inttoptr(val, param.type)
                        elif isinstance(param.type, ir.DoubleType) and isinstance(val.type, ir.IntType):
                            val = self.builder.bitcast(val, param.type)
                        elif isinstance(param.type, ir.IntType) and isinstance(val.type, ir.DoubleType):
                            val = self.builder.bitcast(val, param.type)
                    direct_args.append(val)
            self.builder.call(init_fn, direct_args)
        elif n_args == 0:
            self.builder.call(self.runtime["obj_call_init0"], [obj])
        elif n_args == 1:
            self.builder.call(self.runtime["obj_call_init1"], [obj, init_args[0]])
        elif n_args == 2:
            self.builder.call(self.runtime["obj_call_init2"], [obj, init_args[0], init_args[1]])
        elif n_args == 3:
            self.builder.call(self.runtime["obj_call_init3"],
                              [obj, init_args[0], init_args[1], init_args[2]])
        elif n_args == 4:
            self.builder.call(self.runtime["obj_call_init4"],
                              [obj, init_args[0], init_args[1], init_args[2], init_args[3]])
        else:
            return self._bridge_fallback_expr(node, f"constructor with {n_args} args (max 4)")

        # ── Call-site slot tag patch ───────────────────────────��──────
        # Class methods receive params as bare i64 (no tag). When call-site
        # types conflict (list vs dict vs str), the merged type is None and
        # the __init__ body stamps the static tag (INT) into the slot. That
        # is wrong for pointer-type values. Fix: after __init__ returns,
        # overwrite each affected slot's tag with the correct runtime value
        # known at the call site.
        self._patch_init_slot_tags(cls_info, class_name, node, n_args, obj,
                                   init_args)

        return obj

    def _patch_init_slot_tags(self, cls_info, class_name: str,
                               node: ast.Call, n_args: int,
                               obj: ir.Value,
                               init_args: list[ir.Value]) -> None:
        """Overwrite slot tags that __init__ may have stamped incorrectly.

        When __init__ params have conflicting call-site types (e.g. data
        receives list, dict, and str across different call sites), the
        merged type is None and the method body defaults to tag=INT.  The
        caller knows the correct type — patch the slot directly.

        Only fires when:
        * The class has a user-defined __init__ with AST available
        * The __init__ contains simple ``self.attr = param`` patterns
        * The argument's static VKind differs from INT (lists, dicts, strs)
        """
        init_ast = cls_info.method_asts.get("__init__")
        if init_ast is None:
            return
        class_slots = self._class_attr_slots.get(class_name, {})
        if not class_slots:
            return

        # Build mapping: user_arg_index → slot_index for
        # ``self.attr = param`` assignments in __init__.
        init_params = [a.arg for a in init_ast.args.args]  # includes 'self'
        param_to_slot: dict[int, int] = {}
        for stmt in init_ast.body:
            if (isinstance(stmt, ast.Assign)
                    and len(stmt.targets) == 1
                    and isinstance(stmt.targets[0], ast.Attribute)
                    and isinstance(stmt.targets[0].value, ast.Name)
                    and stmt.targets[0].value.id == "self"
                    and isinstance(stmt.value, ast.Name)
                    and stmt.value.id in init_params
                    and stmt.value.id != "self"):
                attr_name = stmt.targets[0].attr
                param_name = stmt.value.id
                if attr_name in class_slots:
                    param_idx = init_params.index(param_name) - 1  # -1 for self
                    param_to_slot[param_idx] = class_slots[attr_name]

        if not param_to_slot:
            return

        # Check if any of the mapped params have a conflicting call-site
        # type (merged to None). Only patch in that case.
        method_call_types = self._call_site_param_types.get(
            class_name, [])
        has_conflict = False
        for pidx in param_to_slot:
            if pidx >= len(method_call_types) or method_call_types[pidx] is None:
                has_conflict = True
                break
        if not has_conflict:
            return

        n_provided = len(node.args)
        for arg_idx in range(min(n_provided, n_args)):
            if arg_idx not in param_to_slot:
                continue
            slot_idx = param_to_slot[arg_idx]
            arg_node = node.args[arg_idx]

            # Get the runtime tag for this argument.
            tag_val = self._infer_arg_runtime_tag(arg_node)
            if tag_val is None:
                continue

            # Data is already in init_args[arg_idx]; ensure it's i64.
            data_val = init_args[arg_idx]
            if isinstance(data_val.type, ir.PointerType):
                data_val = self.builder.ptrtoint(data_val, i64)
            elif isinstance(data_val.type, ir.DoubleType):
                data_val = self.builder.bitcast(data_val, i64)
            elif isinstance(data_val.type, ir.IntType) and data_val.type.width != 64:
                data_val = self.builder.zext(data_val, i64)

            self._emit_slot_set_direct(obj, slot_idx, tag_val, data_val)

    def _infer_arg_runtime_tag(self, node: ast.expr) -> 'ir.Value | None':
        """Return an i32 IR value with the correct FPY_TAG for *node*.

        For literals and known-type expressions, returns a compile-time
        constant. For variables stored as FpyValue, loads the runtime tag
        from the alloca. Returns None when the tag can't be determined.
        """
        # Literal containers
        if isinstance(node, (ast.List, ast.ListComp)):
            return ir.Constant(i32, FPY_TAG_LIST)
        if isinstance(node, ast.Tuple):
            return ir.Constant(i32, FPY_TAG_LIST)
        if isinstance(node, (ast.Dict, ast.DictComp)):
            return ir.Constant(i32, FPY_TAG_DICT)
        if isinstance(node, (ast.Set, ast.SetComp)):
            return ir.Constant(i32, FPY_TAG_SET)

        # Constants
        if isinstance(node, ast.Constant):
            if isinstance(node.value, str):
                return ir.Constant(i32, FPY_TAG_STR)
            if isinstance(node.value, bool):
                return ir.Constant(i32, FPY_TAG_BOOL)
            if isinstance(node.value, int):
                return ir.Constant(i32, FPY_TAG_INT)
            if isinstance(node.value, float):
                return ir.Constant(i32, FPY_TAG_FLOAT)
            if node.value is None:
                return ir.Constant(i32, FPY_TAG_NONE)
            if isinstance(node.value, bytes):
                return ir.Constant(i32, FPY_TAG_BYTES)

        # Variable with FpyValue alloca: load the runtime tag.
        if isinstance(node, ast.Name) and node.id in self.variables:
            alloca, _ = self.variables[node.id]
            if (isinstance(alloca.type, ir.PointerType)
                    and alloca.type.pointee is fpy_val):
                fv = self.builder.load(alloca, name=f"{node.id}.tag.fv")
                return self.builder.extract_value(fv, 0, name=f"{node.id}.tag")

        # Constructor call → OBJ
        if isinstance(node, ast.Call) and isinstance(node.func, ast.Name):
            if node.func.id in self._user_classes:
                return ir.Constant(i32, FPY_TAG_OBJ)

        return None

    def _emit_lru_cached_call(self, node: ast.Call, name: str) -> ir.Value:
        """Emit a call to an @lru_cache decorated function with caching.

        For single-arg functions (the common case: fib(n)), uses the
        argument as the cache key directly. Multi-arg functions use
        a hash of all args.
        """
        cache_id_gvar = self._lru_cache_ids[name]

        # For now, support single-int-arg functions (covers fib, factorial, etc.)
        if len(node.args) == 1:
            arg = self._emit_expr_value(node.args[0])
            if isinstance(arg.type, ir.PointerType):
                arg = self.builder.ptrtoint(arg, i64)
            elif isinstance(arg.type, ir.IntType) and arg.type.width != 64:
                arg = self.builder.zext(arg, i64)

            cache_id = self.builder.load(cache_id_gvar)
            result_slot = self._create_entry_alloca(i64, "lru.result")

            # Check cache
            hit = self.builder.call(self.runtime["lru_cache_get"],
                                     [cache_id, arg, result_slot])
            is_hit = self.builder.icmp_signed("!=", hit, ir.Constant(i32, 0))

            hit_block = self._new_block("lru.hit")
            miss_block = self._new_block("lru.miss")
            merge_block = self._new_block("lru.merge")

            self.builder.cbranch(is_hit, hit_block, miss_block)

            # Hit path: return cached result
            self.builder.position_at_end(hit_block)
            cached_val = self.builder.load(result_slot)
            self.builder.branch(merge_block)

            # Miss path: call function, store in cache
            self.builder.position_at_end(miss_block)
            computed = self._emit_user_call(node)
            if computed is None:
                computed = ir.Constant(i64, 0)
            # Ensure result is i64
            if isinstance(computed.type, ir.PointerType):
                computed = self.builder.ptrtoint(computed, i64)
            elif isinstance(computed.type, ir.DoubleType):
                computed = self.builder.bitcast(computed, i64)
            elif isinstance(computed.type, ir.IntType) and computed.type.width != 64:
                computed = self.builder.zext(computed, i64)
            elif (isinstance(computed.type, ir.LiteralStructType)
                  and computed.type == fpy_val):
                computed = self._fv_data_i64(computed)
            self.builder.call(self.runtime["lru_cache_put"],
                              [cache_id, arg, computed])
            self.builder.branch(merge_block)
            miss_end = self.builder.block

            # Merge
            self.builder.position_at_end(merge_block)
            phi = self.builder.phi(i64, "lru.val")
            phi.add_incoming(cached_val, hit_block)
            phi.add_incoming(computed, miss_end)
            return phi
        else:
            # Multi-arg or no-arg: fall back to uncached call
            result = self._emit_user_call(node)
            return result if result else ir.Constant(i64, 0)

    def _emit_user_call(self, node: ast.Call) -> ir.Value | None:
        """Emit a call to a user-defined function. Returns the LLVM value (or None for void)."""
        # Expand **dict_literal or **dict_variable to individual keywords.
        # E.g., f(**{"a": 1}) → f(a=1); f(**d) where d={"a":1} → f(a=1)
        if node.keywords:
            expanded = []
            for kw in node.keywords:
                if kw.arg is None and isinstance(kw.value, ast.Dict):
                    # **{key: val, ...} — expand inline dict
                    for k, v in zip(kw.value.keys, kw.value.values):
                        if isinstance(k, ast.Constant) and isinstance(k.value, str):
                            expanded.append(ast.keyword(arg=k.value, value=v))
                elif kw.arg is None and isinstance(kw.value, ast.Name):
                    # **variable — try to resolve from prior assignment
                    var_name = kw.value.id
                    resolved = False
                    # Search for the dict literal assignment in current scope
                    # or module-level statements
                    search_stmts = getattr(self, '_current_scope_stmts', [])
                    if not search_stmts:
                        search_stmts = getattr(self, '_module_stmts', [])
                    for stmt in search_stmts:
                        if (isinstance(stmt, ast.Assign)
                                and len(stmt.targets) == 1
                                and isinstance(stmt.targets[0], ast.Name)
                                and stmt.targets[0].id == var_name
                                and isinstance(stmt.value, ast.Dict)):
                            for k, v in zip(stmt.value.keys, stmt.value.values):
                                if isinstance(k, ast.Constant) and isinstance(k.value, str):
                                    expanded.append(ast.keyword(arg=k.value, value=v))
                            resolved = True
                            break
                    if not resolved:
                        expanded.append(kw)  # keep as-is (runtime unpack)
                else:
                    expanded.append(kw)
            if expanded != node.keywords:
                node = ast.Call(func=node.func, args=node.args,
                                keywords=expanded)
        name = self._resolve_func_alias(node.func.id)
        # Resolve monomorphized specializations: if the function was split into
        # multiple specializations at declaration time, pick the one that
        # matches this call site's argument types.
        if name in self._monomorphized:
            name = self._resolve_specialization(
                name, node.args, node.keywords)
        if name not in self._user_functions:
            return None  # alias resolved to non-existent function
        info = self._user_functions[name]

        # Check if this is a *args or **kwargs function
        if info.is_vararg and info.param_count > 1 and not info.is_kwarg:
            # Mixed: positional params + *rest list + optional kwonly params
            # param_names layout: [pos0, pos1, ..., *rest, kw0, kw1, ...]
            n_kwonly = info.n_kwonly
            n_positional = info.param_count - 1 - n_kwonly  # plain positional
            positional_args = node.args[:n_positional]
            rest_args = node.args[n_positional:]
            # Emit positional args
            args = []
            for arg_node in positional_args:
                args.append(self._emit_expr_value(arg_node))
            # Pack remaining positional call args into *rest tuple
            rest_list = self.builder.call(self.runtime["list_new"], [])
            for arg_node in rest_args:
                if isinstance(arg_node, ast.Starred):
                    src = self._emit_expr_value(arg_node.value)
                    src = self._ensure_ptr(src)
                    self.builder.call(
                        self.runtime["list_extend"], [rest_list, src])
                else:
                    self._emit_list_append_expr(rest_list, arg_node)
            # *args is a tuple in Python, mark it
            self.builder.call(self.runtime["list_mark_tuple"], [rest_list])
            args.append(rest_list)
            # Handle keyword-only params: map keywords to kwonly slots,
            # fill defaults for missing ones.
            if n_kwonly > 0:
                fn_def = getattr(self, '_function_def_nodes', {}).get(name)
                kwonly_names = (
                    [a.arg for a in fn_def.args.kwonlyargs] if fn_def
                    else info.param_names[n_positional + 1:])
                kw_defaults = (
                    fn_def.args.kw_defaults if fn_def
                    else [None] * n_kwonly)
                # Build map from keyword name → emitted value
                kw_values: dict[str, ir.Value] = {}
                if node.keywords:
                    for kw in node.keywords:
                        if kw.arg is not None and kw.arg in kwonly_names:
                            kw_values[kw.arg] = self._emit_expr_value(
                                kw.value)
                # Append kwonly args in declaration order
                for ki, kw_name in enumerate(kwonly_names):
                    if kw_name in kw_values:
                        args.append(kw_values[kw_name])
                    else:
                        # Use default value
                        kwd = (kw_defaults[ki]
                               if ki < len(kw_defaults) else None)
                        if kwd is not None:
                            args.append(self._emit_expr_value(kwd))
                        else:
                            raise CodeGenError(
                                f"{name}() missing required keyword-only "
                                f"argument: '{kw_name}'", node)
            # Coerce types and call
            coerced = []
            for val, param in zip(args, info.func.args):
                if val.type != param.type:
                    if isinstance(param.type, ir.PointerType) and isinstance(val.type, ir.IntType):
                        val = self.builder.inttoptr(val, param.type)
                    elif isinstance(param.type, ir.IntType) and isinstance(val.type, ir.PointerType):
                        val = self.builder.ptrtoint(val, param.type)
                    elif isinstance(param.type, ir.DoubleType) and isinstance(val.type, ir.IntType):
                        val = self.builder.sitofp(val, param.type)
                    elif isinstance(param.type, ir.IntType) and isinstance(val.type, ir.DoubleType):
                        val = self.builder.fptosi(val, param.type)
                    elif param.type == fpy_val and isinstance(val.type, ir.IntType):
                        val = self._fv_from_int(val)
                    elif param.type == fpy_val and isinstance(val.type, ir.PointerType):
                        val = self._fv_from_str(val)
                    elif (isinstance(val.type, ir.LiteralStructType)
                          and val.type == fpy_val):
                        # fpy_val → scalar (caller has MIXED var, callee
                        # is bare-ABI)
                        _fv_tag = self.builder.extract_value(val, 0)
                        _fv_data = self.builder.extract_value(val, 1)
                        if isinstance(param.type, ir.DoubleType):
                            _is_fl = self.builder.icmp_unsigned(
                                "==", _fv_tag,
                                ir.Constant(i32, FPY_TAG_FLOAT))
                            _bc = self.builder.bitcast(_fv_data, double)
                            _si = self.builder.sitofp(_fv_data, double)
                            val = self.builder.select(_is_fl, _bc, _si)
                        elif isinstance(param.type, ir.IntType):
                            if param.type.width < 64:
                                val = self.builder.trunc(
                                    _fv_data, param.type)
                            else:
                                val = _fv_data
                        elif isinstance(param.type, ir.PointerType):
                            val = self.builder.inttoptr(
                                _fv_data, param.type)
                    elif (isinstance(param.type, ir.LiteralStructType)
                          and param.type == fpy_val):
                        val = self._wrap_scalar_to_fv(val)
                coerced.append(val)
            result = self.builder.call(info.func, coerced)
            return result if info.ret_tag != "void" else None

        if info.is_vararg and info.is_kwarg and info.param_count == 2:
            # *args + **kwargs: pack positional into tuple, keywords into dict
            list_ptr = self.builder.call(self.runtime["list_new"], [])
            for arg_node in node.args:
                self._emit_list_append_expr(list_ptr, arg_node)
            self.builder.call(self.runtime["list_mark_tuple"], [list_ptr])
            dict_ptr = self.builder.call(self.runtime["dict_new"], [])
            if node.keywords:
                for kw in node.keywords:
                    key = self._make_string_constant(kw.arg)
                    val = self._emit_expr_value(kw.value)
                    tag, data = self._bare_to_tag_data(val, kw.value)
                    self.builder.call(self.runtime["dict_set_fv"],
                                      [dict_ptr, key, ir.Constant(i32, tag), data])
            result = self.builder.call(info.func, [list_ptr, dict_ptr])
            return result if info.ret_tag != "void" else None

        if (info.is_vararg or info.is_kwarg) and info.param_count == 1:
            # Pack all provided args into a list (tuple for *args)
            # Check for *splat forwarding: if a single starred arg is passed,
            # forward the list directly instead of wrapping it in another list.
            _has_star = any(isinstance(a, ast.Starred) for a in node.args)
            if _has_star and len(node.args) == 1 and isinstance(node.args[0], ast.Starred):
                # Simple forwarding: show(*args) → pass args list directly
                list_ptr = self._emit_expr_value(node.args[0].value)
                list_ptr = self._ensure_ptr(list_ptr)
            elif _has_star:
                # Mixed: some positional + *splat — build list and extend
                list_ptr = self.builder.call(self.runtime["list_new"], [])
                for arg_node in node.args:
                    if isinstance(arg_node, ast.Starred):
                        src = self._emit_expr_value(arg_node.value)
                        src = self._ensure_ptr(src)
                        self.builder.call(
                            self.runtime["list_extend"], [list_ptr, src])
                    else:
                        self._emit_list_append_expr(list_ptr, arg_node)
            else:
                list_ptr = self.builder.call(self.runtime["list_new"], [])
                for arg_node in node.args:
                    self._emit_list_append_expr(list_ptr, arg_node)
            # *args is a tuple in Python
            if info.is_vararg:
                self.builder.call(self.runtime["list_mark_tuple"], [list_ptr])
            # For **kwargs, pack keyword args into a dict
            if node.keywords:
                dict_ptr = self.builder.call(self.runtime["dict_new"], [])
                for kw in node.keywords:
                    key = self._make_string_constant(kw.arg)
                    val = self._emit_expr_value(kw.value)
                    tag, data = self._bare_to_tag_data(val, kw.value)
                    self.builder.call(self.runtime["dict_set_fv"],
                                      [dict_ptr, key, ir.Constant(i32, tag), data])
                result = self.builder.call(info.func, [dict_ptr])
            else:
                result = self.builder.call(info.func, [list_ptr])
            return result if info.ret_tag != "void" else None

        # Evaluate provided arguments (handling *args starred unpack)
        args = []
        for arg_node in node.args:
            if isinstance(arg_node, ast.Starred):
                # *args_list — expand into individual elements based on target arity.
                list_val = self._emit_expr_value(arg_node.value)
                list_val = self._ensure_ptr(list_val)
                if info.is_vararg:
                    # Target function also has *args — pass positional
                    # params individually and forward the rest as a list.
                    n_positional = info.param_count - 1  # exclude *args param
                    n_already = len(args)
                    n_extract = max(0, n_positional - n_already)
                    elem_type = self._get_list_elem_type(arg_node.value)
                    for i in range(n_extract):
                        elem = self._list_get_as_bare(
                            list_val, ir.Constant(i64, i), elem_type)
                        args.append(elem)
                    # Build sub-list for remaining *args elements
                    if n_extract == 0 and n_already == 0:
                        # Simple forwarding: pass the whole list
                        args.append(list_val)
                    else:
                        # Slice: create new list from remaining elements
                        sub = self.builder.call(self.runtime["list_new"], [])
                        list_len = self.builder.call(
                            self.runtime["list_length"],
                            [list_val])
                        # Loop from n_extract to list_len
                        _sl_idx = self._create_entry_alloca(i64, "splat.idx")
                        self.builder.store(
                            ir.Constant(i64, n_extract), _sl_idx)
                        _sl_cond = self._new_block("splat.cond")
                        _sl_body = self._new_block("splat.body")
                        _sl_end = self._new_block("splat.end")
                        self.builder.branch(_sl_cond)
                        self.builder.position_at_end(_sl_cond)
                        _sl_i = self.builder.load(_sl_idx)
                        _sl_len64 = self.builder.sext(list_len, i64)
                        _sl_done = self.builder.icmp_signed(
                            ">=", _sl_i, _sl_len64)
                        self.builder.cbranch(_sl_done, _sl_end, _sl_body)
                        self.builder.position_at_end(_sl_body)
                        _tag_slot = self._create_entry_alloca(i32, "sp.tag")
                        _data_slot = self._create_entry_alloca(i64, "sp.data")
                        self.builder.call(self.runtime["list_get_fv"], [
                            list_val, _sl_i, _tag_slot, _data_slot])
                        _sl_tag = self.builder.load(_tag_slot)
                        _sl_data = self.builder.load(_data_slot)
                        self.builder.call(self.runtime["list_append_fv"], [
                            sub, _sl_tag, _sl_data])
                        self.builder.store(
                            self.builder.add(_sl_i, ir.Constant(i64, 1)),
                            _sl_idx)
                        self.builder.branch(_sl_cond)
                        self.builder.position_at_end(_sl_end)
                        args.append(sub)
                else:
                    remaining = info.param_count - len(args)
                    elem_type = self._get_list_elem_type(arg_node.value)
                    for i in range(remaining):
                        elem = self._list_get_as_bare(
                            list_val, ir.Constant(i64, i), elem_type)
                        args.append(elem)
                break  # starred must be last
            val = self._emit_expr_value(arg_node)
            args.append(val)

        # Track indices that hold cached mutable defaults (from globals).
        # These must NOT be re-evaluated via _load_or_wrap_fv in the FV
        # wrapping loop below — the already-loaded pointer is the value.
        _cached_default_indices: set[int] = set()
        # Map arg index → default AST node (for type inference during FV wrap)
        _default_node_at: dict[int, ast.expr] = {}

        # Handle keyword arguments by mapping them to positional slots
        if node.keywords:
            fn_def = getattr(self, '_function_def_nodes', {}).get(name)
            if fn_def is not None:
                param_names = [a.arg for a in fn_def.args.args]
                param_names += [a.arg for a in fn_def.args.kwonlyargs]
                # For each keyword, find the param position and fill
                kw_values: dict[int, ir.Value] = {}
                for kw in node.keywords:
                    if kw.arg is None:
                        continue  # **kwargs spread, handled elsewhere
                    if kw.arg not in param_names:
                        return self._bridge_fallback_expr(node, f"{name}() got unexpected keyword argument '{kw.arg}'")
                    idx = param_names.index(kw.arg)
                    if idx < len(args):
                        return self._bridge_fallback_expr(node, f"{name}() got multiple values for '{kw.arg}'")
                    kw_values[idx] = self._emit_expr_value(kw.value)
                # Fill gaps from positional to first keyword slot with defaults,
                # then keyword values, then defaults for remaining.
                while len(args) < info.param_count:
                    idx = len(args)
                    if idx in kw_values:
                        args.append(kw_values[idx])
                    else:
                        # Use default for this position
                        default_idx = idx - (info.param_count - len(info.defaults))
                        if default_idx >= 0 and default_idx < len(info.defaults):
                            cached = self._load_cached_default(info.default_globals, default_idx)
                            if cached is not None:
                                args.append(cached)
                                _cached_default_indices.add(idx)
                                _default_node_at[idx] = info.defaults[default_idx]
                            else:
                                val = self._emit_expr_value(info.defaults[default_idx])
                                args.append(val)
                        else:
                            raise CodeGenError(
                                f"{name}() missing required argument at position {idx}",
                                node,
                            )

        # Fill in defaults for missing arguments
        n_provided = len(args)
        if n_provided < info.min_args:
            raise CodeGenError(
                f"{name}() missing {info.min_args - n_provided} required argument(s)",
                node,
            )
        if n_provided > info.param_count:
            raise CodeGenError(
                f"{name}() takes {info.param_count} arguments but {n_provided} were given",
                node,
            )

        # Append default values for unprovided parameters.
        # Track their AST nodes so the FV coercion loop can use
        # _load_or_wrap_fv (preserves None tag for `default=None`).
        # For mutable defaults with cached globals, mark the index so the
        # FV wrapping loop below loads the cached value instead of re-evaluating.
        default_ast_nodes: list[ast.expr] = []
        if n_provided < info.param_count:
            # defaults are right-aligned: defaults[0] is for param[param_count - len(defaults)]
            n_defaults_to_use = info.param_count - n_provided
            defaults_start = len(info.defaults) - n_defaults_to_use
            for di_off, default_node in enumerate(info.defaults[defaults_start:]):
                di = defaults_start + di_off
                arg_idx = n_provided + di_off
                cached = self._load_cached_default(info.default_globals, di)
                if cached is not None:
                    args.append(cached)
                    _cached_default_indices.add(arg_idx)
                    _default_node_at[arg_idx] = default_node
                else:
                    val = self._emit_expr_value(default_node)
                    args.append(val)
                default_ast_nodes.append(default_node)

        # Coerce arguments to function signature
        coerced = []
        if info.uses_fv_abi:
            # Post-refactor: each param is FpyValue. Wrap each bare arg.
            # Match args to AST nodes for AST-based tag inference; when there
            # are more args than AST nodes (starred unpack / defaults), use
            # the tracked default AST node.
            for i, val in enumerate(args):
                # For cached mutable defaults, wrap the already-loaded
                # pointer directly instead of re-evaluating via
                # _load_or_wrap_fv (which would create a fresh object).
                if i in _cached_default_indices:
                    fv = self._wrap_for_print(val, _default_node_at[i])
                    coerced.append(fv)
                    continue
                if i < len(node.args) and not isinstance(node.args[i], ast.Starred):
                    arg_node = node.args[i]
                elif i >= n_provided and (i - n_provided) < len(default_ast_nodes):
                    arg_node = default_ast_nodes[i - n_provided]
                else:
                    arg_node = None
                # For arguments that are FV-backed (Names with fpy_val
                # allocas, or Attributes on obj receivers), use
                # _load_or_wrap_fv to preserve the runtime tag. This
                # avoids the unwrap→re-wrap round-trip that loses NONE
                # tags (e.g. `func(obj.attr)` where attr is None, or
                # `func(var)` where var holds None via an attr load).
                if arg_node is not None:
                    fv = self._load_or_wrap_fv(arg_node)
                    coerced.append(fv)
                    continue
                fv = self._wrap_arg_value(val, arg_node)
                coerced.append(fv)
        else:
            _call_types = self._call_site_param_types.get(name, [])
            for ci, (val, param) in enumerate(zip(args, info.func.args)):
                if val.type != param.type:
                    if isinstance(param.type, ir.IntType) and isinstance(val.type, ir.DoubleType):
                        # If the callee expects a float (passed as i64 at ABI
                        # level), use bitcast to preserve the bit pattern.
                        # Otherwise use fptosi to truncate to integer.
                        _ct = _call_types[ci] if ci < len(_call_types) else None
                        _ck = self._tag_kind(_ct) if _ct else VKind.INT
                        if _ck == VKind.FLOAT:
                            val = self.builder.bitcast(val, param.type)
                        else:
                            val = self.builder.fptosi(val, param.type)
                    elif isinstance(param.type, ir.DoubleType) and isinstance(val.type, ir.IntType):
                        val = self.builder.sitofp(val, param.type)
                    elif isinstance(param.type, ir.IntType) and isinstance(val.type, ir.PointerType):
                        val = self.builder.ptrtoint(val, param.type)
                    elif isinstance(param.type, ir.PointerType) and isinstance(val.type, ir.IntType):
                        val = self.builder.inttoptr(val, param.type)
                    # fpy_val → scalar: unwrap the FpyValue to the
                    # expected scalar type.  This happens when the caller
                    # is FV-ABI (variables stored as fpy_val) but the
                    # callee is bare-ABI (params are i64/double/i32).
                    elif (isinstance(val.type, ir.LiteralStructType)
                          and val.type == fpy_val):
                        _fv_tag = self.builder.extract_value(val, 0)
                        _fv_data = self.builder.extract_value(val, 1)
                        if isinstance(param.type, ir.DoubleType):
                            # Could be int (sitofp) or float (bitcast).
                            _is_fl = self.builder.icmp_unsigned(
                                "==", _fv_tag,
                                ir.Constant(i32, FPY_TAG_FLOAT))
                            _bc = self.builder.bitcast(_fv_data, double)
                            _si = self.builder.sitofp(_fv_data, double)
                            val = self.builder.select(_is_fl, _bc, _si)
                        elif isinstance(param.type, ir.IntType):
                            if param.type.width < 64:
                                val = self.builder.trunc(
                                    _fv_data, param.type)
                            else:
                                val = _fv_data
                        elif isinstance(param.type, ir.PointerType):
                            val = self.builder.inttoptr(
                                _fv_data, param.type)
                    # double/i64/ptr → fpy_val: wrap as FpyValue with
                    # correct tag so FV-ABI functions receive the runtime
                    # tag instead of just the bare scalar.
                    elif (isinstance(param.type, ir.LiteralStructType)
                          and param.type == fpy_val):
                        val = self._wrap_scalar_to_fv(val)
                coerced.append(val)

        result = self.builder.call(info.func, coerced)

        # Unwrap FV return to the caller's expected bare type
        if info.uses_fv_abi and info.ret_tag != "void":
            result = self._unwrap_return_value(result, info)

        return result if info.ret_tag != "void" else None

    def _emit_user_call_fv(self, node: ast.Call) -> ir.Value:
        """Emit a user function call and return the raw FpyValue without
        unwrapping.  Used by _load_or_wrap_fv so the runtime tag from the
        callee is preserved (instead of being discarded by _unwrap_return_value
        and re-inferred from the static type)."""
        # Expand **dict_literal or **variable to individual keywords
        if node.keywords:
            expanded = []
            for kw in node.keywords:
                if kw.arg is None and isinstance(kw.value, ast.Dict):
                    for k, v in zip(kw.value.keys, kw.value.values):
                        if isinstance(k, ast.Constant) and isinstance(k.value, str):
                            expanded.append(ast.keyword(arg=k.value, value=v))
                elif kw.arg is None and isinstance(kw.value, ast.Name):
                    var_name = kw.value.id
                    resolved = False
                    search = getattr(self, '_current_scope_stmts', []) or getattr(self, '_module_stmts', [])
                    for stmt in search:
                        if (isinstance(stmt, ast.Assign)
                                and len(stmt.targets) == 1
                                and isinstance(stmt.targets[0], ast.Name)
                                and stmt.targets[0].id == var_name
                                and isinstance(stmt.value, ast.Dict)):
                            for k, v in zip(stmt.value.keys, stmt.value.values):
                                if isinstance(k, ast.Constant) and isinstance(k.value, str):
                                    expanded.append(ast.keyword(arg=k.value, value=v))
                            resolved = True
                            break
                    if not resolved:
                        expanded.append(kw)
                else:
                    expanded.append(kw)
            if expanded != node.keywords:
                node = ast.Call(func=node.func, args=node.args,
                                keywords=expanded)
        name = self._resolve_func_alias(node.func.id)
        if name in self._monomorphized:
            name = self._resolve_specialization(
                name, node.args, node.keywords)
        info = self._user_functions[name]

        # Same argument handling as _emit_user_call, just skip the unwrap.
        # Handle *args + **kwargs together (2 params)
        if info.is_vararg and info.is_kwarg and info.param_count == 2:
            list_ptr = self.builder.call(self.runtime["list_new"], [])
            for arg_node in node.args:
                self._emit_list_append_expr(list_ptr, arg_node)
            self.builder.call(self.runtime["list_mark_tuple"], [list_ptr])
            dict_ptr = self.builder.call(self.runtime["dict_new"], [])
            if node.keywords:
                for kw in node.keywords:
                    key = self._make_string_constant(kw.arg)
                    val = self._emit_expr_value(kw.value)
                    tag, data = self._bare_to_tag_data(val, kw.value)
                    self.builder.call(self.runtime["dict_set_fv"],
                                      [dict_ptr, key, ir.Constant(i32, tag), data])
            return self.builder.call(info.func, [list_ptr, dict_ptr])

        # Handle *args or **kwargs (single param)
        if (info.is_vararg or info.is_kwarg) and info.param_count == 1:
            _has_star = any(isinstance(a, ast.Starred) for a in node.args)
            if _has_star and len(node.args) == 1 and isinstance(node.args[0], ast.Starred):
                list_ptr = self._emit_expr_value(node.args[0].value)
                list_ptr = self._ensure_ptr(list_ptr)
            elif _has_star:
                list_ptr = self.builder.call(self.runtime["list_new"], [])
                for arg_node in node.args:
                    if isinstance(arg_node, ast.Starred):
                        src = self._emit_expr_value(arg_node.value)
                        src = self._ensure_ptr(src)
                        self.builder.call(
                            self.runtime["list_extend"], [list_ptr, src])
                    else:
                        self._emit_list_append_expr(list_ptr, arg_node)
            else:
                list_ptr = self.builder.call(self.runtime["list_new"], [])
                for arg_node in node.args:
                    self._emit_list_append_expr(list_ptr, arg_node)
            # *args is a tuple in Python
            if info.is_vararg:
                self.builder.call(self.runtime["list_mark_tuple"], [list_ptr])
            if node.keywords:
                dict_ptr = self.builder.call(self.runtime["dict_new"], [])
                for kw in node.keywords:
                    key = self._make_string_constant(kw.arg)
                    val = self._emit_expr_value(kw.value)
                    tag, data = self._bare_to_tag_data(val, kw.value)
                    self.builder.call(self.runtime["dict_set_fv"],
                                      [dict_ptr, key, ir.Constant(i32, tag), data])
                return self.builder.call(info.func, [dict_ptr])
            return self.builder.call(info.func, [list_ptr])

        # Mixed vararg: positional + *rest + kwonly
        if info.is_vararg and info.param_count > 1 and not info.is_kwarg:
            n_kwonly = info.n_kwonly
            n_positional = info.param_count - 1 - n_kwonly
            positional_args = node.args[:n_positional]
            rest_args = node.args[n_positional:]
            args = []
            for arg_node in positional_args:
                args.append(self._emit_expr_value(arg_node))
            rest_list = self.builder.call(self.runtime["list_new"], [])
            for arg_node in rest_args:
                if isinstance(arg_node, ast.Starred):
                    src = self._emit_expr_value(arg_node.value)
                    src = self._ensure_ptr(src)
                    self.builder.call(
                        self.runtime["list_extend"], [rest_list, src])
                else:
                    self._emit_list_append_expr(rest_list, arg_node)
            # *args is a tuple in Python
            self.builder.call(self.runtime["list_mark_tuple"], [rest_list])
            args.append(rest_list)
            if n_kwonly > 0:
                fn_def = getattr(self, '_function_def_nodes', {}).get(name)
                kwonly_names = (
                    [a.arg for a in fn_def.args.kwonlyargs] if fn_def
                    else info.param_names[n_positional + 1:])
                kw_defaults = (
                    fn_def.args.kw_defaults if fn_def
                    else [None] * n_kwonly)
                kw_values: dict[str, ir.Value] = {}
                if node.keywords:
                    for kw in node.keywords:
                        if kw.arg is not None and kw.arg in kwonly_names:
                            kw_values[kw.arg] = self._emit_expr_value(
                                kw.value)
                for ki, kw_name in enumerate(kwonly_names):
                    if kw_name in kw_values:
                        args.append(kw_values[kw_name])
                    else:
                        kwd = (kw_defaults[ki]
                               if ki < len(kw_defaults) else None)
                        if kwd is not None:
                            args.append(self._emit_expr_value(kwd))
                        else:
                            raise CodeGenError(
                                f"{name}() missing required keyword-only "
                                f"argument: '{kw_name}'", node)
            coerced = []
            for val, param in zip(args, info.func.args):
                if val.type != param.type:
                    if (isinstance(param.type, ir.PointerType)
                            and isinstance(val.type, ir.IntType)):
                        val = self.builder.inttoptr(val, param.type)
                    elif (isinstance(param.type, ir.IntType)
                          and isinstance(val.type, ir.PointerType)):
                        val = self.builder.ptrtoint(val, param.type)
                coerced.append(val)
            return self.builder.call(info.func, coerced)

        # Regular call: evaluate args, apply defaults, coerce
        args = []
        arg_source_nodes: list = []  # Track AST nodes for wrapping
        for arg_node in node.args:
            if isinstance(arg_node, ast.Starred):
                list_val = self._emit_expr_value(arg_node.value)
                remaining = info.param_count - len(args)
                elem_type = self._get_list_elem_type(arg_node.value)
                for i in range(remaining):
                    elem = self._list_get_as_bare(list_val, ir.Constant(i64, i), elem_type)
                    args.append(elem)
                    arg_source_nodes.append(None)
                break
            val = self._emit_expr_value(arg_node)
            args.append(val)
            arg_source_nodes.append(arg_node)

        # Track cached mutable defaults across both kw-fill and positional-fill paths
        _cached_fv_indices: set[int] = set()
        _cached_fv_nodes: dict[int, ast.expr] = {}

        # Handle keyword arguments by mapping them to positional slots
        if node.keywords:
            fn_def = getattr(self, '_function_def_nodes', {}).get(name)
            if fn_def is not None:
                param_names = [a.arg for a in fn_def.args.args]
                param_names += [a.arg for a in fn_def.args.kwonlyargs]
                kw_values: dict[int, tuple] = {}
                for kw in node.keywords:
                    if kw.arg is None:
                        continue
                    if kw.arg not in param_names:
                        return self._bridge_fallback_expr(node, f"{name}() got unexpected keyword argument '{kw.arg}'")
                    idx = param_names.index(kw.arg)
                    if idx < len(args):
                        return self._bridge_fallback_expr(node, f"{name}() got multiple values for '{kw.arg}'")
                    kw_values[idx] = (self._emit_expr_value(kw.value), kw.value)
                while len(args) < info.param_count:
                    idx = len(args)
                    if idx in kw_values:
                        args.append(kw_values[idx][0])
                        arg_source_nodes.append(kw_values[idx][1])
                    else:
                        default_idx = idx - (info.param_count - len(info.defaults))
                        if default_idx >= 0 and default_idx < len(info.defaults):
                            cached = self._load_cached_default(info.default_globals, default_idx)
                            if cached is not None:
                                args.append(cached)
                                _cached_fv_indices.add(idx)
                                _cached_fv_nodes[idx] = info.defaults[default_idx]
                                arg_source_nodes.append(info.defaults[default_idx])
                            else:
                                val = self._emit_expr_value(info.defaults[default_idx])
                                args.append(val)
                                arg_source_nodes.append(info.defaults[default_idx])
                        else:
                            raise CodeGenError(
                                f"{name}() missing required argument at position {idx}",
                                node,
                            )

        n_provided = len(args)
        if n_provided < info.param_count:
            n_defaults_to_use = info.param_count - n_provided
            defaults_start = len(info.defaults) - n_defaults_to_use
            for di_off, default_node in enumerate(info.defaults[defaults_start:]):
                di = defaults_start + di_off
                arg_idx = n_provided + di_off
                cached = self._load_cached_default(info.default_globals, di)
                if cached is not None:
                    args.append(cached)
                    _cached_fv_indices.add(arg_idx)
                    _cached_fv_nodes[arg_idx] = default_node
                else:
                    val = self._emit_expr_value(default_node)
                    args.append(val)
                arg_source_nodes.append(default_node)

        coerced = []
        for i, val in enumerate(args):
            # For cached mutable defaults, wrap the already-loaded pointer
            # directly instead of re-evaluating via _load_or_wrap_fv.
            if i in _cached_fv_indices:
                fv = self._wrap_for_print(val, _cached_fv_nodes[i])
                coerced.append(fv)
                continue
            arg_node = arg_source_nodes[i] if i < len(arg_source_nodes) else None
            # Use _load_or_wrap_fv for all AST-backed args to preserve
            # runtime tags (None, obj, etc.) through the FV-ABI boundary.
            if arg_node is not None:
                fv = self._load_or_wrap_fv(arg_node)
                coerced.append(fv)
                continue
            fv = self._wrap_arg_value(val, arg_node)
            coerced.append(fv)

        # Call the function — return the raw FpyValue, no unwrap
        return self.builder.call(info.func, coerced)

    def _load_cached_default(self, default_globals, default_idx):
        """Load a mutable default from its cached global, if available.
        Returns the loaded i8* value or None if no cache exists for this
        default index."""
        if (default_globals is not None
                and default_idx < len(default_globals)
                and default_globals[default_idx] is not None):
            return self.builder.load(default_globals[default_idx])
        return None

    def _wrap_arg_value(self, val: ir.Value, arg_node: ast.expr | None) -> ir.Value:
        """Wrap a bare argument value into an FpyValue for the FV-ABI call.

        `arg_node` is optional — when None (starred unpack, defaults), we fall
        back to LLVM-type-based tag assignment.
        """
        # None constants and None-tagged variables must use NONE tag, not INT.
        # Without this, `func(None)` passes {tag=INT, data=0} and `x is None`
        # inside the function returns False.
        if (arg_node is not None
                and isinstance(arg_node, ast.Constant)
                and arg_node.value is None):
            return self._fv_none()
        if (arg_node is not None
                and isinstance(arg_node, ast.Name)
                and arg_node.id in self.variables
                and self._var_kind(arg_node.id) == VKind.NONE):
            return self._fv_none()
        if isinstance(val.type, ir.IntType):
            if val.type.width == 32:
                return self._fv_from_bool(val)
            # Bool constants (True/False) are emitted as i64 but should be
            # tagged BOOL. Check the AST node.
            if (arg_node is not None
                    and isinstance(arg_node, ast.Constant)
                    and isinstance(arg_node.value, bool)):
                return self._fv_from_bool(self.builder.trunc(val, i32))
            # Bool-typed variables should also keep their BOOL tag
            if (arg_node is not None
                    and isinstance(arg_node, ast.Name)
                    and arg_node.id in self.variables
                    and self._var_kind(arg_node.id) == VKind.BOOL):
                return self._fv_from_bool(self.builder.trunc(val, i32))
            return self._fv_from_int(val)
        if isinstance(val.type, ir.DoubleType):
            return self._fv_from_float(val)
        if isinstance(val.type, ir.PointerType):
            if arg_node is not None:
                if self._is_list_expr(arg_node) or self._is_tuple_expr(arg_node):
                    return self._fv_from_list(val)
                if self._is_dict_expr(arg_node):
                    return self._fv_from_list(val)
                if self._is_obj_expr(arg_node):
                    return self._fv_from_obj(val)
            return self._fv_from_str(val)
        raise CodeGenError(f"Cannot wrap argument of type {val.type}")

    def _unwrap_return_value(self, fv: ir.Value, info: "FuncInfo") -> ir.Value:
        """Unwrap an FpyValue return into the caller's expected bare type.

        The expected type is `info.static_ret_type`.
        """
        ret_type = info.static_ret_type
        if isinstance(ret_type, ir.IntType) and ret_type.width == 64:
            return self._fv_as_int(fv)
        if isinstance(ret_type, ir.IntType) and ret_type.width == 32:
            # Bool — extract data as i64 then truncate
            return self.builder.trunc(self._fv_as_int(fv), i32)
        if isinstance(ret_type, ir.DoubleType):
            return self._fv_as_float(fv)
        if isinstance(ret_type, ir.PointerType):
            return self._fv_as_ptr(fv)
        # Fallback: treat as i64
        return self._fv_data_i64(fv)

    def _emit_print(self, node: ast.Call) -> None:
        """Emit a print() call."""
        # If print has a file= keyword pointing to a non-stdout target,
        # route the entire call through the CPython bridge so file.write()
        # goes to the correct file object (e.g., io.StringIO, sys.stderr).
        has_file_kw = any(kw.arg == "file" for kw in node.keywords)
        if has_file_kw:
            # Get builtins.print via bridge and call with all args+kwargs
            print_fn_name = self._make_string_constant("print")
            builtins_name = self._make_string_constant("builtins")
            builtins_mod = self.builder.call(
                self.runtime["cpython_import"], [builtins_name])
            print_fn = self.builder.call(
                self.runtime["cpython_getattr"], [builtins_mod, print_fn_name])
            n_pos = len(node.args)
            n_kw = len(node.keywords)
            tags_alloca = self.builder.alloca(
                ir.ArrayType(i32, max(n_pos, 1)), name="prt.tags")
            data_alloca = self.builder.alloca(
                ir.ArrayType(i64, max(n_pos, 1)), name="prt.data")
            for i, arg_node in enumerate(node.args):
                val = self._emit_expr_value(arg_node)
                t_ir, d_ir = self._to_tag_data_ir(val, arg_node)
                self.builder.store(t_ir, self.builder.gep(
                    tags_alloca, [ir.Constant(i32, 0), ir.Constant(i32, i)]))
                self.builder.store(d_ir, self.builder.gep(
                    data_alloca, [ir.Constant(i32, 0), ir.Constant(i32, i)]))
            names_alloca = self.builder.alloca(
                ir.ArrayType(i8_ptr, n_kw), name="prt.knames")
            kw_tags_alloca = self.builder.alloca(
                ir.ArrayType(i32, n_kw), name="prt.ktags")
            kw_data_alloca = self.builder.alloca(
                ir.ArrayType(i64, n_kw), name="prt.kdata")
            for i, kw in enumerate(node.keywords):
                name_ptr = self._make_string_constant(kw.arg)
                val = self._emit_expr_value(kw.value)
                t_ir, d_ir = self._to_tag_data_ir(val, kw.value)
                self.builder.store(name_ptr, self.builder.gep(
                    names_alloca, [ir.Constant(i32, 0), ir.Constant(i32, i)]))
                self.builder.store(t_ir, self.builder.gep(
                    kw_tags_alloca, [ir.Constant(i32, 0), ir.Constant(i32, i)]))
                self.builder.store(d_ir, self.builder.gep(
                    kw_data_alloca, [ir.Constant(i32, 0), ir.Constant(i32, i)]))
            out_tag = self._create_entry_alloca(i32, "prt.otag")
            out_data = self._create_entry_alloca(i64, "prt.odata")
            tags_base = self.builder.gep(
                tags_alloca, [ir.Constant(i32, 0), ir.Constant(i32, 0)])
            data_base = self.builder.gep(
                data_alloca, [ir.Constant(i32, 0), ir.Constant(i32, 0)])
            names_base = self.builder.gep(
                names_alloca, [ir.Constant(i32, 0), ir.Constant(i32, 0)])
            kt_base = self.builder.gep(
                kw_tags_alloca, [ir.Constant(i32, 0), ir.Constant(i32, 0)])
            kd_base = self.builder.gep(
                kw_data_alloca, [ir.Constant(i32, 0), ir.Constant(i32, 0)])
            self.builder.call(self.runtime["cpython_call_kw"],
                              [print_fn,
                               ir.Constant(i32, n_pos), tags_base, data_base,
                               ir.Constant(i32, n_kw), names_base, kt_base, kd_base,
                               out_tag, out_data])
            return

        # Extract sep= and end= keyword arguments.
        # Accept both literal strings and variable expressions.
        sep = " "           # Python-level default (None means default)
        end = "\n"          # Python-level default
        sep_ir = None       # LLVM value if non-literal
        end_ir = None       # LLVM value if non-literal
        for kw in node.keywords:
            if kw.arg == "sep":
                if isinstance(kw.value, ast.Constant) and isinstance(kw.value.value, str):
                    sep = kw.value.value
                elif isinstance(kw.value, ast.Constant) and kw.value.value is None:
                    sep = " "   # sep=None → default separator
                else:
                    # Non-literal sep: evaluate as string expression
                    sep_ir = self._emit_expr_value(kw.value)
                    sep_ir = self._ensure_ptr(sep_ir)
                    sep = None  # signal to use sep_ir
            elif kw.arg == "end":
                if isinstance(kw.value, ast.Constant) and isinstance(kw.value.value, str):
                    end = kw.value.value
                elif isinstance(kw.value, ast.Constant) and kw.value.value is None:
                    end = "\n"  # end=None → default end
                else:
                    end_ir = self._emit_expr_value(kw.value)
                    end_ir = self._ensure_ptr(end_ir)
                    end = None  # signal to use end_ir
            else:
                pass  # ignore unknown print kwargs (file=, flush=, etc.)

        # Helper: emit write of end string
        def _write_end():
            if end_ir is not None:
                self.builder.call(self.runtime["write_str"], [end_ir])
            elif end == "\n":
                self.builder.call(self.runtime["print_newline"], [])
            elif end:
                end_ptr = self._make_string_constant(end)
                self.builder.call(self.runtime["write_str"], [end_ptr])
        # Helper: emit write of sep string
        def _write_sep():
            if sep_ir is not None:
                self.builder.call(self.runtime["write_str"], [sep_ir])
            elif sep == " ":
                self.builder.call(self.runtime["write_space"], [])
            elif sep:
                sep_ptr = self._make_string_constant(sep)
                self.builder.call(self.runtime["write_str"], [sep_ptr])

        if len(node.args) == 0:
            _write_end()
            return

        # Handle starred args: print(*[1,2,3]) → iterate the list
        has_star = any(isinstance(a, ast.Starred) for a in node.args)
        if has_star:
            _sep_ptr_star = (sep_ir if sep_ir is not None
                             else self._make_string_constant(sep if sep else " "))
            first_alloca = self._create_entry_alloca(ir.IntType(1), "print.first")
            self.builder.store(ir.Constant(ir.IntType(1), 1), first_alloca)
            for arg in node.args:
                if isinstance(arg, ast.Starred):
                    # Iterate the list and print each element
                    lst = self._emit_expr_value(arg.value)
                    length = self.builder.call(
                        self.runtime["list_length"], [lst])
                    idx_alloca = self._create_entry_alloca(i64, "pstar.idx")
                    self.builder.store(ir.Constant(i64, 0), idx_alloca)
                    cond_b = self._new_block("pstar.cond")
                    body_b = self._new_block("pstar.body")
                    end_b = self._new_block("pstar.end")
                    self.builder.branch(cond_b)
                    self.builder.position_at_end(cond_b)
                    idx = self.builder.load(idx_alloca)
                    self.builder.cbranch(
                        self.builder.icmp_signed("<", idx, length),
                        body_b, end_b)
                    self.builder.position_at_end(body_b)
                    idx = self.builder.load(idx_alloca)
                    is_first = self.builder.load(first_alloca)
                    not_first = self.builder.not_(is_first)
                    sep_b = self._new_block("pstar.sep")
                    nosep_b = self._new_block("pstar.nosep")
                    self.builder.cbranch(not_first, sep_b, nosep_b)
                    self.builder.position_at_end(sep_b)
                    self.builder.call(self.runtime["write_str"], [_sep_ptr_star])
                    self.builder.branch(nosep_b)
                    self.builder.position_at_end(nosep_b)
                    self.builder.store(
                        ir.Constant(ir.IntType(1), 0), first_alloca)
                    # Print element via FV
                    tag_s = self._create_entry_alloca(i32, "pstar.tag")
                    data_s = self._create_entry_alloca(i64, "pstar.data")
                    self._rt_call("list_get_fv",
                                      [lst, idx, tag_s, data_s])
                    tag = self.builder.load(tag_s)
                    data = self.builder.load(data_s)
                    self.builder.call(
                        self.runtime["fv_write"], [tag, data])
                    self.builder.store(
                        self.builder.add(idx, ir.Constant(i64, 1)),
                        idx_alloca)
                    self.builder.branch(cond_b)
                    self.builder.position_at_end(end_b)
                else:
                    # Normal arg
                    is_first = self.builder.load(first_alloca)
                    not_first = self.builder.not_(is_first)
                    sep_b2 = self._new_block("print.sep")
                    nosep_b2 = self._new_block("print.nosep")
                    self.builder.cbranch(not_first, sep_b2, nosep_b2)
                    self.builder.position_at_end(sep_b2)
                    self.builder.call(self.runtime["write_str"], [_sep_ptr_star])
                    self.builder.branch(nosep_b2)
                    self.builder.position_at_end(nosep_b2)
                    self.builder.store(
                        ir.Constant(ir.IntType(1), 0), first_alloca)
                    self._emit_write_single(arg)
            _write_end()
            return

        # Simple case: no custom sep/end, single arg — use fast path
        if (len(node.args) == 1 and sep == " " and end == "\n"
                and sep_ir is None and end_ir is None):
            self._emit_print_single(node.args[0])
            return

        # Write each arg separated by `sep`, then write `end`
        for i, arg in enumerate(node.args):
            if i > 0:
                _write_sep()
            self._emit_write_single(arg)
        _write_end()

    def _emit_print_single(self, node: ast.expr) -> None:
        """Emit print() for a single argument via FpyValue runtime dispatch.

        Evaluates the expression, wraps it into an FpyValue (tag, data),
        and calls fv_print which dispatches by tag at runtime. This replaces
        the old compile-time type dispatch (~50 lines of AST-level checks).
        """
        # For direct pyobj call results (e.g. calendar.monthrange()),
        # print via CPython's str() to preserve IntEnum names, custom
        # __repr__, etc. that would be lost by converting to FpyValue.
        if (isinstance(node, ast.Call)
                and isinstance(node.func, ast.Attribute)
                and self._is_pyobj_receiver(node.func.value)
                and not (isinstance(node.func.value, ast.Name)
                         and node.func.value.id in getattr(
                             self, '_native_modules', set()))
                # Also exclude chained native module calls: os.path.join(...)
                and not (isinstance(node.func.value, ast.Attribute)
                         and isinstance(node.func.value.value, ast.Name)
                         and (node.func.value.value.id + "." + node.func.value.attr)
                             in getattr(self, '_native_modules', set()))):
            ptr = self._emit_cpython_call_raw(node)
            ptr = self._ensure_ptr(ptr)
            self.builder.call(self.runtime["cpython_print_obj"], [ptr])
            self.builder.call(self.runtime["print_newline"], [])
            return
        # For pyobj variables, print via CPython's str() directly.
        # Exception: bridge call results are stored as FpyValue structs
        # (not raw PyObject*), so check _load_fv_raw first to route them
        # through the FV runtime dispatch path.
        if (isinstance(node, ast.Name)
                and node.id in self.variables
                and self._var_kind(node.id) == VKind.PYOBJ):
            fv = self._load_fv_raw(node.id)
            if fv is not None:
                # FpyValue-backed PYOBJ: use runtime dispatch
                tag, data = self._fv_unpack(fv)
                self.builder.call(self.runtime["fv_print"], [tag, data])
                return
            ptr = self._load_variable(node.id, node)
            ptr = self._ensure_ptr(ptr)
            self.builder.call(self.runtime["cpython_print_obj"], [ptr])
            self.builder.call(self.runtime["print_newline"], [])
            return
        # Ellipsis: print "Ellipsis" directly (no runtime tag for it)
        if isinstance(node, ast.Constant) and node.value is ...:
            str_ptr = self._make_string_constant("Ellipsis")
            self.builder.call(self.runtime["write_str"], [str_ptr])
            self.builder.call(self.runtime["print_newline"], [])
            return
        if isinstance(node, ast.Name) and node.id in self._ellipsis_vars:
            str_ptr = self._make_string_constant("Ellipsis")
            self.builder.call(self.runtime["write_str"], [str_ptr])
            self.builder.call(self.runtime["print_newline"], [])
            return
        # Exception variable .args → print as tuple
        if (isinstance(node, ast.Attribute) and node.attr == "args"
                and isinstance(node.value, ast.Name)
                and node.value.id in self._exc_vars):
            tup = self._emit_expr_value(node)
            tup = self._ensure_ptr(tup)
            tag = ir.Constant(i32, FPY_TAG_LIST)
            data = self.builder.ptrtoint(tup, i64)
            self.builder.call(self.runtime["fv_print"], [tag, data])
            return
        # Namedtuple instance: print with field names (Bug 13 fix).
        # Check if the variable is a known namedtuple instance; if so,
        # use namedtuple_print which includes the type name and field names.
        _nt_instances = getattr(self, '_namedtuple_instances', {})
        if (isinstance(node, ast.Name) and node.id in _nt_instances):
            _nt_info = _nt_instances[node.id]
            tup = self._emit_expr_value(node)
            tup = self._ensure_ptr(tup)
            # Find the variable holding the type_id: it's the key in
            # _namedtuple_types whose value matches this _nt_info.
            _nt_types = getattr(self, '_namedtuple_types', {})
            _type_var = None
            for _tv, _ti in _nt_types.items():
                if _ti is _nt_info or _ti.get("type_name") == _nt_info.get("type_name"):
                    _type_var = _tv
                    break
            if _type_var and _type_var in self.variables:
                type_id = self._load_variable(_type_var, node)
                if isinstance(type_id.type, ir.IntType) and type_id.type.width == 64:
                    type_id = self.builder.trunc(type_id, i32)
                self.builder.call(
                    self.runtime["namedtuple_print"], [tup, type_id])
                return
        fv = self._load_or_wrap_fv(node)
        self._emit_try_bail_if_exc()
        tag, data = self._fv_unpack(fv)
        self.builder.call(self.runtime["fv_print"], [tag, data])

    def _load_or_wrap_fv(self, node: ast.expr) -> ir.Value:
        """Get an FpyValue for `node`, preferring the raw stored FV when the
        node is a Name backed by an %fpyvalue alloca, a dict/list subscript,
        or an object attribute access. This preserves the runtime tag
        (which can differ from the compile-time inferred type for
        mixed-type containers and polymorphic attributes).
        """
        # --typed mode: native variable → box to FpyValue
        if (isinstance(node, ast.Name)
                and node.id in self._native_vars):
            native_val = self._load_variable(node.id, node)
            _, kind = self._native_vars[node.id]
            return self._typed_box_native(native_val, kind)
        # CPython pyobj-tagged variables: convert the PyObject* to a native
        # FpyValue via the bridge. Without this, the OBJ tag + raw PyObject*
        # data would crash fv_print (expects an FpyObj*, not PyObject*).
        # Exception: bridge call results are already stored as FpyValue structs
        # with correct runtime tags — return them directly without re-conversion.
        if (isinstance(node, ast.Name)
                and node.id in self.variables
                and self._var_kind(node.id) == VKind.PYOBJ):
            fv = self._load_fv_raw(node.id)
            if fv is not None:
                return fv  # already an FpyValue with correct runtime tag
            ptr = self._load_variable(node.id, node)
            ptr = self._ensure_ptr(ptr)
            tag_slot = self._create_entry_alloca(i32, "pyvar.tag")
            data_slot = self._create_entry_alloca(i64, "pyvar.data")
            # Use peek_fv (borrow, no decref) — the variable still holds
            # the PyObject* reference and may be accessed again later.
            self.builder.call(self.runtime["cpython_peek_fv"],
                              [ptr, tag_slot, data_slot])
            return self._fv_build_from_slots(
                self.builder.load(tag_slot),
                self.builder.load(data_slot))
        # Mixed-type variables (e.g. unpacked from heterogeneous tuple return):
        # the stored FpyValue has the correct runtime tag, load it directly
        # to preserve the type for print/comparison dispatch.
        if (isinstance(node, ast.Name)
                and node.id in self.variables
                and self._var_kind(node.id) == VKind.MIXED):
            fv = self._load_fv_raw(node.id)
            if fv is not None:
                return fv
        # pyobj subscript/attribute/call expressions: convert raw PyObject*
        # result to native FpyValue via cpython_to_fv for printing.
        _is_pyobj_print = False
        if isinstance(node, ast.Subscript):
            if (isinstance(node.value, ast.Name)
                    and node.value.id in self.variables
                    and self._var_kind(node.value.id) == VKind.PYOBJ):
                _is_pyobj_print = True
            elif self._is_pyobj_receiver(node.value):
                _is_pyobj_print = True
        # Attribute access on pyobj: http.HTTPStatus.OK.value, parsed.scheme
        # Exclude native module attributes and path variables — they have native handlers
        if isinstance(node, ast.Attribute) and self._is_pyobj_receiver(node.value):
            _is_native_mod_attr = (isinstance(node.value, ast.Name)
                                   and node.value.id in getattr(self, '_native_modules', set()))
            _is_path_attr = self._is_path_expr(node.value)
            if not _is_native_mod_attr and not _is_path_attr:
                _is_pyobj_print = True
        # Call on pyobj receiver: mimetypes.guess_type("file.txt")
        # Exclude native module calls — they have native handlers that return
        # correct native types, not raw PyObject*.
        if (isinstance(node, ast.Call)
                and isinstance(node.func, ast.Attribute)
                and self._is_pyobj_receiver(node.func.value)):
            # Check if this is a native module call with a native handler
            _has_native = False
            if isinstance(node.func.value, ast.Name):
                _nm = node.func.value.id
                if _nm in getattr(self, '_native_modules', set()):
                    _has_native = True
            # Chained native module: os.path.join(...) where "os.path" is native
            elif (isinstance(node.func.value, ast.Attribute)
                    and isinstance(node.func.value.value, ast.Name)):
                _dotted = node.func.value.value.id + "." + node.func.value.attr
                if _dotted in getattr(self, '_native_modules', set()):
                    _has_native = True
            if not _has_native:
                _is_pyobj_print = True
        if _is_pyobj_print:
            # For Call nodes on pyobj, use _emit_cpython_call_raw to get
            # a raw PyObject* (not an FpyValue-extracted i64).
            # Exclude both flat native module calls (os.getcwd()) and chained
            # native module calls (os.path.join()) — they return native types.
            _is_native_call = False
            if isinstance(node, ast.Call) and isinstance(node.func, ast.Attribute):
                if (isinstance(node.func.value, ast.Name)
                        and node.func.value.id in getattr(self, '_native_modules', set())):
                    _is_native_call = True
                elif (isinstance(node.func.value, ast.Attribute)
                        and isinstance(node.func.value.value, ast.Name)
                        and (node.func.value.value.id + "." + node.func.value.attr)
                            in getattr(self, '_native_modules', set())):
                    _is_native_call = True
            if (isinstance(node, ast.Call)
                    and isinstance(node.func, ast.Attribute)
                    and not _is_native_call):
                ptr = self._emit_cpython_call_raw(node)
            else:
                ptr = self._emit_expr_value(node)
            ptr = self._ensure_ptr(ptr)
            tag_slot = self._create_entry_alloca(i32, "pysub.cvt.tag")
            data_slot = self._create_entry_alloca(i64, "pysub.cvt.data")
            self.builder.call(self.runtime["cpython_to_fv"],
                              [ptr, tag_slot, data_slot])
            return self._fv_build_from_slots(
                self.builder.load(tag_slot),
                self.builder.load(data_slot))
        if (self._USE_FV_LOCALS and isinstance(node, ast.Name)
                and node.id in self.variables
                and node.id not in self._global_vars):
            alloca, type_tag = self.variables[node.id]
            if (self._tag_kind(type_tag) != VKind.CELL
                    and isinstance(alloca.type, ir.PointerType)
                    and alloca.type.pointee is fpy_val):
                fv = self.builder.load(alloca, name=f"{node.id}.fv")
                self._check_fv_undef(fv, node.id)
                return fv
        # defaultdict subscript: must use defaultdict_get for auto-default
        if (isinstance(node, ast.Subscript)
                and self._is_defaultdict_expr(node.value)
                and not isinstance(node.slice, ast.Slice)):
            obj = self._emit_expr_value(node.value)
            obj = self._ensure_ptr(obj)
            key = self._emit_expr_value(node.slice)
            tag_slot = self._create_entry_alloca(i32, "dd.fv.tag")
            data_slot = self._create_entry_alloca(i64, "dd.fv.data")
            if isinstance(key.type, ir.PointerType):
                self.builder.call(self.runtime["defaultdict_get"],
                                  [obj, key, tag_slot, data_slot])
            else:
                tag_c, data_c = self._bare_to_tag_data(key, node.slice)
                self.builder.call(self.runtime["defaultdict_get_fv"],
                                  [obj, ir.Constant(i32, tag_c), data_c,
                                   tag_slot, data_slot])
            return self._fv_build_from_slots(
                self.builder.load(tag_slot),
                self.builder.load(data_slot))
        # Counter subscript: returns 0 for missing keys (Python semantics).
        # Must come before the generic dict subscript handler.
        if (isinstance(node, ast.Subscript)
                and self._is_counter_expr(node.value)
                and not isinstance(node.slice, ast.Slice)):
            obj = self._emit_expr_value(node.value)
            obj = self._ensure_ptr(obj)
            key = self._emit_expr_value(node.slice)
            # Pre-build the zero FV before the branch (avoids PHI ordering issues)
            zero_fv = self._fv_build(FPY_TAG_INT, ir.Constant(i64, 0))
            if isinstance(key.type, ir.PointerType):
                has = self._rt_call("dict_has_key", [obj, key])
                has_bool = self.builder.icmp_unsigned("!=", has, ir.Constant(i32, 0))
                tag_slot = self._create_entry_alloca(i32, "ctr.fv.tag")
                data_slot = self._create_entry_alloca(i64, "ctr.fv.data")
                with_block = self._new_block("ctr.fv.found")
                merge_block = self._new_block("ctr.fv.merge")
                pre_branch_block = self.builder.block
                self.builder.cbranch(has_bool, with_block, merge_block)
                self.builder.position_at_end(with_block)
                self.builder.call(self.runtime["dict_get_fv"],
                                  [obj, key, tag_slot, data_slot])
                found_fv = self._fv_build_from_slots(
                    self.builder.load(tag_slot),
                    self.builder.load(data_slot))
                self.builder.branch(merge_block)
                found_block = self.builder.block
                self.builder.position_at_end(merge_block)
                phi = self.builder.phi(fpy_val, "ctr.fv.val")
                phi.add_incoming(found_fv, found_block)
                phi.add_incoming(zero_fv, pre_branch_block)
                return phi
            else:
                has = self._rt_call("dict_has_int_key", [obj, key])
                has_bool = self.builder.icmp_unsigned("!=", has, ir.Constant(i32, 0))
                with_block = self._new_block("ctr.fv.found")
                merge_block = self._new_block("ctr.fv.merge")
                pre_branch_block = self.builder.block
                self.builder.cbranch(has_bool, with_block, merge_block)
                self.builder.position_at_end(with_block)
                found_val = self.builder.call(
                    self.runtime["dict_get_int_val"], [obj, key])
                found_fv = self._fv_build(FPY_TAG_INT, found_val)
                self.builder.branch(merge_block)
                found_block = self.builder.block
                self.builder.position_at_end(merge_block)
                phi = self.builder.phi(fpy_val, "ctr.fv.val")
                phi.add_incoming(found_fv, found_block)
                phi.add_incoming(zero_fv, pre_branch_block)
                return phi
        # Dict subscript: load the FV directly to preserve the runtime tag
        # (avoids the dict-with-int / dict-with-list heuristic for printing).
        if (isinstance(node, ast.Subscript)
                and self._is_dict_expr(node.value)
                and not isinstance(node.slice, ast.Slice)):
            obj = self._emit_expr_value(node.value)
            obj = self._ensure_ptr(obj)
            key = self._emit_expr_value(node.slice)
            # Tuple/list keys: use generic FpyValue-keyed getter
            _key_is_tuple = (isinstance(node.slice, (ast.Tuple, ast.List))
                             or (isinstance(node.slice, ast.Name)
                                 and node.slice.id in self.variables
                                 and self._var_kind(node.slice.id)
                                 in (VKind.LIST, VKind.TUPLE)))
            if _key_is_tuple:
                kt, kd = self._bare_to_tag_data(key, node.slice)
                if (not isinstance(kd, ir.Constant)
                        and isinstance(kd.type, ir.PointerType)):
                    kd = self.builder.ptrtoint(kd, i64)
                tag_slot = self._create_entry_alloca(i32, "dget.tag")
                data_slot = self._create_entry_alloca(i64, "dget.data")
                self.builder.call(self.runtime["dict_get_kv_fv"],
                                  [obj, ir.Constant(i32, kt), kd,
                                   tag_slot, data_slot])
                return self._fv_build_from_slots(
                    self.builder.load(tag_slot),
                    self.builder.load(data_slot))
            # FpyValue key (from fpy_val variable, e.g. key from dict
            # iteration stored in an fpy_val alloca): extract tag+data and
            # use the generic kv_fv getter which handles all key types.
            if (isinstance(key.type, ir.LiteralStructType)
                    and key.type == fpy_val):
                key_tag = self.builder.extract_value(key, 0)
                key_data = self.builder.extract_value(key, 1)
                tag_slot = self._create_entry_alloca(i32, "dget.tag")
                data_slot = self._create_entry_alloca(i64, "dget.data")
                self.builder.call(self.runtime["dict_get_kv_fv"],
                                  [obj, key_tag, key_data,
                                   tag_slot, data_slot])
                return self._fv_build_from_slots(
                    self.builder.load(tag_slot),
                    self.builder.load(data_slot))
            if isinstance(key.type, ir.PointerType):
                tag_slot = self._create_entry_alloca(i32, "dget.tag")
                data_slot = self._create_entry_alloca(i64, "dget.data")
                self.builder.call(self.runtime["dict_get_fv"],
                                  [obj, key, tag_slot, data_slot])
                return self._fv_build_from_slots(
                    self.builder.load(tag_slot),
                    self.builder.load(data_slot))
            # i64 integer key (e.g. from sorted(dict) with int keys)
            if isinstance(key.type, ir.IntType) and key.type.width == 64:
                tag_slot = self._create_entry_alloca(i32, "dget.tag")
                data_slot = self._create_entry_alloca(i64, "dget.data")
                self.builder.call(self.runtime["dict_get_int_fv"],
                                  [obj, key, tag_slot, data_slot])
                return self._fv_build_from_slots(
                    self.builder.load(tag_slot),
                    self.builder.load(data_slot))
        # List / tuple subscript: load FV directly for runtime-tag print.
        # Tuples can have heterogeneous types (int, str, float, etc.),
        # so the only correct way to access an element is via the runtime
        # tag.
        if (isinstance(node, ast.Subscript)
                and (self._is_list_expr(node.value)
                     or self._is_tuple_expr(node.value))
                and not isinstance(node.slice, ast.Slice)):
            obj = self._emit_expr_value(node.value)
            index = self._emit_expr_value(node.slice)
            tag, data = self._fv_list_get(obj, index)
            return self._fv_build_from_slots(tag, data)
        # FV-backed "unknown" type variable subscript: the variable holds
        # an FpyValue whose runtime tag determines the container type (list,
        # dict, str).  Use fv_subscript for runtime dispatch instead of
        # assuming list.
        if (isinstance(node, ast.Subscript)
                and isinstance(node.value, ast.Name)
                and node.value.id in self.variables
                and not isinstance(node.slice, ast.Slice)):
            _unk_alloca, _unk_tag = self.variables[node.value.id]
            if (self._tag_kind(_unk_tag) in (VKind.UNKNOWN, VKind.FVALUE, VKind.MIXED)
                    and isinstance(_unk_alloca.type, ir.PointerType)
                    and _unk_alloca.type.pointee is fpy_val):
                # Load the container's runtime tag and data
                _fv = self._load_fv_raw(node.value.id)
                _c_tag = self._fv_tag(_fv)
                _c_data = self._fv_data_i64(_fv)
                # Load the key and convert to tag+data
                _k_tag_ir, _k_data_ir = self._expr_to_tag_data(node.slice)
                tag_slot = self._create_entry_alloca(i32, "ufv.tag")
                data_slot = self._create_entry_alloca(i64, "ufv.data")
                self.builder.call(self.runtime["fv_subscript"],
                                  [_c_tag, _c_data,
                                   _k_tag_ir, _k_data_ir,
                                   tag_slot, data_slot])
                return self._fv_build_from_slots(
                    self.builder.load(tag_slot),
                    self.builder.load(data_slot))
        # CPython module attribute (e.g. math.pi, string.ascii_lowercase)
        # — must come BEFORE the generic Attribute handler which calls
        # obj_get_fv.  For natively-handled attrs, return the constant;
        # for everything else, fall through to cpython_getattr bridge.
        if (isinstance(node, ast.Attribute)
                and isinstance(node.value, ast.Name)):
            _nm = node.value.id
            _is_native = ((self._has_var(_nm)
                          and self._var_kind(_nm) in (
                              VKind.PYOBJ, VKind.NATIVE_MOD))
                         or _nm in getattr(self, '_native_modules', set()))
            if _is_native:
                val = self._emit_native_module_attr(_nm, node.attr)
                if val is not None:
                    return self._wrap_for_print(val, node)
                # No native handler — fall through to CPython bridge
                obj = self._load_variable(_nm, node)
                obj = self._ensure_ptr(obj)
                attr_name = self._make_string_constant(node.attr)
                pyobj = self.builder.call(
                    self.runtime["cpython_getattr"], [obj, attr_name])
                tag_slot = self._create_entry_alloca(i32, "natmod.tag")
                data_slot = self._create_entry_alloca(i64, "natmod.data")
                self.builder.call(self.runtime["cpython_to_fv"],
                                  [pyobj, tag_slot, data_slot])
                return self._fv_build_from_slots(
                    self.builder.load(tag_slot),
                    self.builder.load(data_slot))
        # Native module call in print context (print(math.sqrt(x)))
        if (isinstance(node, ast.Call)
                and isinstance(node.func, ast.Attribute)
                and isinstance(node.func.value, ast.Name)):
            _nm = node.func.value.id
            _is_native = ((self._has_var(_nm)
                          and self._var_kind(_nm) == VKind.PYOBJ)
                         or _nm in getattr(self, '_native_modules', set()))
            if _is_native:
                val = self._emit_native_module_call(
                    _nm, node.func.attr, node)
                if val is not None:
                    return self._wrap_for_print(val, node)
        if (isinstance(node, ast.Attribute)
                and isinstance(node.value, ast.Name)
                and node.value.id in self.variables
                and self._var_kind(node.value.id) == VKind.PYOBJ):
            obj = self._load_variable(node.value.id, node)
            obj = self._ensure_ptr(obj)
            attr_name = self._make_string_constant(node.attr)
            pyobj = self.builder.call(
                self.runtime["cpython_getattr"], [obj, attr_name])
            tag_slot = self._create_entry_alloca(i32, "pyattr.tag")
            data_slot = self._create_entry_alloca(i64, "pyattr.data")
            self.builder.call(self.runtime["cpython_to_fv"],
                              [pyobj, tag_slot, data_slot])
            return self._fv_build_from_slots(
                self.builder.load(tag_slot),
                self.builder.load(data_slot))
        # Nested class chained access: Outer.Inner.x
        if (isinstance(node, ast.Attribute)
                and isinstance(node.value, ast.Attribute)
                and isinstance(node.value.value, ast.Name)
                and node.value.value.id in self._user_classes
                and node.value.attr in self._user_classes):
            inner_class = node.value.attr
            const_attrs = self._class_const_attrs.get(inner_class, {})
            if node.attr in const_attrs:
                val = self._emit_expr_value(const_attrs[node.attr])
                return self._wrap_for_print(val, node)

        # type(X).__name__ pattern — resolved at compile time
        # Works for any arg (Name, Call, etc.) — no ast.Name restriction
        if (isinstance(node, ast.Attribute) and node.attr == "__name__"
                and isinstance(node.value, ast.Call)
                and isinstance(node.value.func, ast.Name)
                and node.value.func.id == "type"
                and len(node.value.args) == 1):
            value = self._emit_expr_value(node)
            return self._wrap_for_print(value, node)
        # @property dispatch in FV context: call the getter and wrap result
        if isinstance(node, ast.Attribute):
            prop_cls = self._infer_object_class(node.value)
            if prop_cls:
                prop_info = self._user_classes.get(prop_cls)
                if (prop_info and prop_info.properties
                        and node.attr in prop_info.properties):
                    obj = self._emit_expr_value(node.value)
                    obj = self._ensure_ptr(obj)
                    method_func = prop_info.methods.get(node.attr)
                    if method_func:
                        result = self.builder.call(method_func, [obj])
                        return self._wrap_for_print(result, node)
        # Complex attribute access: z.real, z.imag — evaluate via
        # _emit_expr_value which has the GEP-based field access handler.
        if (isinstance(node, ast.Attribute)
                and node.attr in ("real", "imag")
                and self._is_complex_expr(node.value)):
            val = self._emit_expr_value(node)
            return self._wrap_for_print(val, node)
        # Path attribute access in FV context: evaluate the path expression
        # normally and wrap the result for the correct FpyValue tag.  Must come
        # before the generic obj handler which would call obj_get_fv on a PyObject*.
        if isinstance(node, ast.Attribute) and self._is_path_expr(node.value):
            val = self._emit_expr_value(node)
            return self._wrap_for_print(val, node)
        # Function/class dunder attribute: func.__name__, Class.__name__
        # Functions and classes are not FpyObj instances, so obj_get_fv
        # would segfault.  Return the name as a compile-time string constant.
        if (isinstance(node, ast.Attribute)
                and node.attr in ("__name__", "__qualname__")
                and isinstance(node.value, ast.Name)):
            _dunder_name = node.value.id
            if (_dunder_name in self._user_functions
                    or _dunder_name in self._user_classes):
                s = self._make_string_constant(_dunder_name)
                return self._fv_from_str(s)
            # Resolve function aliases: fn = add → fn.__name__ → "add"
            _resolved = self._resolve_func_alias(_dunder_name)
            if _resolved in self._user_functions:
                s = self._make_string_constant(_resolved)
                return self._fv_from_str(s)
            # Variable holding a callable (closure, function pointer, or
            # captured function parameter).  These are NOT FpyObj instances,
            # so obj_get_fv would segfault.  Return the resolved name (or
            # variable name as fallback) as a compile-time string.
            # Exclude types that may hold real objects at runtime (OBJ,
            # FVALUE, etc.) — those need runtime attribute access.
            if _dunder_name in self.variables:
                _vk = self._var_kind(_dunder_name)
                if _vk not in (VKind.OBJ, VKind.DICT, VKind.LIST,
                               VKind.TUPLE, VKind.SET, VKind.PYOBJ,
                               VKind.FVALUE):
                    s = self._make_string_constant(_resolved)
                    return self._fv_from_str(s)
        # Class.__mro__ → return a tuple of type proxy objects as FV(LIST)
        if (isinstance(node, ast.Attribute)
                and node.attr == "__mro__"
                and isinstance(node.value, ast.Name)
                and node.value.id in self._user_classes):
            tup = self._emit_mro_tuple(node.value.id)
            return self._fv_from_list(tup)
        # Object attribute access: load the FV directly via obj_get_slot
        # (or obj_get_fv as fallback) so the runtime tag is preserved.
        if (isinstance(node, ast.Attribute)
                and not (isinstance(node.value, ast.Name)
                         and node.value.id in self._user_classes)):
            obj = self._emit_expr_value(node.value)
            if isinstance(obj.type, ir.IntType) and obj.type.width == 64:
                obj = self._ensure_ptr(obj, name="obj.ptr")
            if isinstance(obj.type, ir.PointerType):
                slot_idx = self._get_attr_slot(node)
                if slot_idx is not None:
                    init_only = self._is_init_only_attr(node)
                    tag_val, data_val = self._emit_slot_get_direct(
                        obj, slot_idx, init_only=init_only)
                    return self._fv_build_from_slots(tag_val, data_val)
                tag_slot = self._create_entry_alloca(i32, "aget.tag")
                data_slot = self._create_entry_alloca(i64, "aget.data")
                attr_name = self._make_string_constant(node.attr)
                self.builder.call(self.runtime["obj_get_fv"],
                                  [obj, attr_name, tag_slot, data_slot])
                return self._fv_build_from_slots(
                    self.builder.load(tag_slot),
                    self.builder.load(data_slot))
        # Closure call: read fpy_ret_tag to get the runtime tag.
        # Must come BEFORE the user-function check — a decorated function
        # exists in both self._user_functions (original) and self.variables
        # (decorated closure).  The closure variable takes priority.
        if (isinstance(node, ast.Call) and isinstance(node.func, ast.Name)
                and node.func.id in self.variables
                and self._var_kind(node.func.id) == VKind.CLOSURE):
            data = self._emit_expr_value(node)
            # _emit_closure_call may already return FpyValue (e.g., when
            # the closure call dispatches through call_ptr + get_ret_tag).
            if (isinstance(data.type, ir.LiteralStructType)
                    and data.type == fpy_val):
                return data
            # Read the tag stored by the closure body's ret instruction
            tag = self.builder.call(self.runtime["get_ret_tag"], [])
            if isinstance(data.type, ir.PointerType):
                data = self.builder.ptrtoint(data, i64)
            elif isinstance(data.type, ir.IntType) and data.type.width != 64:
                data = self.builder.zext(data, i64)
            return self._fv_build_from_slots(tag, data)
        # User function call returning FpyValue: emit the call and return the
        # FV directly, preserving the runtime tag from the callee. Without
        # this, _emit_user_call unwraps based on the static return type,
        # losing the runtime tag for polymorphic returns.
        if (isinstance(node, ast.Call) and isinstance(node.func, ast.Name)
                and node.func.id in self._user_functions):
            info = self._user_functions[node.func.id]
            if info.uses_fv_abi and info.ret_tag != "void":
                return self._emit_user_call_fv(node)
        # CPython module method call (e.g. math.sqrt(x)) — returns FpyValue
        # with the runtime tag set by the bridge's type conversion.
        # Also handles chained attrs: os.path.exists(x) where os is pyobj.
        if isinstance(node, ast.Call) and isinstance(node.func, ast.Attribute):
            recv = node.func.value
            is_pyobj_recv = (
                (isinstance(recv, ast.Name)
                 and recv.id in self.variables
                 and self._var_kind(recv.id) == VKind.PYOBJ)
                or (isinstance(recv, ast.Attribute)
                    and isinstance(recv.value, ast.Name)
                    and recv.value.id in self.variables
                    and self._var_kind(recv.value.id) == VKind.PYOBJ))
            if is_pyobj_recv:
                return self._emit_cpython_method_call(node)
        # Direct CPython callable (from `from module import func`)
        if (isinstance(node, ast.Call)
                and isinstance(node.func, ast.Name)
                and node.func.id in self.variables
                and self._var_kind(node.func.id) == VKind.PYOBJ):
            return self._emit_cpython_direct_call_expr(node)
        # Method call on user-class object returning i64: the method body
        # calls set_ret_tag() before returning, so read get_ret_tag() to
        # recover the runtime type.  Without this, methods returning
        # dynamic types (e.g. list.pop() returns string but method
        # signature is i64) get the wrong tag (hardcoded INT).
        # Only apply for i64 returns — i8_ptr (str) and double (float)
        # already have correct static types from the method signature.
        if (isinstance(node, ast.Call)
                and isinstance(node.func, ast.Attribute)
                and isinstance(node.func.value, ast.Name)
                and node.func.value.id in self.variables
                and self._var_kind(node.func.value.id) == VKind.OBJ):
            data = self._emit_expr_value(node)
            if (isinstance(data.type, ir.LiteralStructType)
                    and data.type == fpy_val):
                return data  # already an FpyValue
            # Only use get_ret_tag for i64 returns (ambiguous type).
            # Pointer returns are strings, double returns are floats.
            if isinstance(data.type, ir.IntType) and data.type.width == 64:
                tag = self.builder.call(self.runtime["get_ret_tag"], [])
                return self._fv_build_from_slots(tag, data)
        value = self._emit_expr_value(node)
        # If the value is already an FpyValue struct (e.g., from eval()),
        # return it directly — no wrapping needed.
        if (isinstance(value.type, ir.LiteralStructType)
                and value.type == fpy_val):
            return value
        return self._wrap_for_print(value, node)

    def _wrap_for_print(self, value: ir.Value, node: ast.expr) -> ir.Value:
        """Wrap a bare LLVM value into an FpyValue for printing.

        Uses AST-level type checks for pointer disambiguation (str vs list
        vs dict vs tuple vs obj). Falls back to LLVM type for scalars.
        """
        # Already an FpyValue struct — return as-is (e.g. json.loads() result)
        if (isinstance(value.type, ir.LiteralStructType)
                and value.type == fpy_val):
            return value
        # Constants: inline the tag
        if isinstance(node, ast.Constant):
            if node.value is None:
                return self._fv_none()
            if isinstance(node.value, bool):
                return self._fv_from_bool(value)
            if (isinstance(node.value, int)
                    and (node.value > 2**63 - 1 or node.value < -(2**63))):
                return self._fv_build_from_slots(
                    ir.Constant(i32, FPY_TAG_BIGINT), value)
            if isinstance(node.value, complex):
                return self._fv_build_from_slots(
                    ir.Constant(i32, FPY_TAG_COMPLEX), value)

        # Constant-folded BigInt: BinOp that evaluated to a big int at compile time
        if isinstance(node, ast.BinOp):
            folded = self._try_constant_fold(node)
            if (folded is not None and isinstance(folded, int)
                    and (folded > 2**63 - 1 or folded < -(2**63))):
                return self._fv_build_from_slots(
                    ir.Constant(i32, FPY_TAG_BIGINT), value)
        # Negation of BigInt expression
        if (isinstance(node, ast.UnaryOp) and isinstance(node.op, ast.USub)):
            inner = node.operand
            if isinstance(inner, ast.BinOp):
                folded = self._try_constant_fold(inner)
                if (folded is not None and isinstance(folded, int)
                        and (folded > 2**63 - 1 or folded < -(2**63))):
                    return self._fv_build_from_slots(
                        ir.Constant(i32, FPY_TAG_BIGINT), value)

        # Named variables: use the variable's stored type_tag (survives load/unwrap)
        if isinstance(node, ast.Name) and node.id in self.variables:
            vk = self._var_kind(node.id)
            if vk == VKind.MIXED:
                # Mixed-type: runtime tag determines actual type.
                # If value is already an fpy_val struct, return as-is.
                if (isinstance(value.type, ir.LiteralStructType)
                        and value.type == fpy_val):
                    return value
                # Otherwise load the raw FpyValue from the alloca.
                fv = self._load_fv_raw(node.id)
                if fv is not None:
                    return fv
            if vk == VKind.NONE:
                return self._fv_none()
            if vk == VKind.BOOL:
                return self._fv_from_bool(value)
            if vk == VKind.DICT:
                return self._fv_from_dict(value)
            if vk == VKind.OBJ:
                return self._fv_from_obj(value)
            if vk in (VKind.LIST, VKind.TUPLE):
                return self._fv_from_list(value)
            if vk == VKind.STR:
                return self._fv_from_str(value)
            if vk == VKind.FLOAT:
                return self._fv_from_float(value)
            if vk == VKind.INT:
                return self._fv_from_int(value)
            if vk == VKind.BIGINT:
                return self._fv_build_from_slots(
                    ir.Constant(i32, FPY_TAG_BIGINT), value)
            if vk == VKind.COMPLEX:
                return self._fv_build_from_slots(
                    ir.Constant(i32, FPY_TAG_COMPLEX), value)
            if vk == VKind.DECIMAL:
                return self._fv_build_from_slots(
                    ir.Constant(i32, FPY_TAG_DECIMAL), value)
            if vk == VKind.BYTES:
                return self._fv_build_from_slots(
                    ir.Constant(i32, FPY_TAG_BYTES), value)
            if vk == VKind.SET:
                return self._fv_build_from_slots(
                    ir.Constant(i32, FPY_TAG_SET), value)

        # Expression-level type inference (e.g. print(a + b), print(glob.glob(x)))
        inferred = self._infer_type_tag(node, value)
        inf_kind = inferred.kind
        if inf_kind == VKind.BOOL:
            if isinstance(value.type, ir.IntType) and value.type.width != 32:
                value = self.builder.trunc(value, i32)
            return self._fv_from_bool(value)
        if inf_kind == VKind.COMPLEX:
            return self._fv_build_from_slots(
                ir.Constant(i32, FPY_TAG_COMPLEX), value)
        if inf_kind == VKind.DECIMAL:
            return self._fv_build_from_slots(
                ir.Constant(i32, FPY_TAG_DECIMAL), value)
        if inf_kind == VKind.BYTES:
            return self._fv_build_from_slots(
                ir.Constant(i32, FPY_TAG_BYTES), value)

        # Containers: tag from AST or inferred type
        if isinstance(value.type, ir.PointerType):
            if inf_kind == VKind.BIGINT:
                ptr_as_i64 = self.builder.ptrtoint(value, i64)
                return self._fv_build_from_slots(
                    ir.Constant(i32, FPY_TAG_BIGINT), ptr_as_i64)
            if inf_kind in (VKind.LIST, VKind.TUPLE):
                return self._fv_from_list(value)
            if inf_kind in _DICT_LIKE:
                return self._fv_from_dict(value)
            if inf_kind == VKind.SET:
                return self._fv_build_from_slots(
                    ir.Constant(i32, FPY_TAG_SET), value)
            if self._is_list_expr(node):
                return self._fv_from_list(value)
            if self._is_tuple_expr(node):
                return self._fv_from_list(value)  # tuples are lists with is_tuple
            if self._is_dict_expr(node):
                return self._fv_from_dict(value)
            if self._is_set_expr(node):
                return self._fv_build_from_slots(
                    ir.Constant(i32, FPY_TAG_SET), value)
            if self._is_obj_expr(node):
                return self._fv_from_obj(value)
            # Check function calls that return strings
            if isinstance(node, ast.Call) and isinstance(node.func, ast.Name):
                name = node.func.id
                if (name in self._user_functions
                        and self._tag_kind(
                            self._user_functions[name].ret_tag
                        ) == VKind.STR):
                    return self._fv_from_str(value)
            # Default pointer: string
            return self._fv_from_str(value)

        # BoolOp where all operands are boolean-typed: tag as BOOL.
        # (BoolOp uses an i64 alloca internally, so the LLVM type is i64,
        #  but in Python `True and False` is a bool, not an int.)
        if isinstance(node, ast.BoolOp) and all(
                self._is_bool_typed(v) for v in node.values):
            if isinstance(value.type, ir.IntType) and value.type.width == 64:
                value = self.builder.trunc(value, i32)
            return self._fv_from_bool(value)

        # Object method calls returning bool (i32 from _declare_class) —
        # the dispatch wrapper returns i64, so we need AST-level detection.
        if (isinstance(node, ast.Call)
                and isinstance(node.func, ast.Attribute)
                and isinstance(value.type, ir.IntType)
                and value.type.width == 64):
            ret = self._find_method_return_type(node.func.value, node.func.attr)
            if ret is not None and isinstance(ret, ir.IntType) and ret.width == 32:
                value = self.builder.trunc(value, i32)
                return self._fv_from_bool(value)

        # Compare and bool-typed expressions returning i64
        if (isinstance(value.type, ir.IntType) and value.type.width == 64
                and isinstance(node, ast.Compare)):
            return self._fv_from_bool(value)
        if (isinstance(value.type, ir.IntType) and value.type.width == 64
                and self._is_bool_typed(node)):
            return self._fv_from_bool(value)

        # Scalars: tag from LLVM type
        if isinstance(value.type, ir.IntType):
            if value.type.width == 32:
                return self._fv_from_bool(value)
            return self._fv_from_int(value)
        if isinstance(value.type, ir.DoubleType):
            return self._fv_from_float(value)
        # Fallback
        return self._fv_from_int(value)

    def _infer_tuple_return_pos_types(
            self, call_node: ast.expr, n_targets: int
    ) -> 'dict[int, ValueType]':
        """Analyze a function call returning a tuple to get per-position types.

        For `a, b, c = f()`, inspects `f`'s return statement to determine the
        type of each tuple position.  Returns a dict mapping position index to
        ValueType.  Returns empty dict if the call is not a user function or the
        return is not a simple tuple literal.
        """
        if not (isinstance(call_node, ast.Call)
                and isinstance(call_node.func, ast.Name)
                and call_node.func.id in self._user_functions):
            return {}
        fname = call_node.func.id
        info = self._user_functions[fname]
        # Look up the function's AST from CSA analysis
        _csa_funcs = getattr(self, '_csa_func_asts', {})
        func_ast = _csa_funcs.get(fname)
        if func_ast is None:
            return {}
        # Find the return statement with a tuple literal
        ret_tuple = None
        for node in ast.walk(func_ast):
            if isinstance(node, ast.Return) and isinstance(node.value, ast.Tuple):
                ret_tuple = node.value
                break
        if ret_tuple is None or len(ret_tuple.elts) != n_targets:
            return {}
        # Build param_name → call_arg_index mapping for the call site
        param_names = [a.arg for a in func_ast.args.args]
        # Map param_name → call-site argument AST node
        param_to_arg: dict[str, ast.expr] = {}
        for pi, pname in enumerate(param_names):
            if pi < len(call_node.args):
                param_to_arg[pname] = call_node.args[pi]
        # Infer type per position
        pos_types: dict[int, ValueType] = {}
        all_same = True
        first_kind = None
        for i, elt in enumerate(ret_tuple.elts):
            kind = self._infer_elt_kind(elt, func_ast, param_to_arg)
            if first_kind is None:
                first_kind = kind
            elif kind != first_kind:
                all_same = False
            pos_types[i] = ValueType(kind)
        # If all positions have the same type, no per-position override needed
        if all_same:
            return {}
        return pos_types

    @staticmethod
    def _infer_elt_kind(elt: ast.expr,
                        func_ast: ast.FunctionDef,
                        param_to_arg: 'dict[str, ast.expr]') -> 'VKind':
        """Infer the VKind of a tuple element from its AST node.

        Uses constants directly, type annotations, and call-site argument
        types (param_to_arg maps parameter names to the Call's arg AST nodes).
        """
        if isinstance(elt, ast.Constant):
            if isinstance(elt.value, bool):
                return VKind.BOOL
            if isinstance(elt.value, int):
                return VKind.INT
            if isinstance(elt.value, float):
                return VKind.FLOAT
            if isinstance(elt.value, str):
                return VKind.STR
            if elt.value is None:
                return VKind.NONE
        if isinstance(elt, (ast.List, ast.ListComp)):
            return VKind.LIST
        if isinstance(elt, ast.Tuple):
            return VKind.TUPLE
        if isinstance(elt, (ast.Dict, ast.DictComp)):
            return VKind.DICT
        if isinstance(elt, (ast.Set, ast.SetComp)):
            return VKind.SET
        if isinstance(elt, ast.JoinedStr):
            return VKind.STR
        if isinstance(elt, (ast.Compare, ast.BoolOp)):
            return VKind.BOOL
        if isinstance(elt, ast.Call) and isinstance(elt.func, ast.Name):
            _builtin_ret = {
                "str": VKind.STR, "int": VKind.INT, "float": VKind.FLOAT,
                "bool": VKind.BOOL, "list": VKind.LIST, "dict": VKind.DICT,
                "set": VKind.SET, "tuple": VKind.TUPLE, "len": VKind.INT,
                "abs": VKind.INT, "ord": VKind.INT, "chr": VKind.STR,
                "hex": VKind.STR, "oct": VKind.STR, "bin": VKind.STR,
                "repr": VKind.STR, "round": VKind.INT,
            }
            if elt.func.id in _builtin_ret:
                return _builtin_ret[elt.func.id]
        if isinstance(elt, ast.BinOp):
            # String concat: "a" + "b" → STR
            if isinstance(elt.op, ast.Add):
                if (isinstance(elt.left, ast.Constant)
                        and isinstance(elt.left.value, str)):
                    return VKind.STR
                if (isinstance(elt.right, ast.Constant)
                        and isinstance(elt.right.value, str)):
                    return VKind.STR
            # Float arithmetic: check if ANY sub-expression in the
            # BinOp tree contains a float constant.  This catches
            # `a / (2.0 - b - c)` where 2.0 is in a nested BinOp.
            if any(isinstance(n, ast.Constant) and isinstance(n.value, float)
                   for n in ast.walk(elt)):
                return VKind.FLOAT
        if isinstance(elt, ast.Name):
            # Check parameter types by looking for type annotations
            for arg in func_ast.args.args:
                if arg.arg == elt.id and arg.annotation:
                    if isinstance(arg.annotation, ast.Name):
                        _ann = arg.annotation.id
                        if _ann == "str":
                            return VKind.STR
                        if _ann == "float":
                            return VKind.FLOAT
                        if _ann == "int":
                            return VKind.INT
                        if _ann == "bool":
                            return VKind.BOOL
            # Infer from call-site argument type
            if elt.id in param_to_arg:
                arg_node = param_to_arg[elt.id]
                if isinstance(arg_node, ast.Constant):
                    if isinstance(arg_node.value, bool):
                        return VKind.BOOL
                    if isinstance(arg_node.value, int):
                        return VKind.INT
                    if isinstance(arg_node.value, float):
                        return VKind.FLOAT
                    if isinstance(arg_node.value, str):
                        return VKind.STR
            # Check local variable assignment in function body.
            # A variable may be assigned in multiple branches
            # (e.g. `s = a / b` in one branch, `s = a / (2.0 - c)`
            # in another).  Continue past INT (the default) so that a
            # branch with an explicit float constant is found.
            for stmt in ast.walk(func_ast):
                if (isinstance(stmt, ast.Assign)
                        and len(stmt.targets) == 1
                        and isinstance(stmt.targets[0], ast.Name)
                        and stmt.targets[0].id == elt.id):
                    # Recurse on the RHS to determine type
                    rhs_kind = CodeGen._infer_elt_kind(
                        stmt.value, func_ast, param_to_arg)
                    if rhs_kind != VKind.INT:
                        return rhs_kind
                    # INT might be the default — keep looking at
                    # other assignments (e.g. in else branches).
        # Default: unknown → INT
        return VKind.INT

    def _infer_dict_value_kind(self, dict_node: ast.expr) -> 'VKind':
        """Infer the VKind of values in a dict expression.
        Checks dict literals and variable assignments for uniform value types.
        """
        _dict_ast = None
        if isinstance(dict_node, ast.Dict):
            _dict_ast = dict_node
        elif isinstance(dict_node, ast.Name):
            tree = getattr(self, "_csa_root_tree", None)
            if tree is not None:
                for n in ast.walk(tree):
                    if (isinstance(n, ast.Assign)
                            and len(n.targets) == 1
                            and isinstance(n.targets[0], ast.Name)
                            and n.targets[0].id == dict_node.id
                            and isinstance(n.value, ast.Dict)):
                        _dict_ast = n.value
                        break
            if _dict_ast is None:
                for stmt in getattr(self, '_current_scope_stmts', []):
                    if (isinstance(stmt, ast.Assign)
                            and len(stmt.targets) == 1
                            and isinstance(stmt.targets[0], ast.Name)
                            and stmt.targets[0].id == dict_node.id
                            and isinstance(stmt.value, ast.Dict)):
                        _dict_ast = stmt.value
                        break
        if _dict_ast is not None and _dict_ast.values:
            all_float = all(
                isinstance(v, ast.Constant) and isinstance(v.value, float)
                for v in _dict_ast.values)
            if all_float:
                return VKind.FLOAT
            all_int = all(
                isinstance(v, ast.Constant) and isinstance(v.value, int)
                and not isinstance(v.value, bool)
                for v in _dict_ast.values)
            if all_int:
                return VKind.INT
            all_str = all(
                isinstance(v, ast.Constant) and isinstance(v.value, str)
                for v in _dict_ast.values)
            if all_str:
                return VKind.STR
        return VKind.UNKNOWN

    def _infer_tuple_subscript_type(
            self, list_node: ast.expr, index: int) -> 'VKind':
        """For a list of tuples, infer the VKind of element at `index`
        within each tuple.  Scans the literal or assignment AST for the
        first tuple and checks the element at the given position.

        Returns VKind.STR, VKind.INT, VKind.FLOAT, or VKind.UNKNOWN.
        """
        # Direct list literal: [(1, 'a'), (2, 'b')]
        _list_ast = None
        if isinstance(list_node, (ast.List, ast.Tuple)):
            _list_ast = list_node
        elif isinstance(list_node, ast.Name):
            # Look up the assignment in CSA root tree
            tree = getattr(self, "_csa_root_tree", None)
            if tree is not None:
                for n in ast.walk(tree):
                    if (isinstance(n, ast.Assign)
                            and len(n.targets) == 1
                            and isinstance(n.targets[0], ast.Name)
                            and n.targets[0].id == list_node.id
                            and isinstance(n.value, (ast.List, ast.Tuple))):
                        _list_ast = n.value
                        break
            # Also check current scope statements
            if _list_ast is None:
                for stmt in getattr(self, '_current_scope_stmts', []):
                    if (isinstance(stmt, ast.Assign)
                            and len(stmt.targets) == 1
                            and isinstance(stmt.targets[0], ast.Name)
                            and stmt.targets[0].id == list_node.id
                            and isinstance(stmt.value, (ast.List, ast.Tuple))):
                        _list_ast = stmt.value
                        break
        if _list_ast is not None and _list_ast.elts:
            first = _list_ast.elts[0]
            if isinstance(first, ast.Tuple) and index < len(first.elts):
                elem = first.elts[index]
                if isinstance(elem, ast.Constant):
                    if isinstance(elem.value, str):
                        return VKind.STR
                    elif isinstance(elem.value, float):
                        return VKind.FLOAT
                    elif isinstance(elem.value, int):
                        return VKind.INT
                elif isinstance(elem, (ast.List, ast.ListComp)):
                    return VKind.LIST
                elif isinstance(elem, (ast.Dict, ast.DictComp)):
                    return VKind.DICT
                elif isinstance(elem, ast.JoinedStr):
                    return VKind.STR
        return VKind.UNKNOWN

    def _key_lambda_attr_type(
            self, list_node: ast.expr, attr_name: str) -> str | None:
        """For sorted(objs, key=lambda o: o.attr), determine if attr is
        a string.  Uses the list element class and
        _infer_attr_type_from_init to check the attribute type.
        """
        # Identify the class of list elements. Look at:
        #  1. List literal with constructor calls: [Cls(...), Cls(...)]
        #  2. Variable assigned from a list comp or literal with constructors
        _elem_cls = None
        if isinstance(list_node, (ast.List, ast.Tuple)):
            for elt in list_node.elts:
                if (isinstance(elt, ast.Call)
                        and isinstance(elt.func, ast.Name)
                        and elt.func.id in self._user_classes):
                    _elem_cls = elt.func.id
                    break
        elif isinstance(list_node, ast.Name):
            tree = getattr(self, "_csa_root_tree", None)
            if tree is not None:
                for n in ast.walk(tree):
                    if (isinstance(n, ast.Assign)
                            and len(n.targets) == 1
                            and isinstance(n.targets[0], ast.Name)
                            and n.targets[0].id == list_node.id):
                        if isinstance(n.value, (ast.List, ast.Tuple)):
                            for elt in n.value.elts:
                                if (isinstance(elt, ast.Call)
                                        and isinstance(elt.func, ast.Name)
                                        and elt.func.id in self._user_classes):
                                    _elem_cls = elt.func.id
                                    break
                        elif isinstance(n.value, ast.ListComp):
                            elt = n.value.elt
                            if (isinstance(elt, ast.Call)
                                    and isinstance(elt.func, ast.Name)
                                    and elt.func.id in self._user_classes):
                                _elem_cls = elt.func.id
                        if _elem_cls:
                            break
            # Also check current scope
            if _elem_cls is None:
                for stmt in getattr(self, '_current_scope_stmts', []):
                    if (isinstance(stmt, ast.Assign)
                            and len(stmt.targets) == 1
                            and isinstance(stmt.targets[0], ast.Name)
                            and stmt.targets[0].id == list_node.id):
                        if isinstance(stmt.value, (ast.List, ast.Tuple)):
                            for elt in stmt.value.elts:
                                if (isinstance(elt, ast.Call)
                                        and isinstance(elt.func, ast.Name)
                                        and elt.func.id in self._user_classes):
                                    _elem_cls = elt.func.id
                                    break
        if _elem_cls:
            class_parents = getattr(self, '_class_parents', {})
            at = self._infer_attr_type_from_init(
                _elem_cls, attr_name, class_parents)
            return at
        return None

    def _get_list_elem_type(self, node: ast.expr) -> 'ValueType':
        """Get the element type of a list expression."""
        # ClassName.__mro__ → elements are type proxy FpyObj instances
        if (isinstance(node, ast.Attribute)
                and node.attr == "__mro__"
                and isinstance(node.value, ast.Name)
                and node.value.id in self._user_classes):
            return ValueType(VKind.OBJ)
        # self.attr on the current class: resolve through __init__ AST
        # to find the assignment `self.attr = [...]` and infer elem type
        # from the literal.  Also walks parent classes.
        if (isinstance(node, ast.Attribute)
                and isinstance(node.value, ast.Name)
                and node.value.id == "self"
                and self._current_class):
            cls_name: str | None = self._current_class
            while cls_name:
                ci = self._user_classes.get(cls_name)
                if ci and ci.method_asts:
                    init_ast = ci.method_asts.get("__init__")
                    if init_ast:
                        for stmt in ast.walk(init_ast):
                            if (isinstance(stmt, ast.Assign)
                                    and len(stmt.targets) == 1
                                    and isinstance(stmt.targets[0],
                                                   ast.Attribute)
                                    and isinstance(stmt.targets[0].value,
                                                   ast.Name)
                                    and stmt.targets[0].value.id == "self"
                                    and stmt.targets[0].attr == node.attr):
                                et = self._infer_list_elem_type(stmt.value)
                                # When the RHS is a constructor parameter
                                # (e.g. self.data = data), AST inference
                                # returns INT as default.  Consult CSA types
                                # for the parameter to detect list:list etc.
                                if (et.kind == VKind.INT
                                        and isinstance(stmt.value, ast.Name)):
                                    _pname = stmt.value.id
                                    _init_params = [
                                        a.arg for a in init_ast.args.args]
                                    if _pname in _init_params:
                                        _pidx = _init_params.index(_pname) - 1
                                        _csa = self._call_site_param_types
                                        _ct = (_csa.get(cls_name, [])
                                               or _csa.get(
                                                   f"{cls_name}.__init__", []))
                                        if (0 <= _pidx < len(_ct)
                                                and _ct[_pidx]):
                                            _k = self._tag_kind(_ct[_pidx])
                                            if _k == VKind.LIST:
                                                # CSA type is "list" — check
                                                # the sub-type to determine
                                                # what elements the list holds.
                                                # "list" alone → flat list
                                                # (elements are INT/unknown),
                                                # "list:list" → list-of-lists.
                                                _sub = str(_ct[_pidx])
                                                # Split on ":" to extract the
                                                # element descriptor after
                                                # the leading "list".
                                                _parts = _sub.split(":")
                                                _elem_desc = _parts[1] if len(_parts) > 1 else ""
                                                if "list" in _elem_desc:
                                                    et = ValueType(VKind.LIST)
                                                elif "str" in _elem_desc:
                                                    et = ValueType(VKind.STR)
                                                elif "dict" in _elem_desc:
                                                    et = ValueType(VKind.DICT)
                                if et.kind != VKind.INT:
                                    return et
                                # VKind.INT might be wrong default — keep looking
                                # in parent, but remember we found something
                cls_name = ci.parent_name if ci else None
        # obj.attr where obj class is known: same __init__ lookup
        if (isinstance(node, ast.Attribute)
                and isinstance(node.value, ast.Name)
                and node.value.id != "self"):
            obj_cls = self._infer_object_class(node.value)
            if obj_cls:
                ci = self._user_classes.get(obj_cls)
                if ci and ci.method_asts:
                    init_ast = ci.method_asts.get("__init__")
                    if init_ast:
                        for stmt in ast.walk(init_ast):
                            if (isinstance(stmt, ast.Assign)
                                    and len(stmt.targets) == 1
                                    and isinstance(stmt.targets[0],
                                                   ast.Attribute)
                                    and isinstance(stmt.targets[0].value,
                                                   ast.Name)
                                    and stmt.targets[0].value.id == "self"
                                    and stmt.targets[0].attr == node.attr):
                                et = self._infer_list_elem_type(stmt.value)
                                if et.kind != VKind.INT:
                                    return et
        # Phase 3: read elem_type directly from ValueType when available.
        # Only use elem_type if it's explicitly set (not None) — bare "list"
        # variables without a known element type should fall through to the
        # AST-based inference below.
        if isinstance(node, ast.Name) and node.id in self.variables:
            _, type_tag = self.variables[node.id]
            if isinstance(type_tag, ValueType) and type_tag.elem_type is not None:
                return type_tag.elem_type
            # Legacy fallback: parse string tag for colon-separated types.
            # Dead code — all upstream sources now produce ValueType.
            # Kept as safety net until C2 removes the string-compat layer.
            if isinstance(type_tag, str) and ":" in type_tag:  # pragma: no cover
                return ValueType.from_old_tag(type_tag.split(":", 1)[1])
            # For tuples, check the literal definition for element type
            if self._tag_kind(type_tag) == VKind.TUPLE and node.id in self._tuple_elem_types:
                _tet = self._tuple_elem_types[node.id]
                return _tet if isinstance(_tet, ValueType) else ValueType(VKind.INT)
        # .values(), .items(), .keys() return lists of tagged values / strings.
        # items() returns tuples (list with is_tuple=1).
        # keys() returns strings (or ints for int-keyed dicts).
        # values() returns mixed FpyValues (default "str" for compatibility).
        # ONLY match dict receivers — user-class methods named "values"/"keys"
        # should not be intercepted here.
        if (isinstance(node, ast.Call) and isinstance(node.func, ast.Attribute)
                and node.func.attr in ("values", "items", "keys")
                and self._is_dict_expr(node.func.value)):
            if node.func.attr == "items":
                return ValueType(VKind.LIST)  # items() returns list of tuples (stored as FpyList)
            if (node.func.attr == "keys"
                    and isinstance(node.func.value, ast.Name)
                    and self._is_int_keyed_dict(node.func.value)):
                return ValueType(VKind.INT)
            return ValueType(VKind.STR)
        # String methods that return lists of strings
        if (isinstance(node, ast.Call) and isinstance(node.func, ast.Attribute)
                and node.func.attr in ("split", "rsplit", "splitlines")):
            return ValueType(VKind.STR)
        # sorted(dict) or sorted(dict.keys()) returns list of keys
        if (isinstance(node, ast.Call) and isinstance(node.func, ast.Name)
                and node.func.id == "sorted" and len(node.args) == 1):
            arg = node.args[0]
            if self._is_dict_expr(arg):
                if isinstance(arg, ast.Name) and self._is_int_keyed_dict(arg):
                    return ValueType(VKind.INT)
                return ValueType(VKind.STR)
            # sorted(dict.keys()) / sorted(dict.values())
            if (isinstance(arg, ast.Call) and isinstance(arg.func, ast.Attribute)
                    and arg.func.attr in ("keys", "values", "items")):
                if (arg.func.attr == "keys"
                        and isinstance(arg.func.value, ast.Name)
                        and self._is_int_keyed_dict(arg.func.value)):
                    return ValueType(VKind.INT)
                return ValueType(VKind.STR)
        # Check if this is a function call that returns a list of lists
        # or a tuple of floats (from _func_ret_types analysis).
        # NOTE: info.ret_tag is set early in the declaration pass and only
        # records "ptr" for all pointer-returning functions.  The refined
        # type from the CSA pass (_func_ret_types) distinguishes "ptr:list"
        # (list-of-lists) from plain "ptr" (flat list).
        if isinstance(node, ast.Call) and isinstance(node.func, ast.Name):
            if node.func.id in self._user_functions:
                info = self._user_functions[node.func.id]
                frt = getattr(self, '_func_ret_types', {})
                _actual_ret = frt.get(node.func.id, info.ret_tag)
                if _actual_ret == "ptr:list":
                    return ValueType(VKind.LIST)
                if info.ret_tag == "ptr":
                    rt = frt.get(node.func.id, "")
                    if self._tag_kind(rt) == VKind.TUPLE and ":" in str(rt):
                        return ValueType.from_old_tag(rt.split(":", 1)[1])
        # Global variable whose element type isn't in the tag: look up the
        # module-level AST definition and infer element type from the literal.
        if isinstance(node, ast.Name):
            _tree = getattr(self, "_csa_root_tree", None)
            if _tree is not None:
                for _stmt in _tree.body:
                    if (isinstance(_stmt, ast.Assign)
                            and len(_stmt.targets) == 1
                            and isinstance(_stmt.targets[0], ast.Name)
                            and _stmt.targets[0].id == node.id):
                        _et = self._infer_list_elem_type(_stmt.value)
                        if _et.kind != VKind.INT:  # non-default → trust it
                            return _et
                        break
        # Infer from AST
        return self._infer_list_elem_type(node)

    def _is_confident_elem_type(self, iter_node: ast.expr,
                                   elem_type: str) -> bool:
        """Check if the inferred element type is confidently determined.

        Returns True only when there's explicit evidence the elements are
        the claimed type (not just the "int" default). Used by F1 inline
        GEP optimization to avoid reading string/object data as raw i64.
        """
        # Literal list/tuple with all-int or all-float elements → confident
        if isinstance(iter_node, (ast.List, ast.Tuple)):
            if not iter_node.elts:
                return False
            for elt in iter_node.elts:
                if isinstance(elt, ast.Constant):
                    _et_k = self._tag_kind(elem_type)
                    if _et_k == VKind.INT and not isinstance(elt.value, int):
                        return False
                    if _et_k == VKind.FLOAT and not isinstance(elt.value, (int, float)):
                        return False
                elif isinstance(elt, ast.UnaryOp) and isinstance(elt.op, ast.USub):
                    pass  # negative literal — OK
                else:
                    return False  # non-literal element — can't be sure
            return True
        # Named variable with explicit element type in the tag
        if isinstance(iter_node, ast.Name) and iter_node.id in self.variables:
            _, type_tag = self.variables[iter_node.id]
            if isinstance(type_tag, ValueType) and type_tag.elem_type is not None:
                return True
            if isinstance(type_tag, str) and ":" in type_tag:
                return True  # "list:int", "list:float" — explicit
        # List comprehension with constant or typed element
        if isinstance(iter_node, ast.ListComp):
            elt = iter_node.elt
            if isinstance(elt, ast.Constant):
                _et_k2 = self._tag_kind(elem_type)
                if _et_k2 == VKind.FLOAT and isinstance(elt.value, float):
                    return True
                if _et_k2 == VKind.INT and isinstance(elt.value, int):
                    return True
        return False

    def _known_pointer_type(self, node: ast.expr) -> str | None:
        """If node is known to be a specific pointer kind at compile time,
        return 'list' / 'str' / 'dict' / 'tuple' / 'obj'. Return None if
        polymorphic or not a pointer. Used to detect type mismatches in
        binary operators (e.g., list + str should raise TypeError).
        """
        if isinstance(node, (ast.List, ast.ListComp, ast.Set,
                              ast.GeneratorExp)):
            return "list"
        if isinstance(node, ast.Tuple):
            return "tuple"
        if isinstance(node, (ast.Dict, ast.DictComp)):
            return "dict"
        if isinstance(node, ast.Constant) and isinstance(node.value, str):
            return "str"
        if isinstance(node, ast.JoinedStr):
            return "str"
        if isinstance(node, ast.Name) and node.id in self.variables:
            kind = self._var_kind(node.id)
            _KIND_TO_PTR_NAME = {
                VKind.STR: "str", VKind.LIST: "list", VKind.DICT: "dict",
                VKind.TUPLE: "tuple", VKind.OBJ: "obj",
            }
            return _KIND_TO_PTR_NAME.get(kind)
        return None

    def _emit_type_error(self, msg: str, node: ast.AST) -> ir.Value:
        """Emit a runtime TypeError raise with the given message and return
        a placeholder value. The raise aborts execution before the value is
        used, but we still need to return *something* of a matching LLVM
        type so the builder stays consistent."""
        name_ptr = self._make_string_constant("TypeError")
        exc_id = self.builder.call(self.runtime["exc_name_to_id"], [name_ptr])
        msg_ptr = self._make_string_constant(msg)
        self.builder.call(self.runtime["raise"], [exc_id, msg_ptr])
        # Early-return if not in try: mirrors _emit_raise behavior so the
        # error surfaces immediately rather than after more bad ops.
        if not self._in_try_block:
            ret_type = self.function.return_value.type
            if isinstance(ret_type, ir.VoidType):
                self.builder.ret_void()
            elif isinstance(ret_type, ir.LiteralStructType):
                self.builder.ret(self._fv_none())
            elif isinstance(ret_type, ir.DoubleType):
                self.builder.ret(ir.Constant(double, 0.0))
            elif isinstance(ret_type, ir.PointerType):
                self.builder.ret(ir.Constant(ret_type, None))
            else:
                self.builder.ret(ir.Constant(ret_type, 0))
            # Builder is now terminated; caller won't use the return value.
            # Create an unreachable block so subsequent IR emission has a
            # valid insertion point.
            unreachable = self.function.append_basic_block("after_raise")
            self.builder.position_at_end(unreachable)
        # Return a null pointer as placeholder (won't be reached).
        return ir.Constant(i8_ptr, None)

    def _is_set_expr(self, node: ast.expr) -> bool:
        """Check if an AST expression evaluates to a set (dict-backed)."""
        if isinstance(node, (ast.Set, ast.SetComp)):
            return True
        if isinstance(node, ast.Name):
            _entry = None
            if node.id in self.variables:
                _entry = self.variables[node.id]
            elif node.id in self._global_vars:
                _entry = self._global_vars[node.id]
            if _entry is not None:
                _, type_tag = _entry
                return self._tag_kind(type_tag) == VKind.SET
        if isinstance(node, ast.Call) and isinstance(node.func, ast.Name):
            if node.func.id == "set":
                return True
        # Set operations produce sets
        if isinstance(node, ast.BinOp):
            if isinstance(node.op, (ast.BitOr, ast.BitAnd, ast.BitXor)):
                if self._is_set_expr(node.left) or self._is_set_expr(node.right):
                    return True
            if isinstance(node.op, ast.Sub):
                if self._is_set_expr(node.left):
                    return True
        # Set methods that return sets
        if (isinstance(node, ast.Call) and isinstance(node.func, ast.Attribute)
                and node.func.attr in ("union", "intersection", "difference",
                                        "symmetric_difference", "copy")
                and self._is_set_expr(node.func.value)):
            return True
        return False

    def _is_deque_expr(self, node: ast.expr) -> bool:
        """Check if an AST expression evaluates to a deque."""
        if isinstance(node, ast.Name) and node.id in self.variables:
            return self._var_kind(node.id) == VKind.DEQUE
        if isinstance(node, ast.Call) and isinstance(node.func, ast.Name):
            native_imports = getattr(self, '_native_imports', {})
            if node.func.id in native_imports:
                mod, fn = native_imports[node.func.id]
                return mod == "collections" and fn == "deque"
        return False

    def _is_counter_expr(self, node: ast.expr) -> bool:
        """Check if an AST expression evaluates to a Counter."""
        if isinstance(node, ast.Name) and node.id in self.variables:
            return self._var_kind(node.id) == VKind.COUNTER
        if isinstance(node, ast.Call) and isinstance(node.func, ast.Name):
            native_imports = getattr(self, '_native_imports', {})
            if node.func.id in native_imports:
                mod, fn = native_imports[node.func.id]
                return mod == "collections" and fn == "Counter"
        # Counter arithmetic produces counters
        if isinstance(node, ast.BinOp):
            if isinstance(node.op, (ast.Add, ast.Sub, ast.BitOr, ast.BitAnd)):
                if self._is_counter_expr(node.left) and self._is_counter_expr(node.right):
                    return True
        return False

    def _is_defaultdict_expr(self, node: ast.expr) -> bool:
        """Check if an AST expression evaluates to a defaultdict."""
        if isinstance(node, ast.Name) and node.id in self.variables:
            return self._var_kind(node.id) == VKind.DEFAULTDICT
        if isinstance(node, ast.Call) and isinstance(node.func, ast.Name):
            native_imports = getattr(self, '_native_imports', {})
            if node.func.id in native_imports:
                mod, fn = native_imports[node.func.id]
                return mod == "collections" and fn == "defaultdict"
        return False

    def _is_chainmap_expr(self, node: ast.expr) -> bool:
        """Check if an AST expression evaluates to a ChainMap."""
        if isinstance(node, ast.Name) and node.id in self.variables:
            return self._var_kind(node.id) == VKind.CHAINMAP
        return False

    def _is_logger_expr(self, node: ast.expr) -> bool:
        """Check if an AST expression evaluates to a logging.Logger."""
        if isinstance(node, ast.Name) and node.id in self.variables:
            return self._var_kind(node.id) == VKind.LOGGER
        return False

    def _is_pyobj_receiver(self, node: ast.expr, *,
                           include_native_mod: bool = True) -> bool:
        """Check if a receiver expression is a pyobj (bridge object).
        Handles: name, name.attr, name[key], call(...).attr, etc.

        When *include_native_mod* is False, NATIVE_MOD modules (itertools,
        sys, etc.) are excluded.  Use this in builtin handlers like list()
        where NATIVE_MOD calls compile natively and their results are native
        pointers, not PyObject*."""
        # Direct variable: qs where qs is pyobj (or native module needing bridge)
        # Check both local scope and globals — bridge imports land in globals.
        if isinstance(node, ast.Name) and self._has_var(node.id):
            if include_native_mod:
                return self._var_kind(node.id) in (VKind.PYOBJ, VKind.NATIVE_MOD)
            return self._var_kind(node.id) == VKind.PYOBJ
        # Attribute on pyobj: User.objects where User is pyobj
        if isinstance(node, ast.Attribute):
            return self._is_pyobj_receiver(node.value,
                                           include_native_mod=include_native_mod)
        # Subscript on pyobj: data["key"] where data is pyobj
        if isinstance(node, ast.Subscript):
            return self._is_pyobj_receiver(node.value,
                                           include_native_mod=include_native_mod)
        # Call result on pyobj chain: User.objects.filter(...) where User is pyobj
        if isinstance(node, ast.Call) and isinstance(node.func, ast.Attribute):
            return self._is_pyobj_receiver(node.func.value,
                                           include_native_mod=include_native_mod)
        # Call on pyobj variable: ctx("test") where ctx is pyobj (e.g. @contextmanager)
        if isinstance(node, ast.Call) and isinstance(node.func, ast.Name):
            if self._has_var(node.func.id):
                kind = self._var_kind(node.func.id)
                if kind == VKind.PYOBJ:
                    return True
                if include_native_mod and kind == VKind.NATIVE_MOD:
                    return True
        return False

    def _match_prefix_reverse(self, target: ast.Subscript,
                              value_node: ast.expr | None
                              ) -> tuple[str, ast.expr] | None:
        """Detect `a[:N] = a[M::-1]` where N = M+1 (in-place prefix reverse).

        Returns (list_name, count_ast_node) so the caller can emit
        list_reverse_prefix(list, count) instead of allocating a reversed
        copy via list_slice_step + list_slice_assign.

        Matches patterns like:
          a[:k+1] = a[k::-1]     count = k+1
          a[:n]   = a[n-1::-1]   count = n
        """
        if value_node is None:
            return None
        # Both sides must be subscripts on the same named variable
        if not (isinstance(target, ast.Subscript)
                and isinstance(value_node, ast.Subscript)):
            return None
        if not (isinstance(target.value, ast.Name)
                and isinstance(value_node.value, ast.Name)):
            return None
        if target.value.id != value_node.value.id:
            return None
        # LHS must be a slice with lower=None or 0, upper present, no step
        lslice = target.slice
        if not isinstance(lslice, ast.Slice):
            return None
        if lslice.step is not None:
            return None
        if lslice.lower is not None:
            if not (isinstance(lslice.lower, ast.Constant)
                    and lslice.lower.value == 0):
                return None
        if lslice.upper is None:
            return None
        # RHS must be a slice with step=-1, upper=None
        rslice = value_node.slice
        if not isinstance(rslice, ast.Slice):
            return None
        if rslice.upper is not None:
            return None
        # Check step is -1: either Constant(-1) or UnaryOp(USub, Constant(1))
        step = rslice.step
        if step is None:
            return None
        if isinstance(step, ast.Constant) and step.value == -1:
            pass
        elif (isinstance(step, ast.UnaryOp)
              and isinstance(step.op, ast.USub)
              and isinstance(step.operand, ast.Constant)
              and step.operand.value == 1):
            pass
        else:
            return None
        # RHS lower exists (the start of the reverse)
        if rslice.lower is None:
            return None
        # The count is the LHS upper.  For correctness we check that
        # lhs.upper == rhs.lower + 1  (i.e. they cover the same prefix).
        # Pattern 1: a[:k+1] = a[k::-1]
        #   lhs.upper = BinOp(k, Add, 1), rhs.lower = k
        upper = lslice.upper
        lower = rslice.lower
        if (isinstance(upper, ast.BinOp)
                and isinstance(upper.op, ast.Add)
                and isinstance(upper.right, ast.Constant)
                and upper.right.value == 1
                and ast.dump(upper.left) == ast.dump(lower)):
            return (target.value.id, upper)
        # Pattern 2: a[:n] = a[n-1::-1]
        #   lhs.upper = n, rhs.lower = BinOp(n, Sub, 1)
        if (isinstance(lower, ast.BinOp)
                and isinstance(lower.op, ast.Sub)
                and isinstance(lower.right, ast.Constant)
                and lower.right.value == 1
                and ast.dump(lower.left) == ast.dump(upper)):
            return (target.value.id, upper)
        # Pattern 3: a[:N] = a[N-1::-1] where N is a constant
        if (isinstance(upper, ast.Constant)
                and isinstance(lower, ast.Constant)
                and isinstance(upper.value, int)
                and isinstance(lower.value, int)
                and upper.value == lower.value + 1):
            return (target.value.id, upper)
        return None

    def _is_path_expr(self, node: ast.expr) -> bool:
        """Check if an AST expression evaluates to a pathlib.Path."""
        if isinstance(node, ast.Name) and node.id in self.variables:
            return self._var_kind(node.id) == VKind.PATH
        # Direct Path(...) call via imported name
        if isinstance(node, ast.Call) and isinstance(node.func, ast.Name):
            native_imports = getattr(self, '_native_imports', {})
            if node.func.id in native_imports:
                mod, fn = native_imports[node.func.id]
                return mod == "pathlib" and fn == "Path"
        # Module-qualified call: pathlib.Path(...)
        if (isinstance(node, ast.Call)
                and isinstance(node.func, ast.Attribute)
                and isinstance(node.func.value, ast.Name)
                and node.func.value.id == "pathlib"
                and node.func.attr == "Path"):
            return True
        # Path method calls that return Path: .resolve(), .parent (as call), .with_suffix()
        _PATH_RETURNING_METHODS = {
            "resolve", "parent", "with_suffix", "joinpath", "absolute",
        }
        if (isinstance(node, ast.Call)
                and isinstance(node.func, ast.Attribute)
                and node.func.attr in _PATH_RETURNING_METHODS
                and self._is_path_expr(node.func.value)):
            return True
        # Path attribute that returns Path: .parent
        if (isinstance(node, ast.Attribute)
                and node.attr == "parent"
                and self._is_path_expr(node.value)):
            return True
        # Path / str division
        if (isinstance(node, ast.BinOp)
                and isinstance(node.op, ast.Div)
                and self._is_path_expr(node.left)):
            return True
        return False

    def _is_list_expr(self, node: ast.expr) -> bool:
        """Check if an AST expression evaluates to a list."""
        if isinstance(node, (ast.List, ast.ListComp, ast.GeneratorExp)):
            return True
        if isinstance(node, ast.Name) and node.id in self.variables:
            kind = self._var_kind(node.id)
            return kind == VKind.LIST
        # Global variables not yet copied to self.variables (first access
        # from inside a function before _load_variable has been called):
        if isinstance(node, ast.Name) and node.id in self._global_vars:
            _, type_tag = self._global_vars[node.id]
            kind = (type_tag.kind if isinstance(type_tag, ValueType)
                    else self._tag_kind(type_tag))
            return kind == VKind.LIST
        # sorted(), reversed(), list() return lists (set() now returns dict-backed set)
        if isinstance(node, ast.Call) and isinstance(node.func, ast.Name):
            if node.func.id in ("sorted", "reversed", "list", "enumerate", "zip", "map", "filter", "range"):
                return True
            # User functions that return lists (ret_tag "ptr" with list_vars)
            if node.func.id in self._user_functions:
                info = self._user_functions[node.func.id]
                if self._tag_kind(info.ret_tag) == VKind.LIST:
                    return True
        # .split(), .keys(), .values(), .items(), .copy() return lists
        if (isinstance(node, ast.Call) and isinstance(node.func, ast.Attribute)
                and node.func.attr in ("split", "rsplit", "keys", "values", "items",
                                      "splitlines", "copy", "partition", "rpartition")):
            return True
        # dict.setdefault(key, default) / dict.get(key, default) — if the
        # default is a list, the result is a list.  Recognising this lets
        # chained mutations like d.setdefault("a", []).append(1) emit a
        # direct fastpy_list_append_fv instead of going through the CPython
        # bridge (which copies the list and loses in-place mutations).
        if (isinstance(node, ast.Call) and isinstance(node.func, ast.Attribute)
                and node.func.attr in ("setdefault", "get")
                and self._is_dict_expr(node.func.value)
                and len(node.args) >= 2
                and self._is_list_expr(node.args[1])):
            return True
        # User class method returning list
        if isinstance(node, ast.Call) and isinstance(node.func, ast.Attribute):
            if self._method_returns_list(node.func.value, node.func.attr):
                return True
        # List slicing returns a list
        if isinstance(node, ast.Subscript) and isinstance(node.slice, ast.Slice):
            if self._is_list_expr(node.value):
                return True
        # Indexing a list-of-lists returns a list
        if isinstance(node, ast.Subscript) and not isinstance(node.slice, ast.Slice):
            if self._is_list_expr(node.value):
                elem_type = self._get_list_elem_type(node.value)
                if elem_type.kind == VKind.LIST:
                    return True
            # Indexing a dict-with-list-values returns a list
            if (isinstance(node.value, ast.Name)
                    and node.value.id in self._dict_var_list_values):
                return True
            # Defaultdict with list factory: d["x"] returns a list
            if (isinstance(node.value, ast.Name)
                    and self._is_defaultdict_expr(node.value)):
                factory = getattr(self, '_defaultdict_var_factories', {}).get(
                    node.value.id)
                if self._tag_kind(factory) == VKind.LIST:
                    return True
        # BinOp on lists (concatenation, set ops) returns a list
        if isinstance(node, ast.BinOp):
            if self._is_list_expr(node.left) or self._is_list_expr(node.right):
                return True
        # Object attribute access: obj.attr where attr is a list
        if isinstance(node, ast.Attribute):
            obj_cls = self._infer_object_class(node.value)
            if obj_cls and obj_cls in self._class_container_attrs:
                list_attrs, _ = self._class_container_attrs[obj_cls]
                if node.attr in list_attrs:
                    return True
            elif not obj_cls:
                # Cross-class lookup: check if ANY class has this attr as list
                for _chk_cls in self._user_classes:
                    _chk_cont = self._class_container_attrs.get(
                        _chk_cls, (set(), set()))
                    if node.attr in _chk_cont[0]:
                        return True
        return False

    def _infer_object_class(self, node: ast.expr) -> str | None:
        """Try to determine the class of an object expression."""
        # Class constructor call: ClassName(...)
        if isinstance(node, ast.Call) and isinstance(node.func, ast.Name):
            if node.func.id in self._user_classes:
                # Resolve to variant for monomorphized classes so downstream
                # lookups (_per_class_float_attrs etc.) use the right variant.
                if node.func.id in self._monomorphized_classes:
                    return self._resolve_class_specialization(
                        node.func.id, node.args, node.keywords)
                return node.func.id
            # User function that returns an obj — infer the class from the
            # function's body (look for `return ClassName(...)` or `return
            # var_assigned_from_ClassName`).
            if node.func.id in self._user_functions:
                info = self._user_functions[node.func.id]
                if self._tag_kind(info.ret_tag) == VKind.OBJ:
                    fn_def = getattr(self, "_function_def_nodes", {}).get(
                        node.func.id)
                    if fn_def is not None:
                        # Find obj-typed vars in the function body
                        body_obj_classes: dict[str, str] = {}
                        for n in ast.walk(fn_def):
                            if (isinstance(n, ast.Assign)
                                    and len(n.targets) == 1
                                    and isinstance(n.targets[0], ast.Name)
                                    and isinstance(n.value, ast.Call)
                                    and isinstance(n.value.func, ast.Name)
                                    and n.value.func.id in self._user_classes):
                                body_obj_classes[n.targets[0].id] = n.value.func.id
                        # Check return statements
                        for n in ast.walk(fn_def):
                            if isinstance(n, ast.Return) and n.value is not None:
                                if (isinstance(n.value, ast.Call)
                                        and isinstance(n.value.func, ast.Name)
                                        and n.value.func.id in self._user_classes):
                                    return n.value.func.id
                                if (isinstance(n.value, ast.Name)
                                        and n.value.id in body_obj_classes):
                                    return body_obj_classes[n.value.id]
        # ClassName.classmethod(...) returning cls(...) or self — caller class
        if (isinstance(node, ast.Call) and isinstance(node.func, ast.Attribute)
                and isinstance(node.func.value, ast.Name)
                and node.func.value.id in self._user_classes):
            class_name = node.func.value.id
            cls_info = self._user_classes[class_name]
            if cls_info.method_asts:
                m_ast = cls_info.method_asts.get(node.func.attr)
                if m_ast is not None:
                    for n in ast.walk(m_ast):
                        if not (isinstance(n, ast.Return) and n.value is not None):
                            continue
                        # `return cls(...)` or `return self`
                        if (isinstance(n.value, ast.Call)
                                and isinstance(n.value.func, ast.Name)
                                and n.value.func.id == "cls"):
                            return class_name
                        if (isinstance(n.value, ast.Name)
                                and n.value.id == "self"):
                            return class_name
        # Method call returning self/cls/ClassName(...): infer class from return
        if isinstance(node, ast.Call) and isinstance(node.func, ast.Attribute):
            receiver_cls = self._infer_object_class(node.func.value)
            if receiver_cls is not None:
                cls_info = self._user_classes.get(receiver_cls)
                if cls_info and cls_info.method_asts:
                    m_ast = cls_info.method_asts.get(node.func.attr)
                    if m_ast is not None:
                        for n in ast.walk(m_ast):
                            if not (isinstance(n, ast.Return) and n.value is not None):
                                continue
                            if (isinstance(n.value, ast.Name)
                                    and n.value.id == "self"):
                                return receiver_cls
                            if (isinstance(n.value, ast.Call)
                                    and isinstance(n.value.func, ast.Name)
                                    and n.value.func.id == "cls"):
                                return receiver_cls
                            # return ClassName(...) — new instance of that class
                            if (isinstance(n.value, ast.Call)
                                    and isinstance(n.value.func, ast.Name)
                                    and n.value.func.id in self._user_classes):
                                return n.value.func.id
        # Variable with known class
        if isinstance(node, ast.Name):
            if node.id == "self" and self._current_class:
                return self._current_class
            if node.id in self._obj_var_class:
                return self._obj_var_class[node.id]
            # Module-level globals that hold user class instances
            if node.id in getattr(self, '_global_obj_classes', {}):
                return self._global_obj_classes[node.id]
        # Nested attribute access: obj.attr where attr is a known obj attr
        if isinstance(node, ast.Attribute):
            inner_cls = self._infer_object_class(node.value)
            if inner_cls:
                obj_types = self._class_obj_attr_types.get(inner_cls, {})
                if node.attr in obj_types:
                    return obj_types[node.attr]
        return None

    def _is_tuple_expr(self, node: ast.expr) -> bool:
        if isinstance(node, ast.Tuple):
            return True
        # ClassName.__mro__ → tuple of type proxy objects
        if (isinstance(node, ast.Attribute) and node.attr == "__mro__"
                and isinstance(node.value, ast.Name)
                and node.value.id in self._user_classes):
            return True
        # Exception variable .args → tuple
        if (isinstance(node, ast.Attribute) and node.attr == "args"
                and isinstance(node.value, ast.Name)
                and node.value.id in self._exc_vars):
            return True
        if isinstance(node, ast.Name):
            _entry = None
            if node.id in self.variables:
                _entry = self.variables[node.id]
            elif node.id in self._global_vars:
                _entry = self._global_vars[node.id]
            if _entry is not None:
                _, type_tag = _entry
                return self._tag_kind(type_tag) == VKind.TUPLE
        # Function calls that return tuples
        if isinstance(node, ast.Call) and isinstance(node.func, ast.Name):
            name = node.func.id
            if name == "divmod":
                return True
            elif name in self._user_functions:
                info = self._user_functions[name]
                if info.ret_tag == "ptr":
                    return True  # ptr return from user func = likely tuple
        # Method calls that return tuples
        if isinstance(node, ast.Call) and isinstance(node.func, ast.Attribute):
            if self._method_returns_tuple(node.func.value, node.func.attr):
                return True
            # Built-in: dict.popitem() returns a tuple
            if (node.func.attr == "popitem"
                    and self._is_dict_expr(node.func.value)):
                return True
            # float.as_integer_ratio() returns a tuple
            if node.func.attr == "as_integer_ratio":
                return True
        return False

    def _is_int_keyed_dict(self, node: ast.expr) -> bool:
        """Check if a dict expression uses integer keys (from dict comp with
        int iterator, dict literal with int keys, or subscript-store with
        int keys)."""
        if isinstance(node, ast.DictComp):
            gen = node.generators[0]
            key_expr = node.key
            iter_var = gen.target
            # {i: ... for i in range(...)} → int keys ONLY if the key
            # expression is the raw iterator variable (not str(i), etc.)
            if (isinstance(gen.iter, ast.Call)
                    and isinstance(gen.iter.func, ast.Name)
                    and gen.iter.func.id == "range"):
                # Key must be the plain iterator variable (int), not a
                # transformation like str(i) which produces string keys.
                if (isinstance(key_expr, ast.Name)
                        and isinstance(iter_var, ast.Name)
                        and key_expr.id == iter_var.id):
                    return True
                # Also int if key is an arithmetic expression on the
                # iterator variable (e.g. {i+1: ... for i in range(n)}).
                # But NOT if the BinOp involves str/chr calls or string
                # literals — that's string concatenation, not arithmetic.
                if isinstance(key_expr, ast.BinOp):
                    def _binop_has_str(expr):
                        if (isinstance(expr, ast.Call)
                                and isinstance(expr.func, ast.Name)
                                and expr.func.id in ("str", "chr", "repr")):
                            return True
                        if (isinstance(expr, ast.Constant)
                                and isinstance(expr.value, str)):
                            return True
                        if isinstance(expr, ast.JoinedStr):
                            return True
                        if isinstance(expr, ast.BinOp):
                            return (_binop_has_str(expr.left)
                                    or _binop_has_str(expr.right))
                        return False
                    if not _binop_has_str(key_expr):
                        return True
                # If key is a function call (str(i), etc.), NOT int-keyed
                return False
            # {x: ... for x in some_list} where list elements are ints
            # and key is the raw iterator variable → int keys
            if (isinstance(key_expr, ast.Name)
                    and isinstance(iter_var, ast.Name)
                    and key_expr.id == iter_var.id):
                # Key is the raw iterator variable — key type = elem type
                _elem = self._get_list_elem_type(gen.iter)
                if _elem.kind in (VKind.INT, VKind.UNKNOWN):
                    return True
            # {expr(x): ... for x in some_list} where key is arithmetic
            if isinstance(key_expr, ast.BinOp):
                _elem = self._get_list_elem_type(gen.iter)
                if _elem.kind in (VKind.INT, VKind.UNKNOWN):
                    return True
            # Tuple-unpacking generator with enumerate:
            # {i: w for i, w in enumerate(seq)} → int keys when key=i
            # (the first unpacked element, which is always the int index).
            if (isinstance(iter_var, ast.Tuple)
                    and isinstance(key_expr, ast.Name)
                    and isinstance(gen.iter, ast.Call)
                    and isinstance(gen.iter.func, ast.Name)
                    and gen.iter.func.id == "enumerate"
                    and len(iter_var.elts) >= 1
                    and isinstance(iter_var.elts[0], ast.Name)
                    and key_expr.id == iter_var.elts[0].id):
                return True
            # If key is a function call like str(x), NOT int-keyed
            if (isinstance(key_expr, ast.Call)
                    and isinstance(key_expr.func, ast.Name)
                    and key_expr.func.id == "str"):
                return False
        if isinstance(node, ast.Dict) and node.keys:
            # Filter out None keys (dict unpacking via **).
            # Must use a concrete list so `all()` on an empty iterable
            # (pure-unpack dicts like {**d}) doesn't falsely return True.
            concrete_keys = [k for k in node.keys if k is not None]
            if not concrete_keys:
                return False
            return all(isinstance(k, ast.Constant) and isinstance(k.value, int)
                       and not isinstance(k.value, bool)
                       for k in concrete_keys)
        if isinstance(node, ast.Name):
            # Check via _csa_root_tree for the binding
            tree = getattr(self, "_csa_root_tree", None)
            if tree is not None:
                _found_literal = False
                _has_int_key_mutation = False
                for n in ast.walk(tree):
                    if (isinstance(n, ast.Assign)
                            and len(n.targets) == 1
                            and isinstance(n.targets[0], ast.Name)
                            and n.targets[0].id == node.id):
                        result = self._is_int_keyed_dict(n.value)
                        if result:
                            return True
                        # Track if the literal itself was an empty dict
                        if isinstance(n.value, ast.Dict) and not n.value.keys:
                            _found_literal = True
                        # Function call return: check the function body for
                        # int-keyed dict patterns in its return statements.
                        if (isinstance(n.value, ast.Call)
                                and isinstance(n.value.func, ast.Name)):
                            _fn_name = n.value.func.id
                            _fn_asts = getattr(self, '_csa_func_asts', {})
                            _fn_ast = _fn_asts.get(_fn_name)
                            if _fn_ast is not None:
                                if self._func_returns_int_keyed_dict(_fn_ast):
                                    return True
                    # d.setdefault(int_const, ...) → int-keyed
                    if (isinstance(n, ast.Call)
                            and isinstance(n.func, ast.Attribute)
                            and n.func.attr == "setdefault"
                            and isinstance(n.func.value, ast.Name)
                            and n.func.value.id == node.id
                            and n.args
                            and isinstance(n.args[0], ast.Constant)
                            and isinstance(n.args[0].value, int)
                            and not isinstance(n.args[0].value, bool)):
                        _has_int_key_mutation = True
                    # d.setdefault(len(x), ...) → int-keyed (len returns int)
                    if (isinstance(n, ast.Call)
                            and isinstance(n.func, ast.Attribute)
                            and n.func.attr == "setdefault"
                            and isinstance(n.func.value, ast.Name)
                            and n.func.value.id == node.id
                            and n.args
                            and isinstance(n.args[0], ast.Call)
                            and isinstance(n.args[0].func, ast.Name)
                            and n.args[0].func.id in (
                                "len", "int", "abs", "ord", "hash")):
                        _has_int_key_mutation = True
                    # d[int_const] = ... → int-keyed
                    if (isinstance(n, ast.Assign)
                            and len(n.targets) == 1
                            and isinstance(n.targets[0], ast.Subscript)
                            and isinstance(n.targets[0].value, ast.Name)
                            and n.targets[0].value.id == node.id
                            and isinstance(n.targets[0].slice, ast.Constant)
                            and isinstance(n.targets[0].slice.value, int)
                            and not isinstance(n.targets[0].slice.value, bool)):
                        _has_int_key_mutation = True
                    # d[int_const] += ... → int-keyed (augmented assign)
                    if (isinstance(n, ast.AugAssign)
                            and isinstance(n.target, ast.Subscript)
                            and isinstance(n.target.value, ast.Name)
                            and n.target.value.id == node.id
                            and isinstance(n.target.slice, ast.Constant)
                            and isinstance(n.target.slice.value, int)
                            and not isinstance(n.target.slice.value, bool)):
                        _has_int_key_mutation = True
                if _found_literal and _has_int_key_mutation:
                    return True
                # Check for d[loop_var] = ... inside for loops
                # iterating int-typed iterables (range, list of ints).
                if _found_literal and not _has_int_key_mutation:
                    for _f in ast.walk(tree):
                        if not isinstance(_f, ast.For):
                            continue
                        if not isinstance(_f.target, ast.Name):
                            continue
                        _lv = _f.target.id
                        # Check if the for-loop body contains
                        # d[loop_var] = ... or d[loop_var] += ...
                        _uses_lv_as_key = False
                        for _s in ast.walk(_f):
                            if (isinstance(_s, ast.Assign)
                                    and len(_s.targets) == 1
                                    and isinstance(_s.targets[0], ast.Subscript)
                                    and isinstance(_s.targets[0].value, ast.Name)
                                    and _s.targets[0].value.id == node.id
                                    and isinstance(_s.targets[0].slice, ast.Name)
                                    and _s.targets[0].slice.id == _lv):
                                _uses_lv_as_key = True
                                break
                            if (isinstance(_s, ast.AugAssign)
                                    and isinstance(_s.target, ast.Subscript)
                                    and isinstance(_s.target.value, ast.Name)
                                    and _s.target.value.id == node.id
                                    and isinstance(_s.target.slice, ast.Name)
                                    and _s.target.slice.id == _lv):
                                _uses_lv_as_key = True
                                break
                        if not _uses_lv_as_key:
                            continue
                        # Check if the iterable produces int elements
                        _iter = _f.iter
                        if (isinstance(_iter, ast.Call)
                                and isinstance(_iter.func, ast.Name)
                                and _iter.func.id == "range"):
                            return True
                        # Iterating a list literal with int elements
                        if isinstance(_iter, ast.List) and _iter.elts:
                            if all(isinstance(e, ast.Constant)
                                   and isinstance(e.value, int)
                                   and not isinstance(e.value, bool)
                                   for e in _iter.elts):
                                return True
                        # Iterating a list variable — check its
                        # definition for int elements.  We can't use
                        # _get_list_elem_type here because it defaults
                        # to INT for unknowns (would false-positive on
                        # string variables like `for c in s:`).
                        if isinstance(_iter, ast.Name):
                            # Look for literal assignment in the tree
                            _found_iter_def = False
                            for _n2 in ast.walk(tree):
                                if (isinstance(_n2, ast.Assign)
                                        and len(_n2.targets) == 1
                                        and isinstance(_n2.targets[0], ast.Name)
                                        and _n2.targets[0].id == _iter.id
                                        and isinstance(_n2.value, ast.List)
                                        and _n2.value.elts):
                                    if all(isinstance(_e2, ast.Constant)
                                           and isinstance(_e2.value, int)
                                           and not isinstance(_e2.value, bool)
                                           for _e2 in _n2.value.elts):
                                        return True
                                    _found_iter_def = True
                                    break
                            # Function parameter: check CSA.
                            # "list" (plain) → int elements (default).
                            # "list:str" → string elements → NOT int.
                            if not _found_iter_def:
                                _csa = getattr(self, '_call_site_param_types', {})
                                for _fn2 in ast.walk(tree):
                                    if not isinstance(_fn2, ast.FunctionDef):
                                        continue
                                    _prms = [a.arg for a in _fn2.args.args]
                                    if _iter.id not in _prms:
                                        continue
                                    _pi = _prms.index(_iter.id)
                                    _fcsa = _csa.get(_fn2.name, [])
                                    if (_pi < len(_fcsa)
                                            and _fcsa[_pi] == "list"):
                                        return True
                                    break
        return False

    def _func_returns_int_keyed_dict(self, func_ast: ast.FunctionDef) -> bool:
        """Check if a function's return statements indicate an int-keyed dict.

        Looks for patterns like:
          d = {}; d[int_literal] = ...; return d
          d = {}; d[len(x)] = ...; return d
          d = {}; k = len(x); d[k] = ...; return d
          d = {}; d.setdefault(int_literal, ...); return d
        Only considers definitely-int keys. Variable keys are only treated
        as int if the variable is assigned from an int-producing expression
        (literal int, len(), int(), abs(), ord(), hash(), arithmetic).
        """
        _INT_BUILTINS = {"len", "int", "abs", "ord", "hash"}
        _empty_dicts: set[str] = set()
        _int_keyed_vars: set[str] = set()
        _returned_vars: set[str] = set()
        # First pass: find variables known to hold int values
        _int_vars: set[str] = set()
        for n in ast.walk(func_ast):
            if (isinstance(n, ast.Assign) and len(n.targets) == 1
                    and isinstance(n.targets[0], ast.Name)):
                _rhs = n.value
                if (isinstance(_rhs, ast.Constant) and isinstance(_rhs.value, int)
                        and not isinstance(_rhs.value, bool)):
                    _int_vars.add(n.targets[0].id)
                elif (isinstance(_rhs, ast.Call) and isinstance(_rhs.func, ast.Name)
                        and _rhs.func.id in _INT_BUILTINS):
                    _int_vars.add(n.targets[0].id)
                elif isinstance(_rhs, ast.BinOp):
                    # Arithmetic expressions produce ints (unless strings involved)
                    _int_vars.add(n.targets[0].id)
            # for i in range(...): → i is an int variable
            if (isinstance(n, ast.For)
                    and isinstance(n.target, ast.Name)
                    and isinstance(n.iter, ast.Call)
                    and isinstance(n.iter.func, ast.Name)
                    and n.iter.func.id == "range"):
                _int_vars.add(n.target.id)
            # for i, v in enumerate(...): → i is an int variable
            if (isinstance(n, ast.For)
                    and isinstance(n.target, ast.Tuple)
                    and len(n.target.elts) >= 1
                    and isinstance(n.target.elts[0], ast.Name)
                    and isinstance(n.iter, ast.Call)
                    and isinstance(n.iter.func, ast.Name)
                    and n.iter.func.id == "enumerate"):
                _int_vars.add(n.target.elts[0].id)
        # Second pass: check dict mutations
        for n in ast.walk(func_ast):
            # d = {}
            if (isinstance(n, ast.Assign) and len(n.targets) == 1
                    and isinstance(n.targets[0], ast.Name)
                    and isinstance(n.value, ast.Dict)
                    and not n.value.keys):
                _empty_dicts.add(n.targets[0].id)
            # d[key] = ...
            if (isinstance(n, ast.Assign) and len(n.targets) == 1
                    and isinstance(n.targets[0], ast.Subscript)
                    and isinstance(n.targets[0].value, ast.Name)
                    and n.targets[0].value.id in _empty_dicts):
                _sl = n.targets[0].slice
                if (isinstance(_sl, ast.Constant) and isinstance(_sl.value, int)
                        and not isinstance(_sl.value, bool)):
                    _int_keyed_vars.add(n.targets[0].value.id)
                elif (isinstance(_sl, ast.Call) and isinstance(_sl.func, ast.Name)
                        and _sl.func.id in _INT_BUILTINS):
                    _int_keyed_vars.add(n.targets[0].value.id)
                elif (isinstance(_sl, ast.Name) and _sl.id in _int_vars):
                    _int_keyed_vars.add(n.targets[0].value.id)
            # d.setdefault(int_expr, ...)
            if (isinstance(n, ast.Call) and isinstance(n.func, ast.Attribute)
                    and n.func.attr == "setdefault"
                    and isinstance(n.func.value, ast.Name)
                    and n.func.value.id in _empty_dicts
                    and n.args):
                _a = n.args[0]
                if (isinstance(_a, ast.Constant) and isinstance(_a.value, int)
                        and not isinstance(_a.value, bool)):
                    _int_keyed_vars.add(n.func.value.id)
                elif (isinstance(_a, ast.Call) and isinstance(_a.func, ast.Name)
                        and _a.func.id in _INT_BUILTINS):
                    _int_keyed_vars.add(n.func.value.id)
                elif (isinstance(_a, ast.Name) and _a.id in _int_vars):
                    _int_keyed_vars.add(n.func.value.id)
            # return d
            if isinstance(n, ast.Return) and n.value is not None:
                if isinstance(n.value, ast.Name):
                    _returned_vars.add(n.value.id)
        return bool(_int_keyed_vars & _returned_vars)

    def _is_dict_expr(self, node: ast.expr) -> bool:
        if isinstance(node, (ast.Dict, ast.DictComp)):
            return True
        if isinstance(node, ast.Name):
            _kind = VKind.UNKNOWN
            if node.id in self.variables:
                _kind = self._var_kind(node.id)
            elif node.id in self._global_vars:
                _, _gt = self._global_vars[node.id]
                _kind = (_gt.kind if isinstance(_gt, ValueType)
                         else self._tag_kind(_gt))
            if _kind in _DICT_LIKE:
                return True
        # Function calls that return dicts
        if isinstance(node, ast.Call) and isinstance(node.func, ast.Name):
            name = node.func.id
            if name == "dict":
                return True
            elif name in self._user_functions:
                return self._tag_kind(
                    self._user_functions[name].ret_tag) == VKind.DICT
        # Object attribute access: obj.attr where attr is a dict
        if isinstance(node, ast.Attribute):
            obj_cls = self._infer_object_class(node.value)
            if obj_cls and obj_cls in self._class_container_attrs:
                _, dict_attrs = self._class_container_attrs[obj_cls]
                if node.attr in dict_attrs:
                    return True
            elif not obj_cls:
                # Cross-class lookup: check if ANY class has this attr as dict
                for _chk_cls in self._user_classes:
                    _chk_cont = self._class_container_attrs.get(
                        _chk_cls, (set(), set()))
                    if node.attr in _chk_cont[1]:
                        return True
        # Indexing a list of dicts or dict-of-dicts returns a dict
        if isinstance(node, ast.Subscript) and not isinstance(node.slice, ast.Slice):
            if self._is_list_expr(node.value):
                elem_type = self._get_list_elem_type(node.value)
                if elem_type.kind == VKind.DICT:
                    return True
            if (isinstance(node.value, ast.Name)
                    and node.value.id in self._dict_var_dict_values):
                return True
            # Per-key type lookup: d["database"] where d has per-key type
            # info and "database" maps to "dict" — the subscript yields a dict.
            if (isinstance(node.value, ast.Name)
                    and node.value.id in self._dict_var_key_types
                    and isinstance(node.slice, ast.Constant)
                    and isinstance(node.slice.value, str)):
                kt = self._dict_var_key_types[node.value.id].get(
                    node.slice.value)
                if self._tag_kind(kt) == VKind.DICT:
                    return True
            # Recursive: d["a"]["b"] where d["a"] is itself a dict
            # Walk up the subscript chain to find the base Name variable.
            if isinstance(node.value, ast.Subscript):
                base = node.value
                while isinstance(base, ast.Subscript):
                    base = base.value
                if (isinstance(base, ast.Name)
                        and base.id in self._dict_var_dict_values):
                    return True
        # Method calls that return dicts
        if isinstance(node, ast.Call) and isinstance(node.func, ast.Attribute):
            if self._method_returns_dict(node.func.value, node.func.attr):
                return True
            # Built-in dict.copy() returns a dict
            if (node.func.attr == "copy"
                    and self._is_dict_expr(node.func.value)):
                return True
            # dict.fromkeys(...) returns a dict
            if (node.func.attr == "fromkeys"
                    and isinstance(node.func.value, ast.Name)
                    and node.func.value.id == "dict"):
                return True
        # Dict merge: dict | dict → new dict
        if (isinstance(node, ast.BinOp) and isinstance(node.op, ast.BitOr)
                and self._is_dict_expr(node.left) and self._is_dict_expr(node.right)):
            return True
        return False

    def _emit_write_single(self, node: ast.expr) -> None:
        """Emit a write (no newline) for a single expression via FV dispatch."""
        # Ellipsis: write "Ellipsis" directly (no runtime tag for it)
        if isinstance(node, ast.Constant) and node.value is ...:
            str_ptr = self._make_string_constant("Ellipsis")
            self.builder.call(self.runtime["write_str"], [str_ptr])
            return
        if isinstance(node, ast.Name) and node.id in self._ellipsis_vars:
            str_ptr = self._make_string_constant("Ellipsis")
            self.builder.call(self.runtime["write_str"], [str_ptr])
            return
        fv = self._load_or_wrap_fv(node)
        self._emit_try_bail_if_exc()
        tag, data = self._fv_unpack(fv)
        self.builder.call(self.runtime["fv_write"], [tag, data])

    def _is_pyobj_var(self, node: ast.expr) -> bool:
        """Check if an expression is a pyobj-tagged variable."""
        if isinstance(node, ast.Name) and node.id in self.variables:
            return self._var_kind(node.id) == VKind.PYOBJ
        return False

    def _is_mixed_var(self, node: ast.expr) -> bool:
        """Check if an expression is a variable with 'mixed' type tag
        (could hold different types at runtime, e.g., function parameter
        called with both int and str arguments at different call sites)."""
        if isinstance(node, ast.Name) and node.id in self.variables:
            return self._var_kind(node.id) == VKind.MIXED
        return False

    def _is_fv_float_var(self, node: ast.expr) -> bool:
        """Check if an expression is a variable backed by an FpyValue that
        might hold a float (e.g. result of CPython bridge call)."""
        if not isinstance(node, ast.Name):
            # Direct CPython method call in expression: math.sqrt(9)+1
            if (isinstance(node, ast.Call)
                    and isinstance(node.func, ast.Attribute)):
                recv = node.func.value
                if (isinstance(recv, ast.Name)
                        and recv.id in self.variables
                        and self._var_kind(recv.id) == VKind.PYOBJ):
                    return True
            return False
        if node.id not in self.variables:
            return False
        # Check if variable was marked as from CPython bridge
        return node.id in getattr(self, '_cpython_result_vars', set())

    def _maybe_unwrap_fv_float(self, val: ir.Value,
                                node: ast.expr) -> ir.Value:
        """If a value comes from an FV-backed variable that might hold a float
        (e.g. from CPython bridge), check the runtime tag and bitcast to double.
        Returns the value unchanged if it's not an FV float."""
        if not self._USE_FV_LOCALS:
            return val
        if not (isinstance(val.type, ir.IntType) and val.type.width == 64):
            return val
        if not isinstance(node, ast.Name):
            return val
        if node.id not in self.variables:
            return val
        alloca, tag = self.variables[node.id]
        if not (isinstance(alloca.type, ir.PointerType)
                and alloca.type.pointee is fpy_val):
            return val
        # Load the FV and check if tag is FLOAT
        fv = self.builder.load(alloca)
        fv_tag = self.builder.extract_value(fv, 0)
        is_float = self.builder.icmp_signed(
            "==", fv_tag, ir.Constant(i32, FPY_TAG_FLOAT))
        float_val = self.builder.bitcast(val, double)
        # If float, return double; otherwise return original i64.
        # To unify the return type, convert the double path to i64 and
        # let the caller handle both. Actually, for arithmetic we need to
        # branch: if either operand is float, do float arithmetic.
        # Return a sentinel — use select to bitcast when float.
        # Since we can't change the type at runtime, tag this for the caller.
        return val  # caller must handle via _check_fv_float_operands

    def _convert_pyobj_to_numeric(self, val: ir.Value,
                                   node: ast.expr) -> ir.Value:
        """Convert a pyobj-tagged variable to a numeric value for arithmetic.
        Returns a double (converting int→double via sitofp, float→double
        via bitcast from the FpyValue data)."""
        if isinstance(val.type, ir.PointerType):
            # pyobj variable — convert through bridge to FpyValue.
            # Use peek_fv (borrow) since the variable still holds the
            # PyObject* reference and may be accessed again in the same
            # scope (e.g. inside a loop or used in multiple expressions).
            tag_a = self._create_entry_alloca(i32, "py2num.tag")
            data_a = self._create_entry_alloca(i64, "py2num.data")
            self.builder.call(self.runtime["cpython_peek_fv"],
                              [val, tag_a, data_a])
            tag = self.builder.load(tag_a)
            data = self.builder.load(data_a)
            is_float = self.builder.icmp_signed(
                "==", tag, ir.Constant(i32, FPY_TAG_FLOAT))
            float_val = self.builder.bitcast(data, double)
            int_as_float = self.builder.sitofp(data, double)
            return self.builder.select(is_float, float_val, int_as_float)
        return None  # not a pyobj

    def _is_bigint_expr(self, node: ast.expr) -> bool:
        """Check if an expression evaluates to a BigInt value."""
        if isinstance(node, ast.Constant) and isinstance(node.value, int):
            return (node.value > 2**63 - 1 or node.value < -(2**63))
        if isinstance(node, ast.Name) and node.id in self.variables:
            return self._var_kind(node.id) == VKind.BIGINT
        if isinstance(node, ast.BinOp):
            return (self._is_bigint_expr(node.left)
                    or self._is_bigint_expr(node.right))
        if isinstance(node, ast.UnaryOp):
            return self._is_bigint_expr(node.operand)
        return False

    def _is_complex_expr(self, node: ast.expr) -> bool:
        """Check if an expression evaluates to a complex number."""
        if isinstance(node, ast.Constant) and isinstance(node.value, complex):
            return True
        if isinstance(node, ast.Name) and node.id in self.variables:
            return self._var_kind(node.id) == VKind.COMPLEX
        if (isinstance(node, ast.Call) and isinstance(node.func, ast.Name)
                and node.func.id == "complex"):
            return True
        if isinstance(node, ast.BinOp):
            return (self._is_complex_expr(node.left)
                    or self._is_complex_expr(node.right))
        if isinstance(node, ast.UnaryOp):
            return self._is_complex_expr(node.operand)
        return False

    def _is_bytes_expr(self, node: ast.expr) -> bool:
        """Check if an expression evaluates to a bytes value."""
        if isinstance(node, ast.Constant) and isinstance(node.value, bytes):
            return True
        if isinstance(node, ast.Name) and node.id in self.variables:
            return self._var_kind(node.id) == VKind.BYTES
        if isinstance(node, ast.BinOp):
            return (self._is_bytes_expr(node.left)
                    or self._is_bytes_expr(node.right))
        return False

    def _emit_complex_binop(self, node: ast.BinOp,
                              left_is_complex: bool,
                              right_is_complex: bool) -> ir.Value:
        """Emit binary operation with complex operands."""
        # Get both operands as complex pointers
        if left_is_complex:
            left_val = self._emit_expr_value(node.left)
            left_ptr = self._ensure_ptr(left_val)
        else:
            # Convert scalar to complex(val, 0)
            left_val = self._emit_expr_value(node.left)
            if isinstance(left_val.type, ir.IntType):
                left_val = self.builder.sitofp(left_val, double)
            left_ptr = self.builder.call(
                self.runtime["complex_new"],
                [left_val, ir.Constant(double, 0.0)])
        if right_is_complex:
            right_val = self._emit_expr_value(node.right)
            right_ptr = self._ensure_ptr(right_val)
        else:
            right_val = self._emit_expr_value(node.right)
            if isinstance(right_val.type, ir.IntType):
                right_val = self.builder.sitofp(right_val, double)
            right_ptr = self.builder.call(
                self.runtime["complex_new"],
                [right_val, ir.Constant(double, 0.0)])

        op = node.op
        if isinstance(op, ast.Add):
            result = self.builder.call(self.runtime["complex_add"],
                                       [left_ptr, right_ptr])
        elif isinstance(op, ast.Sub):
            result = self.builder.call(self.runtime["complex_sub"],
                                       [left_ptr, right_ptr])
        elif isinstance(op, ast.Mult):
            result = self.builder.call(self.runtime["complex_mul"],
                                       [left_ptr, right_ptr])
        elif isinstance(op, ast.Div):
            result = self.builder.call(self.runtime["complex_div"],
                                       [left_ptr, right_ptr])
        elif isinstance(op, ast.Pow):
            result = self.builder.call(self.runtime["complex_pow"],
                                       [left_ptr, right_ptr])
        else:
            return self._bridge_fallback_expr(
                node, f"complex operation: {type(op).__name__}")
        return self.builder.ptrtoint(result, i64)

    def _unknown_fv_to_double(self, node: ast.expr,
                              val: ir.Value) -> ir.Value:
        """Convert an UNKNOWN FV variable's bare i64 value to double using
        the runtime tag.  For FLOAT data: bitcast(i64→double) recovers the
        original double.  For INT data: sitofp(i64→double) converts correctly.
        Uses ``select`` so no extra basic blocks are needed."""
        if isinstance(node, ast.Name) and node.id in self.variables:
            alloca, tag = self.variables[node.id]
            if (self._tag_kind(tag) in (VKind.UNKNOWN, VKind.FVALUE, VKind.MIXED)
                    and isinstance(alloca.type, ir.PointerType)
                    and alloca.type.pointee is fpy_val):
                fv = self.builder.load(alloca, name=f"{node.id}.fv.arith")
                rt_tag = self._fv_tag(fv)
                is_float = self.builder.icmp_unsigned(
                    "==", rt_tag, ir.Constant(i32, 1))
                float_val = self.builder.bitcast(val, double)
                int_val = self.builder.sitofp(val, double)
                return self.builder.select(is_float, float_val, int_val)
        # Fallback: integer → sitofp promotion
        if isinstance(val.type, ir.IntType):
            return self.builder.sitofp(val, double)
        return val

    def _emit_binop_unknown(self, node, ltv, rtv, lk, rk, op):
        """Handle binop when either operand has VKind.UNKNOWN (runtime-tag dispatch)."""
        # For Add with FpyValue operands, check runtime tags for STR.
        # String pointers bitcast to double produce garbage, so we must
        # dispatch to str_concat when both operands are strings.
        if op == ast.Add:
            l_fv = ltv.val
            r_fv = rtv.val
            # Extract runtime tags from FpyValue operands
            l_tag = r_tag = None
            if isinstance(l_fv.type, ir.LiteralStructType):
                l_tag = self.builder.extract_value(l_fv, 0)
            elif lk in (VKind.UNKNOWN, VKind.FVALUE, VKind.MIXED) and isinstance(node.left, ast.Name):
                alloca, _ = self.variables.get(node.left.id, (None, None))
                if (alloca and isinstance(alloca.type, ir.PointerType)
                        and alloca.type.pointee is fpy_val):
                    fv = self.builder.load(alloca)
                    l_tag = self.builder.extract_value(fv, 0)
            if isinstance(r_fv.type, ir.LiteralStructType):
                r_tag = self.builder.extract_value(r_fv, 0)
            elif rk in (VKind.UNKNOWN, VKind.FVALUE, VKind.MIXED) and isinstance(node.right, ast.Name):
                alloca, _ = self.variables.get(node.right.id, (None, None))
                if (alloca and isinstance(alloca.type, ir.PointerType)
                        and alloca.type.pointee is fpy_val):
                    fv = self.builder.load(alloca)
                    r_tag = self.builder.extract_value(fv, 0)
            if l_tag is not None and r_tag is not None:
                both_str = self.builder.and_(
                    self.builder.icmp_unsigned(
                        "==", l_tag, ir.Constant(i32, FPY_TAG_STR)),
                    self.builder.icmp_unsigned(
                        "==", r_tag, ir.Constant(i32, FPY_TAG_STR)))
                str_blk = self._new_block("unkn.str_add")
                num_blk = self._new_block("unkn.num_add")
                join_blk = self._new_block("unkn.add_join")
                self.builder.cbranch(both_str, str_blk, num_blk)

                # String path: extract data as pointers, call str_concat
                self.builder.position_at_end(str_blk)
                l_data = self.builder.extract_value(l_fv, 1) \
                    if isinstance(l_fv.type, ir.LiteralStructType) \
                    else ltv.as_i64(self.builder)
                r_data = self.builder.extract_value(r_fv, 1) \
                    if isinstance(r_fv.type, ir.LiteralStructType) \
                    else rtv.as_i64(self.builder)
                l_ptr = self._ensure_ptr(l_data)
                r_ptr = self._ensure_ptr(r_data)
                str_result = self.builder.call(
                    self.runtime["str_concat"], [l_ptr, r_ptr])
                # Convert to i8* result (same as VKind.STR)
                str_as_i64 = self.builder.ptrtoint(str_result, i64)
                self.builder.branch(join_blk)
                str_end = self.builder.block

                # Numeric path: split into int-preserving and float
                # sub-paths when runtime tags are available so that
                # UNKNOWN(INT) + UNKNOWN(INT) stays int.
                self.builder.position_at_end(num_blk)
                # Extract i64 data from each operand
                _nl = l_fv if isinstance(l_fv.type, ir.LiteralStructType) \
                    else ltv.val
                _nr = r_fv if isinstance(r_fv.type, ir.LiteralStructType) \
                    else rtv.val
                _nl_i64 = self.builder.extract_value(_nl, 1) \
                    if isinstance(_nl.type, ir.LiteralStructType) \
                    else (_nl if isinstance(_nl.type, ir.IntType)
                          and _nl.type.width == 64
                          else self.builder.sext(_nl, i64)
                          if isinstance(_nl.type, ir.IntType) else _nl)
                _nr_i64 = self.builder.extract_value(_nr, 1) \
                    if isinstance(_nr.type, ir.LiteralStructType) \
                    else (_nr if isinstance(_nr.type, ir.IntType)
                          and _nr.type.width == 64
                          else self.builder.sext(_nr, i64)
                          if isinstance(_nr.type, ir.IntType) else _nr)
                # Check if both are INT
                _n_both_int = self.builder.and_(
                    self.builder.icmp_unsigned(
                        "==", l_tag, ir.Constant(i32, FPY_TAG_INT)),
                    self.builder.icmp_unsigned(
                        "==", r_tag, ir.Constant(i32, FPY_TAG_INT)))
                _n_int_blk = self._new_block("unkn.num_int")
                _n_flt_blk = self._new_block("unkn.num_flt")
                _n_join = self._new_block("unkn.num_join")
                self.builder.cbranch(_n_both_int, _n_int_blk, _n_flt_blk)
                # ── both-INT sub-path: integer addition ──
                self.builder.position_at_end(_n_int_blk)
                _n_ires = self._emit_int_binop(
                    node.op, _nl_i64, _nr_i64, node)
                # Consume BigInt overflow flag from _emit_int_binop
                _n_bigint_flag = self._bigint_overflow_flag
                self._bigint_overflow_flag = None
                if isinstance(_n_ires.type, ir.DoubleType):
                    _n_idata = self.builder.bitcast(_n_ires, i64)
                    _n_itag = ir.Constant(i32, FPY_TAG_FLOAT)
                elif (isinstance(_n_ires.type, ir.LiteralStructType)
                        and _n_ires.type == fpy_val):
                    _n_idata = self.builder.extract_value(_n_ires, 1)
                    _n_itag = self.builder.extract_value(_n_ires, 0)
                elif (isinstance(_n_ires.type, ir.IntType)
                        and _n_ires.type.width == 64):
                    _n_idata = _n_ires
                    if _n_bigint_flag is not None:
                        _n_itag = self.builder.select(
                            _n_bigint_flag,
                            ir.Constant(i32, FPY_TAG_BIGINT),
                            ir.Constant(i32, FPY_TAG_INT))
                    else:
                        _n_itag = ir.Constant(i32, FPY_TAG_INT)
                else:
                    _n_idata = self.builder.sext(_n_ires, i64) \
                        if isinstance(_n_ires.type, ir.IntType) \
                        else self.builder.ptrtoint(_n_ires, i64)
                    _n_itag = ir.Constant(i32, FPY_TAG_INT)
                self.builder.branch(_n_join)
                _n_int_end = self.builder.block
                # ── float sub-path: tag-aware double conversion ──
                self.builder.position_at_end(_n_flt_blk)
                _lf = self.builder.icmp_unsigned(
                    "==", l_tag, ir.Constant(i32, FPY_TAG_FLOAT))
                _l_bc = self.builder.bitcast(_nl_i64, double)
                _l_si = self.builder.sitofp(_nl_i64, double)
                _ld = self.builder.select(_lf, _l_bc, _l_si)
                _rf = self.builder.icmp_unsigned(
                    "==", r_tag, ir.Constant(i32, FPY_TAG_FLOAT))
                _r_bc = self.builder.bitcast(_nr_i64, double)
                _r_si = self.builder.sitofp(_nr_i64, double)
                _rd = self.builder.select(_rf, _r_bc, _r_si)
                _n_fres = self._emit_float_binop(node.op, _ld, _rd, node)
                if isinstance(_n_fres.type, ir.DoubleType):
                    _n_fdata = self.builder.bitcast(_n_fres, i64)
                elif (isinstance(_n_fres.type, ir.IntType)
                        and _n_fres.type.width == 64):
                    _n_fdata = _n_fres
                else:
                    _n_fdata = self.builder.sext(_n_fres, i64) \
                        if isinstance(_n_fres.type, ir.IntType) \
                        else self.builder.ptrtoint(_n_fres, i64)
                self.builder.branch(_n_join)
                _n_flt_end = self.builder.block
                # ── numeric merge ──
                self.builder.position_at_end(_n_join)
                _n_tphi = self.builder.phi(i32, "unkn.num.tag")
                _n_tphi.add_incoming(_n_itag, _n_int_end)
                _n_tphi.add_incoming(
                    ir.Constant(i32, FPY_TAG_FLOAT), _n_flt_end)
                _n_dphi = self.builder.phi(i64, "unkn.num.data")
                _n_dphi.add_incoming(_n_idata, _n_int_end)
                _n_dphi.add_incoming(_n_fdata, _n_flt_end)
                num_as_i64 = _n_dphi
                num_tag = _n_tphi
                self.builder.branch(join_blk)
                num_end = self.builder.block

                # Join: phi between string result and numeric result
                self.builder.position_at_end(join_blk)
                # Build FpyValue with correct tag
                tag_phi = self.builder.phi(i32, "unkn.add.tag")
                tag_phi.add_incoming(ir.Constant(i32, FPY_TAG_STR), str_end)
                tag_phi.add_incoming(num_tag, num_end)
                data_phi = self.builder.phi(i64, "unkn.add.data")
                data_phi.add_incoming(str_as_i64, str_end)
                data_phi.add_incoming(num_as_i64, num_end)
                fv = self._fv_build_from_slots(tag_phi, data_phi)
                return fv

        # ── UNKNOWN + INT (or INT + UNKNOWN): runtime branch to
        #    preserve integer results when the UNKNOWN operand is
        #    actually INT at runtime.  Fixes the dict.get() counter
        #    pattern: d[k] = d.get(k, 0) + 1 should stay int. ──────
        if op != ast.Div and (
            (lk == VKind.UNKNOWN and rk == VKind.INT)
            or (lk == VKind.INT and rk == VKind.UNKNOWN)
        ):
            unkn_left = (lk == VKind.UNKNOWN)
            unkn_raw = ltv.val if unkn_left else rtv.val
            int_val = rtv.val if unkn_left else ltv.val
            # Ensure int_val is i64
            if isinstance(int_val.type, ir.IntType) and int_val.type.width != 64:
                int_val = self.builder.sext(int_val, i64)
            # Extract runtime tag and i64 data from the UNKNOWN operand.
            # Two shapes: (a) raw FpyValue struct from a call like dict.get(),
            # (b) bare i64 loaded from a named FV variable.
            _rt_tag = None
            _unkn_i64 = None
            if (isinstance(unkn_raw.type, ir.LiteralStructType)
                    and unkn_raw.type == fpy_val):
                # Direct FpyValue struct (e.g. dict.get() result)
                _rt_tag = self.builder.extract_value(unkn_raw, 0)
                _unkn_i64 = self.builder.extract_value(unkn_raw, 1)
            else:
                # Bare i64 from a named variable — reload the FV for the tag
                unkn_node = node.left if unkn_left else node.right
                if isinstance(unkn_node, ast.Name):
                    _alloca_info = self.variables.get(unkn_node.id)
                    if _alloca_info is not None:
                        _a, _ = _alloca_info
                        if (isinstance(_a.type, ir.PointerType)
                                and _a.type.pointee is fpy_val):
                            _fv = self.builder.load(_a)
                            _rt_tag = self._fv_tag(_fv)
                if isinstance(unkn_raw.type, ir.IntType):
                    _unkn_i64 = unkn_raw if unkn_raw.type.width == 64 \
                        else self.builder.sext(unkn_raw, i64)
            if _rt_tag is not None and _unkn_i64 is not None:
                _is_int = self.builder.icmp_unsigned(
                    "==", _rt_tag, ir.Constant(i32, FPY_TAG_INT))
                _int_bb = self._new_block("unkn_int.iarith")
                _flt_bb = self._new_block("unkn_int.farith")
                _mrg_bb = self._new_block("unkn_int.merge")
                self.builder.cbranch(_is_int, _int_bb, _flt_bb)
                # ── INT path: integer arithmetic ──
                self.builder.position_at_end(_int_bb)
                if unkn_left:
                    _ires = self._emit_int_binop(
                        node.op, _unkn_i64, int_val, node)
                else:
                    _ires = self._emit_int_binop(
                        node.op, int_val, _unkn_i64, node)
                if isinstance(_ires.type, ir.DoubleType):
                    _idata = self.builder.bitcast(_ires, i64)
                    _itag = ir.Constant(i32, FPY_TAG_FLOAT)
                elif (isinstance(_ires.type, ir.IntType)
                        and _ires.type.width == 64):
                    _idata = _ires
                    _itag = ir.Constant(i32, FPY_TAG_INT)
                else:
                    _idata = self.builder.sext(_ires, i64) \
                        if isinstance(_ires.type, ir.IntType) \
                        else self.builder.ptrtoint(_ires, i64)
                    _itag = ir.Constant(i32, FPY_TAG_INT)
                self.builder.branch(_mrg_bb)
                _int_end = self.builder.block
                # ── FLOAT path: float arithmetic ──
                self.builder.position_at_end(_flt_bb)
                _unkn_d = self.builder.bitcast(_unkn_i64, double)
                _int_d = self.builder.sitofp(int_val, double)
                if unkn_left:
                    _fres = self._emit_float_binop(
                        node.op, _unkn_d, _int_d, node)
                else:
                    _fres = self._emit_float_binop(
                        node.op, _int_d, _unkn_d, node)
                if isinstance(_fres.type, ir.DoubleType):
                    _fdata = self.builder.bitcast(_fres, i64)
                elif (isinstance(_fres.type, ir.IntType)
                        and _fres.type.width == 64):
                    _fdata = _fres
                else:
                    _fdata = self.builder.sext(_fres, i64) \
                        if isinstance(_fres.type, ir.IntType) \
                        else self.builder.ptrtoint(_fres, i64)
                self.builder.branch(_mrg_bb)
                _flt_end = self.builder.block
                # ── Merge: FpyValue with runtime-correct tag ──
                self.builder.position_at_end(_mrg_bb)
                _tag_phi = self.builder.phi(i32, "unkn_int.tag")
                _tag_phi.add_incoming(_itag, _int_end)
                _tag_phi.add_incoming(
                    ir.Constant(i32, FPY_TAG_FLOAT), _flt_end)
                _data_phi = self.builder.phi(i64, "unkn_int.data")
                _data_phi.add_incoming(_idata, _int_end)
                _data_phi.add_incoming(_fdata, _flt_end)
                return self._fv_build_from_slots(_tag_phi, _data_phi)

        # ── UNKNOWN + UNKNOWN: runtime branch preserving int-ness ──
        # When both operands are UNKNOWN FpyValue structs (e.g. two
        # dict.get() calls), check if both are INT at runtime and use
        # integer arithmetic if so.
        if (lk == VKind.UNKNOWN and rk == VKind.UNKNOWN
                and op != ast.Div):
            _lraw = ltv.val
            _rraw = rtv.val
            _ltag = _rtag = None
            _li64 = _ri64 = None
            # Extract tag + data from left
            if (isinstance(_lraw.type, ir.LiteralStructType)
                    and _lraw.type == fpy_val):
                _ltag = self.builder.extract_value(_lraw, 0)
                _li64 = self.builder.extract_value(_lraw, 1)
            elif isinstance(node.left, ast.Name):
                _la = self.variables.get(node.left.id)
                if _la:
                    _a, _ = _la
                    if (isinstance(_a.type, ir.PointerType)
                            and _a.type.pointee is fpy_val):
                        _fv = self.builder.load(_a)
                        _ltag = self._fv_tag(_fv)
                if isinstance(_lraw.type, ir.IntType):
                    _li64 = _lraw if _lraw.type.width == 64 \
                        else self.builder.sext(_lraw, i64)
            # Extract tag + data from right
            if (isinstance(_rraw.type, ir.LiteralStructType)
                    and _rraw.type == fpy_val):
                _rtag = self.builder.extract_value(_rraw, 0)
                _ri64 = self.builder.extract_value(_rraw, 1)
            elif isinstance(node.right, ast.Name):
                _ra = self.variables.get(node.right.id)
                if _ra:
                    _a, _ = _ra
                    if (isinstance(_a.type, ir.PointerType)
                            and _a.type.pointee is fpy_val):
                        _fv = self.builder.load(_a)
                        _rtag = self._fv_tag(_fv)
                if isinstance(_rraw.type, ir.IntType):
                    _ri64 = _rraw if _rraw.type.width == 64 \
                        else self.builder.sext(_rraw, i64)
            if (_ltag is not None and _rtag is not None
                    and _li64 is not None and _ri64 is not None):
                _both_int = self.builder.and_(
                    self.builder.icmp_unsigned(
                        "==", _ltag, ir.Constant(i32, FPY_TAG_INT)),
                    self.builder.icmp_unsigned(
                        "==", _rtag, ir.Constant(i32, FPY_TAG_INT)))
                _uu_int = self._new_block("unkn_uu.iarith")
                _uu_flt = self._new_block("unkn_uu.farith")
                _uu_mrg = self._new_block("unkn_uu.merge")
                self.builder.cbranch(_both_int, _uu_int, _uu_flt)
                # ── both-INT path ──
                self.builder.position_at_end(_uu_int)
                _uires = self._emit_int_binop(
                    node.op, _li64, _ri64, node)
                if isinstance(_uires.type, ir.DoubleType):
                    _uidata = self.builder.bitcast(_uires, i64)
                    _uitag = ir.Constant(i32, FPY_TAG_FLOAT)
                elif (isinstance(_uires.type, ir.IntType)
                        and _uires.type.width == 64):
                    _uidata = _uires
                    _uitag = ir.Constant(i32, FPY_TAG_INT)
                else:
                    _uidata = self.builder.sext(_uires, i64) \
                        if isinstance(_uires.type, ir.IntType) \
                        else self.builder.ptrtoint(_uires, i64)
                    _uitag = ir.Constant(i32, FPY_TAG_INT)
                self.builder.branch(_uu_mrg)
                _uu_int_end = self.builder.block
                # ── float path: tag-aware conversion ──
                self.builder.position_at_end(_uu_flt)
                # Left: select(tag==FLOAT, bitcast, sitofp)
                _l_is_f = self.builder.icmp_unsigned(
                    "==", _ltag, ir.Constant(i32, FPY_TAG_FLOAT))
                _l_bc = self.builder.bitcast(_li64, double)
                _l_si = self.builder.sitofp(_li64, double)
                _ld = self.builder.select(_l_is_f, _l_bc, _l_si)
                # Right: same
                _r_is_f = self.builder.icmp_unsigned(
                    "==", _rtag, ir.Constant(i32, FPY_TAG_FLOAT))
                _r_bc = self.builder.bitcast(_ri64, double)
                _r_si = self.builder.sitofp(_ri64, double)
                _rd = self.builder.select(_r_is_f, _r_bc, _r_si)
                _ufres = self._emit_float_binop(
                    node.op, _ld, _rd, node)
                if isinstance(_ufres.type, ir.DoubleType):
                    _ufdata = self.builder.bitcast(_ufres, i64)
                elif (isinstance(_ufres.type, ir.IntType)
                        and _ufres.type.width == 64):
                    _ufdata = _ufres
                else:
                    _ufdata = self.builder.sext(_ufres, i64) \
                        if isinstance(_ufres.type, ir.IntType) \
                        else self.builder.ptrtoint(_ufres, i64)
                self.builder.branch(_uu_mrg)
                _uu_flt_end = self.builder.block
                # ── merge ──
                self.builder.position_at_end(_uu_mrg)
                _uu_tphi = self.builder.phi(i32, "unkn_uu.tag")
                _uu_tphi.add_incoming(_uitag, _uu_int_end)
                _uu_tphi.add_incoming(
                    ir.Constant(i32, FPY_TAG_FLOAT), _uu_flt_end)
                _uu_dphi = self.builder.phi(i64, "unkn_uu.data")
                _uu_dphi.add_incoming(_uidata, _uu_int_end)
                _uu_dphi.add_incoming(_ufdata, _uu_flt_end)
                return self._fv_build_from_slots(_uu_tphi, _uu_dphi)

        # ── UNKNOWN with extractable tags: fv_binop dispatch ─────
        # The tag-preserving fast paths above skip ast.Div (division
        # always returns float so int-preservation is moot) and only
        # handle INT/FLOAT branches — non-numeric types (str, list,
        # etc.) cause garbage double conversions.  Route through the
        # C fv_binop which handles ALL type combinations correctly
        # (str concat, repeat, TypeError for invalid combos, and
        # proper INT→FLOAT promotion for truediv).
        _fv_op_map = {ast.Add: 0, ast.Sub: 1, ast.Mult: 2, ast.Div: 3,
                      ast.FloorDiv: 4, ast.Mod: 5}
        _gf_opc = _fv_op_map.get(op)
        if _gf_opc is not None:
            _gf_lt = _gf_ld = _gf_rt = _gf_rd = None
            # Extract left tag + data
            if lk == VKind.UNKNOWN:
                if (isinstance(ltv.val.type, ir.LiteralStructType)
                        and ltv.val.type == fpy_val):
                    _gf_lt = self.builder.extract_value(ltv.val, 0)
                    _gf_ld = self.builder.extract_value(ltv.val, 1)
                elif isinstance(node.left, ast.Name):
                    _al = self.variables.get(node.left.id)
                    if _al:
                        _a, _ = _al
                        if (isinstance(_a.type, ir.PointerType)
                                and _a.type.pointee is fpy_val):
                            _fv = self.builder.load(_a)
                            _gf_lt = self.builder.extract_value(_fv, 0)
                            _gf_ld = self.builder.extract_value(_fv, 1)
            else:
                _gf_lt = ir.Constant(i32, ltv.vtype.kind.fpy_tag)
                _gf_ld = ltv.as_i64(self.builder)
            # Extract right tag + data
            if rk == VKind.UNKNOWN:
                if (isinstance(rtv.val.type, ir.LiteralStructType)
                        and rtv.val.type == fpy_val):
                    _gf_rt = self.builder.extract_value(rtv.val, 0)
                    _gf_rd = self.builder.extract_value(rtv.val, 1)
                elif isinstance(node.right, ast.Name):
                    _ar = self.variables.get(node.right.id)
                    if _ar:
                        _a, _ = _ar
                        if (isinstance(_a.type, ir.PointerType)
                                and _a.type.pointee is fpy_val):
                            _fv = self.builder.load(_a)
                            _gf_rt = self.builder.extract_value(_fv, 0)
                            _gf_rd = self.builder.extract_value(_fv, 1)
            else:
                _gf_rt = ir.Constant(i32, rtv.vtype.kind.fpy_tag)
                _gf_rd = rtv.as_i64(self.builder)
            if (_gf_lt is not None and _gf_ld is not None
                    and _gf_rt is not None and _gf_rd is not None):
                _ot = self._create_entry_alloca(i32, "ugf.tag")
                _od = self._create_entry_alloca(i64, "ugf.data")
                self.builder.call(self.runtime["fv_binop"],
                                  [_gf_lt, _gf_ld, _gf_rt, _gf_rd,
                                   ir.Constant(i32, _gf_opc),
                                   _ot, _od])
                self._emit_try_bail_if_exc()
                return self._fv_build_from_slots(
                    self.builder.load(_ot),
                    self.builder.load(_od))

        # ── Generic UNKNOWN fallback: promote both to double ──────
        # This path handles cases where runtime tags couldn't be
        # extracted (non-Name, non-struct operands).
        left_v = ltv.val
        right_v = rtv.val
        if lk == VKind.UNKNOWN:
            left_v = self._unknown_fv_to_double(node.left, left_v)
        elif lk == VKind.INT:
            left_v = self.builder.sitofp(left_v, double)
        elif lk != VKind.FLOAT:
            left_v = left_v if isinstance(left_v.type, ir.DoubleType) \
                else self.builder.sitofp(left_v, double) \
                if isinstance(left_v.type, ir.IntType) else left_v
        if rk == VKind.UNKNOWN:
            right_v = self._unknown_fv_to_double(node.right, right_v)
        elif rk == VKind.INT:
            right_v = self.builder.sitofp(right_v, double)
        elif rk != VKind.FLOAT:
            right_v = right_v if isinstance(right_v.type, ir.DoubleType) \
                else self.builder.sitofp(right_v, double) \
                if isinstance(right_v.type, ir.IntType) else right_v
        # Safety: if either operand is still an FpyValue struct (not a
        # bare scalar), extract the data i64 and use tag-aware
        # conversion (sitofp for INT, bitcast for FLOAT).
        for lbl, v, setter in [("left", left_v, "left_v"),
                               ("right", right_v, "right_v")]:
            if isinstance(v.type, ir.LiteralStructType):
                _s_tag = self.builder.extract_value(v, 0)
                _s_data = self.builder.extract_value(v, 1)
                _s_is_flt = self.builder.icmp_unsigned(
                    "==", _s_tag, ir.Constant(i32, FPY_TAG_FLOAT))
                _s_bc = self.builder.bitcast(_s_data, double)
                _s_si = self.builder.sitofp(_s_data, double)
                converted = self.builder.select(
                    _s_is_flt, _s_bc, _s_si)
                if setter == "left_v":
                    left_v = converted
                else:
                    right_v = converted
        return self._emit_float_binop(node.op, left_v, right_v, node)

    def _emit_binop(self, node: ast.BinOp) -> ir.Value:
        """Emit a binary operation. Phase 2: TypedValue dispatch with fast paths."""
        ltv = self._emit_expr(node.left)
        rtv = self._emit_expr(node.right)
        lk = ltv.vtype.kind
        rk = rtv.vtype.kind
        op = type(node.op)

        # ── UNKNOWN FV operands: runtime-tag arithmetic dispatch ──────
        # Variables from deep/nested for-loop unpacking have type "unknown"
        # — the i64 data may be a float bit-pattern, not an integer.
        # Convert to double via a select(tag==FLOAT, bitcast, sitofp).
        if lk == VKind.UNKNOWN or rk == VKind.UNKNOWN:
            return self._emit_binop_unknown(node, ltv, rtv, lk, rk, op)

        # ── Fast path: BigInt arithmetic ───────────────────────────────
        if lk == VKind.BIGINT or rk == VKind.BIGINT:
            # Promote INT operand to BigInt if needed
            if lk == VKind.BIGINT:
                l_ptr = ltv.as_ptr(self.builder)
            else:
                l_ptr = self.builder.call(
                    self.runtime["bigint_from_i64"],
                    [ltv.as_i64(self.builder)])
            if rk == VKind.BIGINT:
                r_ptr = rtv.as_ptr(self.builder)
            else:
                r_ptr = self.builder.call(
                    self.runtime["bigint_from_i64"],
                    [rtv.as_i64(self.builder)])
            _bigint_ops = {
                ast.Add: "bigint_add", ast.Sub: "bigint_sub",
                ast.Mult: "bigint_mul", ast.FloorDiv: "bigint_floordiv",
                ast.Mod: "bigint_mod", ast.Pow: "bigint_pow",
            }
            rt_name = _bigint_ops.get(op)
            if rt_name:
                return self.builder.call(
                    self.runtime[rt_name], [l_ptr, r_ptr])

        # ── Fast path: int op int ──────────────────────────────────────
        if lk == VKind.INT and rk == VKind.INT:
            result = self._emit_int_binop(node.op, ltv.as_i64(self.builder),
                                           rtv.as_i64(self.builder), node)
            # If the operation might have overflowed to BigInt, wrap in an
            # FpyValue struct with a dynamic tag so the runtime can distinguish.
            bigint_flag = self._bigint_overflow_flag
            self._bigint_overflow_flag = None
            if bigint_flag is not None:
                tag = self.builder.select(
                    bigint_flag,
                    ir.Constant(i32, FPY_TAG_BIGINT),
                    ir.Constant(i32, FPY_TAG_INT))
                fv = ir.Constant(fpy_val, ir.Undefined)
                fv = self.builder.insert_value(fv, tag, 0)
                fv = self.builder.insert_value(fv, result, 1)
                return fv
            return result

        # ── Fast path: str % ... (format) — must be checked before the
        #    float fast path, because "%.2f" % 3.14 has rk==FLOAT and
        #    would be misrouted to float modulo. ────────────────────────
        if lk == VKind.STR and op == ast.Mod:
            # fmt % args
            args_list = rtv.as_ptr(self.builder) if rk in (VKind.LIST, VKind.TUPLE) \
                else self._wrap_single_as_list(rtv)
            return self._rt_call("str_format_percent", [ltv, TypedValue(args_list, ValueType(VKind.LIST))])

        # ── Fast path: float op float (or int+float promotion) ─────────
        # Guard: float+container is always TypeError (e.g. "hello" + 1.5).
        # Only promote to float when the other side is numeric-compatible.
        _float_incompatible = (VKind.STR, VKind.LIST, VKind.DICT, VKind.SET,
                               VKind.TUPLE, VKind.BYTES, VKind.OBJ)
        if ((lk == VKind.FLOAT or rk == VKind.FLOAT)
                and lk not in _float_incompatible
                and rk not in _float_incompatible):
            left_d = ltv.val if lk == VKind.FLOAT else self.builder.sitofp(ltv.as_i64(self.builder), double)
            right_d = rtv.val if rk == VKind.FLOAT else self.builder.sitofp(rtv.as_i64(self.builder), double)
            return self._emit_float_binop(node.op, left_d, right_d, node)

        # ── Fast path: str + str → concat ──────────────────────────────
        if lk == VKind.STR and rk == VKind.STR and op == ast.Add:
            return self._rt_call("str_concat", [ltv, rtv])
        if lk == VKind.STR and rk in (VKind.INT, VKind.BOOL) and op == ast.Mult:
            return self._rt_call("str_repeat", [ltv, rtv])
        if lk in (VKind.INT, VKind.BOOL) and rk == VKind.STR and op == ast.Mult:
            return self._rt_call("str_repeat", [rtv, ltv])
        # bytes + bytes → concat, bytes * int → repetition (same runtime as str)
        if lk == VKind.BYTES and rk == VKind.BYTES and op == ast.Add:
            return self._rt_call("str_concat", [ltv, rtv])
        if lk == VKind.BYTES and rk in (VKind.INT, VKind.BOOL) and op == ast.Mult:
            return self._rt_call("str_repeat", [ltv, rtv])
        if lk in (VKind.INT, VKind.BOOL) and rk == VKind.BYTES and op == ast.Mult:
            return self._rt_call("str_repeat", [rtv, ltv])
        # str + i64 or i64 + str from a closure/function-pointer call:
        # the i64 is likely a string pointer whose type tag was lost through
        # the closure calling convention (common in decorator wrappers doing
        # "<b>" + fn(*args) + "</b>"). Coerce to string pointer.
        # Matches: direct closure call results AND variables assigned from
        # closure calls (the result = fn(*args); "x" + result pattern).
        _ccv = getattr(self, '_closure_call_vars', set())
        if op == ast.Add and lk == VKind.STR and rk == VKind.INT:
            _is_closure_result = (
                (isinstance(node.right, ast.Call)
                 and isinstance(node.right.func, ast.Name)
                 and node.right.func.id in self.variables)
                or (isinstance(node.right, ast.Name)
                    and node.right.id in _ccv))
            if _is_closure_result:
                r_ptr = self.builder.inttoptr(
                    rtv.as_i64(self.builder), i8_ptr)
                return self._rt_call("str_concat",
                                     [ltv.as_ptr(self.builder), r_ptr])
        if op == ast.Add and lk == VKind.INT and rk == VKind.STR:
            _is_closure_result = (
                (isinstance(node.left, ast.Call)
                 and isinstance(node.left.func, ast.Name)
                 and node.left.func.id in self.variables)
                or (isinstance(node.left, ast.Name)
                    and node.left.id in _ccv))
            if _is_closure_result:
                l_ptr = self.builder.inttoptr(
                    ltv.as_i64(self.builder), i8_ptr)
                return self._rt_call("str_concat",
                                     [l_ptr, rtv.as_ptr(self.builder)])
        # NOTE: true str + int and int + str are NOT valid in Python (TypeError).
        # These fall through to the container guard → fv_binop → TypeError.

        # ── Fast path: list + list → concat, list * int → repeat ───────
        if lk == VKind.LIST and rk == VKind.LIST and op == ast.Add:
            return self._rt_call("list_concat", [ltv, rtv])
        # list + pyobj or pyobj + list: convert pyobj to native list first
        if lk == VKind.LIST and rk == VKind.PYOBJ and op == ast.Add:
            r_native = self._rt_call("cpython_to_list", [rtv])
            return self._rt_call("list_concat", [ltv, r_native])
        if lk == VKind.PYOBJ and rk == VKind.LIST and op == ast.Add:
            l_native = self._rt_call("cpython_to_list", [ltv])
            return self._rt_call("list_concat", [l_native, rtv])
        if lk == VKind.LIST and rk in (VKind.INT, VKind.BOOL) and op == ast.Mult:
            return self._rt_call("list_repeat", [ltv, rtv])
        if lk in (VKind.INT, VKind.BOOL) and rk == VKind.LIST and op == ast.Mult:
            return self._rt_call("list_repeat", [rtv, ltv])

        # ── Fast path: dict | dict → merge ─────────────────────────────
        if lk == VKind.DICT and rk == VKind.DICT and op == ast.BitOr:
            return self._rt_call("dict_merge", [ltv, rtv])
        # dict | pyobj or pyobj | dict: convert pyobj to native dict first
        if lk == VKind.DICT and rk == VKind.PYOBJ and op == ast.BitOr:
            r_native = self._rt_call("cpython_to_dict", [rtv])
            return self._rt_call("dict_merge", [ltv, r_native])
        if lk == VKind.PYOBJ and rk == VKind.DICT and op == ast.BitOr:
            l_native = self._rt_call("cpython_to_dict", [ltv])
            return self._rt_call("dict_merge", [l_native, rtv])

        # ── Fast path: Counter arithmetic ──────────────────────────────
        if lk == VKind.COUNTER and rk == VKind.COUNTER:
            _counter_ops = {
                ast.Add: "counter_add", ast.Sub: "counter_sub",
                ast.BitOr: "counter_union", ast.BitAnd: "counter_intersection",
            }
            rt_name = _counter_ops.get(op)
            if rt_name:
                return self._rt_call(rt_name, [ltv, rtv])

        # ── Fast path: set operations ──────────────────────────────────
        if lk == VKind.SET or rk == VKind.SET:
            _set_ops = {ast.BitOr: "set_union", ast.BitAnd: "set_intersection",
                        ast.Sub: "set_difference", ast.BitXor: "set_symmetric_diff"}
            if op in _set_ops:
                return self._rt_call(_set_ops[op], [ltv, rtv])

        # ── Fast path: Path / str → path join ─────────────────────────
        if op == ast.Div and (lk == VKind.PATH or self._is_path_expr(node.left)):
            return self._rt_call("path_join", [ltv, rtv])

        # ── Fast path: Decimal arithmetic ──────────────────────────────
        if lk == VKind.DECIMAL or rk == VKind.DECIMAL:
            if lk != VKind.DECIMAL:
                ltv = TypedValue(self._rt_call("decimal_from_int", [ltv]), ValueType(VKind.DECIMAL))
            if rk != VKind.DECIMAL:
                rtv = TypedValue(self._rt_call("decimal_from_int", [rtv]), ValueType(VKind.DECIMAL))
            _dec_ops = {ast.Add: "decimal_add", ast.Sub: "decimal_sub",
                        ast.Mult: "decimal_mul", ast.Div: "decimal_div",
                        ast.FloorDiv: "decimal_div"}
            if op in _dec_ops:
                return self._rt_call(_dec_ops[op], [ltv, rtv])

        # ── Fast path: Complex arithmetic ──────────────────────────────
        if lk == VKind.COMPLEX or rk == VKind.COMPLEX:
            return self._emit_complex_binop(node,
                lk == VKind.COMPLEX, rk == VKind.COMPLEX)

        # ── Fast path: OBJ operator overloading ────────────────────────
        if lk == VKind.OBJ:
            _obj_ops = {ast.Add: "__add__", ast.Sub: "__sub__", ast.Mult: "__mul__",
                        ast.FloorDiv: "__floordiv__", ast.Div: "__truediv__",
                        ast.Mod: "__mod__", ast.Pow: "__pow__",
                        ast.MatMult: "__matmul__",
                        ast.BitAnd: "__and__", ast.BitOr: "__or__",
                        ast.BitXor: "__xor__", ast.LShift: "__lshift__",
                        ast.RShift: "__rshift__"}
            method = _obj_ops.get(op)
            if method:
                name_ptr = self._make_string_constant(method)
                result = self.builder.call(
                    self.runtime["obj_call_method1"],
                    [ltv.as_ptr(self.builder), name_ptr, rtv.as_i64(self.builder)])
                # Check method return type: only inttoptr if it returns a pointer.
                # For scalar returns (int/float), wrap in FpyValue so that
                # _emit_expr tags it as FVALUE — this prevents _infer_type_tag
                # from blindly tagging it "obj" (since the BinOp has an OBJ
                # operand) which would make downstream binops treat the raw
                # scalar as a pointer.
                ret_type = self._find_method_return_type(node.left, method)
                if ret_type is None:
                    # Unknown class/method → assume object (safe default)
                    return self._ensure_ptr(result)
                if isinstance(ret_type, ir.PointerType):
                    return self._ensure_ptr(result)
                if isinstance(ret_type, ir.DoubleType):
                    data = self.builder.bitcast(result, i64)
                    return self._fv_build_from_slots(
                        ir.Constant(i32, FPY_TAG_FLOAT), data)
                # int return → FpyValue with INT tag
                return self._fv_build_from_slots(
                    ir.Constant(i32, FPY_TAG_INT), result)

        # ── Fast path: bool as int ─────────────────────────────────────
        if lk == VKind.BOOL and rk in (VKind.INT, VKind.BOOL):
            return self._emit_int_binop(node.op, ltv.as_i64(self.builder),
                                         rtv.as_i64(self.builder), node)
        if rk == VKind.BOOL and lk == VKind.INT:
            return self._emit_int_binop(node.op, ltv.as_i64(self.builder),
                                         rtv.as_i64(self.builder), node)

        # ── Reverse dunder: int + OBJ → OBJ.__radd__(int) ─────────────
        if rk == VKind.OBJ and self._is_obj_expr(node.right):
            _robj_ops = {
                ast.Add: "__radd__", ast.Sub: "__rsub__", ast.Mult: "__rmul__",
                ast.FloorDiv: "__rfloordiv__", ast.Div: "__rtruediv__",
                ast.Mod: "__rmod__", ast.Pow: "__rpow__",
                ast.MatMult: "__rmatmul__",
                ast.BitAnd: "__rand__", ast.BitOr: "__ror__",
                ast.BitXor: "__rxor__", ast.LShift: "__rlshift__",
                ast.RShift: "__rrshift__"}
            rmethod = _robj_ops.get(op)
            if rmethod:
                name_ptr = self._make_string_constant(rmethod)
                result = self.builder.call(
                    self.runtime["obj_call_method1"],
                    [rtv.as_ptr(self.builder), name_ptr, ltv.as_i64(self.builder)])
                ret_type = self._find_method_return_type(node.right, rmethod)
                if ret_type is None:
                    return self._ensure_ptr(result)
                if isinstance(ret_type, ir.PointerType):
                    return self._ensure_ptr(result)
                if isinstance(ret_type, ir.DoubleType):
                    data = self.builder.bitcast(result, i64)
                    return self._fv_build_from_slots(
                        ir.Constant(i32, FPY_TAG_FLOAT), data)
                # int return → FpyValue with INT tag
                return self._fv_build_from_slots(
                    ir.Constant(i32, FPY_TAG_INT), result)

        # ── Fast path: OBJ used as int (e.g. attr from unknown-class
        #    receiver holding an integer value) ────────────────────────
        if (lk == VKind.OBJ and rk in (VKind.INT, VKind.BOOL)
                and op in (ast.Add, ast.Sub, ast.Mult, ast.FloorDiv,
                           ast.Mod, ast.Pow, ast.BitAnd, ast.BitOr,
                           ast.BitXor, ast.LShift, ast.RShift)):
            return self._emit_int_binop(node.op, ltv.as_i64(self.builder),
                                         rtv.as_i64(self.builder), node)
        if (rk == VKind.OBJ and lk in (VKind.INT, VKind.BOOL)
                and op in (ast.Add, ast.Sub, ast.Mult, ast.FloorDiv,
                           ast.Mod, ast.Pow, ast.BitAnd, ast.BitOr,
                           ast.BitXor, ast.LShift, ast.RShift)):
            return self._emit_int_binop(node.op, ltv.as_i64(self.builder),
                                         rtv.as_i64(self.builder), node)

        # ── FpyValue runtime dispatch: when either operand is a runtime-
        #    typed FpyValue struct, dispatch to fastpy_fv_binop so string
        #    concat, list concat, and mixed arithmetic are handled
        #    correctly at runtime. ──────────────────────────────────────
        _l_is_fv = (isinstance(ltv.val.type, ir.LiteralStructType) and ltv.val.type == fpy_val)
        _r_is_fv = (isinstance(rtv.val.type, ir.LiteralStructType) and rtv.val.type == fpy_val)
        if _l_is_fv or _r_is_fv:
            _fv_ops = {ast.Add: 0, ast.Sub: 1, ast.Mult: 2, ast.Div: 3,
                       ast.FloorDiv: 4, ast.Mod: 5}
            if op in _fv_ops:
                lt_tag, lt_data = (self.builder.extract_value(ltv.val, 0),
                                   self.builder.extract_value(ltv.val, 1)) \
                    if _l_is_fv else (ir.Constant(i32, ltv.vtype.kind.fpy_tag),
                                       ltv.as_i64(self.builder))
                rt_tag, rt_data = (self.builder.extract_value(rtv.val, 0),
                                   self.builder.extract_value(rtv.val, 1)) \
                    if _r_is_fv else (ir.Constant(i32, rtv.vtype.kind.fpy_tag),
                                       rtv.as_i64(self.builder))
                out_tag = self._create_entry_alloca(i32, "fvbop.tag")
                out_data = self._create_entry_alloca(i64, "fvbop.data")
                self.builder.call(self.runtime["fv_binop"],
                                  [lt_tag, lt_data, rt_tag, rt_data,
                                   ir.Constant(i32, _fv_ops[op]),
                                   out_tag, out_data])
                self._emit_try_bail_if_exc()
                return self._fv_build_from_slots(
                    self.builder.load(out_tag),
                    self.builder.load(out_data))
            # Bitwise/shift ops on FpyValue: extract the i64 data and
            # dispatch through _emit_int_binop.  This handles the common
            # case where an earlier checked_* (BigInt-capable) arithmetic
            # result feeds a bitwise/shift operator — the FpyValue struct
            # must not reach cpython_binop (which treats it as PyObject*).
            _BITWISE_OPS = (ast.BitAnd, ast.BitOr, ast.BitXor,
                            ast.LShift, ast.RShift)
            if op in _BITWISE_OPS:
                l_i64 = (self.builder.extract_value(ltv.val, 1)
                         if _l_is_fv else ltv.as_i64(self.builder))
                r_i64 = (self.builder.extract_value(rtv.val, 1)
                         if _r_is_fv else rtv.as_i64(self.builder))
                return self._emit_int_binop(node.op, l_i64, r_i64, node)

        # ── Fast path: PYOBJ binary ops — dispatch to CPython ──────────
        if lk == VKind.PYOBJ or rk == VKind.PYOBJ:
            _pyobj_ops = {ast.Add: 0, ast.Sub: 1, ast.Mult: 2, ast.Div: 3,
                          ast.FloorDiv: 4, ast.Mod: 5, ast.Pow: 6}
            if op in _pyobj_ops:
                out_tag = self._create_entry_alloca(i32, "pybop.tag")
                out_data = self._create_entry_alloca(i64, "pybop.data")
                if lk == VKind.PYOBJ:
                    # left is PyObject*, right is tag+data
                    self.builder.call(self.runtime["cpython_binop"],
                                      [ltv.as_ptr(self.builder),
                                       ir.Constant(i32, rtv.vtype.kind.fpy_tag),
                                       rtv.as_i64(self.builder),
                                       ir.Constant(i32, _pyobj_ops[op]),
                                       out_tag, out_data])
                else:
                    # left is tag+data, right is PyObject* — use rbinop
                    self.builder.call(self.runtime["cpython_rbinop"],
                                      [ir.Constant(i32, ltv.vtype.kind.fpy_tag),
                                       ltv.as_i64(self.builder),
                                       rtv.as_ptr(self.builder),
                                       ir.Constant(i32, _pyobj_ops[op]),
                                       out_tag, out_data])
                self._emit_try_bail_if_exc()
                return self._fv_build_from_slots(
                    self.builder.load(out_tag),
                    self.builder.load(out_data))

        # ── Fast path: int bitwise ops ─────────────────────────────────
        if lk in (VKind.INT, VKind.BOOL, VKind.UNKNOWN) and rk in (VKind.INT, VKind.BOOL, VKind.UNKNOWN):
            return self._emit_int_binop(node.op, ltv.as_i64(self.builder),
                                         rtv.as_i64(self.builder), node)

        # ── Guard: native container types must not reach cpython_binop ──
        # Native containers (FpyList*, FpyDict*, etc.) are not PyObject*;
        # passing them to cpython_binop causes an access violation.  Route
        # through fv_binop which handles valid ops (concat, repeat) and
        # raises TypeError for invalid combinations.
        _container_kinds = (VKind.LIST, VKind.DICT, VKind.SET, VKind.TUPLE,
                            VKind.STR, VKind.BYTES)
        if lk in _container_kinds or rk in _container_kinds:
            _fv_ops = {ast.Add: 0, ast.Sub: 1, ast.Mult: 2, ast.Div: 3,
                       ast.FloorDiv: 4, ast.Mod: 5}
            if op in _fv_ops:
                lt_tag = ir.Constant(i32, ltv.vtype.kind.fpy_tag)
                lt_data = ltv.as_i64(self.builder)
                rt_tag = ir.Constant(i32, rtv.vtype.kind.fpy_tag)
                rt_data = rtv.as_i64(self.builder)
                out_tag = self._create_entry_alloca(i32, "ctbop.tag")
                out_data = self._create_entry_alloca(i64, "ctbop.data")
                self.builder.call(self.runtime["fv_binop"],
                                  [lt_tag, lt_data, rt_tag, rt_data,
                                   ir.Constant(i32, _fv_ops[op]),
                                   out_tag, out_data])
                self._emit_try_bail_if_exc()
                return self._fv_build_from_slots(
                    self.builder.load(out_tag),
                    self.builder.load(out_data))

        # ── Slow path: CPython bridge (works for ANY type) ─────────────
        op_code = {ast.Add: 0, ast.Sub: 1, ast.Mult: 2, ast.Div: 3,
                   ast.FloorDiv: 4, ast.Mod: 5, ast.Pow: 6}.get(op, 0)
        out_tag = self._create_entry_alloca(i32, "bop.tag")
        out_data = self._create_entry_alloca(i64, "bop.data")
        self.builder.call(self.runtime["cpython_binop"],
                          [ltv.as_ptr(self.builder),
                           ir.Constant(i32, rtv.vtype.kind.fpy_tag),
                           rtv.as_i64(self.builder),
                           ir.Constant(i32, op_code),
                           out_tag, out_data])
        self._emit_try_bail_if_exc()
        return self._fv_build_from_slots(
            self.builder.load(out_tag),
            self.builder.load(out_data))

    def _wrap_single_as_list(self, tv: TypedValue) -> ir.Value:
        """Wrap a single value into a list for % formatting."""
        args_list = self.builder.call(self.runtime["list_new"], [])
        self._emit_list_append_value(args_list, tv.val)
        return args_list

    def _get_int_mode_for_binop(self, node: ast.BinOp) -> str | None:
        """Return per-variable int mode for a BinOp, if any operand has one.

        Checks both operands of the BinOp against ``_int_mode_vars``.
        Returns one of ``"unchecked"``, ``"checked"``, ``"unchecked32"``,
        ``"checked32"``, or ``None`` (use default).

        Priority (most specific / narrowest wins):
        ``unchecked32`` > ``checked32`` > ``unchecked`` > ``checked``.
        Within the same width, unchecked wins over checked (the user
        explicitly opted into raw arithmetic).
        """
        modes: set[str] = set()
        for operand in (node.left, node.right):
            if isinstance(operand, ast.Name) and operand.id in self._int_mode_vars:
                modes.add(self._int_mode_vars[operand.id])
        if "unchecked32" in modes:
            return "unchecked32"
        if "checked32" in modes:
            return "checked32"
        if "unchecked" in modes:
            return "unchecked"
        if "checked" in modes:
            return "checked"
        return None

    def _emit_unchecked_int_op(
        self, op: ast.operator, left: ir.Value, right: ir.Value,
    ) -> ir.Value:
        """Emit raw integer arithmetic with no overflow checks.

        Used for variables marked with ``Unchecked`` / ``unchecked_int()``.
        Wraps silently on overflow (C / two's-complement semantics).
        """
        if isinstance(op, ast.Add):
            return self.builder.add(left, right)
        elif isinstance(op, ast.Sub):
            return self.builder.sub(left, right)
        elif isinstance(op, ast.Mult):
            return self.builder.mul(left, right)
        elif isinstance(op, ast.Pow):
            return self._emit_raw_ipow(left, right)
        # Unreachable for the ops we gate on, but be safe.
        return self.builder.add(left, right)

    # ── 32-bit integer arithmetic ────────────────────────────────────

    def _emit_unchecked_int32_op(
        self, op: ast.operator, left: ir.Value, right: ir.Value,
    ) -> ir.Value:
        """Emit raw 32-bit integer arithmetic with no overflow checks.

        Truncates i64 operands to i32, performs the operation, and
        sign-extends the result back to i64.  Wraps silently at the
        32-bit boundary (two's-complement).
        """
        i32_ty = ir.IntType(32)
        left32 = self.builder.trunc(left, i32_ty)
        right32 = self.builder.trunc(right, i32_ty)
        if isinstance(op, ast.Add):
            result32 = self.builder.add(left32, right32)
        elif isinstance(op, ast.Sub):
            result32 = self.builder.sub(left32, right32)
        elif isinstance(op, ast.Mult):
            result32 = self.builder.mul(left32, right32)
        elif isinstance(op, ast.Pow):
            # Compute in i64, then truncate to i32 (wrapping)
            result64 = self._emit_raw_ipow(left, right)
            return self.builder.sext(self.builder.trunc(result64, i32_ty), i64)
        else:
            result32 = self.builder.add(left32, right32)
        return self.builder.sext(result32, i64)

    def _emit_intrinsic_overflow_op_i32(
        self, intrinsic_name: str,
        left32: ir.Value, right32: ir.Value,
    ) -> ir.Value:
        """Emit an overflow-checked i32 op using an LLVM intrinsic.

        Like ``_emit_intrinsic_overflow_op`` but for 32-bit operands.
        Returns i64 (sign-extended from the i32 result).
        """
        i1 = ir.IntType(1)
        i32_ty = ir.IntType(32)
        ovf_struct = ir.LiteralStructType([i32_ty, i1])
        fn_ty = ir.FunctionType(ovf_struct, [i32_ty, i32_ty])

        try:
            fn = self.module.globals[intrinsic_name]
        except KeyError:
            fn = ir.Function(self.module, fn_ty, name=intrinsic_name)

        result_struct = self.builder.call(fn, [left32, right32])
        value32 = self.builder.extract_value(result_struct, 0)
        overflowed = self.builder.extract_value(result_struct, 1)

        overflow_block = self._new_block("intrinsic_ovf32.err")
        ok_block = self._new_block("intrinsic_ovf32.ok")
        self.builder.cbranch(overflowed, overflow_block, ok_block)

        self.builder.position_at_end(overflow_block)
        exc_name = self._make_string_constant("OverflowError")
        exc_id = self.builder.call(self.runtime["exc_name_to_id"], [exc_name])
        msg = self._make_string_constant("integer overflow (i32)")
        self.builder.call(self.runtime["raise"], [exc_id, msg])
        self.builder.branch(ok_block)

        self.builder.position_at_end(ok_block)
        return self.builder.sext(value32, i64)

    def _emit_checked_int32_op(
        self, op: ast.operator, left: ir.Value, right: ir.Value,
    ) -> ir.Value:
        """Emit checked 32-bit integer arithmetic (OverflowError on overflow).

        Truncates i64 operands to i32, uses LLVM i32 overflow intrinsics
        for add/sub/mul, and sign-extends the result back to i64.
        """
        i32_ty = ir.IntType(32)
        left32 = self.builder.trunc(left, i32_ty)
        right32 = self.builder.trunc(right, i32_ty)

        intrinsic = {
            ast.Add: "llvm.sadd.with.overflow.i32",
            ast.Sub: "llvm.ssub.with.overflow.i32",
            ast.Mult: "llvm.smul.with.overflow.i32",
        }.get(type(op))
        if intrinsic is not None:
            return self._emit_intrinsic_overflow_op_i32(
                intrinsic, left32, right32)

        # Pow: compute in i64 and range-check to i32
        if isinstance(op, ast.Pow):
            result = self._emit_checked_int_op(
                op, left, right, force_overflow_error=True)
            i32_max = ir.Constant(i64, 2147483647)
            i32_min = ir.Constant(i64, -2147483648)
            too_big = self.builder.icmp_signed(">", result, i32_max)
            too_small = self.builder.icmp_signed("<", result, i32_min)
            out_of_range = self.builder.or_(too_big, too_small)
            overflow_block = self._new_block("checked32_pow.err")
            ok_block = self._new_block("checked32_pow.ok")
            self.builder.cbranch(out_of_range, overflow_block, ok_block)
            self.builder.position_at_end(overflow_block)
            exc_name = self._make_string_constant("OverflowError")
            exc_id = self.builder.call(
                self.runtime["exc_name_to_id"], [exc_name])
            msg = self._make_string_constant("integer overflow (i32)")
            self.builder.call(self.runtime["raise"], [exc_id, msg])
            self.builder.branch(ok_block)
            self.builder.position_at_end(ok_block)
            return result

        # Fallback (shouldn't reach)
        return self.builder.sext(self.builder.add(left32, right32), i64)

    def _emit_int_binop(
        self, op: ast.operator, left: ir.Value, right: ir.Value, node: ast.AST
    ) -> ir.Value:
        """Emit an integer binary operation."""
        # Clear BigInt overflow flag from any prior call — the flag is only
        # meaningful for the immediately preceding _emit_int_binop call.
        self._bigint_overflow_flag = None
        # Safety: coerce pointer types to i64.  This handles cases where
        # a variable has VKind.OBJ but actually holds an integer value
        # (e.g. attr loads from receivers whose class isn't known).
        if isinstance(left.type, ir.PointerType):
            left = self.builder.ptrtoint(left, i64)
        if isinstance(right.type, ir.PointerType):
            right = self.builder.ptrtoint(right, i64)
        # Unwrap FpyValue structs to i64 data field.
        if (isinstance(left.type, ir.LiteralStructType)
                and left.type == fpy_val):
            left = self.builder.extract_value(left, 1)
        if (isinstance(right.type, ir.LiteralStructType)
                and right.type == fpy_val):
            right = self.builder.extract_value(right, 1)
        if isinstance(op, (ast.Add, ast.Sub, ast.Mult, ast.Pow)):
            # ── Per-variable int mode (Annotated markers / constructors) ──
            mode = None
            if isinstance(node, ast.BinOp):
                mode = self._get_int_mode_for_binop(node)
            elif isinstance(node, ast.AugAssign):
                # x += 1 — check the target variable's mode
                if (isinstance(node.target, ast.Name)
                        and node.target.id in self._int_mode_vars):
                    mode = self._int_mode_vars[node.target.id]
            if mode == "unchecked":
                return self._emit_unchecked_int_op(op, left, right)
            elif mode == "checked":
                return self._emit_checked_int_op(
                    op, left, right, force_overflow_error=True)
            elif mode == "unchecked32":
                return self._emit_unchecked_int32_op(op, left, right)
            elif mode == "checked32":
                return self._emit_checked_int32_op(op, left, right)
            return self._emit_checked_int_op(op, left, right)
        elif isinstance(op, ast.FloorDiv):
            return self._emit_python_floordiv(left, right)
        elif isinstance(op, ast.Mod):
            return self._emit_python_mod(left, right)
        elif isinstance(op, ast.Div):
            # Python's / always returns float, even for ints. Use the
            # int-flavored safe division so the ZeroDivisionError message
            # matches CPython ("division by zero" for int/int, "float
            # division by zero" only when a float operand is involved).
            result = self.builder.call(self.runtime["safe_int_fdiv"], [left, right])
            self._emit_try_bail_if_exc()
            return result
        elif isinstance(op, ast.BitAnd):
            return self.builder.and_(left, right)
        elif isinstance(op, ast.BitOr):
            return self.builder.or_(left, right)
        elif isinstance(op, ast.BitXor):
            return self.builder.xor(left, right)
        elif isinstance(op, ast.LShift):
            return self.builder.shl(left, right)
        elif isinstance(op, ast.RShift):
            return self.builder.ashr(left, right)
        else:
            return self._bridge_fallback_expr(node, f"unsupported int operator: {type(op).__name__}")

    def _emit_try_bail_if_exc(self) -> None:
        """If inside a try block, check exc_pending() and bail to the except
        handler immediately.  This prevents side-effectful code from executing
        after a call that raised (e.g. list.append running with a garbage
        return value from a division that raised ZeroDivisionError).

        At module level (fastpy_main, not in a try block), check exc_pending()
        and call exc_unhandled() (print traceback + exit) — uncaught exceptions
        must halt execution immediately, not let subsequent code run with
        garbage values."""
        if self._in_try_block:
            target = getattr(self, '_try_except_target', None)
            if target is None:
                return
            pending = self.builder.call(self.runtime["exc_pending"], [])
            is_exc = self.builder.icmp_signed("!=", pending, ir.Constant(i32, 0))
            cont = self._new_block("try.earlycheck")
            self.builder.cbranch(is_exc, target, cont)
            self.builder.position_at_end(cont)
            return
        # Module-level (or top-level function not in try): bail to
        # exc_unhandled on pending exception.
        if (not self._current_fn_bare_abi
                and self.function.name == "fastpy_main"):
            pending = self.builder.call(self.runtime["exc_pending"], [])
            is_exc = self.builder.icmp_signed(
                "!=", pending, ir.Constant(i32, 0))
            exc_blk = self._new_block("module.bail_exc")
            cont = self._new_block("module.bail_cont")
            self.builder.cbranch(is_exc, exc_blk, cont)
            self.builder.position_at_end(exc_blk)
            self.builder.call(self.runtime["exc_unhandled"], [])
            self.builder.unreachable()
            self.builder.position_at_end(cont)

    def _emit_python_floordiv(self, left: ir.Value, right: ir.Value) -> ir.Value:
        """
        Python-style floor division: rounds toward negative infinity.
        C's sdiv truncates toward zero. We correct by:
          q = trunc(left / right)
          r = left - q * right
          if r != 0 and (r ^ right) < 0: q -= 1
        """
        q = self.builder.call(self.runtime["safe_div"], [left, right])
        self._emit_try_bail_if_exc()
        r = self.builder.call(self.runtime["safe_mod"], [left, right])
        zero = ir.Constant(i64, 0)
        one = ir.Constant(i64, 1)

        # Check if remainder is nonzero
        r_nonzero = self.builder.icmp_signed("!=", r, zero)
        # Check if remainder and divisor have different signs (XOR < 0)
        r_xor_right = self.builder.xor(r, right)
        signs_differ = self.builder.icmp_signed("<", r_xor_right, zero)
        # Need adjustment if both conditions are true
        needs_adjust = self.builder.and_(r_nonzero, signs_differ)
        adjusted = self.builder.sub(q, one)
        return self.builder.select(needs_adjust, adjusted, q)

    def _emit_python_mod(self, left: ir.Value, right: ir.Value) -> ir.Value:
        """
        Python-style modulo: result has the sign of the divisor.
        C's srem result has the sign of the dividend. We correct by:
          r = left % right (C-style)
          if r != 0 and (r ^ right) < 0: r += right
        """
        r = self.builder.call(self.runtime["safe_mod"], [left, right])
        self._emit_try_bail_if_exc()
        zero = ir.Constant(i64, 0)

        r_nonzero = self.builder.icmp_signed("!=", r, zero)
        r_xor_right = self.builder.xor(r, right)
        signs_differ = self.builder.icmp_signed("<", r_xor_right, zero)
        needs_adjust = self.builder.and_(r_nonzero, signs_differ)
        adjusted = self.builder.add(r, right)
        return self.builder.select(needs_adjust, adjusted, r)

    def _emit_checked_int_op(self, op: ast.operator,
                              left: ir.Value, right: ir.Value,
                              force_overflow_error: bool = False) -> ir.Value:
        """Emit overflow-checked integer arithmetic.
        On overflow: promotes to BigInt (default) or raises OverflowError (--int64).
        Returns i64 (for small results) or i64 (BigInt pointer cast, tagged BIGINT).

        When *force_overflow_error* is True (per-variable ``Checked`` mode),
        the intrinsic / OverflowError path is used regardless of the global
        ``--int64`` flag — equivalent to ``--typed --int64`` for this one op.
        """
        # Bare-ABI functions: use plain LLVM arithmetic (add/sub/mul).
        # No BigInt, no function calls — lets LLVM constant-fold, inline,
        # and vectorize exactly as C++ would.  Bare-ABI functions are
        # guaranteed to have only i64/double locals.
        # Exception: when _program_uses_bigint is True, the program contains
        # values that could overflow i64 — must use checked arithmetic even
        # in bare-ABI mode to avoid silent wraparound.
        if self._current_fn_bare_abi and not self._program_uses_bigint:
            plain = {
                ast.Add: self.builder.add,
                ast.Sub: self.builder.sub,
                ast.Mult: self.builder.mul,
            }.get(type(op))
            if plain is not None:
                return plain(left, right)
            # Pow: fall through to checked_pow runtime (rare in tight loops)

        # Programs that don't need BigInt: use plain LLVM arithmetic (same
        # as bare-ABI).  The _program_uses_bigint flag is set during AST
        # analysis only when the source contains very large int literals or
        # ** with large exponents.  This eliminates the fpy_checked_add
        # function-call overhead for the vast majority of programs.
        if not self._program_uses_bigint and not force_overflow_error:
            plain = {
                ast.Add: self.builder.add,
                ast.Sub: self.builder.sub,
                ast.Mult: self.builder.mul,
            }.get(type(op))
            if plain is not None:
                return plain(left, right)

        # --typed --int64 (or per-variable Checked): use LLVM overflow
        # intrinsics — no BigInt fallback, no runtime function calls,
        # SIMD-vectorisable by LLVM.  Still raises OverflowError on
        # overflow (safe), but avoids the checked_* runtime functions and
        # their BigInt allocation paths.
        use_intrinsics = (self._typed_mode and self._int64_mode) or force_overflow_error
        if use_intrinsics:
            intrinsic = {
                ast.Add: "llvm.sadd.with.overflow.i64",
                ast.Sub: "llvm.ssub.with.overflow.i64",
                ast.Mult: "llvm.smul.with.overflow.i64",
            }.get(type(op))
            if intrinsic is not None:
                return self._emit_intrinsic_overflow_op(intrinsic, left, right)
            # Pow: fall through to runtime checked_pow (intrinsic not
            # available for exponentiation; the OverflowError path below
            # handles it correctly).

        op_map = {
            ast.Add: "checked_add",
            ast.Sub: "checked_sub",
            ast.Mult: "checked_mul",
            ast.Pow: "checked_pow",
        }
        rt_name = op_map.get(type(op))
        if rt_name is None:
            # Fallback for unsupported ops
            if isinstance(op, ast.Add): return self.builder.add(left, right)
            if isinstance(op, ast.Sub): return self.builder.sub(left, right)
            if isinstance(op, ast.Mult): return self.builder.mul(left, right)

        # Allocate output pointer for BigInt
        big_out = self._create_entry_alloca(i8_ptr, "big_out")
        self.builder.store(ir.Constant(i8_ptr, None), big_out)

        result = self.builder.call(self.runtime[rt_name],
                                    [left, right, big_out])

        # Check if overflow occurred (big_out != NULL)
        big_ptr = self.builder.load(big_out)
        is_big = self.builder.icmp_unsigned(
            "!=", big_ptr, ir.Constant(i8_ptr, None))

        if self._int64_mode or force_overflow_error:
            # --int64 / per-variable Checked: raise OverflowError
            overflow_block = self._new_block("overflow.err")
            ok_block = self._new_block("overflow.ok")
            self.builder.cbranch(is_big, overflow_block, ok_block)

            self.builder.position_at_end(overflow_block)
            exc_name = self._make_string_constant("OverflowError")
            exc_id = self.builder.call(self.runtime["exc_name_to_id"], [exc_name])
            msg = self._make_string_constant("integer overflow")
            self.builder.call(self.runtime["raise"], [exc_id, msg])
            # fastpy_raise sets the exception flag and returns — branch
            # to ok_block so execution continues.  The statement-level
            # exc_pending() check will catch the flag.
            self.builder.branch(ok_block)

            self.builder.position_at_end(ok_block)
            return result
        else:
            # Default: return BigInt-tagged value or i64.
            # Set the overflow flag so _emit_binop can build an FpyValue
            # with the correct dynamic tag (BIGINT vs INT).
            big_as_i64 = self.builder.ptrtoint(big_ptr, i64)
            self._bigint_overflow_flag = is_big
            return self.builder.select(is_big, big_as_i64, result)

    def _emit_intrinsic_overflow_op(
        self, intrinsic_name: str,
        left: ir.Value, right: ir.Value,
    ) -> ir.Value:
        """Emit an overflow-checked integer op using an LLVM intrinsic.

        Uses llvm.sadd/ssub/smul.with.overflow.i64 — a single instruction
        that returns {i64, i1} (result + overflow flag).  On overflow we
        raise OverflowError.  No runtime function call, no BigInt allocation,
        and the pattern is transparent to LLVM's auto-vectoriser.
        """
        i1 = ir.IntType(1)
        ovf_struct = ir.LiteralStructType([i64, i1])
        fn_ty = ir.FunctionType(ovf_struct, [i64, i64])

        # Get-or-declare the intrinsic in the current module
        try:
            fn = self.module.globals[intrinsic_name]
        except KeyError:
            fn = ir.Function(self.module, fn_ty, name=intrinsic_name)

        result_struct = self.builder.call(fn, [left, right])
        value = self.builder.extract_value(result_struct, 0)
        overflowed = self.builder.extract_value(result_struct, 1)

        overflow_block = self._new_block("intrinsic_ovf.err")
        ok_block = self._new_block("intrinsic_ovf.ok")
        self.builder.cbranch(overflowed, overflow_block, ok_block)

        self.builder.position_at_end(overflow_block)
        exc_name = self._make_string_constant("OverflowError")
        exc_id = self.builder.call(self.runtime["exc_name_to_id"], [exc_name])
        msg = self._make_string_constant("integer overflow")
        self.builder.call(self.runtime["raise"], [exc_id, msg])
        # fastpy_raise sets the exception flag and returns — branch to
        # ok_block so execution continues with the truncated value.  The
        # statement-level exc_pending() check will catch the flag and
        # route to the except handler.
        self.builder.branch(ok_block)

        self.builder.position_at_end(ok_block)
        return value

    def _emit_raw_ipow(self, base: ir.Value, exp: ir.Value) -> ir.Value:
        """Emit raw integer power via binary exponentiation (no overflow check).

        Used when --typed --int64 are both active for C-like performance.
        Computes base**exp with the standard square-and-multiply algorithm.
        """
        one = ir.Constant(i64, 1)
        zero = ir.Constant(i64, 0)

        entry_block = self.builder.block
        loop_block = self._new_block("ipow.loop")
        odd_block = self._new_block("ipow.odd")
        step_block = self._new_block("ipow.step")
        done_block = self._new_block("ipow.done")

        # Entry: if exp <= 0, result is 1
        exp_pos = self.builder.icmp_signed(">", exp, zero)
        self.builder.cbranch(exp_pos, loop_block, done_block)

        # Loop header with PHI nodes
        self.builder.position_at_end(loop_block)
        phi_res = self.builder.phi(i64, name="ipow.res")
        phi_base = self.builder.phi(i64, name="ipow.base")
        phi_exp = self.builder.phi(i64, name="ipow.exp")
        phi_res.add_incoming(one, entry_block)
        phi_base.add_incoming(base, entry_block)
        phi_exp.add_incoming(exp, entry_block)

        # if exp & 1: result *= base
        is_odd = self.builder.icmp_signed(
            "!=", self.builder.and_(phi_exp, one), zero)
        self.builder.cbranch(is_odd, odd_block, step_block)

        self.builder.position_at_end(odd_block)
        res_times_base = self.builder.mul(phi_res, phi_base)
        self.builder.branch(step_block)

        # step: base *= base, exp >>= 1, loop if exp > 0
        self.builder.position_at_end(step_block)
        merged_res = self.builder.phi(i64, name="ipow.merged")
        merged_res.add_incoming(phi_res, loop_block)
        merged_res.add_incoming(res_times_base, odd_block)

        new_base = self.builder.mul(phi_base, phi_base)
        new_exp = self.builder.ashr(phi_exp, one)
        still_pos = self.builder.icmp_signed(">", new_exp, zero)
        self.builder.cbranch(still_pos, loop_block, done_block)

        phi_res.add_incoming(merged_res, step_block)
        phi_base.add_incoming(new_base, step_block)
        phi_exp.add_incoming(new_exp, step_block)

        # Done: merge entry (exp<=0 → 1) and loop exit
        self.builder.position_at_end(done_block)
        final = self.builder.phi(i64, name="ipow.final")
        final.add_incoming(one, entry_block)
        final.add_incoming(merged_res, step_block)
        return final

    def _emit_float_binop(
        self, op: ast.operator, left: ir.Value, right: ir.Value, node: ast.AST
    ) -> ir.Value:
        """Emit a float binary operation."""
        # Unwrap FpyValue structs to double.  This happens when an
        # UNKNOWN-typed intermediate result (e.g. from tuple unpacking)
        # flows into a float arithmetic context.
        for _lbl in ("left", "right"):
            v = left if _lbl == "left" else right
            if (isinstance(v.type, ir.LiteralStructType)
                    and v.type == fpy_val):
                _tag = self.builder.extract_value(v, 0)
                _data = self.builder.extract_value(v, 1)
                _is_flt = self.builder.icmp_unsigned(
                    "==", _tag, ir.Constant(i32, FPY_TAG_FLOAT))
                _bc = self.builder.bitcast(_data, double)
                _si = self.builder.sitofp(_data, double)
                _dbl = self.builder.select(_is_flt, _bc, _si)
                if _lbl == "left":
                    left = _dbl
                else:
                    right = _dbl
        if isinstance(op, ast.Add):
            return self.builder.fadd(left, right)
        elif isinstance(op, ast.Sub):
            return self.builder.fsub(left, right)
        elif isinstance(op, ast.Mult):
            return self.builder.fmul(left, right)
        elif isinstance(op, ast.FloorDiv):
            # Python's // on floats: divide (raising on /0) then floor
            result = self.builder.call(self.runtime["safe_fdiv"],
                                       [left, right])
            self._emit_try_bail_if_exc()
            # Use intrinsic for floor
            floor_fn = self.module.declare_intrinsic("llvm.floor", [double])
            return self.builder.call(floor_fn, [result])
        elif isinstance(op, ast.Mod):
            # Python-compatible float modulo: result has same sign as divisor.
            # rem = fmod(a, b); if sign(rem) != sign(b) and rem != 0: rem += b
            rem = self.builder.frem(left, right)
            rem_neg = self.builder.fcmp_ordered("<", rem, ir.Constant(double, 0.0))
            b_neg = self.builder.fcmp_ordered("<", right, ir.Constant(double, 0.0))
            signs_differ = self.builder.xor(rem_neg, b_neg)
            rem_nonzero = self.builder.fcmp_ordered("!=", rem, ir.Constant(double, 0.0))
            needs_adjust = self.builder.and_(signs_differ, rem_nonzero)
            adjusted = self.builder.fadd(rem, right)
            return self.builder.select(needs_adjust, adjusted, rem)
        elif isinstance(op, ast.Div):
            result = self.builder.call(self.runtime["safe_fdiv"],
                                     [left, right])
            self._emit_try_bail_if_exc()
            return result
        elif isinstance(op, ast.Pow):
            return self.builder.call(self.runtime["pow_float"], [left, right])
        else:
            return self._bridge_fallback_expr(node, f"unsupported float operator: {type(op).__name__}")

    def _try_constant_fold(self, node: ast.expr) -> int | float | str | None:
        """Try to evaluate an expression at compile time. Returns None if not constant."""
        if isinstance(node, ast.Constant):
            return node.value
        if isinstance(node, ast.UnaryOp) and isinstance(node.op, ast.USub):
            val = self._try_constant_fold(node.operand)
            if isinstance(val, (int, float, complex)):
                return -val
        if isinstance(node, ast.BinOp):
            left = self._try_constant_fold(node.left)
            right = self._try_constant_fold(node.right)
            if isinstance(left, int) and isinstance(right, int):
                try:
                    if isinstance(node.op, ast.Add): return left + right
                    if isinstance(node.op, ast.Sub): return left - right
                    if isinstance(node.op, ast.Mult): return left * right
                    if isinstance(node.op, ast.Pow): return left ** right
                    if isinstance(node.op, ast.FloorDiv) and right != 0: return left // right
                    if isinstance(node.op, ast.Mod) and right != 0: return left % right
                except (OverflowError, ValueError):
                    pass
        return None

    def _emit_expr_value(self, node: ast.expr) -> ir.Value:
        """Emit an expression and return its LLVM value."""
        # Try compile-time constant folding (handles BigInt like 2**100, -(2**100))
        if isinstance(node, (ast.BinOp, ast.UnaryOp)):
            folded = self._try_constant_fold(node)
            if folded is not None:
                return self._emit_constant_value(folded)

        if isinstance(node, ast.Constant):
            return self._emit_constant_value(node.value)
        elif isinstance(node, ast.Name):
            # Built-in constants
            if node.id == "NotImplemented":
                return ir.Constant(i64, 0)  # sentinel
            # Native module constants (e.g., logging.DEBUG, logging.INFO)
            native_imports = getattr(self, '_native_imports', {})
            if node.id in native_imports:
                mod, attr = native_imports[node.id]
                val = self._emit_native_module_attr(mod, attr)
                if val is not None:
                    return val
            # Check if this is a lambda-assigned function name used as a value
            if node.id in self._user_functions and node.id not in self.variables:
                info = self._user_functions[node.id]
                # FV-ABI functions expect {i32,i64} struct params — incompatible
                # with closure dispatch (call_ptr/closure_call_list) which passes
                # raw i64.  Use the i64 wrapper so the function can be called
                # safely through any dispatch path.
                if info.uses_fv_abi:
                    wrapper = self._get_or_emit_i64_wrapper(info)
                    return self.builder.ptrtoint(wrapper, i64)
                return self.builder.ptrtoint(info.func, i64)
            return self._load_variable(node.id, node)
        elif isinstance(node, ast.UnaryOp) and isinstance(node.op, ast.USub):
            # __neg__ on user-class objects
            if self._is_obj_expr(node.operand):
                obj = self._emit_expr_value(node.operand)
                obj = self._ensure_ptr(obj)
                name_ptr = self._make_string_constant("__neg__")
                result = self.builder.call(
                    self.runtime["obj_call_method0"], [obj, name_ptr])
                return self._ensure_ptr(result)
            # BigInt negation: if the operand is a bigint variable, call bigint_neg
            # and return the result tagged as BIGINT so print/assignment handle it correctly.
            if (isinstance(node.operand, ast.Name)
                    and node.operand.id in self.variables
                    and self._var_kind(node.operand.id) == VKind.BIGINT):
                operand = self._emit_expr_value(node.operand)
                ptr = self._ensure_ptr(operand)
                result = self.builder.call(self.runtime["bigint_neg"], [ptr])
                result_i64 = self.builder.ptrtoint(result, i64)
                # Return as FpyValue with BIGINT tag
                fv = ir.Constant(fpy_val, ir.Undefined)
                fv = self.builder.insert_value(fv, ir.Constant(i32, FPY_TAG_BIGINT), 0)
                fv = self.builder.insert_value(fv, result_i64, 1)
                return fv
            # Complex negation: -c → complex_neg(c)
            if self._is_complex_expr(node.operand):
                operand = self._emit_expr_value(node.operand)
                ptr = self._ensure_ptr(operand)
                result = self.builder.call(self.runtime["complex_neg"], [ptr])
                return self.builder.ptrtoint(result, i64)
            operand = self._emit_expr_value(node.operand)
            if isinstance(operand.type, ir.IntType):
                return self.builder.neg(operand)
            elif isinstance(operand.type, ir.DoubleType):
                return self.builder.fneg(operand)
            elif (isinstance(operand.type, ir.LiteralStructType)
                  and operand.type == fpy_val):
                # FpyValue: runtime dispatch based on tag (INT vs FLOAT)
                tag = self.builder.extract_value(operand, 0)
                data = self.builder.extract_value(operand, 1)
                is_float = self.builder.icmp_unsigned(
                    "==", tag, ir.Constant(i32, FPY_TAG_FLOAT))
                int_neg = self.builder.neg(data)
                float_val = self.builder.bitcast(data, double)
                float_neg = self.builder.fneg(float_val)
                float_neg_i64 = self.builder.bitcast(float_neg, i64)
                neg_data = self.builder.select(is_float, float_neg_i64, int_neg)
                result = ir.Constant(fpy_val, ir.Undefined)
                result = self.builder.insert_value(result, tag, 0)
                result = self.builder.insert_value(result, neg_data, 1)
                return result
            return self._bridge_fallback_expr(node, "unsupported unary operand type")
        elif isinstance(node, ast.UnaryOp) and isinstance(node.op, ast.UAdd):
            # __pos__ on user-class objects
            if self._is_obj_expr(node.operand):
                obj_cls = self._infer_object_class(node.operand)
                if obj_cls and self._class_has_method(obj_cls, "__pos__"):
                    obj = self._emit_expr_value(node.operand)
                    obj = self._ensure_ptr(obj)
                    name_ptr = self._make_string_constant("__pos__")
                    result = self.builder.call(
                        self.runtime["obj_call_method0"], [obj, name_ptr])
                    return self._ensure_ptr(result)
            return self._emit_expr_value(node.operand)
        elif isinstance(node, ast.UnaryOp) and isinstance(node.op, ast.Invert):
            # __invert__ on user-class objects
            if self._is_obj_expr(node.operand):
                obj_cls = self._infer_object_class(node.operand)
                if obj_cls and self._class_has_method(obj_cls, "__invert__"):
                    obj = self._emit_expr_value(node.operand)
                    obj = self._ensure_ptr(obj)
                    name_ptr = self._make_string_constant("__invert__")
                    result = self.builder.call(
                        self.runtime["obj_call_method0"], [obj, name_ptr])
                    return self._ensure_ptr(result)
            operand = self._emit_expr_value(node.operand)
            if isinstance(operand.type, ir.IntType):
                return self.builder.not_(operand)
            return self._bridge_fallback_expr(node, "~ on non-integer operand")
        elif isinstance(node, ast.BinOp):
            return self._emit_binop(node)
        elif isinstance(node, ast.Call):
            return self._emit_call_expr(node)
        elif isinstance(node, ast.Compare):
            cmp = self._emit_compare(node)
            return self.builder.zext(cmp, i32)
        elif isinstance(node, ast.BoolOp):
            # BoolOp returns operand value (not bool) per Python semantics
            return self._emit_boolop(node)
        elif isinstance(node, ast.UnaryOp) and isinstance(node.op, ast.Not):
            cmp = self._emit_condition(node.operand)
            result = self.builder.not_(cmp)
            return self.builder.zext(result, i32)
        elif isinstance(node, ast.Subscript):
            return self._emit_subscript(node)
        elif isinstance(node, ast.JoinedStr):
            return self._emit_fstring(node)
        elif isinstance(node, ast.List):
            return self._emit_list_literal(node)
        elif isinstance(node, ast.Tuple):
            return self._emit_tuple_literal(node)
        elif isinstance(node, ast.ListComp):
            return self._emit_list_comprehension(node)
        elif isinstance(node, ast.Dict):
            return self._emit_dict_literal(node)
        elif isinstance(node, ast.IfExp):
            return self._emit_ifexp(node)
        elif isinstance(node, ast.NamedExpr):
            value = self._emit_expr_value(node.value)
            tag = self._infer_type_tag(node.value, value)
            self._store_variable(node.target.id, value, tag)
            return value
        elif isinstance(node, ast.Attribute):
            # type(X).__name__ pattern: return the type name (or metaclass)
            if (node.attr == "__name__"
                    and isinstance(node.value, ast.Call)
                    and isinstance(node.value.func, ast.Name)
                    and node.value.func.id == "type"
                    and len(node.value.args) == 1):
                arg_node = node.value.args[0]
                # Name arg: check exception vars, metaclasses, user classes, FV variables
                if isinstance(arg_node, ast.Name):
                    target = arg_node.id
                    # Exception variable: type(e).__name__ → actual class name
                    # from runtime (not the handler's declared type, which
                    # may be a parent class that caught a child exception).
                    # Use the saved alloca (persists past exc_clear).
                    if target in self._exc_class_allocas:
                        return self.builder.load(
                            self._exc_class_allocas[target])
                    if target in self._exc_vars:
                        return self._make_string_constant(
                            self._exc_vars[target])
                    metaclasses = getattr(self, '_class_metaclasses', {})
                    if target in metaclasses:
                        return self._make_string_constant(metaclasses[target])
                    elif target in self._user_classes:
                        # type(ClassName).__name__ → "type" (or metaclass name)
                        mc = getattr(self, '_class_metaclasses', {})
                        return self._make_string_constant(
                            mc.get(target, "type"))
                    # User-defined function, lambda, or function alias → "function"
                    elif (target in self._user_functions
                          or target in getattr(self, '_lambda_names', set())
                          or target in self._func_aliases):
                        return self._make_string_constant("function")
                # FV-backed: resolve by runtime tag (works for Name & expr args)
                try:
                    fv = self._load_or_wrap_fv(arg_node)
                    if (isinstance(fv.type, ir.LiteralStructType)
                            and fv.type == fpy_val):
                        fv_tag = self.builder.extract_value(fv, 0)
                        fv_data = self.builder.extract_value(fv, 1)
                        type_names = {
                            FPY_TAG_INT: "int", FPY_TAG_FLOAT: "float",
                            FPY_TAG_STR: "str", FPY_TAG_BOOL: "bool",
                            FPY_TAG_NONE: "NoneType", FPY_TAG_LIST: "list",
                            FPY_TAG_DICT: "dict", FPY_TAG_SET: "set",
                            FPY_TAG_BIGINT: "int",
                            FPY_TAG_COMPLEX: "complex",
                            FPY_TAG_BYTES: "bytes",
                            FPY_TAG_DECIMAL: "Decimal",
                        }
                        result_alloca = self._create_entry_alloca(
                            i8_ptr, "typename")
                        default = self._make_string_constant("object")
                        self.builder.store(default, result_alloca)
                        # For OBJ tag, use obj_classname_safe which handles
                        # both native FpyObj* and opaque PyObject* (bridge
                        # values like uuid.UUID) via the magic header check.
                        is_obj = self.builder.icmp_signed(
                            "==", fv_tag, ir.Constant(i32, FPY_TAG_OBJ))
                        obj_block = self._new_block("typename.obj")
                        merge_block = self._new_block("typename.merge")
                        self.builder.cbranch(is_obj, obj_block, merge_block)
                        self.builder.position_at_end(obj_block)
                        obj_ptr = self._ensure_ptr(fv_data)
                        runtime_name = self.builder.call(
                            self.runtime["obj_classname_safe"], [obj_ptr])
                        self.builder.store(runtime_name, result_alloca)
                        self.builder.branch(merge_block)
                        self.builder.position_at_end(merge_block)
                        for tv, tn in type_names.items():
                            is_m = self.builder.icmp_signed(
                                "==", fv_tag, ir.Constant(i32, tv))
                            s = self._make_string_constant(tn)
                            cur = self.builder.load(result_alloca)
                            self.builder.store(
                                self.builder.select(is_m, s, cur),
                                result_alloca)
                        return self.builder.load(result_alloca)
                except Exception:
                    pass
                # Fallback: static type analysis
                display = self._static_type_of(arg_node)
                return self._make_string_constant(display)
            # Namedtuple field access: p.x → p[index]
            # Must come before native module check because the namedtuple
            # variable is a plain local, not a pyobj or native module.
            if isinstance(node.value, ast.Name):
                _nt_instances = getattr(self, '_namedtuple_instances', {})
                _nt_info = _nt_instances.get(node.value.id)
                if _nt_info is not None and node.attr in _nt_info["fields"]:
                    idx = _nt_info["fields"].index(node.attr)
                    tup = self._emit_expr_value(node.value)
                    tup = self._ensure_ptr(tup)
                    tag_slot = self._create_entry_alloca(
                        i32, f"nt.{node.attr}.tag")
                    data_slot = self._create_entry_alloca(
                        i64, f"nt.{node.attr}.data")
                    self._rt_call("list_get_fv", [
                        tup, ir.Constant(i64, idx),
                        tag_slot, data_slot])
                    tag = self.builder.load(tag_slot)
                    data = self.builder.load(data_slot)
                    return self._fv_build_from_slots(tag, data)
            # Complex attribute access: z.real, z.imag
            if node.attr in ("real", "imag") and self._is_complex_expr(node.value):
                obj = self._emit_expr_value(node.value)
                obj = self._ensure_ptr(obj)
                # FpyComplex = { double real, double imag }
                _complex_struct = ir.LiteralStructType([double, double])
                typed_ptr = self.builder.bitcast(
                    obj, ir.PointerType(_complex_struct))
                idx = 0 if node.attr == "real" else 1
                field_ptr = self.builder.gep(
                    typed_ptr,
                    [ir.Constant(i32, 0), ir.Constant(i32, idx)],
                    name=f"complex.{node.attr}")
                return self.builder.load(field_ptr)
            # Native module attribute (e.g. math.pi): return constant
            if isinstance(node.value, ast.Name):
                _nm = node.value.id
                _is_native = ((self._has_var(_nm)
                              and self._var_kind(_nm) == VKind.PYOBJ)
                             or _nm in getattr(self, '_native_modules', set()))
                if _is_native:
                    result = self._emit_native_module_attr(_nm, node.attr)
                    if result is not None:
                        return result
            # pathlib.Path attribute access: p.name, p.parent, p.suffix, p.stem
            if self._is_path_expr(node.value):
                obj = self._emit_expr_value(node.value)
                obj = self._ensure_ptr(obj)
                _path_attrs = {
                    "name": "path_name", "parent": "path_parent",
                    "suffix": "path_suffix", "stem": "path_stem",
                }
                if node.attr in _path_attrs:
                    return self.builder.call(
                        self.runtime[_path_attrs[node.attr]], [obj])
            # CPython module/object attribute (e.g. os.sep, response.status_code)
            # Returns raw PyObject* — callers that need FpyValue (print, etc.)
            # go through _load_or_wrap_fv which does bridge conversion.
            # Check both local scope (self.variables) and module-level
            # imports (_cpython_modules) so that module attributes are
            # resolved correctly inside functions, not just at module scope.
            _is_pyobj_var = (isinstance(node.value, ast.Name)
                             and node.value.id in self.variables
                             and self._var_kind(node.value.id) in (
                                 VKind.PYOBJ, VKind.NATIVE_MOD))
            _is_module_import = (isinstance(node.value, ast.Name)
                                 and node.value.id in self._cpython_modules)
            if _is_pyobj_var or _is_module_import:
                if _is_pyobj_var:
                    actual_tag = self.variables[node.value.id][1]
                else:
                    actual_tag = "pyobj"
                if self._tag_kind(actual_tag) == VKind.NATIVE_MOD:
                    # For native_mod: try native attr first, fall back to bridge
                    result = self._emit_native_module_attr(node.value.id, node.attr)
                    if result is not None:
                        return result
                # Load the stored object pointer and getattr on it.
                if _is_module_import and not _is_pyobj_var:
                    # Module-level import: load from the global variable
                    obj = self.builder.load(self._cpython_modules[node.value.id])
                else:
                    obj = self._load_variable(node.value.id, node)
                obj = self._ensure_ptr(obj)
                attr_name = self._make_string_constant(node.attr)
                return self.builder.call(
                    self.runtime["cpython_getattr"], [obj, attr_name])
            # Chained pyobj attribute: foo.bar.baz where foo is pyobj
            if self._is_pyobj_receiver(node.value):
                obj = self._emit_expr_value(node.value)
                obj = self._ensure_ptr(obj)
                attr_name = self._make_string_constant(node.attr)
                return self.builder.call(
                    self.runtime["cpython_getattr"], [obj, attr_name])
            return self._emit_attr_load(node)
        elif isinstance(node, ast.Lambda):
            return self._emit_inline_lambda(node)
        elif isinstance(node, ast.DictComp):
            return self._emit_dict_comprehension(node)
        elif isinstance(node, ast.GeneratorExp):
            # Treat generator expressions as list comprehensions (eager)
            return self._emit_generator_as_list(node)
        elif isinstance(node, ast.Set):
            return self._emit_set_literal(node)
        elif isinstance(node, ast.Yield):
            # yield as expression (x = yield val) — emit the yield and
            # return None (send() not supported in simple generators)
            self._emit_yield(node)
            return ir.Constant(i64, 0)
        elif isinstance(node, ast.YieldFrom):
            self._emit_yield_from(node)
            return ir.Constant(i64, 0)
        elif isinstance(node, ast.SetComp):
            # Set comprehension: build as list, then convert to dict-backed set
            fake = ast.ListComp(elt=node.elt, generators=node.generators)
            ast.copy_location(fake, node)
            result = self._emit_list_comprehension(fake)
            return self._rt_call("set_from_list", [result])
        elif isinstance(node, ast.Starred):
            # *expr in non-call context — evaluate the inner expression
            return self._emit_expr_value(node.value)
        elif isinstance(node, ast.Slice):
            # Standalone slice object — return dummy (used in __getitem__)
            return ir.Constant(i64, 0)
        else:
            raise CodeGenError(
                f"Unsupported expression: {type(node).__name__}", node
            )


    _BUILTIN_DISPATCH = {

        "abs": "_emit_builtin_abs",

        "all": "_emit_builtin_all",

        "any": "_emit_builtin_any",

        "bin": "_emit_builtin_bin",

        "bool": "_emit_builtin_bool",

        "callable": "_emit_builtin_callable",

        "chr": "_emit_builtin_chr",

        "complex": "_emit_builtin_complex",

        "dict": "_emit_builtin_dict",

        "divmod": "_emit_builtin_divmod",

        "enumerate": "_emit_builtin_enumerate",

        "eval": "_emit_builtin_eval",

        "exec": "_emit_builtin_exec",

        "filter": "_emit_builtin_filter",

        "float": "_emit_builtin_float",

        "getattr": "_emit_builtin_getattr",

        "globals": "_emit_builtin_globals",

        "hasattr": "_emit_builtin_hasattr",

        "hash": "_emit_builtin_hash",

        "hex": "_emit_builtin_hex",

        "int": "_emit_builtin_int",

        "isinstance": "_emit_builtin_isinstance",

        "issubclass": "_emit_builtin_issubclass",

        "iter": "_emit_builtin_iter",

        "len": "_emit_builtin_len",

        "list": "_emit_builtin_list",

        "locals": "_emit_builtin_locals",

        "map": "_emit_builtin_map",

        "min": "_emit_builtin_min",

        "max": "_emit_builtin_min",

        "next": "_emit_builtin_next",

        "oct": "_emit_builtin_oct",

        "ord": "_emit_builtin_ord",

        "pow": "_emit_builtin_pow",

        "range": "_emit_builtin_range",

        "repr": "_emit_builtin_repr",

        "reversed": "_emit_builtin_reversed",

        "round": "_emit_builtin_round",

        "set": "_emit_builtin_set",

        "setattr": "_emit_builtin_setattr",

        "sorted": "_emit_builtin_sorted",

        "str": "_emit_builtin_str",

        "sum": "_emit_builtin_sum",

        "tuple": "_emit_builtin_tuple",

        "type": "_emit_builtin_type",

        "zip": "_emit_builtin_zip",

    }


    def _emit_builtin_callable(self, node):
        """callable(x) → True if x is a function, class, or has __call__."""
        if len(node.args) != 1:
            return self._emit_unknown_builtin_call(node, "callable")
        arg_node = node.args[0]
        # Known function, class, lambda, or alias → always callable
        if isinstance(arg_node, ast.Name):
            name = arg_node.id
            if (name in self._user_functions
                    or name in self._user_classes
                    or name in getattr(self, '_lambda_names', set())
                    or name in self._func_aliases):
                return ir.Constant(i64, 1)
        # For FV-backed variables, check the runtime tag.
        # OBJ-tagged values might have __call__; primitive types are not
        # callable.  Functions stored as FV are i64 pointers with INT tag
        # but we already caught those above via _user_functions.
        # Fall back to the CPython bridge for unknown types.
        return self._emit_unknown_builtin_call(node, "callable")

    def _emit_builtin_type(self, node):
        if len(node.args) == 1:
            arg_node = node.args[0]
            # User-defined functions are native code pointers, not
            # Python function objects. type(f) should return the
            # CPython types.FunctionType object so that comparisons
            # like `type(f) == types.FunctionType` work correctly.
            if (isinstance(arg_node, ast.Name)
                    and arg_node.id in self._user_functions):
                types_name = self._make_string_constant("types")
                types_mod = self.builder.call(
                    self.runtime["cpython_import"], [types_name])
                ft_name = self._make_string_constant("FunctionType")
                return self.builder.call(
                    self.runtime["cpython_getattr"],
                    [types_mod, ft_name])
            # Exception variable: type(e) → <class 'ExceptionName'>
            if (isinstance(arg_node, ast.Name)
                    and arg_node.id in self._exc_vars):
                cls_name = self._exc_vars[arg_node.id]
                return self._make_string_constant(
                    f"<class '{cls_name}'>")
            # For FV-backed variables, check runtime tag to determine
            # the actual type (handles CPython bridge results correctly)
            if (self._USE_FV_LOCALS
                    and isinstance(arg_node, ast.Name)
                    and arg_node.id in self.variables):
                alloca, tag = self.variables[arg_node.id]
                if (isinstance(alloca.type, ir.PointerType)
                        and alloca.type.pointee is fpy_val):
                    fv = self.builder.load(alloca)
                    fv_tag = self.builder.extract_value(fv, 0)
                    fv_data = self.builder.extract_value(fv, 1)
                    # Build a runtime switch on tag
                    type_strs = {
                        FPY_TAG_INT: "<class 'int'>",
                        FPY_TAG_FLOAT: "<class 'float'>",
                        FPY_TAG_STR: "<class 'str'>",
                        FPY_TAG_BOOL: "<class 'bool'>",
                        FPY_TAG_NONE: "<class 'NoneType'>",
                        FPY_TAG_LIST: "<class 'list'>",
                        FPY_TAG_DICT: "<class 'dict'>",
                        FPY_TAG_SET: "<class 'set'>",
                        FPY_TAG_BIGINT: "<class 'int'>",
                        FPY_TAG_COMPLEX: "<class 'complex'>",
                        FPY_TAG_BYTES: "<class 'bytes'>",
                        FPY_TAG_DECIMAL: "<class 'Decimal'>",
                    }
                    result_alloca = self._create_entry_alloca(
                        i8_ptr, "type.result")
                    default_str = self._make_string_constant(
                        "<class 'object'>")
                    self.builder.store(default_str, result_alloca)
                    # For OBJ tag, use native obj_type_repr (NOT
                    # cpython_type_repr — native FpyObj isn't PyObject*)
                    is_obj = self.builder.icmp_signed(
                        "==", fv_tag, ir.Constant(i32, FPY_TAG_OBJ))
                    obj_block = self._new_block("type.obj")
                    merge_block = self._new_block("type.merge")
                    self.builder.cbranch(is_obj, obj_block, merge_block)
                    self.builder.position_at_end(obj_block)
                    obj_ptr = self._ensure_ptr(fv_data)
                    runtime_type = self.builder.call(
                        self.runtime["obj_type_repr"], [obj_ptr])
                    self.builder.store(runtime_type, result_alloca)
                    self.builder.branch(merge_block)
                    self.builder.position_at_end(merge_block)
                    for tag_val, type_str in type_strs.items():
                        is_match = self.builder.icmp_signed(
                            "==", fv_tag, ir.Constant(i32, tag_val))
                        str_ptr = self._make_string_constant(type_str)
                        current = self.builder.load(result_alloca)
                        selected = self.builder.select(
                            is_match, str_ptr, current)
                        self.builder.store(selected, result_alloca)
                    # Refine LIST → tuple if compiler knows static kind
                    _static_vk = self._var_kind(arg_node.id)
                    if _static_vk == VKind.TUPLE:
                        is_list_tag = self.builder.icmp_signed(
                            "==", fv_tag,
                            ir.Constant(i32, FPY_TAG_LIST))
                        tuple_str = self._make_string_constant(
                            "<class 'tuple'>")
                        current = self.builder.load(result_alloca)
                        refined = self.builder.select(
                            is_list_tag, tuple_str, current)
                        self.builder.store(refined, result_alloca)
                    return self.builder.load(result_alloca)
            # Try runtime tag dispatch via _load_or_wrap_fv for
            # expression args (bridge calls, native module calls, etc.)
            try:
                fv = self._load_or_wrap_fv(arg_node)
                if (isinstance(fv.type, ir.LiteralStructType)
                        and fv.type == fpy_val):
                    fv_tag = self.builder.extract_value(fv, 0)
                    fv_data = self.builder.extract_value(fv, 1)
                    type_strs = {
                        FPY_TAG_INT: "<class 'int'>",
                        FPY_TAG_FLOAT: "<class 'float'>",
                        FPY_TAG_STR: "<class 'str'>",
                        FPY_TAG_BOOL: "<class 'bool'>",
                        FPY_TAG_NONE: "<class 'NoneType'>",
                        FPY_TAG_LIST: "<class 'list'>",
                        FPY_TAG_DICT: "<class 'dict'>",
                        FPY_TAG_SET: "<class 'set'>",
                        FPY_TAG_BIGINT: "<class 'int'>",
                        FPY_TAG_COMPLEX: "<class 'complex'>",
                        FPY_TAG_BYTES: "<class 'bytes'>",
                        FPY_TAG_DECIMAL: "<class 'Decimal'>",
                    }
                    result_alloca = self._create_entry_alloca(
                        i8_ptr, "type.result")
                    default_str = self._make_string_constant(
                        "<class 'object'>")
                    self.builder.store(default_str, result_alloca)
                    # For OBJ tag, use native obj_type_repr
                    is_obj = self.builder.icmp_signed(
                        "==", fv_tag, ir.Constant(i32, FPY_TAG_OBJ))
                    obj_block = self._new_block("type.expr.obj")
                    merge_block = self._new_block("type.expr.merge")
                    self.builder.cbranch(is_obj, obj_block, merge_block)
                    self.builder.position_at_end(obj_block)
                    obj_ptr = self._ensure_ptr(fv_data)
                    runtime_type = self.builder.call(
                        self.runtime["obj_type_repr"], [obj_ptr])
                    self.builder.store(runtime_type, result_alloca)
                    self.builder.branch(merge_block)
                    self.builder.position_at_end(merge_block)
                    for tag_val, type_str in type_strs.items():
                        is_match = self.builder.icmp_signed(
                            "==", fv_tag, ir.Constant(i32, tag_val))
                        str_ptr = self._make_string_constant(type_str)
                        current = self.builder.load(result_alloca)
                        selected = self.builder.select(
                            is_match, str_ptr, current)
                        self.builder.store(selected, result_alloca)
                    return self.builder.load(result_alloca)
            except Exception:
                pass
            # Static type analysis fallback
            actual = self._static_type_of(node.args[0])
            # Also check for list/dict via type tags
            if actual == "unknown":
                if self._is_list_expr(node.args[0]):
                    actual = "list"
                elif self._is_dict_expr(node.args[0]):
                    actual = "dict"
            if actual == "unknown":
                # Default: Python prints class name or type object
                actual = "object"
            type_name_map = {
                "int": "int", "bool": "bool", "float": "float",
                "str": "str", "list": "list", "dict": "dict",
                "tuple": "tuple", "object": "object",
            }
            display = type_name_map.get(actual, actual)
            return self._make_string_constant(f"<class '{display}'>")
        return self._bridge_fallback_expr(node, "type() with multiple args")

    def _emit_builtin_range(self, node):
        # range(stop) / range(start, stop) / range(start, stop, step) -> list
        def _range_to_i64(val):
            """Coerce a range argument to bare i64."""
            if (isinstance(val.type, ir.LiteralStructType)
                    and val.type == fpy_val):
                return self.builder.extract_value(val, 1)
            if isinstance(val.type, ir.PointerType):
                return self.builder.ptrtoint(val, i64)
            if isinstance(val.type, ir.DoubleType):
                return self.builder.fptosi(val, i64)
            if isinstance(val.type, ir.IntType) and val.type.width != 64:
                return self.builder.zext(val, i64)
            return val

        if len(node.args) == 1:
            start = ir.Constant(i64, 0)
            stop = _range_to_i64(self._emit_expr_value(node.args[0]))
            step = ir.Constant(i64, 1)
        elif len(node.args) == 2:
            start = _range_to_i64(self._emit_expr_value(node.args[0]))
            stop = _range_to_i64(self._emit_expr_value(node.args[1]))
            step = ir.Constant(i64, 1)
        elif len(node.args) == 3:
            start = _range_to_i64(self._emit_expr_value(node.args[0]))
            stop = _range_to_i64(self._emit_expr_value(node.args[1]))
            step = _range_to_i64(self._emit_expr_value(node.args[2]))
        else:
            raise CodeGenError("range() takes 1-3 arguments", node)
        return self.builder.call(self.runtime["range"], [start, stop, step])

    def _emit_builtin_list(self, node):
        # list(dict) → list of keys
        if len(node.args) == 1 and self._is_dict_expr(node.args[0]):
            d = self._emit_expr_value(node.args[0])
            return self._rt_call("dict_keys", [d])
        # list(deque) → deque_to_list conversion
        if len(node.args) == 1 and self._is_deque_expr(node.args[0]):
            dq = self._emit_expr_value(node.args[0])
            dq = self._ensure_ptr(dq)
            return self.builder.call(self.runtime["deque_to_list"], [dq])
        # list(bytes) → list of byte values (ints)
        if len(node.args) == 1:
            arg = node.args[0]
            # Check if argument is a bytes-typed variable
            is_bytes = False
            if isinstance(arg, ast.Name) and arg.id in self.variables:
                _, vtag = self.variables[arg.id]
                is_bytes = (self._tag_kind(vtag) == VKind.BYTES)
            if is_bytes:
                b = self._emit_expr_value(arg)
                b = self._ensure_ptr(b)
                return self.builder.call(self.runtime["bytes_to_list"], [b])
        # list(str) — split into list of single-character strings
        if len(node.args) == 1:
            arg = node.args[0]
            _is_str = False
            if isinstance(arg, ast.Constant) and isinstance(arg.value, str):
                _is_str = True
            elif isinstance(arg, ast.Name) and arg.id in self.variables:
                _is_str = (self._var_kind(arg.id) == VKind.STR)
            if _is_str:
                s = self._emit_expr_value(arg)
                s = self._ensure_ptr(s)
                return self.builder.call(self.runtime["str_to_list"], [s])
        # list(obj) — iterate via __iter__/__next__ protocol
        if len(node.args) == 1 and self._is_obj_expr(node.args[0]):
            obj = self._emit_expr_value(node.args[0])
            obj = self._ensure_ptr(obj)
            return self._rt_call("list_from_obj_iter", [obj])
        # list(pyobj) — iterate a CPython iterable (generator, map, filter,
        # etc.) into a native FpyList via the bridge.  Without this, the
        # raw PyObject* is returned as-is, producing a broken single-element
        # list instead of iterating the contents.
        if len(node.args) == 1:
            arg = node.args[0]
            _is_pyobj = False
            if isinstance(arg, ast.Name) and arg.id in self.variables:
                _is_pyobj = self._var_kind(arg.id) == VKind.PYOBJ
            if not _is_pyobj:
                # Exclude NATIVE_MOD — their calls compile natively
                _is_pyobj = self._is_pyobj_receiver(
                    arg, include_native_mod=False)
            if not _is_pyobj and isinstance(arg, ast.Call):
                # Call result from a bridge function (e.g. ts.static_order())
                if (isinstance(arg.func, ast.Attribute)
                        and self._is_pyobj_receiver(
                            arg.func.value, include_native_mod=False)):
                    _is_pyobj = True
            if _is_pyobj:
                val = self._emit_expr_value(arg)
                return self._pyobj_to_list(val)
        # list(set) — convert set to list of its elements
        if len(node.args) == 1:
            arg = node.args[0]
            if self._is_set_expr(arg):
                s = self._emit_expr_value(arg)
                s = self._ensure_ptr(s)
                return self._rt_call("set_to_list", [s])
        # list(list) / list(tuple) — shallow copy
        if len(node.args) == 1:
            arg = node.args[0]
            if self._is_list_expr(arg):
                lst = self._emit_expr_value(arg)
                lst = self._ensure_ptr(lst)
                return self.builder.call(self.runtime["list_copy"], [lst])
            if self._is_tuple_expr(arg):
                lst = self._emit_expr_value(arg)
                lst = self._ensure_ptr(lst)
                result = self.builder.call(self.runtime["list_copy"], [lst])
                # Clear the is_tuple flag so it prints as a list
                self.builder.call(self.runtime["list_mark_list"], [result])
                return result
        # list(x) — fallback: if result is FpyValue, dispatch at runtime
        if len(node.args) == 1:
            val = self._emit_expr_value(node.args[0])
            if isinstance(val.type, ir.LiteralStructType) and val.type == fpy_val:
                tag = self.builder.extract_value(val, 0)
                data = self.builder.extract_value(val, 1)
                return self.builder.call(self.runtime["fv_to_list"], [tag, data])
            return val
        if len(node.args) == 0:
            return self.builder.call(self.runtime["list_new"], [])
        raise CodeGenError("list() with wrong number of args", node)

    def _emit_builtin_dict(self, node):
        # dict() or dict([(k, v), ...])
        if len(node.args) == 0:
            return self.builder.call(self.runtime["dict_new"], [])
        if len(node.args) == 1:
            # dict([(k, v), ...]) — build dict by iterating
            arg_node = node.args[0]
            if isinstance(arg_node, ast.List):
                # Build a dict from literal list of tuples at compile time
                d = self.builder.call(self.runtime["dict_new"], [])
                for elt in arg_node.elts:
                    if isinstance(elt, ast.Tuple) and len(elt.elts) == 2:
                        k_node, v_node = elt.elts
                        k_val = self._emit_expr_value(k_node)
                        v_val = self._emit_expr_value(v_node)
                        tag, data = self._bare_to_tag_data(v_val, v_node)
                        if isinstance(k_val.type, ir.PointerType):
                            self.builder.call(self.runtime["dict_set_fv"],
                                              [d, k_val, ir.Constant(i32, tag), data])
                        elif isinstance(k_val.type, ir.IntType):
                            self.builder.call(self.runtime["dict_set_int_fv"],
                                              [d, k_val, ir.Constant(i32, tag), data])
                        else:
                            return self._bridge_fallback_expr(
                                node, f"dict() with unsupported key type {k_val.type}")
                return d
            # dict(list_variable) or dict(zip(...)) — build from pairs at runtime
            if (self._is_list_expr(arg_node) or self._is_tuple_expr(arg_node)
                    or (isinstance(arg_node, ast.Call)
                        and isinstance(arg_node.func, ast.Name)
                        and arg_node.func.id in ("zip", "sorted", "reversed",
                                                  "list", "tuple"))):
                pairs = self._emit_expr_value(arg_node)
                pairs = self._ensure_ptr(pairs)
                return self.builder.call(self.runtime["dict_from_pairs"], [pairs])
            # dict(existing_dict) — shallow copy (works for dict, defaultdict, Counter)
            if (self._is_dict_expr(arg_node)
                    or self._is_defaultdict_expr(arg_node)
                    or self._is_counter_expr(arg_node)):
                d = self._emit_expr_value(arg_node)
                d = self._ensure_ptr(d)
                return self._rt_call("dict_copy", [d])
            return self._bridge_fallback_expr(node, "dict() with non-literal argument")

    def _emit_builtin_tuple(self, node):
        # tuple(iter) — build a list from the iterable, then mark as tuple
        if len(node.args) == 1:
            arg = node.args[0]
            # tuple(str) → tuple of single-char strings
            _is_str = False
            if isinstance(arg, ast.Constant) and isinstance(arg.value, str):
                _is_str = True
            elif isinstance(arg, ast.Name) and arg.id in self.variables:
                _is_str = (self._var_kind(arg.id) == VKind.STR)
            if _is_str:
                s = self._emit_expr_value(arg)
                s = self._ensure_ptr(s)
                result = self.builder.call(self.runtime["str_to_list"], [s])
                self.builder.call(self.runtime["list_mark_tuple"], [result])
                return result
            # tuple(dict) → tuple of keys
            if self._is_dict_expr(arg):
                result = self._emit_expr_value(arg)
                result = self._rt_call("dict_keys", [result])
                result = self._ensure_ptr(result)
                self.builder.call(self.runtime["list_mark_tuple"], [result])
                return result
            # tuple(pyobj) → iterate CPython iterable
            _is_pyobj = False
            if isinstance(arg, ast.Name) and arg.id in self.variables:
                _is_pyobj = self._var_kind(arg.id) == VKind.PYOBJ
            if not _is_pyobj:
                _is_pyobj = self._is_pyobj_receiver(
                    arg, include_native_mod=False)
            if not _is_pyobj and isinstance(arg, ast.Call):
                if (isinstance(arg.func, ast.Attribute)
                        and self._is_pyobj_receiver(
                            arg.func.value, include_native_mod=False)):
                    _is_pyobj = True
            if _is_pyobj:
                val = self._emit_expr_value(arg)
                result = self._pyobj_to_list(val)
                result = self._ensure_ptr(result)
                self.builder.call(self.runtime["list_mark_tuple"], [result])
                return result
            # tuple(obj) — materialize via __iter__/__next__
            if self._is_obj_expr(arg):
                obj = self._emit_expr_value(arg)
                obj = self._ensure_ptr(obj)
                result = self._rt_call("list_from_obj_iter", [obj])
                self.builder.call(self.runtime["list_mark_tuple"], [result])
                return result
            # tuple(set) → convert set to list, then mark as tuple
            if self._is_set_expr(arg):
                s = self._emit_expr_value(arg)
                s = self._ensure_ptr(s)
                result = self._rt_call("set_to_list", [s])
                self.builder.call(self.runtime["list_mark_tuple"], [result])
                return result
            # tuple(list/tuple) — copy and mark as tuple
            result = self._emit_expr_value(arg)
            if self._is_list_expr(arg) or self._is_tuple_expr(arg):
                result = self._ensure_ptr(result)
                result = self.builder.call(self.runtime["list_copy"], [result])
            # FpyValue fallback: dispatch at runtime, then mark as tuple
            if isinstance(result.type, ir.LiteralStructType) and result.type == fpy_val:
                tag = self.builder.extract_value(result, 0)
                data = self.builder.extract_value(result, 1)
                result = self.builder.call(self.runtime["fv_to_list"], [tag, data])
            # Ensure the result is a list pointer, then mark as tuple
            result = self._ensure_ptr(result)
            self.builder.call(self.runtime["list_mark_tuple"], [result])
            return result
        if len(node.args) == 0:
            return self.builder.call(self.runtime["tuple_new"], [])
        raise CodeGenError("tuple() with wrong number of args", node)

    def _emit_builtin_complex(self, node):
        # complex(real, imag) or complex(real)
        if len(node.args) == 0:
            real = ir.Constant(double, 0.0)
            imag = ir.Constant(double, 0.0)
        elif len(node.args) == 1:
            real = self._emit_expr_value(node.args[0])
            if isinstance(real.type, ir.IntType):
                real = self.builder.sitofp(real, double)
            imag = ir.Constant(double, 0.0)
        elif len(node.args) == 2:
            real = self._emit_expr_value(node.args[0])
            imag = self._emit_expr_value(node.args[1])
            if isinstance(real.type, ir.IntType):
                real = self.builder.sitofp(real, double)
            if isinstance(imag.type, ir.IntType):
                imag = self.builder.sitofp(imag, double)
        else:
            raise CodeGenError("complex() takes 0-2 args", node)
        ptr = self.builder.call(self.runtime["complex_new"],
                                [real, imag])
        return self.builder.ptrtoint(ptr, i64)

    def _emit_builtin_reversed(self, node):
        if len(node.args) == 1:
            arg_node = node.args[0]
            # String argument: use str_reversed to get list of chars in
            # reverse order (avoids passing char* to list_reversed which
            # expects FpyList*).
            if (isinstance(arg_node, ast.Constant) and isinstance(arg_node.value, str)):
                arg = self._emit_expr_value(arg_node)
                return self._rt_call("str_reversed", [arg])
            if isinstance(arg_node, ast.Name) and arg_node.id in self.variables:
                if self._var_kind(arg_node.id) == VKind.STR:
                    arg = self._emit_expr_value(arg_node)
                    return self._rt_call("str_reversed", [arg])
            if isinstance(arg_node, ast.JoinedStr):
                arg = self._emit_expr_value(arg_node)
                return self._rt_call("str_reversed", [arg])
