    def _emit_builtin_bool(self, node):
        if len(node.args) == 0:
            return ir.Constant(i32, 0)  # bool() → False
        if len(node.args) == 1:
            return self.builder.zext(self._truthiness_of_expr(node.args[0]), i32)
