    def _emit_set_method_copy(self, node, obj):
        if len(node.args) != 0:
            return None
        return self._rt_call("set_copy", [obj])

    def _emit_set_method_clear(self, node, obj):
        if len(node.args) != 0:
            return None
        self._rt_call("set_clear", [obj])
