    def _emit_set_method_pop(self, node, obj):
        if len(node.args) != 0:
            return None
        tag_slot = self._create_entry_alloca(i32, "spop.tag")
        data_slot = self._create_entry_alloca(i64, "spop.data")
        self.builder.call(self.runtime["set_pop_fv"],
                          [obj, tag_slot, data_slot])
        return self._fv_build_from_slots(
            self.builder.load(tag_slot), self.builder.load(data_slot))

    def _emit_set_method_update(self, node, obj):
        if len(node.args) != 1:
            return None
        other = self._emit_expr_value(node.args[0])
        other = self._ensure_ptr(other)
        self._rt_call("set_update", [obj, other])
        return obj

    # ---- Dict method dispatch table (B3) ----
    _DICT_METHOD_DISPATCH = {
        "keys": "_emit_dict_method_keys",
        "values": "_emit_dict_method_values",
        "items": "_emit_dict_method_items",
        "get": "_emit_dict_method_get",
        "update": "_emit_dict_method_update",
        "pop": "_emit_dict_method_pop",
        "setdefault": "_emit_dict_method_setdefault",
        "popitem": "_emit_dict_method_popitem",
        "copy": "_emit_dict_method_copy",
        "clear": "_emit_dict_method_clear",
    }

    def _emit_method_call_dict(self, node):
        """Emit dict method calls via dispatch table. Returns None if not recognized."""
        method = node.func.attr
        handler_name = self._DICT_METHOD_DISPATCH.get(method)
        if handler_name is None:
            return None
        obj = self._emit_expr_value(node.func.value)
        return getattr(self, handler_name)(node, obj)

    # ---- Dict method handlers (B3) ----

    def _emit_dict_method_keys(self, node, obj):
        return self._rt_call("dict_keys", [obj])

    def _emit_dict_method_values(self, node, obj):
        return self._rt_call("dict_values", [obj])

    def _emit_dict_method_items(self, node, obj):
        return self._rt_call("dict_items", [obj])

    def _emit_dict_method_get(self, node, obj):
        if len(node.args) < 1:
            return None
        key = self._emit_expr_value(node.args[0])
        is_str_key = isinstance(key.type, ir.PointerType)
        is_int_key = (isinstance(key.type, ir.IntType)
                      and key.type.width == 64)
        if is_str_key or is_int_key:
            if is_str_key:
                has = self._rt_call("dict_has_key", [obj, key])
            else:
                has = self._rt_call("dict_has_int_key", [obj, key])
            has_bool = self.builder.icmp_unsigned(
                "!=", has, ir.Constant(i32, 0))
            tag_slot = self._create_entry_alloca(i32, "dget.tag")
            data_slot = self._create_entry_alloca(i64, "dget.data")
            found_block = self._new_block("dget.found")
            default_block = self._new_block("dget.default")
            merge_block = self._new_block("dget.merge")
            self.builder.cbranch(has_bool, found_block, default_block)
            # Found path
            self.builder.position_at_end(found_block)
            if is_str_key:
                self.builder.call(self.runtime["dict_get_fv"],
                                  [obj, key, tag_slot, data_slot])
            else:
                self.builder.call(self.runtime["dict_get_int_fv"],
                                  [obj, key, tag_slot, data_slot])
            found_tag = self.builder.load(tag_slot)
            found_data = self.builder.load(data_slot)
            found_fv = self._fv_build_from_slots(found_tag, found_data)
            self.builder.branch(merge_block)
            found_end = self.builder.block
            # Default path
            self.builder.position_at_end(default_block)
            if len(node.args) >= 2:
                default = self._emit_expr_value(node.args[1])
                if isinstance(default.type, ir.LiteralStructType):
                    default_fv = default
                else:
                    default_tag = self._infer_type_tag(
                        node.args[1], default)
                    default_fv = self._wrap_bare_to_fv(
                        default, default_tag)
            else:
                default_fv = self._fv_none()
            self.builder.branch(merge_block)
            default_end = self.builder.block
            # Merge
            self.builder.position_at_end(merge_block)
            phi = self.builder.phi(fpy_val, "dget.fv")
            phi.add_incoming(found_fv, found_end)
            phi.add_incoming(default_fv, default_end)
            return phi
        # FpyValue key (e.g. from list.pop(), for-each iteration)
        if key.type == fpy_val:
            kt = self.builder.extract_value(key, 0, "dget.kt")
            kd = self.builder.extract_value(key, 1, "dget.kd")
            has = self.builder.call(self.runtime["dict_has_kv_key"],
                                   [obj, kt, kd])
            has_bool = self.builder.icmp_unsigned(
                "!=", has, ir.Constant(i32, 0))
            tag_slot = self._create_entry_alloca(i32, "dget.tag")
            data_slot = self._create_entry_alloca(i64, "dget.data")
            found_block = self._new_block("dget.found")
            default_block = self._new_block("dget.default")
            merge_block = self._new_block("dget.merge")
            self.builder.cbranch(has_bool, found_block, default_block)
            # Found path
            self.builder.position_at_end(found_block)
            self.builder.call(self.runtime["dict_get_kv_fv"],
                              [obj, kt, kd, tag_slot, data_slot])
            found_tag = self.builder.load(tag_slot)
            found_data = self.builder.load(data_slot)
            found_fv = self._fv_build_from_slots(found_tag, found_data)
            self.builder.branch(merge_block)
            found_end = self.builder.block
            # Default path
            self.builder.position_at_end(default_block)
            if len(node.args) >= 2:
                default = self._emit_expr_value(node.args[1])
                if isinstance(default.type, ir.LiteralStructType):
                    default_fv = default
                else:
                    default_tag = self._infer_type_tag(
                        node.args[1], default)
                    default_fv = self._wrap_bare_to_fv(
                        default, default_tag)
            else:
                default_fv = self._fv_none()
            self.builder.branch(merge_block)
            default_end = self.builder.block
            # Merge
            self.builder.position_at_end(merge_block)
            phi = self.builder.phi(fpy_val, "dget.fv")
            phi.add_incoming(found_fv, found_end)
            phi.add_incoming(default_fv, default_end)
            return phi
        # Unknown key type fallback
        if len(node.args) >= 2:
            default = self._emit_expr_value(node.args[1])
            if not isinstance(default.type, ir.PointerType):
                default = self.builder.call(
                    self.runtime["int_to_str"], [default])
        else:
            default = self._make_string_constant("None")
        return self._rt_call("dict_get_default", [obj, key, default])

    def _emit_dict_method_update(self, node, obj):
        if len(node.args) == 1:
            other = self._emit_expr_value(node.args[0])
            # If the argument is a bridge PyObject (e.g. dict returned from
            # a CPython call), convert to native FpyDict first.
            # fastpy_dict_update expects FpyDict*, not raw PyObject*.
            # Exclude NATIVE_MOD — their calls already return native dicts.
            if (self._is_pyobj_var(node.args[0])
                    or self._is_pyobj_receiver(
                        node.args[0], include_native_mod=False)):
                other = self._rt_call("cpython_to_dict", [other])
            self._rt_call("dict_update", [obj, other])
        # dict.update(key=val, ...) keyword form: build a temp dict, merge it
        if node.keywords:
            tmp = self.builder.call(self.runtime["dict_new"], [])
            for kw in node.keywords:
                if kw.arg is None:
                    # **kwargs unpacking
                    other = self._emit_expr_value(kw.value)
                    other = self._ensure_ptr(other)
                    self._rt_call("dict_update", [tmp, other])
                else:
                    key_str = self._make_string_constant(kw.arg)
                    val = self._emit_expr_value(kw.value)
                    tag, data = self._bare_to_tag_data(val, kw.value)
                    self.builder.call(self.runtime["dict_set_fv"],
                                      [tmp, key_str,
                                       ir.Constant(i32, tag), data])
            self._rt_call("dict_update", [obj, tmp])
        if len(node.args) <= 1:
            return obj
        return None

    def _emit_dict_method_pop(self, node, obj):
        if len(node.args) == 1:
            key = self._emit_expr_value(node.args[0])
            key_tag, key_data = self._to_tag_data_ir(key, node.args[0])
            out_tag = self._create_entry_alloca(i32, "dpop1.tag")
            out_data = self._create_entry_alloca(i64, "dpop1.data")
            key_is_str = (isinstance(key_tag, ir.Constant)
                          and key_tag.constant == FPY_TAG_STR)
            if key_is_str:
                self.builder.call(self.runtime["dict_pop_nodefault_fv"],
                                  [obj, key, out_tag, out_data])
            else:
                self.builder.call(self.runtime["dict_pop_nodefault_generic"],
                                  [obj, key_tag, key_data, out_tag, out_data])
            tag = self.builder.load(out_tag)
            data = self.builder.load(out_data)
            return self._fv_build_from_slots(tag, data)
        if len(node.args) == 2:
            key = self._emit_expr_value(node.args[0])
            default_val = self._emit_expr_value(node.args[1])
            key_tag, key_data = self._to_tag_data_ir(key, node.args[0])
            def_tag, def_data = self._to_tag_data_ir(
                default_val, node.args[1])
            out_tag = self._create_entry_alloca(i32, "dpop.tag")
            out_data = self._create_entry_alloca(i64, "dpop.data")
            key_is_str = (isinstance(key_tag, ir.Constant)
                          and key_tag.constant == FPY_TAG_STR)
            if key_is_str:
                self.builder.call(self.runtime["dict_pop_fv"],
                                  [obj, key, def_tag, def_data,
                                   out_tag, out_data])
            else:
                self.builder.call(self.runtime["dict_pop_generic"],
                                  [obj, key_tag, key_data, def_tag, def_data,
                                   out_tag, out_data])
            return self._fv_build_from_slots(
                self.builder.load(out_tag),
                self.builder.load(out_data))
        return None

    def _emit_dict_method_setdefault(self, node, obj):
        if len(node.args) == 2:
            key = self._emit_expr_value(node.args[0])
            default = self._emit_expr_value(node.args[1])
            def_tag, def_data = self._bare_to_tag_data(default, node.args[1])
            key_tag, key_data = self._to_tag_data_ir(key, node.args[0])
            out_tag = self._create_entry_alloca(i32, "sd.tag")
            out_data = self._create_entry_alloca(i64, "sd.data")
            # Check if key is known to be a string at compile time
            key_is_str = (isinstance(key_tag, ir.Constant)
                          and key_tag.constant == FPY_TAG_STR)
            if key_is_str:
                # Fast path: string key uses the optimized str-only function
                self.builder.call(self.runtime["dict_setdefault_fv"],
                                  [obj, key, ir.Constant(i32, def_tag),
                                   def_data, out_tag, out_data])
            else:
                # Generic path: handles int, tuple, bool, etc. keys
                self.builder.call(self.runtime["dict_setdefault_generic"],
                                  [obj, key_tag, key_data,
                                   ir.Constant(i32, def_tag), def_data,
                                   out_tag, out_data])
            r_tag = self.builder.load(out_tag)
            r_data = self.builder.load(out_data)
            return self._fv_build_from_slots(r_tag, r_data)
        return None

    def _emit_dict_method_popitem(self, node, obj):
        if len(node.args) != 0:
            return None
        kt = self._create_entry_alloca(i32, "pi.kt")
        kd = self._create_entry_alloca(i64, "pi.kd")
        vt = self._create_entry_alloca(i32, "pi.vt")
        vd = self._create_entry_alloca(i64, "pi.vd")
        self.builder.call(self.runtime["dict_popitem"],
                          [obj, kt, kd, vt, vd])
        tup = self._rt_call("tuple_new", [])
        self.builder.call(self.runtime["list_append_fv"],
                          [tup, self.builder.load(kt),
                           self.builder.load(kd)])
        self.builder.call(self.runtime["list_append_fv"],
                          [tup, self.builder.load(vt),
                           self.builder.load(vd)])
        return tup

    def _emit_dict_method_copy(self, node, obj):
        if len(node.args) != 0:
            return None
        return self._rt_call("dict_copy", [obj])

    def _emit_dict_method_clear(self, node, obj):
        if len(node.args) != 0:
            return None
        self._rt_call("dict_clear", [obj])
        return obj

    def _emit_method_call_userobj(self, node):
        """Emit user-class instance method calls (with direct dispatch optimization)."""
        attr = node.func
        method = node.func.attr

        # Callable attribute: obj.fn(args) where fn is an attribute slot
        # (not a method).  Load the attribute value and dispatch through
        # the closure/function-pointer call path.
        _ca_cls = self._infer_object_class(attr.value)
        if _ca_cls and not self._class_has_method(_ca_cls, method):
            _ca_slots = self._class_attr_slots.get(_ca_cls)
            if _ca_slots and method in _ca_slots:
                _ca_slot_idx = _ca_slots[method]
                _ca_obj = self._emit_expr_value(attr.value)
                _ca_obj = self._ensure_ptr(_ca_obj)
                _s_tag, _s_data = self._emit_slot_get_direct(
                    _ca_obj, _ca_slot_idx)
                # The slot data holds a function pointer or closure pointer
                fn_ptr = self.builder.inttoptr(_s_data, i8_ptr)
                n_args = len(node.args)
                # Evaluate args and set arg_tags so callee knows types
                _ca_args = []
                for _cai, arg_node in enumerate(node.args):
                    v = self._emit_expr_value(arg_node)
                    _at_tag, _ = self._bare_to_tag_data(v, value_node=arg_node)
                    self.builder.call(self.runtime["set_arg_tag"],
                                      [ir.Constant(i32, _cai),
                                       ir.Constant(i32, _at_tag)])
                    if isinstance(v.type, ir.PointerType):
                        v = self.builder.ptrtoint(v, i64)
                    elif isinstance(v.type, ir.DoubleType):
                        v = self.builder.bitcast(v, i64)
                    elif isinstance(v.type, ir.IntType) and v.type.width != 64:
                        v = self.builder.zext(v, i64)
                    _ca_args.append(v)
                if n_args == 0:
                    return self.builder.call(
                        self.runtime["call_ptr0"], [fn_ptr])
                elif n_args == 1:
                    return self.builder.call(
                        self.runtime["call_ptr1"], [fn_ptr, _ca_args[0]])
                elif n_args == 2:
                    return self.builder.call(
                        self.runtime["call_ptr2"],
                        [fn_ptr, _ca_args[0], _ca_args[1]])
                else:
                    # 3+ args: pack into list
                    args_list = self.builder.call(self.runtime["list_new"], [])
                    for _cai, arg_node in enumerate(node.args):
                        v = _ca_args[_cai]
                        tag, _ = self._bare_to_tag_data(
                            self._emit_expr_value(arg_node), value_node=arg_node)
                        self._rt_call("list_append_fv",
                                      [args_list, ir.Constant(i32, tag), v])
                    return self.builder.call(
                        self.runtime["closure_call_list"], [fn_ptr, args_list])

        obj = self._emit_expr_value(attr.value)
        if (isinstance(obj.type, ir.LiteralStructType)
                and obj.type == fpy_val):
            # FpyValue struct: extract data and convert to pointer
            obj = self._ensure_ptr(obj, name="obj.ptr")
        elif isinstance(obj.type, ir.IntType) and obj.type.width == 64:
            obj = self._ensure_ptr(obj, name="obj.ptr")
        method_name_ptr = self._make_string_constant(method)
        n_args = len(node.args)
        # Check which params are mixed for this method
        obj_cls = self._infer_object_class(attr.value)
        method_mixed = set()
        if obj_cls:
            mkey = f"{obj_cls}.{method}"
            method_mixed = getattr(self, '_mixed_param_methods', {}).get(mkey, set())
        # Resolve keyword arguments → positional by consulting method AST
        resolved_arg_nodes = list(node.args)
        if node.keywords and obj_cls:
            # Find the method's AST to get param names and defaults
            m_ast = None
            cn = obj_cls
            while cn and cn in self._user_classes:
                ci = self._user_classes[cn]
                if ci.method_asts and method in ci.method_asts:
                    m_ast = ci.method_asts[method]
                    break
                cn = ci.parent_name
            if m_ast is not None:
                m_params = [a.arg for a in m_ast.args.args[1:]]  # skip self
                m_defaults = m_ast.args.defaults
                kw_nodes: dict[int, ast.expr] = {}
                for kw in node.keywords:
                    if kw.arg is None:
                        continue
                    if kw.arg not in m_params:
                        continue  # Phase 4: unknown kwarg → skip
                    idx = m_params.index(kw.arg)
                    if idx < len(resolved_arg_nodes):
                        continue  # Phase 4: duplicate kwarg → skip
                    kw_nodes[idx] = kw.value
                while len(resolved_arg_nodes) < len(m_params):
                    idx = len(resolved_arg_nodes)
                    if idx in kw_nodes:
                        resolved_arg_nodes.append(kw_nodes[idx])
                    else:
                        default_idx = idx - (len(m_params) - len(m_defaults))
                        if default_idx >= 0 and default_idx < len(m_defaults):
                            resolved_arg_nodes.append(m_defaults[default_idx])
                        else:
                            raise CodeGenError(
                                f".{method}() missing argument at position {idx}",
                                node,
                            )
        # For non-kwarg calls, also fill in defaults for missing positional args
        elif obj_cls and not node.keywords:
            m_ast = None
            cn = obj_cls
            while cn and cn in self._user_classes:
                ci = self._user_classes[cn]
                if ci.method_asts and method in ci.method_asts:
                    m_ast = ci.method_asts[method]
                    break
                cn = ci.parent_name
            if m_ast is not None:
                m_params = [a.arg for a in m_ast.args.args[1:]]
                m_defaults = m_ast.args.defaults
                while len(resolved_arg_nodes) < len(m_params):
                    idx = len(resolved_arg_nodes)
                    default_idx = idx - (len(m_params) - len(m_defaults))
                    if default_idx >= 0 and default_idx < len(m_defaults):
                        resolved_arg_nodes.append(m_defaults[default_idx])
                    else:
                        break
        n_args = len(resolved_arg_nodes)

        # Evaluate and coerce args to i64 (runtime dispatch expects i64).
        # For "mixed" params, pass (tag_i64, data_i64) as two separate args.
        call_args = []
        for arg_idx, arg_node in enumerate(resolved_arg_nodes):
            param_idx = arg_idx + 1  # +1 for self
            v = self._emit_expr_value(arg_node)
            if param_idx in method_mixed:
                # Mixed param: pass tag and data as two separate i64 args
                tag_int, data_val = self._bare_to_tag_data(v, value_node=arg_node)
                call_args.append(ir.Constant(i64, tag_int))
                call_args.append(data_val)
            else:
                if (isinstance(v.type, ir.LiteralStructType)
                        and v.type == fpy_val):
                    # FpyValue struct: extract the data part (i64)
                    v = self.builder.extract_value(v, 1)
                elif isinstance(v.type, ir.PointerType):
                    v = self.builder.ptrtoint(v, i64)
                elif isinstance(v.type, ir.DoubleType):
                    v = self.builder.bitcast(v, i64)
                elif isinstance(v.type, ir.IntType) and v.type.width != 64:
                    v = self.builder.zext(v, i64)
                call_args.append(v)

        # Determine if method returns double
        method_ret_type = self._find_method_return_type(attr.value, method)
        is_double_ret = method_ret_type and isinstance(method_ret_type, ir.DoubleType)

        # Check if method has *args (need this for dispatch decisions)
        _method_is_vararg = False
        if obj_cls:
            _va_cn = obj_cls
            while _va_cn and _va_cn in self._user_classes:
                _va_ci = self._user_classes[_va_cn]
                if _va_ci.method_asts and method in _va_ci.method_asts:
                    _va_mast = _va_ci.method_asts[method]
                    _method_is_vararg = _va_mast.args.vararg is not None
                    break
                _va_cn = _va_ci.parent_name

        # Direct dispatch optimization: when the object's class is known
        # statically and there are no mixed params, call the method
        # function directly instead of going through obj_call_methodN.
        # This skips string comparison and enables LLVM inlining.
        if obj_cls and not method_mixed:
            # Walk class chain to find the actual method (handles inheritance)
            direct_func = None
            cn = obj_cls
            while cn and cn in self._user_classes:
                ci = self._user_classes[cn]
                if method in ci.methods:
                    direct_func = ci.methods[method]
                    break
                cn = ci.parent_name
            # Virtual dispatch decision.
            # For `self` inside a class method: _infer_object_class
            # returns the declaring class, so _method_overridden_in_subclass
            # correctly checks all subclasses. Direct dispatch is safe
            # when no subclass overrides the method.
            #
            # For other non-pinned receivers (function params, loop vars,
            # method returns): _infer_object_class may return ANY class
            # in the hierarchy (from call-site analysis), not necessarily
            # the base class. Checking _method_overridden_in_subclass
            # on the WRONG class would miss overrides.  So for non-self
            # non-pinned receivers, always use vtable dispatch.
            # Skip vtable for vararg methods — runtime dispatch handles packing.
            _may_sub = self._receiver_may_be_subclass(attr.value) if direct_func is not None else False
            _is_self = isinstance(attr.value, ast.Name) and attr.value.id == "self"
            _need_vtable = False
            if direct_func is not None and _may_sub and not _method_is_vararg:
                if _is_self:
                    # self: safe to check overrides on declaring class
                    _need_vtable = self._method_overridden_in_subclass(obj_cls, method)
                else:
                    # Non-self non-pinned: always need vtable dispatch
                    _need_vtable = True
            if _need_vtable:
                # Can't statically bind — need virtual dispatch.
                # Use O(1) vtable lookup instead of falling through to
                # the string-based obj_call_methodN runtime functions.
                vtable_slot = getattr(self, '_vtable_indices', {}).get(method)
                if vtable_slot is not None:
                    n_dispatch_args = len(call_args)
                    # Inline vtable lookup — unchecked because direct_func
                    # was already resolved (the method exists in this
                    # hierarchy), so the vtable entry is guaranteed valid.
                    func_ptr = self._emit_inline_vtable_lookup(
                        obj, vtable_slot, unchecked=True)
                    # The vtable stores the i64-ABI dispatch function,
                    # same pointer that register_method receives.
                    if is_double_ret:
                        ret_t = ir.DoubleType()
                    else:
                        ret_t = i64
                    ftype = ir.FunctionType(
                        ret_t, [i8_ptr] + [i64] * n_dispatch_args)
                    func_typed = self.builder.bitcast(
                        func_ptr, ir.PointerType(ftype))
                    result = self.builder.call(
                        func_typed, [obj] + call_args)
                    # Post-process return type to match caller expectations
                    if not is_double_ret:
                        ret_type = self._find_method_return_type(
                            attr.value, method)
                        if ret_type and isinstance(ret_type, ir.PointerType):
                            result = self._ensure_ptr(result)
                        elif (ret_type
                              and isinstance(ret_type, ir.IntType)
                              and ret_type.width == 32):
                            result = self.builder.trunc(result, i32)
                    # Vtable: self-return FpyValue packing.
                    if (not is_double_ret
                            and isinstance(ret_t, ir.IntType) and ret_t.width == 64
                            and self._direct_method_may_return_ptr(
                                obj_cls, method)):
                        _rt = self.builder.call(self.runtime["get_ret_tag"], [])
                        fv = ir.Constant(fpy_val, ir.Undefined)
                        fv = self.builder.insert_value(fv, _rt, 0)
                        fv = self.builder.insert_value(fv, result, 1)
                        return fv
                    return result
                direct_func = None  # no vtable slot → string-based fallback
            if direct_func is not None:
                # Check if the method has *args
                _d_mast = None
                _d_cn = obj_cls
                while _d_cn and _d_cn in self._user_classes:
                    _d_ci = self._user_classes[_d_cn]
                    if _d_ci.method_asts and method in _d_ci.method_asts:
                        _d_mast = _d_ci.method_asts[method]
                        break
                    _d_cn = _d_ci.parent_name
                _d_has_vararg = _d_mast and _d_mast.args.vararg is not None
                _d_n_positional = (len(_d_mast.args.args) - 1
                                   if _d_has_vararg else len(call_args))

                # Coerce args to match the method's LLVM signature
                direct_args = [obj]  # self
                for i, val in enumerate(call_args):
                    if _d_has_vararg and i >= _d_n_positional:
                        break  # remaining args go into *args list
                    if 1 + i >= len(direct_func.args):
                        break
                    expected = direct_func.args[1 + i].type
                    if val.type != expected:
                        if (isinstance(expected, ir.IntType)
                                and isinstance(val.type, ir.IntType)
                                and expected.width != val.type.width):
                            if expected.width > val.type.width:
                                val = self.builder.zext(val, expected)
                            else:
                                val = self.builder.trunc(val, expected)
                        elif (isinstance(expected, ir.IntType)
                                and isinstance(val.type, ir.PointerType)):
                            val = self.builder.ptrtoint(val, expected)
                        elif (isinstance(expected, ir.PointerType)
                                and isinstance(val.type, ir.IntType)):
                            val = self.builder.inttoptr(val, expected)
                        elif (isinstance(expected, ir.DoubleType)
                                and isinstance(val.type, ir.IntType)):
                            val = self.builder.bitcast(val, expected)
                        elif (isinstance(expected, ir.IntType)
                                and isinstance(val.type, ir.DoubleType)):
                            val = self.builder.bitcast(val, expected)
                    direct_args.append(val)
                # Pack remaining args into a list for *args
                if _d_has_vararg:
                    va_list = self.builder.call(self.runtime["list_new"], [])
                    for vi in range(_d_n_positional, len(call_args)):
                        v = call_args[vi]
                        va_node = (resolved_arg_nodes[vi]
                                   if vi < len(resolved_arg_nodes) else None)
                        _va_tag, _ = self._bare_to_tag_data(
                            v, value_node=va_node)
                        if isinstance(v.type, ir.PointerType):
                            v = self.builder.ptrtoint(v, i64)
                        elif isinstance(v.type, ir.DoubleType):
                            v = self.builder.bitcast(v, i64)
                        elif isinstance(v.type, ir.IntType) and v.type.width != 64:
                            v = self.builder.zext(v, i64)
                        self.builder.call(self.runtime["list_append_fv"], [
                            va_list, ir.Constant(i32, _va_tag), v])
                    direct_args.append(va_list)
                # Set arg tags before the direct call so the callee can
                # recover runtime types for polymorphic parameters (e.g.
                # def echo(self, val): return val — val could be any type).
                for _ati, _atv in enumerate(call_args):
                    _at_node = (resolved_arg_nodes[_ati]
                                if _ati < len(resolved_arg_nodes) else None)
                    # For FV-local (mixed) variables, extract the runtime
                    # tag from the FpyValue struct — the compile-time tag
                    # would just default to INT.
                    _rt_tag_val = None
                    if (_at_node is not None
                            and isinstance(_at_node, ast.Name)
                            and _at_node.id in self.variables):
                        _v_alloca, _v_vtag = self.variables[_at_node.id]
                        if (isinstance(_v_alloca.type, ir.PointerType)
                                and _v_alloca.type.pointee is fpy_val):
                            _fv_load = self.builder.load(_v_alloca,
                                                         name=f"fv.{_at_node.id}")
                            _rt_tag_val = self.builder.extract_value(
                                _fv_load, 0, name=f"fv.{_at_node.id}.tag")
                    if _rt_tag_val is not None:
                        self.builder.call(self.runtime["set_arg_tag"],
                                          [ir.Constant(i32, _ati), _rt_tag_val])
                    else:
                        _at_tag, _ = self._bare_to_tag_data(
                            _atv, value_node=_at_node)
                        self.builder.call(self.runtime["set_arg_tag"],
                                          [ir.Constant(i32, _ati),
                                           ir.Constant(i32, _at_tag)])
                # Call the method function directly
                result = self.builder.call(direct_func, direct_args)
                # Post-process result based on actual return type
                ret_type = direct_func.return_value.type
                if isinstance(ret_type, ir.VoidType):
                    return ir.Constant(i64, 0)  # void methods — return placeholder
                # Methods that return self (fluent API / builder pattern)
                # encode the object pointer as i64 and set the runtime tag
                # via set_ret_tag(OBJ).  Read that tag and pack as FpyValue
                # so callers storing the result in FV locals get the correct
                # type tag (prevents OBJ→INT mistagging).
                if (isinstance(ret_type, ir.IntType) and ret_type.width == 64
                        and self._direct_method_may_return_ptr(
                            obj_cls, method)):
                    _rt = self.builder.call(self.runtime["get_ret_tag"], [])
                    fv = ir.Constant(fpy_val, ir.Undefined)
                    fv = self.builder.insert_value(fv, _rt, 0)
                    fv = self.builder.insert_value(fv, result, 1)
                    return fv
                return result

        # Use actual dispatch arg count (mixed params expand to 2 args each)
        n_dispatch_args = len(call_args)

        # CHA sole-implementor fast-path: when every class in the program
        # shares the same function pointer for this method (defined once in
        # a base, inherited everywhere), skip the vtable entirely and call
        # the function directly.  No type check needed — guaranteed correct
        # for any receiver class.
        cha_func = getattr(self, '_cha_sole_impl', {}).get(method)
        if cha_func is not None and not method_mixed and not _method_is_vararg:
            # Set arg tags before the CHA direct call so the callee can
            # recover runtime types for polymorphic parameters (e.g.
            # def echo(self, val): return val — val could be any type).
            for _ati, _atv in enumerate(call_args):
                _at_node = (resolved_arg_nodes[_ati]
                            if _ati < len(resolved_arg_nodes) else None)
                _rt_tag_val = None
                if (_at_node is not None
                        and isinstance(_at_node, ast.Name)
                        and _at_node.id in self.variables):
                    _v_alloca, _v_vtag = self.variables[_at_node.id]
                    if (isinstance(_v_alloca.type, ir.PointerType)
                            and _v_alloca.type.pointee is fpy_val):
                        _fv_load = self.builder.load(_v_alloca,
                                                     name=f"fv.{_at_node.id}")
                        _rt_tag_val = self.builder.extract_value(
                            _fv_load, 0, name=f"fv.{_at_node.id}.tag")
                if _rt_tag_val is not None:
                    self.builder.call(self.runtime["set_arg_tag"],
                                      [ir.Constant(i32, _ati), _rt_tag_val])
                else:
                    _at_tag, _ = self._bare_to_tag_data(
                        _atv, value_node=_at_node)
                    self.builder.call(self.runtime["set_arg_tag"],
                                      [ir.Constant(i32, _ati),
                                       ir.Constant(i32, _at_tag)])
            direct_args = [obj]
            for i, val in enumerate(call_args):
                if 1 + i >= len(cha_func.args):
                    break
                expected = cha_func.args[1 + i].type
                if val.type != expected:
                    if (isinstance(expected, ir.IntType)
                            and isinstance(val.type, ir.IntType)
                            and expected.width != val.type.width):
                        if expected.width > val.type.width:
                            val = self.builder.zext(val, expected)
                        else:
                            val = self.builder.trunc(val, expected)
                    elif (isinstance(expected, ir.IntType)
                            and isinstance(val.type, ir.PointerType)):
                        val = self.builder.ptrtoint(val, expected)
                    elif (isinstance(expected, ir.PointerType)
                            and isinstance(val.type, ir.IntType)):
                        val = self.builder.inttoptr(val, expected)
                    elif (isinstance(expected, ir.DoubleType)
                            and isinstance(val.type, ir.IntType)):
                        val = self.builder.bitcast(val, expected)
                    elif (isinstance(expected, ir.IntType)
                            and isinstance(val.type, ir.DoubleType)):
                        val = self.builder.bitcast(val, expected)
                direct_args.append(val)
            result = self.builder.call(cha_func, direct_args)
            ret_type = cha_func.return_value.type
            if isinstance(ret_type, ir.VoidType):
                return ir.Constant(i64, 0)
            if not is_double_ret:
                ret_type2 = self._find_method_return_type(attr.value, method)
                if ret_type2 and isinstance(ret_type2, ir.PointerType):
                    result = self._ensure_ptr(result)
                elif (ret_type2 and isinstance(ret_type2, ir.IntType)
                        and ret_type2.width == 32):
                    result = self.builder.trunc(result, i32)
            # CHA: same self-return FpyValue packing as direct dispatch.
            if (isinstance(ret_type, ir.IntType) and ret_type.width == 64
                    and not is_double_ret
                    and self._direct_method_may_return_ptr(None, method)):
                _rt = self.builder.call(self.runtime["get_ret_tag"], [])
                fv = ir.Constant(fpy_val, ir.Undefined)
                fv = self.builder.insert_value(fv, _rt, 0)
                fv = self.builder.insert_value(fv, result, 1)
                return fv
            return result

        # Speculative devirtualization: when only 2-4 classes implement a
        # method, emit a class_id switch with direct calls.  LLVM can
        # inline small method bodies through the switch, eliminating
        # both the vtable load AND the indirect call.
        spec_entries = getattr(self, '_cha_speculative', {}).get(method)
        # Check for mixed return types among speculative entries — if
        # some methods return double and others return i64, fall through
        # to runtime dispatch which handles type tags correctly.
        if spec_entries is not None and len(spec_entries) > 1:
            _ret_types_sd = {f.return_value.type for _, f in spec_entries}
            if len(_ret_types_sd) > 1:
                spec_entries = None  # mixed return types, skip SD
        if spec_entries is not None and not method_mixed and n_dispatch_args <= 4:
            # Extract class_id from obj.
            _obj_typed = self.builder.bitcast(obj, fpy_obj_ptr)
            _f4_ptr = self.builder.gep(
                _obj_typed,
                [ir.Constant(i32, 0), ir.Constant(i32, 4)],
                inbounds=True)
            _f4 = self.builder.load(_f4_ptr, name="sd.magic_cid")
            _cid64 = self.builder.lshr(_f4, ir.Constant(i64, 32))
            _cid = self.builder.trunc(_cid64, i32, name="sd.cid")

            if is_double_ret:
                ret_t = ir.DoubleType()
            else:
                ret_t = i64

            bb_fallback = self.builder.append_basic_block("sd.fallback")
            bb_merge = self.builder.append_basic_block("sd.merge")

            # Build one basic block per unique (class_id, func) pair.
            # Multiple class IDs may share the same function (inherited).
            # Group entries by function identity so each function body
            # appears only once with multiple branch-to entries.
            from collections import OrderedDict
            _func_groups: OrderedDict[int, tuple] = OrderedDict()
            for cid_gvar, func in spec_entries:
                fid = id(func)
                if fid not in _func_groups:
                    _func_groups[fid] = (func, [], None)  # (func, cid_gvars, bb)
                _func_groups[fid][1].append(cid_gvar)

            cases = []   # (cid_ir_val, bb) for switch
            phi_in = []  # (result, bb) for merge PHI

            for fid in _func_groups:
                func, cid_gvars, _ = _func_groups[fid]
                bb = self.builder.append_basic_block(f"sd.cls.{func.name.split('.')[-2]}")
                _func_groups[fid] = (func, cid_gvars, bb)
                for cid_gvar in cid_gvars:
                    cid_val = self.builder.load(cid_gvar)
                    cases.append((cid_val, bb))

            # Emit the switch (compare chain since llvmlite's switch
            # requires compile-time constants but class IDs are runtime).
            cur_bb = self.builder.block
            for cid_val, target_bb in cases:
                cmp = self.builder.icmp_unsigned(
                    "==", _cid, cid_val, name="sd.eq")
                next_bb = self.builder.append_basic_block("sd.next")
                self.builder.cbranch(cmp, target_bb, next_bb)
                self.builder.position_at_end(next_bb)
            # Last "next" block falls through to fallback.
            self.builder.branch(bb_fallback)

            # Emit direct call for each unique function.
            for fid, (func, cid_gvars, sd_bb) in _func_groups.items():
                self.builder.position_at_end(sd_bb)
                # Coerce args to match the method's parameter types.
                direct_args = [obj]
                for i, val in enumerate(call_args):
                    if 1 + i >= len(func.args):
                        break
                    expected = func.args[1 + i].type
                    v = val
                    if v.type != expected:
                        if (isinstance(expected, ir.IntType)
                                and isinstance(v.type, ir.IntType)):
                            if expected.width > v.type.width:
                                v = self.builder.zext(v, expected)
                            else:
                                v = self.builder.trunc(v, expected)
                        elif (isinstance(expected, ir.PointerType)
                                and isinstance(v.type, ir.IntType)):
                            v = self.builder.inttoptr(v, expected)
                        elif (isinstance(expected, ir.IntType)
                                and isinstance(v.type, ir.PointerType)):
                            v = self.builder.ptrtoint(v, expected)
                        elif (isinstance(expected, ir.DoubleType)
                                and isinstance(v.type, ir.IntType)):
                            v = self.builder.bitcast(v, expected)
                        elif (isinstance(expected, ir.IntType)
                                and isinstance(v.type, ir.DoubleType)):
                            v = self.builder.bitcast(v, expected)
                    direct_args.append(v)
                call_res = self.builder.call(func, direct_args)
                # Coerce return value to match ret_t.
                fret = func.return_value.type
                if isinstance(fret, ir.VoidType):
                    call_res = ir.Constant(ret_t, 0)
                elif fret != ret_t:
                    if (isinstance(ret_t, ir.IntType)
                            and isinstance(fret, ir.PointerType)):
                        call_res = self.builder.ptrtoint(call_res, ret_t)
                    elif (isinstance(ret_t, ir.IntType)
                            and isinstance(fret, ir.DoubleType)):
                        call_res = self.builder.bitcast(call_res, ret_t)
                    elif (isinstance(ret_t, ir.DoubleType)
                            and isinstance(fret, ir.IntType)):
                        call_res = self.builder.bitcast(call_res, ret_t)
                    elif (isinstance(ret_t, ir.IntType)
                            and isinstance(fret, ir.IntType)
                            and fret.width != ret_t.width):
                        if ret_t.width > fret.width:
                            call_res = self.builder.zext(call_res, ret_t)
                        else:
                            call_res = self.builder.trunc(call_res, ret_t)
                bb_end = self.builder.block
                self.builder.branch(bb_merge)
                phi_in.append((call_res, bb_end))

            # Fallback: vtable or string dispatch.
            self.builder.position_at_end(bb_fallback)
            vtable_slot = getattr(self, '_vtable_indices', {}).get(method)
            if vtable_slot is not None:
                fb_ptr = self._emit_inline_vtable_lookup(
                    obj, vtable_slot, unchecked=False)
                null_p = ir.Constant(i8_ptr, None)
                is_null_fb = self.builder.icmp_unsigned("==", fb_ptr, null_p)
                bb_vt_call = self.builder.append_basic_block("sd.vt.call")
                bb_str_fb = self.builder.append_basic_block("sd.str.fb")
                self.builder.cbranch(is_null_fb, bb_str_fb, bb_vt_call)

                self.builder.position_at_end(bb_vt_call)
                ftype = ir.FunctionType(ret_t, [i8_ptr] + [i64] * n_dispatch_args)
                func_typed = self.builder.bitcast(fb_ptr, ir.PointerType(ftype))
                vt_res = self.builder.call(func_typed, [obj] + call_args)
                bb_vt_end = self.builder.block
                self.builder.branch(bb_merge)
                phi_in.append((vt_res, bb_vt_end))

                self.builder.position_at_end(bb_str_fb)
                str_res = self._emit_string_method_dispatch(
                    obj, method_name_ptr, call_args, n_dispatch_args,
                    is_double_ret, node)
                if str_res is None:
                    str_res = ir.Constant(ret_t, 0)
                bb_str_end = self.builder.block
                self.builder.branch(bb_merge)
                phi_in.append((str_res, bb_str_end))
            else:
                str_res = self._emit_string_method_dispatch(
                    obj, method_name_ptr, call_args, n_dispatch_args,
                    is_double_ret, node)
                if str_res is None:
                    str_res = ir.Constant(ret_t, 0)
                bb_str_end = self.builder.block
                self.builder.branch(bb_merge)
                phi_in.append((str_res, bb_str_end))

            self.builder.position_at_end(bb_merge)
            result = self.builder.phi(ret_t, name="sd.result")
            for val, blk in phi_in:
                result.add_incoming(val, blk)

            if not is_double_ret:
                ret_type = self._find_method_return_type(attr.value, method)
                if ret_type and isinstance(ret_type, ir.PointerType):
                    result = self._ensure_ptr(result)
                elif (ret_type and isinstance(ret_type, ir.IntType)
                        and ret_type.width == 32):
                    result = self.builder.trunc(result, i32)
            return result

        # Vtable fast-path: if the method name has a vtable slot, try O(1)
        # dispatch first.  Falls back to string-based obj_call_methodN when
        # the vtable returns NULL (method not on this specific class's
        # hierarchy — possible because vtable slot indices are shared
        # across all class hierarchies).
        # Skip vtable dispatch when methods have mixed return types
        # (some return double, others i64).  The vtable call would use
        # the wrong calling convention for one of the types.
        vtable_slot = getattr(self, '_vtable_indices', {}).get(method)
        _mixed_ret = False
        if vtable_slot is not None:
            _ret_types_vt = set()
            for _ci in self._user_classes.values():
                if method in _ci.methods:
                    _ret_types_vt.add(type(_ci.methods[method].return_value.type))
            if len(_ret_types_vt) > 1:
                _mixed_ret = True
                vtable_slot = None
        if vtable_slot is not None and n_dispatch_args <= 4:
            # Inline vtable lookup — checked, because the receiver's class
            # is unknown at compile time and may lack this vtable slot.
            func_ptr = self._emit_inline_vtable_lookup(
                obj, vtable_slot, unchecked=False)
            null_ptr = ir.Constant(i8_ptr, None)
            is_null = self.builder.icmp_unsigned("==", func_ptr, null_ptr)

            bb_vtable = self.builder.append_basic_block("vt.dispatch")
            bb_fallback = self.builder.append_basic_block("vt.fallback")
            bb_merge = self.builder.append_basic_block("vt.merge")
            self.builder.cbranch(is_null, bb_fallback, bb_vtable)

            # ── vtable hit: call directly ──
            self.builder.position_at_end(bb_vtable)
            if is_double_ret:
                ret_t = ir.DoubleType()
            else:
                ret_t = i64
            ftype = ir.FunctionType(
                ret_t, [i8_ptr] + [i64] * n_dispatch_args)
            func_typed = self.builder.bitcast(
                func_ptr, ir.PointerType(ftype))
            vt_result = self.builder.call(
                func_typed, [obj] + call_args)
            bb_vt_end = self.builder.block  # may differ after call
            self.builder.branch(bb_merge)

            # ── vtable miss: string-based fallback ──
            self.builder.position_at_end(bb_fallback)
            fb_result = self._emit_string_method_dispatch(
                obj, method_name_ptr, call_args, n_dispatch_args,
                is_double_ret, node)
            if fb_result is None:
                # bridge fallback path — can't merge
                self.builder.position_at_end(bb_merge)
                return vt_result
            bb_fb_end = self.builder.block
            self.builder.branch(bb_merge)

            # ── merge ──
            self.builder.position_at_end(bb_merge)
            result = self.builder.phi(ret_t, name="vt.result")
            result.add_incoming(vt_result, bb_vt_end)
            result.add_incoming(fb_result, bb_fb_end)
        else:
            # When return types are mixed across the hierarchy, always use
            # the i64 dispatch.  obj_call_method0 already checks return_tag
            # and uses the correct calling convention for double-returning
            # methods (reads XMM0 then bitcasts to i64).  Using the _double
            # variant would break for classes that return i64 (ABI mismatch:
            # expects XMM0 but method returns in RAX).
            _dispatch_double = is_double_ret and not _mixed_ret
            result = self._emit_string_method_dispatch(
                obj, method_name_ptr, call_args, n_dispatch_args,
                _dispatch_double, node)
            if result is None:
                return self._bridge_fallback_expr(
                    node, f"method call with {n_dispatch_args} args (max 4)")

        # Mixed return types: wrap as FpyValue with runtime tag so
        # downstream code (print, assignment, etc.) handles the actual
        # type correctly.
        if _mixed_ret:
            _rt = self.builder.call(self.runtime["get_ret_tag"], [])
            fv = self._fv_build_from_slots(_rt, result)
            return fv

        # Check if the method returns a string or bool — cast from i64
        if not is_double_ret:
            ret_type = self._find_method_return_type(attr.value, method)
            if ret_type and isinstance(ret_type, ir.PointerType):
                result = self._ensure_ptr(result)
            elif ret_type and isinstance(ret_type, ir.IntType) and ret_type.width == 32:
                result = self.builder.trunc(result, i32)
        return result


    def _emit_string_method_dispatch(self, obj, method_name_ptr,
                                      call_args, n_dispatch_args,
                                      is_double_ret, node):
        """Emit the old string-based obj_call_methodN dispatch.

        Returns the LLVM result value, or None if the arg count exceeds
        the supported maximum (caller should use bridge fallback).
        """
        if n_dispatch_args == 0:
            if is_double_ret:
                return self.builder.call(
                    self.runtime["obj_call_method0_double"],
                    [obj, method_name_ptr])
            return self.builder.call(
                self.runtime["obj_call_method0"],
                [obj, method_name_ptr])
        elif n_dispatch_args == 1:
            if is_double_ret:
                return self.builder.call(
                    self.runtime["obj_call_method1_double"],
                    [obj, method_name_ptr, call_args[0]])
            return self.builder.call(
                self.runtime["obj_call_method1"],
                [obj, method_name_ptr, call_args[0]])
        elif n_dispatch_args == 2:
            return self.builder.call(
                self.runtime["obj_call_method2"],
                [obj, method_name_ptr, call_args[0], call_args[1]])
        elif n_dispatch_args == 3:
            return self.builder.call(
                self.runtime["obj_call_method3"],
                [obj, method_name_ptr,
                 call_args[0], call_args[1], call_args[2]])
        elif n_dispatch_args == 4:
            return self.builder.call(
                self.runtime["obj_call_method4"],
                [obj, method_name_ptr,
                 call_args[0], call_args[1], call_args[2], call_args[3]])
        return None  # unsupported arg count

    # ---- String method dispatch table (B3) ----
    _STR_METHOD_DISPATCH = {
        # Zero-arg methods (no arg-count check, just pass [obj])
        "lower": ("str_lower",),
        "upper": ("str_upper",),
        "isdigit": ("str_isdigit",),
        "isalpha": ("str_isalpha",),
        "isalnum": ("str_isalnum",),
        "isspace": ("str_isspace",),
        "capitalize": ("str_capitalize",),
        "title": ("str_title",),
        "swapcase": ("str_swapcase",),
        "splitlines": ("str_splitlines",),
        "encode": ("str_encode",),
        # Zero-arg methods (with arg-count check)
        "isupper": ("str_isupper", 0),
        "islower": ("str_islower", 0),
        "istitle": ("str_istitle", 0),
        "isidentifier": ("str_isidentifier", 0),
        "isprintable": ("str_isprintable", 0),
        "isdecimal": ("str_isdecimal", 0),
        "isnumeric": ("str_isnumeric", 0),
        "casefold": ("str_casefold", 0),
        # One-arg methods (check exactly 1 arg)
        "join": ("str_join", 1),
        "partition": ("str_partition", 1),
        "rpartition": ("str_rpartition", 1),
        "zfill": ("str_zfill", 1),
        "removeprefix": ("str_removeprefix", 1),
        "removesuffix": ("str_removesuffix", 1),
        "translate": ("str_translate", 1),
        # Complex methods -> handler
        "strip": "_emit_str_method_strip",
        "lstrip": "_emit_str_method_lstrip",
        "rstrip": "_emit_str_method_rstrip",
        "center": "_emit_str_method_center",
        "ljust": "_emit_str_method_ljust",
        "rjust": "_emit_str_method_rjust",
        "expandtabs": "_emit_str_method_expandtabs",
        "split": "_emit_str_method_split",
        "rsplit": "_emit_str_method_rsplit",
        "replace": "_emit_str_method_replace",
        "startswith": "_emit_str_method_startswith",
        "endswith": "_emit_str_method_endswith",
        "find": "_emit_str_method_find",
        "rfind": "_emit_str_method_rfind",
        "index": "_emit_str_method_index",
        "rindex": "_emit_str_method_rindex",
        "count": "_emit_str_method_count",
        "format": "_emit_str_format",
    }

    def _emit_method_call_str(self, node, obj):
        """Emit string method calls via dispatch table. Returns None if not recognized."""
        method = node.func.attr
        # str.join(obj_iter): materialize generator/iterator to list first
        if (method == "join" and len(node.args) == 1
                and self._is_obj_expr(node.args[0])):
            _jobj = self._emit_expr_value(node.args[0])
            _jobj = self._ensure_ptr(_jobj)
            lst = self._rt_call("list_from_obj_iter", [_jobj])
            return self._rt_call("str_join", [obj, lst])
        entry = self._STR_METHOD_DISPATCH.get(method)
        if entry is None:
            return None
        if isinstance(entry, str):
            return getattr(self, entry)(node, obj)
        # Data entry: (rt_func,) or (rt_func, nargs)
        rt_func = entry[0]
        if len(entry) > 1:
            nargs = entry[1]
            if len(node.args) != nargs:
                return None
            args = [obj] + [self._emit_expr_value(node.args[i])
                            for i in range(nargs)]
        else:
            args = [obj]
        return self._rt_call(rt_func, args)

    # ---- String method handlers (B3) ----

    def _emit_str_method_strip(self, node, obj):
        if len(node.args) == 1:
            chars = self._emit_expr_value(node.args[0])
            return self._rt_call("str_strip_chars", [obj, chars])
        return self._rt_call("str_strip", [obj])

